class RulerWidget(tk.Canvas):

    """

    Widget de régua visual com ponteiros ajustáveis para representar detalhes de grades

    e ranges para parafusos

    """

    def __init__(self, parent, grade_value=0, max_value=200, width=400, height=60, max_pointers=5, **kwargs):

        super().__init__(parent, width=width, height=height, **kwargs)

        

        self.grade_value = grade_value

        self.max_value = max_value

        self.width = width

        self.height = height

        self.max_pointers = max_pointers

        

        # Lista de ponteiros (posições dos detalhes) - suportando até max_pointers

        self.pointers = [0] * self.max_pointers

        self.pointer_radius = 8

        self.pointer_colors = ['#45B7D1', '#45B7D1', '#45B7D1', '#45B7D1', '#45B7D1']  # Todos azuis

        

        # Lista de ranges de parafusos (posições dos parafusos com margem de 3cm)

        self.parafuso_ranges = []  # Lista de tuplas (posição, margem_esquerda, margem_direita)

        self.parafuso_margin = 3  # Margem de 3cm para cada lado

        

        # Ponteiros de distância (posições absolutas das distâncias 1 e 2)

        self.distance_pointers = []  # Lista de floats
        
        # Lista de ranges de aberturas (posição, largura, lado)
        # Formato: [(posicao, largura, lado), ...] onde lado é 'esquerda' ou 'direita'
        self.abertura_ranges = []  # Lista de tuplas (posição, largura, lado, cor)

        

        # Variáveis para arrastar ponteiros

        self.dragging = False

        self.drag_pointer = None

        self.drag_start_x = 0

        

        # Callback para atualizar campos quando ponteiros mudam

        self.on_pointer_change = None

        

        # Configurar eventos

        self.bind('<Button-1>', self.on_click)

        self.bind('<B1-Motion>', self.on_drag)

        self.bind('<ButtonRelease-1>', self.on_release)

        

        # Desenhar a régua

        self.draw_ruler()

    

    def set_grade_value(self, value):

        """Define o valor da grade e recalcula as posições dos ponteiros"""

        self.grade_value = value

        self.calculate_pointer_positions()

        self.draw_ruler()

    

    def set_pointers(self, detail_values):

        """Define os valores dos detalhes e posiciona os ponteiros"""

        # Trabalhar com a quantidade configurada de ponteiros (ex.: 15)

        for i in range(self.max_pointers):

            if i < len(detail_values):

                self.pointers[i] = detail_values[i]

            else:

                self.pointers[i] = 0

        self.draw_ruler()

    

    def set_parafuso_ranges(self, parafuso_positions):

        """Define as posições dos parafusos e cria ranges com margem de 3cm"""


        # Normalizar e aplicar regra: se houver apenas 1 parafuso válido, não exibir

        valid_positions = [pos for pos in parafuso_positions if pos > 0]


        # Verificar se deve exibir baseado na quantidade ORIGINAL de parafusos

        if len(valid_positions) <= 1:

            # Se há 1 ou menos parafusos válidos, não exibir

            pass

            self.parafuso_ranges = []

            self.draw_ruler()

            return

        # Aplicar regra de desconsiderar último parafuso APÓS verificar se deve exibir

        if len(valid_positions) >= 2:

            # Desconsiderar o último parafuso preenchido (igual às grades E e F)

            valid_positions = valid_positions[:-1]



        self.parafuso_ranges = []

        for pos in valid_positions:

            left_margin = max(0, pos - self.parafuso_margin)

            right_margin = pos + self.parafuso_margin

            self.parafuso_ranges.append((pos, left_margin, right_margin))


        self.draw_ruler()



    def set_parafuso_ranges_allow_single(self, parafuso_positions, letra=None):

        """Define as posições dos parafusos permitindo exibir quando há apenas 1 válido.

        Mantém a mesma lógica de margens de 3cm. A regra de desconsiderar o último
        parafuso é aplicada APENAS para Grades E e F, NÃO para Grades A e B.
        """


        valid_positions = [pos for pos in parafuso_positions if pos > 0]


        # Se não há nenhum parafuso válido, limpar e sair
        if len(valid_positions) == 0:
            self.parafuso_ranges = []
            self.draw_ruler()
            return

        # Aplicar regra de desconsiderar o último parafuso APENAS para Grades E e F
        if len(valid_positions) >= 2 and letra and letra.lower() in ['e', 'f']:
            valid_positions = valid_positions[:-1]
        elif len(valid_positions) >= 2 and letra and letra.lower() in ['a', 'b']:
            pass


        self.parafuso_ranges = []

        for pos in valid_positions:
            left_margin = max(0, pos - self.parafuso_margin)
            right_margin = pos + self.parafuso_margin
            self.parafuso_ranges.append((pos, left_margin, right_margin))

        self.draw_ruler()



    def set_distance_pointers(self, distance_positions):

        """Define as posições absolutas das distâncias para desenhar ponteiros de distância"""

        self.distance_pointers = [p for p in distance_positions if p >= 0]

        self.draw_ruler()

    

    def calculate_pointer_positions(self):

        """Calcula as posições dos ponteiros baseado nos valores dos detalhes"""

        if self.grade_value <= 0:

            return

        

        # Calcular detalhes usando a lógica original

        try:

            detalhes = self.calcular_detalhes_com_logica_original(self.grade_value)

            self.pointers = detalhes[:self.max_pointers]

        except:

            # Se não conseguir calcular, usar valores padrão

            self.pointers = [0] * self.max_pointers

    

    # Função movida para classe PilarAnalyzer para ser acessível em todo o sistema

    

    def draw_ruler(self):

        """Desenha a régua visual com marcações, ponteiros e ranges de parafusos"""

        self.delete("all")

        

        # Desenhar fundo da régua

        self.create_rectangle(10, 20, self.width - 10, self.height - 20, 

                            fill='#F8F9FA', outline='#DEE2E6', width=2)

        

        # Desenhar linha central

        center_y = self.height // 2

        self.create_line(10, center_y, self.width - 10, center_y, 

                        fill='#6C757D', width=1)

        

        # Desenhar marcações da régua

        self.draw_scale_marks()

        

        # Desenhar ranges de parafusos (antes dos ponteiros para ficar atrás)

        self.draw_parafuso_ranges()
        
        

        # Desenhar ponteiros de distância (após parafusos, antes dos detalhes)

        self.draw_distance_pointers()
        
        

        # Desenhar ponteiros (antes das aberturas)

        self.draw_pointers()
        
        # Desenhar ranges de aberturas POR ÚLTIMO para ficarem visíveis acima de tudo
        self.draw_abertura_ranges()

        

        # Desenhar valor da grade

        self.create_text(self.width // 2, 10, text=f"Grade: {self.grade_value:.1f}cm", 

                        font=('Arial', 8, 'bold'), fill='#495057')

    

    def draw_parafuso_ranges(self):

        """Desenha os parafusos como ponteiros vermelhos com retângulo de 3cm"""

        if not self.parafuso_ranges or self.max_value <= 0:

            return

        

        center_y = self.height // 2

        ruler_width = self.width - 20

        

        for i, (pos, left_margin, right_margin) in enumerate(self.parafuso_ranges):

            # Calcular posições X na régua

            left_x = 10 + (ruler_width * left_margin / self.max_value)

            right_x = 10 + (ruler_width * right_margin / self.max_value)

            center_x = 10 + (ruler_width * pos / self.max_value)

            

            # Desenhar retângulo vermelho (3cm em cada direção)

            self.create_rectangle(left_x, center_y - 12, right_x, center_y + 12,

                                fill='#FF6B6B', outline='#E53E3E', width=2, tags=f"parafuso_{i}")

            

            # Desenhar linha central do parafuso (mais escura)

            self.create_line(center_x, center_y - 15, center_x, center_y + 15,

                           fill='#C53030', width=3, tags=f"parafuso_line_{i}")

            

            # Adicionar texto com posição do parafuso

            self.create_text(center_x, center_y - 25, text=f"{pos:.1f}",

                           font=('Arial', 7, 'bold'), fill='#C53030', tags=f"parafuso_text_{i}")

    def set_abertura_ranges(self, aberturas_list):
        """Define as posições das aberturas para desenhar blocos
        Formato: [(posicao, largura, lado, cor), ...]
        onde lado é 'esquerda' ou 'direita' e cor é 'verde' ou 'roxo'
        """
        self.abertura_ranges = aberturas_list
        self.draw_ruler()

    def draw_abertura_ranges(self):
        """Desenha os blocos das aberturas (verde para lado A, roxo para lado B)"""
        
        if not self.abertura_ranges or self.max_value <= 0:
            return
        
        center_y = self.height // 2
        ruler_width = self.width - 20
        
        for i, (posicao, largura, lado, cor) in enumerate(self.abertura_ranges):
            if posicao < 0 or largura <= 0:  # Posição pode ser 0 (encostado na parede), mas largura deve ser > 0
                continue
            
            # Ajustar largura visual na régua baseado na distância (apenas visual, não altera dados reais)
            # Se distância = 0: soma 3 na largura exibida
            # Se distância > 0: soma 6 na largura exibida
            if posicao == 0:
                largura_visual = largura + 3
            else:
                largura_visual = largura + 6
            
            # Calcular posições X na régua
            # posicao é a distância da esquerda (se lado='esquerda') ou da direita (se lado='direita')
            if lado == 'esquerda':
                # Abertura esquerda: posição começa da esquerda da régua
                left_x = 10 + (ruler_width * posicao / self.max_value)
                right_x = left_x + (ruler_width * largura_visual / self.max_value)
            else:  # lado == 'direita'
                # Abertura direita: posição começa da direita da régua (invertido)
                right_x = (self.width - 10) - (ruler_width * posicao / self.max_value)
                left_x = right_x - (ruler_width * largura_visual / self.max_value)
            
            # Limitar dentro da régua (garantir que não ultrapasse os limites)
            left_x = max(10, min(self.width - 10, left_x))
            right_x = max(10, min(self.width - 10, right_x))
            
            # Garantir que left_x < right_x
            if left_x >= right_x:
                continue
            
            # Definir cor baseado no parâmetro e posição Y
            # Aberturas verdes (lado A): topo da régua (mais fino)
            # Aberturas roxas (lado B): fundo da régua (mais fino)
            if cor == 'verde':
                fill_color = '#4CAF50'  # Verde
                outline_color = '#2E7D32'  # Verde escuro
                # Abertura A no topo: center_y - 10 até center_y - 6 (4px de altura)
                y1 = center_y - 10
                y2 = center_y - 6
            else:  # cor == 'roxo'
                fill_color = '#9C27B0'  # Roxo
                outline_color = '#6A1B9A'  # Roxo escuro
                # Abertura B no fundo: center_y + 6 até center_y + 10 (4px de altura)
                y1 = center_y + 6
                y2 = center_y + 10
            
            # Desenhar retângulo da abertura (muito fino em Y para permitir visualização de ambas)
            # Parafusos: center_y - 12 até center_y + 12 (24px de altura)
            # Aberturas A (verde): center_y - 10 até center_y - 6 (4px de altura - topo)
            # Aberturas B (roxo): center_y + 6 até center_y + 10 (4px de altura - fundo)
            rect_id = self.create_rectangle(left_x, y1, right_x, y2,
                                fill=fill_color, outline=outline_color, width=1, 
                                tags=f"abertura_{i}")
            # Garantir que o retângulo fique visível acima de outros elementos
            self.tag_raise(f"abertura_{i}")

    def draw_distance_pointers(self):

        """Desenha ponteiros das distâncias como linhas verdes
        Desenha labels DIST1/DIST2 lado A (acima) e lado B (abaixo, espelhado)"""

        if not self.distance_pointers or self.max_value <= 0:

            return

        center_y = self.height // 2

        ruler_width = self.width - 20

        # Primeiro, desenhar todas as distâncias e labels lado A
        for idx, pos in enumerate(self.distance_pointers):

            if pos <= 0:  # Só desenhar se posição > 0
                continue
                
            x = 10 + (ruler_width * pos / self.max_value)

            x = max(10, min(self.width - 10, x))

            # linha verde sutil

            self.create_line(x, center_y - 18, x, center_y + 18, fill='#2F9E44', width=2, dash=(3,2), tags=f"dist_{idx}")

            # Label DIST lado A (acima)
            dist_num = idx + 1  # DIST1 ou DIST2
            self.create_text(x, center_y + 24, text=f"DIST{dist_num}", font=('Arial', 6, 'bold'), fill='#2F9E44', tags=f"dist_{idx}_label_a")
        
        # Agora, desenhar labels lado B (espelhado)
        total_dists = len(self.distance_pointers)
        for idx, pos in enumerate(self.distance_pointers):
            if pos <= 0:
                continue
                
            # Usar a MESMA posição X da distância atual (alinhado verticalmente com lado A)
            x = 10 + (ruler_width * pos / self.max_value)
            x = max(10, min(self.width - 10, x))
                
            # Calcular índice invertido: a distância que deve aparecer espelhada
            # DIST1(0) → DIST2(1) invertido, DIST2(1) → DIST1(0) invertido
            idx_invertido = total_dists - 1 - idx
            
            # Verificar se a distância invertida tem posição > 0
            if idx_invertido < len(self.distance_pointers) and self.distance_pointers[idx_invertido] > 0:
                dist_num_inv = idx_invertido + 1
                
                # Desenhar label lado B na MESMA posição X da distância atual (abaixo do label lado A)
                self.create_text(x, center_y + 39, text=f"DIST{dist_num_inv}", font=('Arial', 6, 'bold'), fill='#9C27B0', tags=f"dist_{idx_invertido}_label_b")

    

    def draw_scale_marks(self):

        """Desenha as marcações da escala com suporte a números fracionados"""

        center_y = self.height // 2

        ruler_width = self.width - 20

        

        # Calcular intervalo inteligente baseado no valor máximo

        if self.max_value <= 50:

            # Para valores pequenos: marcas a cada 10cm

            interval = 10

            num_marks = int(self.max_value / interval) + 1

        elif self.max_value <= 100:

            # Para valores médios: marcas a cada 20cm

            interval = 20

            num_marks = int(self.max_value / interval) + 1

        else:

            # Para valores grandes: marcas a cada 25cm

            interval = 25

            num_marks = int(self.max_value / interval) + 1

        

        # Desenhar marcações principais

        for i in range(num_marks):

            value = i * interval

            if value > self.max_value:

                break

                

            x = 10 + (ruler_width * value / self.max_value)

            

            # Linha principal

            self.create_line(x, center_y - 8, x, center_y + 8, 

                           fill='#6C757D', width=2)

            

            # Valor (mostrar decimais se necessário)

            if value % 1 == 0:

                text_value = f"{int(value)}"

            else:

                text_value = f"{value:.1f}"

            

            self.create_text(x, center_y + 15, text=text_value, 

                           font=('Arial', 7), fill='#6C757D')

        

        # Marcações menores (a cada 5cm ou 10cm dependendo do intervalo)

        minor_interval = interval / 2

        for i in range(1, int(self.max_value / minor_interval) + 1):

            value = i * minor_interval

            if value > self.max_value or value % interval == 0:

                continue

                

            x = 10 + (ruler_width * value / self.max_value)

            self.create_line(x, center_y - 4, x, center_y + 4, 

                           fill='#ADB5BD', width=1)

    

    def draw_pointers(self):

        """Desenha os ponteiros na régua - apenas linhas verticais quando valor > 0
        Desenha labels lado A (acima) e lado B (abaixo, espelhado)"""

        center_y = self.height // 2

        ruler_width = self.width - 20

        # Primeiro, desenhar todos os ponteiros e labels lado A
        for i, value in enumerate(self.pointers):

            if value > 0:  # Só desenhar ponteiro se valor for maior que 0

                # Calcular posição X baseada no valor

                x = 10 + (ruler_width * value / self.max_value)

                x = max(10, min(self.width - 10, x))  # Limitar dentro da régua

                

                # Desenhar apenas linha vertical (sem bolinha)

                color = self.pointer_colors[i % len(self.pointer_colors)]

                self.create_line(x, center_y - 15, 

                               x, center_y + 15,

                               fill=color, width=2, tags=f"pointer_{i}")

                

                # Valor do detalhe

                self.create_text(x, center_y - self.pointer_radius - 15, 

                               text=f"{value:.1f}", font=('Arial', 7, 'bold'), 

                               fill=color, tags=f"pointer_{i}")

                

                # Label do campo (Grade e Detalhe) - LADO A (acima)
                grade_num = (i // 5) + 1  # Grade 1, 2 ou 3
                detalhe_num = (i % 5) + 1  # Detalhe 1, 2, 3, 4 ou 5
                self.create_text(x, center_y + self.pointer_radius + 15, 
                               text=f"G{grade_num}D{detalhe_num}", font=('Arial', 6), 
                               fill=color, tags=f"pointer_{i}_label_a")
        
        # Agora, desenhar labels lado B (espelhado)
        # Reestruturação completa: para cada ponteiro do lado A que existe, sempre desenhar um label do lado B na MESMA POSIÇÃO X
        # Se o ponteiro invertido ideal não existir, usar o último ponteiro disponível do lado B
        if self.max_value > 0:
            total_pointers = len(self.pointers)
            
            # Coletar todos os ponteiros do lado B que existem (na ordem invertida)
            ponteiros_b_disponiveis = []
            for j in range(len(self.pointers) - 1, -1, -1):
                if self.pointers[j] > 0:
                    ponteiros_b_disponiveis.append(j)
            
            # Set para rastrear quais ponteiros do lado B já foram usados (evitar duplicatas)
            ponteiros_b_usados = set()
            
            # Iterar pelos ponteiros do lado A na ordem normal
            for i, value in enumerate(self.pointers):
                if value > 0:
                    # Calcular posição X do ponteiro do lado A
                    x = 10 + (ruler_width * value / self.max_value)
                    x = max(10, min(self.width - 10, x))
                    
                    # Calcular índice invertido ideal: o ponteiro que deveria aparecer espelhado nesta posição
                    # Sequência lado A: G1D1(0) G1D2(1) ... G1D5(4) G2D1(5) ... G2D5(9) G3D1(10) ... G3D5(14)
                    # Sequência lado B: G3D5(14) G3D4(13) ... G3D1(10) G2D5(9) ... G2D1(5) G1D5(4) ... G1D1(0)
                    idx_invertido_ideal = total_pointers - 1 - i
                    
                    # Tentar usar o ponteiro invertido ideal primeiro
                    idx_invertido = None
                    if (idx_invertido_ideal < len(self.pointers) and 
                        self.pointers[idx_invertido_ideal] > 0 and 
                        idx_invertido_ideal not in ponteiros_b_usados):
                        idx_invertido = idx_invertido_ideal
                    else:
                        # Se o ideal não existe ou já foi usado, encontrar o ponteiro invertido mais próximo que existe
                        # Procurar para trás (em direção ao início) primeiro, depois para frente
                        idx_mais_proximo = None
                        menor_distancia = float('inf')
                        
                        for idx_b in ponteiros_b_disponiveis:
                            if idx_b not in ponteiros_b_usados:
                                # Calcular distância do ideal
                                distancia = abs(idx_b - idx_invertido_ideal)
                                if distancia < menor_distancia:
                                    menor_distancia = distancia
                                    idx_mais_proximo = idx_b
                        
                        idx_invertido = idx_mais_proximo
                    
                    # Se encontrou um ponteiro do lado B para usar, desenhar
                    if idx_invertido is not None:
                        # Calcular grade e detalhe do ponteiro invertido
                        grade_num_inv = (idx_invertido // 5) + 1
                        detalhe_num_inv = (idx_invertido % 5) + 1
                        label_text = f"G{grade_num_inv}D{detalhe_num_inv}"
                        
                        # Desenhar label lado B na MESMA posição X do ponteiro do lado A (abaixo do label lado A)
                        self.create_text(x, center_y + self.pointer_radius + 30, 
                                       text=label_text, font=('Arial', 6), 
                                       fill='#9C27B0', tags=f"pointer_{idx_invertido}_label_b")
                        
                        # Marcar como usado
                        ponteiros_b_usados.add(idx_invertido)

    

    def on_click(self, event):

        """Manipula clique do mouse para selecionar ponteiro"""

        x, y = event.x, event.y

        

        # Verificar se clicou em algum ponteiro visível (valor > 0)

        for i, value in enumerate(self.pointers):

            if value > 0:  # Só considerar ponteiros visíveis

                pointer_x = 10 + ((self.width - 20) * value / self.max_value)

                pointer_x = max(10, min(self.width - 10, pointer_x))

                

                # Verificar se o clique está dentro do ponteiro

                if (abs(x - pointer_x) <= self.pointer_radius and 

                    abs(y - self.height // 2) <= self.pointer_radius):

                    self.dragging = True

                    self.drag_pointer = i

                    self.drag_start_x = x

                    break

    

    def on_drag(self, event):

        """Manipula arrastar do ponteiro"""

        if not self.dragging or self.drag_pointer is None:

            return

        

        x = event.x

        x = max(10, min(self.width - 10, x))  # Limitar dentro da régua

        

        # Calcular novo valor baseado na posição

        ruler_width = self.width - 20

        new_value = ((x - 10) / ruler_width) * self.max_value

        new_value = max(0, min(self.max_value, new_value))

        

        # Atualizar valor do ponteiro

        self.pointers[self.drag_pointer] = new_value

        

        # Redesenhar

        self.draw_ruler()

        

        # Chamar callback se definido

        if self.on_pointer_change:

            self.on_pointer_change(self.drag_pointer, new_value)

    

    def on_release(self, event):

        """Manipula soltar do ponteiro"""

        if self.dragging and self.drag_pointer is not None:

            # Chamar callback final se definido

            if self.on_pointer_change:

                self.on_pointer_change(self.drag_pointer, self.pointers[self.drag_pointer])

        

        self.dragging = False

        self.drag_pointer = None

