class PilarAnalyzer(tk.Tk, CanvasPreviewMixin, UtilsMixin, GradeParafusosMixin, PainelControleDesenhoPMixin):

    

    def limpar_todos_campos_especiais(self, letras=None):

        """

        Limpa todos os campos de grades especiais, detalhes, distâncias e parafusos

        

        Args:

            letras: Lista de letras específicas para limpar (ex: ['a', 'b']) 

                   Se None, limpa todas: ['a', 'b', 'e', 'f', 'g', 'h']

        """

        try:

            if letras is None:

                letras = ['a', 'b', 'e', 'f', 'g', 'h']

            


            

            for letra in letras:

                # Limpar grades (1, 2, 3)

                for grade_num in range(1, 4):

                    campo_grade = f"grade_{letra}_{grade_num}"

                    if hasattr(self, campo_grade):

                        getattr(self, campo_grade).delete(0, tk.END)

                        getattr(self, campo_grade).insert(0, "0")

                

                # Limpar distâncias (1, 2)

                for dist_num in range(1, 3):

                    campo_dist = f"dist_{letra}_{dist_num}"

                    if hasattr(self, campo_dist):

                        getattr(self, campo_dist).delete(0, tk.END)

                        getattr(self, campo_dist).insert(0, "0")

                

                # Limpar TODOS os detalhes de TODAS as grades (1, 2, 3) x (1-5 detalhes)

                for grade_num in range(1, 4):

                    for detalhe_num in range(1, 6):

                        campo_detalhe = f"detalhe_{letra}_{grade_num}_{detalhe_num}"

                        if hasattr(self, campo_detalhe):

                            getattr(self, campo_detalhe).delete(0, tk.END)

                            getattr(self, campo_detalhe).insert(0, "0")

                

                # Limpar parafusos especiais (1-9)

                for parafuso_num in range(1, 10):

                    campo_parafuso = f"par_{letra}_{parafuso_num}"

                    if hasattr(self, campo_parafuso):

                        getattr(self, campo_parafuso).delete(0, tk.END)

                        getattr(self, campo_parafuso).insert(0, "0")

            


            

        except Exception as e:

            pass




    def mostrar_janela_config_abcd_frente(self, janela: tk.Toplevel) -> None:
        """Traz a janela de configurações ABCD à frente e aumenta +50px na altura.
        Chame esta função logo após criar a Toplevel das configurações ABCD.
        """
        try:
            janela.update_idletasks()
            geo = janela.geometry()  # 'WxH+X+Y'
            try:
                size, x_str, y_str = geo.split('+')
            except ValueError:
                size, x_str, y_str = geo, None, None
            if 'x' in size:
                w_str, h_str = size.split('x')
                w, h = int(w_str), int(h_str)
                h += 50
                if x_str is not None and y_str is not None:
                    janela.geometry(f"{w}x{h}+{x_str}+{y_str}")
                else:
                    janela.geometry(f"{w}x{h}")

            janela.deiconify()
            janela.lift()
            janela.attributes('-topmost', True)
            janela.focus_force()
            janela.attributes('-topmost', False)
        except Exception:
            try:
                janela.lift()
                janela.focus_force()
            except Exception:
                pass


    def calcular_detalhes_com_logica_original(self, valor_grade):

        """Calcula detalhes usando quantidade necessária de campos para não exceder 33cm"""

        try:

            import math

            

            if valor_grade <= 0:

                return [0, 0, 0, 0, 0]  # 5 detalhes por grade

            

            # Calcular quantidade MÍNIMA de detalhes para que nenhum exceda 33cm

            quantidade_necessaria = math.ceil(valor_grade / 33.0)

            quantidade = min(quantidade_necessaria, 5)  # Máximo 5 campos

            


            

            # Verificar se a grade é inteira ou tem fração

            eh_inteira = abs(valor_grade - round(valor_grade)) < 0.01

            

            if eh_inteira:

                # Grade é inteira - TODOS os detalhes devem ser inteiros

                valor_int = int(round(valor_grade))

                detalhes = [0] * 5  # Inicializar com 5 zeros

                

                # Distribuir de forma equilibrada, todos inteiros

                base = valor_int // quantidade

                resto = valor_int % quantidade

                

                # Preencher com valores base

                for i in range(quantidade):

                    detalhes[i] = base

                

                # Distribuir o resto (1 por vez) de forma equilibrada

                if resto > 0:

                    # Distribuir começando pelos primeiros campos

                    for i in range(resto):

                        detalhes[i] += 1

                


            else:

                # Grade tem fração - fração fica em APENAS UM detalhe

                detalhes = [0] * 5  # Inicializar com 5 zeros

                

                # Distribuir valores inteiros primeiro

                base = int(valor_grade / quantidade)

                resto = valor_grade - (base * quantidade)

                

                # Preencher com valores base

                for i in range(quantidade):

                    detalhes[i] = base

                

                # Adicionar a fração no centro

                centro = quantidade // 2

                detalhes[centro] += resto

                


            

            # VALIDAÇÃO FINAL: Garantir soma exata

            soma_atual = sum(detalhes)

            if abs(soma_atual - valor_grade) > 0.01:

                diferenca = valor_grade - soma_atual


                # Adicionar diferença ao último detalhe preenchido

                for i in range(quantidade - 1, -1, -1):

                    if detalhes[i] > 0:

                        detalhes[i] += diferenca

                        break

            


            return detalhes

            

        except Exception as e:

            pass

            return [0, 0, 0, 0, 0]



    def copiar_do_conjunto1(self):

        """Copia os valores do conjunto 1 para os outros conjuntos"""

        try:

            # Função auxiliar para verificar se um valor é válido (não é 0, não é vazio)
            def eh_valor_valido(valor):
                """Retorna True se o valor for válido (não vazio e não é 0)"""
                if not valor or not valor.strip():
                    return False
                valor_limpo = valor.strip()
                # Verificar se é "0" ou 0 numérico
                try:
                    if float(valor_limpo) == 0:
                        return False
                except (ValueError, TypeError):
                    pass
                return True

            

            # Obter valores do conjunto 1

            grade1_valor = self.grade_1.get().strip()

            grade2_valor = self.grade_2.get().strip()

            grade3_valor = self.grade_3.get().strip()

            dist1_valor = self.distancia_1.get().strip()

            dist2_valor = self.distancia_2.get().strip()

            

            # Copiar detalhes da grade 1 (manter valores originais, incluindo 0)
            # A validação será feita apenas na inversão e cópia
            detalhes_grade1 = []

            for i in range(1, 6):

                campo = getattr(self, f"detalhe_grade1_{i}", None)

                if campo:

                    detalhes_grade1.append(campo.get().strip())

            

            # Copiar detalhes da grade 2 (manter valores originais, incluindo 0)
            detalhes_grade2 = []

            for i in range(1, 6):

                campo = getattr(self, f"detalhe_grade2_{i}", None)

                if campo:

                    detalhes_grade2.append(campo.get().strip())

            

            # Copiar detalhes da grade 3 (manter valores originais, incluindo 0)
            detalhes_grade3 = []

            for i in range(1, 6):

                campo = getattr(self, f"detalhe_grade3_{i}", None)

                if campo:

                    detalhes_grade3.append(campo.get().strip())

            

            # COPIAR PARA O CONJUNTO 2 (GRUPO 2) COM INVERSÃO (ESPELHADO)
            
            # ===== VERIFICAR QUAIS GRADES ESTÃO ATIVAS =====
            # Uma grade está ativa se tem valor válido OU tem pelo menos um detalhe válido
            def grade_esta_ativa(grade_valor, detalhes_grade):
                """Verifica se uma grade está ativa (tem valor válido ou detalhes válidos)"""
                if eh_valor_valido(grade_valor):
                    return True
                # Verificar se tem pelo menos um detalhe válido
                for detalhe in detalhes_grade:
                    if eh_valor_valido(detalhe):
                        return True
                return False
            
            grade1_ativa = grade_esta_ativa(grade1_valor, detalhes_grade1)
            grade2_ativa = grade_esta_ativa(grade2_valor, detalhes_grade2)
            grade3_ativa = grade_esta_ativa(grade3_valor, detalhes_grade3)
            
            # Contar quantas grades estão ativas
            grades_ativas = []
            if grade1_ativa:
                grades_ativas.append(1)
            if grade2_ativa:
                grades_ativas.append(2)
            if grade3_ativa:
                grades_ativas.append(3)
            
            num_grades_ativas = len(grades_ativas)
            
            # ===== INVERSÃO DINÂMICA BASEADA NAS GRADES ATIVAS =====
            # Se apenas 1 grade ativa: ela vai para a Grade 1 do Conjunto 2
            # Se 2 grades ativas: elas invertem entre si (1↔2, 1↔3, ou 2↔3)
            # Se 3 grades ativas: Grade 1↔Grade 3, Grade 2 permanece, Grade 3↔Grade 1
            
            # Inicializar valores invertidos como vazios
            grade1_invertido = ""
            grade2_invertido = ""
            grade3_invertido = ""
            
            if num_grades_ativas == 1:
                # Apenas 1 grade ativa: vai para Grade 1 do Conjunto 2
                if grade1_ativa:
                    grade1_invertido = grade1_valor if eh_valor_valido(grade1_valor) else ""
                elif grade2_ativa:
                    grade1_invertido = grade2_valor if eh_valor_valido(grade2_valor) else ""
                elif grade3_ativa:
                    grade1_invertido = grade3_valor if eh_valor_valido(grade3_valor) else ""
            elif num_grades_ativas == 2:
                # 2 grades ativas: invertem entre si
                if grade1_ativa and grade2_ativa:
                    # Grade 1 ↔ Grade 2
                    grade1_invertido = grade2_valor if eh_valor_valido(grade2_valor) else ""
                    grade2_invertido = grade1_valor if eh_valor_valido(grade1_valor) else ""
                elif grade1_ativa and grade3_ativa:
                    # Grade 1 ↔ Grade 3
                    grade1_invertido = grade3_valor if eh_valor_valido(grade3_valor) else ""
                    grade3_invertido = grade1_valor if eh_valor_valido(grade1_valor) else ""
                elif grade2_ativa and grade3_ativa:
                    # Grade 2 ↔ Grade 3
                    grade2_invertido = grade3_valor if eh_valor_valido(grade3_valor) else ""
                    grade3_invertido = grade2_valor if eh_valor_valido(grade2_valor) else ""
            elif num_grades_ativas == 3:
                # Todas as 3 ativas: Grade 1 ↔ Grade 3, Grade 2 permanece
                grade1_invertido = grade3_valor if eh_valor_valido(grade3_valor) else ""
                grade2_invertido = grade2_valor if eh_valor_valido(grade2_valor) else ""
                grade3_invertido = grade1_valor if eh_valor_valido(grade1_valor) else ""
            
            # ===== INVERSÃO DINÂMICA DE DISTÂNCIAS =====
            # Se apenas 1 distância ativa: vai para a mesma posição (não espelhar)
            # Se ambas ativas: espelhar (Dist 1 ↔ Dist 2)
            dist1_ativa = eh_valor_valido(dist1_valor)
            dist2_ativa = eh_valor_valido(dist2_valor)
            
            dist1_invertido = ""
            dist2_invertido = ""
            
            if dist1_ativa and dist2_ativa:
                # Ambas ativas: espelhar
                dist1_invertido = dist2_valor
                dist2_invertido = dist1_valor
            elif dist1_ativa:
                # Apenas Dist 1 ativa: vai para Dist 1 (não espelhar)
                dist1_invertido = dist1_valor
            elif dist2_ativa:
                # Apenas Dist 2 ativa: vai para Dist 2 (não espelhar)
                dist2_invertido = dist2_valor
            
            # Função auxiliar para inverter detalhes dentro de uma grade
            # IMPORTANTE: A inversão é DINÂMICA baseada na quantidade de valores válidos
            # Valores 0 são tratados como inválidos e não são copiados
            # A inversão inverte os valores válidos: primeiro ↔ último, segundo ↔ penúltimo, etc.
            # Após a inversão, os valores válidos são compactados (sem espaços vazios no início)
            def inverter_detalhes_grade(detalhes_originais):
                # Garantir que temos pelo menos 5 elementos (preencher com strings vazias se necessário)
                while len(detalhes_originais) < 5:
                    detalhes_originais.append("")
                
                # Primeiro, coletar apenas os valores válidos (ignorar 0s)
                valores_validos_originais = []
                for valor in detalhes_originais:
                    if valor and eh_valor_valido(valor):
                        valores_validos_originais.append(valor)
                
                # Inverter a lista de valores válidos: primeiro ↔ último, segundo ↔ penúltimo, etc.
                valores_validos_invertidos = []
                for i in range(len(valores_validos_originais) - 1, -1, -1):
                    valores_validos_invertidos.append(valores_validos_originais[i])
                
                # Preencher resultado: valores invertidos primeiro, depois vazios
                detalhes_invertidos = [""] * 5
                for i, valor in enumerate(valores_validos_invertidos):
                    if i < 5:
                        detalhes_invertidos[i] = valor
                # Os restantes já são "" (vazios)
                
                return detalhes_invertidos
            
            # Inverter detalhes dentro de cada grade
            detalhes_grade1_inv = inverter_detalhes_grade(detalhes_grade1)
            detalhes_grade2_inv = inverter_detalhes_grade(detalhes_grade2)
            detalhes_grade3_inv = inverter_detalhes_grade(detalhes_grade3)
            
            # Aplicar inversão dinâmica dos detalhes baseada nas grades ativas
            detalhes_grade1_final = [""] * 5
            detalhes_grade2_final = [""] * 5
            detalhes_grade3_final = [""] * 5
            
            if num_grades_ativas == 1:
                # Apenas 1 grade ativa: vai para Grade 1 do Conjunto 2
                if grade1_ativa:
                    detalhes_grade1_final = detalhes_grade1_inv
                elif grade2_ativa:
                    detalhes_grade1_final = detalhes_grade2_inv
                elif grade3_ativa:
                    detalhes_grade1_final = detalhes_grade3_inv
            elif num_grades_ativas == 2:
                # 2 grades ativas: invertem entre si
                if grade1_ativa and grade2_ativa:
                    # Grade 1 ↔ Grade 2
                    detalhes_grade1_final = detalhes_grade2_inv
                    detalhes_grade2_final = detalhes_grade1_inv
                elif grade1_ativa and grade3_ativa:
                    # Grade 1 ↔ Grade 3
                    detalhes_grade1_final = detalhes_grade3_inv
                    detalhes_grade3_final = detalhes_grade1_inv
                elif grade2_ativa and grade3_ativa:
                    # Grade 2 ↔ Grade 3
                    detalhes_grade2_final = detalhes_grade3_inv
                    detalhes_grade3_final = detalhes_grade2_inv
            elif num_grades_ativas == 3:
                # Todas as 3 ativas: Grade 1 ↔ Grade 3, Grade 2 permanece
                detalhes_grade1_final = detalhes_grade3_inv  # Grade 1 recebe Grade 3 invertida
                detalhes_grade2_final = detalhes_grade2_inv  # Grade 2 permanece (mas invertida)
                detalhes_grade3_final = detalhes_grade1_inv  # Grade 3 recebe Grade 1 invertida

            # Copiar grades e distâncias INVERTIDAS (só se forem válidos)
            if hasattr(self, 'grade_1_grupo2'):
                self.grade_1_grupo2.delete(0, tk.END)
                if eh_valor_valido(grade1_invertido):
                    self.grade_1_grupo2.insert(0, grade1_invertido)

            if hasattr(self, 'distancia_1_grupo2'):
                self.distancia_1_grupo2.delete(0, tk.END)
                if eh_valor_valido(dist1_invertido):
                    self.distancia_1_grupo2.insert(0, dist1_invertido)

            if hasattr(self, 'grade_2_grupo2'):
                self.grade_2_grupo2.delete(0, tk.END)
                if eh_valor_valido(grade2_invertido):
                    self.grade_2_grupo2.insert(0, grade2_invertido)

            if hasattr(self, 'distancia_2_grupo2'):
                self.distancia_2_grupo2.delete(0, tk.END)
                if eh_valor_valido(dist2_invertido):
                    self.distancia_2_grupo2.insert(0, dist2_invertido)

            if hasattr(self, 'grade_3_grupo2'):
                self.grade_3_grupo2.delete(0, tk.END)
                if eh_valor_valido(grade3_invertido):
                    self.grade_3_grupo2.insert(0, grade3_invertido)

            # Copiar detalhes das grades INVERTIDAS (só valores válidos, não copiar 0)
            # Grade 1 Grupo 2 recebe detalhes da Grade 3 (invertidos)
            for i, valor in enumerate(detalhes_grade1_final):
                campo = getattr(self, f"detalhe_grade1_{i+1}_grupo2", None)
                if campo:
                    campo.delete(0, tk.END)
                    if eh_valor_valido(valor):  # Só inserir se for válido (não é 0)
                        campo.insert(0, valor)

            # Grade 2 Grupo 2 recebe detalhes da Grade 2 (invertidos)
            for i, valor in enumerate(detalhes_grade2_final):
                campo = getattr(self, f"detalhe_grade2_{i+1}_grupo2", None)
                if campo:
                    campo.delete(0, tk.END)
                    if eh_valor_valido(valor):  # Só inserir se for válido (não é 0)
                        campo.insert(0, valor)

            # Grade 3 Grupo 2 recebe detalhes da Grade 1 (invertidos)
            for i, valor in enumerate(detalhes_grade3_final):
                campo = getattr(self, f"detalhe_grade3_{i+1}_grupo2", None)
                if campo:
                    campo.delete(0, tk.END)
                    if eh_valor_valido(valor):  # Só inserir se for válido (não é 0)
                        campo.insert(0, valor)

            # REMOVIDO: Não copiar alturas - manter configurações atuais
            # A função copiar_valores_grupo1_para_grupo2() copiava alturas, então foi removida

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()



