    def _normalize_key_component(self, value, placeholder=""):
        """Normaliza texto para composição de chaves únicas."""
        if value is None:
            return placeholder
        value = str(value).strip()
        return value if value else placeholder

    def _make_pilar_key(self, numero, pavimento, obra):
        """Gera chave exclusiva (obra||pavimento||numero)."""
        numero_norm = self._normalize_key_component(numero, "__SEM_NUMERO__")
        pav_norm = self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__")
        obra_norm = self._normalize_key_component(obra, "__SEM_OBRA__")
        return f"{obra_norm}||{pav_norm}||{numero_norm}"

    def _split_pilar_key(self, key):
        """Divide chave exclusiva em componentes normalizados."""
        if isinstance(key, str) and "||" in key:
            obra, pavimento, numero = key.split("||", 2)
            return (
                self._normalize_key_component(numero, "__SEM_NUMERO__"),
                self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__"),
                self._normalize_key_component(obra, "__SEM_OBRA__"),
            )
        numero = key
        pavimento = ""
        obra = ""
        if isinstance(key, str) and "_" in key and key.count("_") == 1:
            numero, pavimento = key.split("_", 1)
        return (
            self._normalize_key_component(numero, "__SEM_NUMERO__"),
            self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__"),
            self._normalize_key_component(obra, "__SEM_OBRA__"),
        )

    def _extract_metadata_from_entry(self, entry):
        """Obtém numero/pavimento/obra a partir da entrada salva."""
        dados = entry.get("dados", {}) if isinstance(entry, dict) else {}
        numero = entry.get("numero") or dados.get("numero") or entry.get("item_id")
        pavimento = entry.get("pavimento") or dados.get("pavimento")
        obra = entry.get("obra") or dados.get("obra")
        return (
            self._normalize_key_component(numero, "__SEM_NUMERO__"),
            self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__"),
            self._normalize_key_component(obra, "__SEM_OBRA__"),
        )

    def _migrar_pilares_salvos_para_chaves_unicas(self):
        """Migra entradas antigas para chaves únicas por obra/pavimento."""
        if getattr(self, "_pilares_salvos_migrados", False):
            return
        if not hasattr(self, "pilares_salvos") or not self.pilares_salvos:
            self.pilares_salvos = {}
            self._pilares_salvos_migrados = True
            return
        novos_dados = {}
        for chave_antiga, valor in list(self.pilares_salvos.items()):
            if not isinstance(valor, dict):
                continue
            if isinstance(chave_antiga, str) and "||" in chave_antiga:
                numero_norm, pav_norm, obra_norm = self._split_pilar_key(chave_antiga)
            else:
                numero_norm, pav_norm, obra_norm = self._extract_metadata_from_entry(valor)
                if (not pav_norm or pav_norm == "__SEM_PAVIMENTO__") and isinstance(chave_antiga, str) and "_" in chave_antiga:
                    numero_guess, pav_guess = chave_antiga.split("_", 1)
                    if pav_norm in ("", "__SEM_PAVIMENTO__"):
                        pav_norm = self._normalize_key_component(pav_guess, "__SEM_PAVIMENTO__")
                    if numero_norm in ("", "__SEM_NUMERO__"):
                        numero_norm = self._normalize_key_component(numero_guess, "__SEM_NUMERO__")
            if obra_norm in ("", "__SEM_OBRA__"):
                obra_norm = self._normalize_key_component(
                    self.obra_filtro_var.get() if hasattr(self, "obra_filtro_var") else "",
                    "__SEM_OBRA__",
                )
            novo_key = self._make_pilar_key(numero_norm, pav_norm, obra_norm)
            valor.setdefault("obra", obra_norm)
            valor.setdefault("pavimento", pav_norm)
            if "dados" in valor and isinstance(valor["dados"], dict):
                valor["dados"].setdefault("obra", obra_norm)
                valor["dados"].setdefault("pavimento", pav_norm)
                valor["dados"].setdefault("numero", numero_norm)
            novos_dados[novo_key] = valor
        self.pilares_salvos = novos_dados
        self._pilares_salvos_migrados = True

    def _get_pilar_salvo_entry(self, numero, pavimento=None, obra=None, allow_partial=True):
        """Busca entrada correspondente em pilares_salvos."""
        if not hasattr(self, "pilares_salvos"):
            self.pilares_salvos = {}
        if not getattr(self, "_pilares_salvos_migrados", False):
            self._migrar_pilares_salvos_para_chaves_unicas()
        numero_norm = self._normalize_key_component(numero, "__SEM_NUMERO__")
        pav_norm = self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__")
        obra_norm = self._normalize_key_component(obra, "__SEM_OBRA__")
        if pavimento is not None and obra is not None:
            key = self._make_pilar_key(numero_norm, pav_norm, obra_norm)
            if key in self.pilares_salvos:
                return key, self.pilares_salvos[key]
        matches = []
        for key, entry in self.pilares_salvos.items():
            key_num, key_pav, key_obra = self._split_pilar_key(key)
            if numero_norm not in ("", "__SEM_NUMERO__") and key_num != numero_norm:
                continue
            if pavimento is not None and key_pav != pav_norm:
                continue
            if obra is not None and key_obra != obra_norm:
                continue
            matches.append((key, entry))
        if matches:
            if len(matches) == 1 or not allow_partial:
                return matches[-1]
            for key, entry in matches:
                entry_num, entry_pav, entry_obra = self._extract_metadata_from_entry(entry)
                if (pavimento is None or entry_pav == pav_norm) and (obra is None or entry_obra == obra_norm):
                    return key, entry
            return matches[-1]
        return None, None

    def _set_pilar_salvo_entry(self, numero, pavimento, obra, entry):
        """Define/atualiza entrada em pilares_salvos."""
        if entry is None:
            return None
        numero_norm = self._normalize_key_component(numero, "__SEM_NUMERO__")
        pav_norm = self._normalize_key_component(pavimento, "__SEM_PAVIMENTO__")
        obra_norm = self._normalize_key_component(obra, "__SEM_OBRA__")
        key = self._make_pilar_key(numero_norm, pav_norm, obra_norm)
        if not isinstance(entry, dict):
            entry = {"dados": entry}
        entry["obra"] = obra_norm
        entry["pavimento"] = pav_norm
        entry.setdefault("item_id", numero_norm)
        if "dados" in entry and isinstance(entry["dados"], dict):
            entry["dados"]["obra"] = obra_norm
            entry["dados"]["pavimento"] = pav_norm
            entry["dados"]["numero"] = entry["dados"].get("numero", numero_norm)
        self.pilares_salvos[key] = entry
        return key

    def _delete_pilar_salvo_entry(self, numero, pavimento=None, obra=None):
        """Remove entrada específica de pilares_salvos.
        CRÍTICO: Usa allow_partial=False para garantir que encontra a chave exata."""
        # Usar allow_partial=False para garantir busca exata
        key, _ = self._get_pilar_salvo_entry(numero, pavimento, obra, allow_partial=False)
        if key and key in self.pilares_salvos:
            del self.pilares_salvos[key]
            print(f">>> Item removido de pilares_salvos: chave={key}, numero={numero}, pavimento={pavimento}, obra={obra}")
            return True
        # Se não encontrou com allow_partial=False, tentar com allow_partial=True como fallback
        if not key:
            key, _ = self._get_pilar_salvo_entry(numero, pavimento, obra, allow_partial=True)
            if key and key in self.pilares_salvos:
                del self.pilares_salvos[key]
                print(f">>> Item removido de pilares_salvos (fallback): chave={key}, numero={numero}, pavimento={pavimento}, obra={obra}")
            return True
        return False

    def _pilar_salvo_exists(self, numero, pavimento=None, obra=None):
        """Retorna True se existir entrada correspondente em pilares_salvos."""
        _, entry = self._get_pilar_salvo_entry(numero, pavimento, obra)
        return entry is not None

    def obter_caminho_dados(self, nome_arquivo):

        """Função auxiliar para obter caminho correto dos arquivos de dados
        Funciona tanto em ambiente frozen (executável) quanto em desenvolvimento"""

        import os
        import sys

        # Detectar ambiente frozen - método robusto
        is_frozen = getattr(sys, 'frozen', False)
        if not is_frozen:
            # Detecção alternativa para Nuitka/PyInstaller
            if hasattr(sys, 'executable') and sys.executable:
                exe_name = os.path.basename(sys.executable).lower()
                exe_dir = os.path.dirname(sys.executable)
                
                # 1. Se é .exe e o nome NÃO é python.exe
                if exe_name.endswith('.exe') and exe_name != 'python.exe':
                    is_frozen = True
                
                # 2. Verificar caminho do executável (Nuitka usa .dist)
                if not is_frozen:
                    if '.dist' in exe_dir or os.path.basename(exe_dir) in ['run.dist', 'dist', 'dist_nuitka', 'dist_debug', 'dist_nuitka_debug']:
                        is_frozen = True

        if is_frozen:
            # Em ambiente frozen, usar diretório do executável
            script_dir = os.path.dirname(sys.executable)
            
            # Tentar múltiplos locais possíveis (em ordem de preferência)
            locais_possveis = [
                # 1. Diretório do executável diretamente (mais simples e confiável)
                os.path.join(script_dir, nome_arquivo),
                # 2. Subdiretório "data" no diretório do executável
                os.path.join(script_dir, "data", nome_arquivo),
                # 3. Estrutura src/core (para compatibilidade)
                os.path.join(script_dir, "src", "core", nome_arquivo),
                # 4. Estrutura core (para compatibilidade)
                os.path.join(script_dir, "core", nome_arquivo),
                # 5. Diretório pai (caso executável esteja em subdiretório)
                os.path.join(os.path.dirname(script_dir), "data", nome_arquivo),
            ]
            
            # Verificar se algum arquivo já existe
            for caminho in locais_possveis:
                if os.path.exists(caminho):
                    return caminho
            
            # Se não encontrou, usar o primeiro local (diretório do executável)
            # e criar diretório se necessário
            caminho = locais_possveis[0]
            try:
                # Garantir que o diretório existe antes de criar arquivo
                dir_path = os.path.dirname(caminho)
                if dir_path:  # Se há diretório no caminho
                    os.makedirs(dir_path, exist_ok=True)
                else:  # Se não há diretório, usar diretório do executável
                    caminho = os.path.join(script_dir, nome_arquivo)
            except (OSError, PermissionError) as e:
                # Se falhar (ex: sem permissão), tentar próximo local
                caminho = locais_possveis[1]  # Tentar subdiretório "data"
                try:
                    dir_path = os.path.dirname(caminho)
                    if dir_path:
                        os.makedirs(dir_path, exist_ok=True)
                    else:
                        caminho = os.path.join(script_dir, "data", nome_arquivo)
                        os.makedirs(os.path.dirname(caminho), exist_ok=True)
                except (OSError, PermissionError) as e2:
                    # Último recurso: usar diretório do executável diretamente
                    caminho = os.path.join(script_dir, nome_arquivo)
                    # Tentar criar pelo menos o diretório do executável se possível
                    try:
                        os.makedirs(script_dir, exist_ok=True)
                    except:
                        pass
            
            return caminho
        else:
            # Em desenvolvimento, usar estrutura normal
            try:
                from config_paths import PROJECT_ROOT
                caminho = os.path.join(PROJECT_ROOT, "src", "core", nome_arquivo)
                # Criar diretório se não existir
                os.makedirs(os.path.dirname(caminho), exist_ok=True)
                return caminho
            except ImportError:
                pass

            # Fallback para estrutura antiga - procurar em vários locais
            locais_possveis = [
                os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "core", nome_arquivo),
                os.path.join(os.path.dirname(os.path.abspath(__file__)), nome_arquivo),
                os.path.join(os.getcwd(), nome_arquivo),
                os.path.join(os.getcwd(), "src", "core", nome_arquivo)
            ]

            for caminho in locais_possveis:
                if os.path.exists(caminho):
                    return caminho

            # Se não encontrou, retorna o caminho preferido (core) e cria o diretório
            try:
                from config_paths import PROJECT_ROOT
                caminho = os.path.join(PROJECT_ROOT, "src", "core", nome_arquivo)
            except ImportError:
                caminho = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "core", nome_arquivo)

            os.makedirs(os.path.dirname(caminho), exist_ok=True)
            return caminho

        


        # Carregar lista de pilares salva, se existir

        import os, pickle

        caminho_arquivo = self.obter_caminho_dados("pilares_salvos.pkl")

        if os.path.exists(caminho_arquivo):

            try:

                with open(caminho_arquivo, 'rb') as arquivo:

                    self.pilares_salvos = pickle.load(arquivo)

            except Exception:

                self.pilares_salvos = {}

        else:

            self.pilares_salvos = {}


        


        # Inicializa a instância do AC_Module passando a si mesma como parent_tk_root

        self.ac = load_ac_functions(parent_tk_root=self)


        


        self.pavimentos_lista = [["", ""] for _ in range(10)]  # [ [pavimento, nivel], ... ]

        self.pavimentos_entries = []
        
        # Armazenar nomes antigos dos pavimentos para detectar mudanças
        self.pavimentos_nomes_antigos = {}  # {indice: nome_antigo}

