    def atualizar_lista(self, event=None):
        
        # Obter filtros atuais
        obra_filtro = self.obra_filtro_var.get()
        pavimento_filtro = self.pavimento_filtro_var.get()
        
        # Preservar seleção atual antes de atualizar
        selecao_atual = self.lista_pilares.selection()
        numero_selecionado = None
        if selecao_atual:
            try:
                item_selecionado = self.lista_pilares.item(selecao_atual[0])
                valores = item_selecionado.get('values', [])
                if valores:
                    numero_selecionado = str(valores[0]).strip()
            except Exception:
                pass
        
        # O combobox de pavimentos é atualizado pela função atualizar_pavimentos_por_obra
        
        # Limpar lista atual
        for item in self.lista_pilares.get_children():
            self.lista_pilares.delete(item)
        
        # Coletar itens baseado nos filtros
        itens_para_ordenar = []
        total_m2_pav = 0.0
        
        # Mostrar apenas itens da obra selecionada
        if obra_filtro and obra_filtro in self.obras:
            for pav_nome, pav_itens in self.obras[obra_filtro].items():
                if pavimento_filtro != "Todos" and pav_nome != pavimento_filtro:
                    continue
                
                # Verificar se pav_itens é um dicionário (estrutura antiga) ou lista (estrutura nova)
                if isinstance(pav_itens, dict):
                    for numero, item_dados in pav_itens.items():
                        dados = item_dados["dados"]
                        num_float = float(numero) if numero.replace('.','',1).isdigit() else float('inf')
                        itens_para_ordenar.append((num_float, numero, dados, item_dados, obra_filtro, pav_nome))
                
                elif isinstance(pav_itens, list) and pav_nome == "pavimentos_data":
                    # Ignorar dados de pavimentos na lista principal
                    continue

        # Ordenar itens por número (primeiro elemento da tupla)
        itens_para_ordenar.sort(key=lambda x: x[0])
        
        # Inserir itens na lista
        item_id_para_selecionar = None
        for _, numero, dados, item_dados, obra_nome, pav_nome in itens_para_ordenar:
            m2 = self.obter_m2_salvo(dados)
            total_m2_pav += m2
            
            novo_item = self.lista_pilares.insert('', 'end', values=(
                numero,
                dados.get('nome', ''),
                pav_nome,
                f"{m2:.2f}"
            ))
            
            item_dados["item_id"] = novo_item
            
            # Verificar se este é o item que estava selecionado
            if numero_selecionado and str(numero).strip() == numero_selecionado:
                item_id_para_selecionar = novo_item
        
        # Restaurar seleção se o item ainda existir
        # Bloquear evento de seleção para evitar loop infinito
        if item_id_para_selecionar:
            try:
                # Marcar que estamos restaurando seleção programaticamente
                self._restaurando_selecao = True
                self.lista_pilares.selection_set(item_id_para_selecionar)
                self.lista_pilares.focus(item_id_para_selecionar)
            except Exception:
                pass
            finally:
                # Liberar flag após um pequeno delay para garantir que o evento não seja processado
                self.after(50, lambda: setattr(self, '_restaurando_selecao', False))
        
        self.label_total_m2.config(text=f"Total m²: {total_m2_pav:.2f}")


        

        # Atualizar saldo de créditos na interface

        self.atualizar_creditos_interface()

    

    def migrar_dados_para_obras(self):
        """Migra dados existentes para a nova estrutura de obras"""
        import sys
        
        # Primeiro, tentar carregar obras existentes
        if self.carregar_obras():
            return

        # Se não conseguiu carregar, migrar dados existentes
        if not self.pilares_salvos:
            # Se não há dados, criar obra padrão vazia
            self.obras["Obra Padrão"] = {}
            return

        

        # Coletar todos os pavimentos únicos dos dados existentes

        pavimentos_existentes = set()

        for item_dados in self.pilares_salvos.values():

            dados = item_dados.get('dados', {})

            pav = str(dados.get('pavimento', '')).strip()

            if pav:

                pavimentos_existentes.add(pav)

        

        # Se não há pavimentos, usar um padrão

        if not pavimentos_existentes:

            pavimentos_existentes = {"Subsolo"}
        

        # Criar "Obra Padrão" com os pavimentos existentes
        self.obras["Obra Padrão"] = {}

        

        # Migrar dados para a nova estrutura

        for numero, item_dados in self.pilares_salvos.items():

            dados = item_dados.get('dados', {})

            pavimento = str(dados.get('pavimento', '')).strip()

            

            # Se não há pavimento, usar "Subsolo" (pavimento padrão)
            if not pavimento:

                pavimento = "Subsolo"
            

            # Inicializar pavimento se não existir
            if pavimento not in self.obras["Obra Padrão"]:
                self.obras["Obra Padrão"][pavimento] = {}

            # Migrar dados
            self.obras["Obra Padrão"][pavimento][numero] = {

                "dados": dados,

                "item_id": item_dados.get("item_id"),

                "locks": item_dados.get("locks", {})

            }

        

        

    

    def salvar_obras(self):

        """Salva a estrutura de obras em arquivo"""

        try:

            import pickle

            import os

            caminho_arquivo = self.obter_caminho_dados("obras_salvas.pkl")
            
            print(f">>> [salvar_obras] Salvando em: {caminho_arquivo}")
            print(f">>> [salvar_obras] Obras a salvar: {list(self.obras.keys())}")

            with open(caminho_arquivo, 'wb') as arquivo:

                pickle.dump(self.obras, arquivo)
            
            print(f">>> [salvar_obras] Arquivo salvo com sucesso!")
            return True


        except Exception as e:
            print(f">>> [salvar_obras] ERRO ao salvar: {e}")
            import traceback
            traceback.print_exc()
            return False

    
    def _forcar_salvamento_todos_itens_obra(self, obra_atual):
        """
        Força o salvamento de TODOS os itens da obra com TODOS os campos.
        Percorre todos os pavimentos e itens, carrega cada item na interface e salva novamente.
        Isso garante que todos os campos (lajes, posições de laje, aberturas, checkbuttons, etc.) sejam salvos.
        
        FUNCIONA EM MODO FROZEN: Usa diretamente self.obras em vez de depender do conector.
        CRÍTICO: No modo frozen, salva diretamente na estrutura self.obras para evitar mistura de dados.
        """
        import copy
        import time
        
        if not obra_atual or obra_atual not in self.obras:
            return
        
        total_itens_salvos = 0
        total_erros = 0
        
        # CRÍTICO: Fazer cópia profunda da estrutura para evitar mistura de dados
        # No modo frozen, trabalhar com cópia evita problemas de referência
        obra_backup = copy.deepcopy(self.obras[obra_atual])
        
        # Percorrer todos os pavimentos da obra DIRETAMENTE de self.obras
        for pavimento_nome, pavimento_dados in self.obras[obra_atual].items():
            if pavimento_nome == "pavimentos_data" or not isinstance(pavimento_dados, dict):
                continue
            
            # Percorrer todos os itens do pavimento DIRETAMENTE
            for item_id, item_dados in pavimento_dados.items():
                if not isinstance(item_dados, dict) or "dados" not in item_dados:
                    continue
                
                try:
                    # Obter número do item (pode ser string ou int)
                    numero_item = str(item_id)
                    
                    # CRÍTICO: Fazer cópia profunda dos dados do item para evitar mistura
                    dados_item_original = item_dados.get("dados", {})
                    dados_item = copy.deepcopy(dados_item_original)
                    
                    # Se não tiver nome, usar o número
                    if "nome" not in dados_item:
                        dados_item["nome"] = numero_item
                    
                    # CRÍTICO: Definir obra, pavimento e número ANTES de carregar
                    # Isso garante que salvar_pilar salve no local correto
                    if hasattr(self, 'obra_filtro_var'):
                        try:
                            self.obra_filtro_var.set(obra_atual)
                        except Exception as e:
                            pass
                    
                    if hasattr(self, 'pavimento_var'):
                        try:
                            self.pavimento_var.set(pavimento_nome)
                        except Exception as e:
                            pass
                    
                    if hasattr(self, 'excel_column'):
                        try:
                            self.excel_column.set(numero_item)
                        except Exception as e:
                            pass
                    
                    # CRÍTICO: Aguardar antes de carregar para garantir que os campos foram atualizados
                    self.update_idletasks()
                    time.sleep(0.1)
                    
                    # Carregar item na interface (isso preenche todos os campos)
                    self._carregar_item_para_salvamento(numero_item, pavimento_nome, {"dados": dados_item})
                    
                    # CRÍTICO: Aguardar múltiplas vezes para garantir que os campos foram atualizados
                    # No modo frozen, pode ser necessário mais tempo para atualizar a interface
                    for _ in range(3):
                        self.update_idletasks()
                        time.sleep(0.1)
                    
                    # Verificar se os campos foram carregados corretamente (debug)
                    paineis_carregados = dados_item.get('paineis', {})
                    lajes_verificadas = 0
                    lajes_ok = 0
                    if paineis_carregados:
                        for letra in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:
                            painel = paineis_carregados.get(letra, {})
                            laje_valor = painel.get('laje', '')
                            if laje_valor:
                                lajes_verificadas += 1
                                # Verificar se foi carregado na interface
                                campo_laje = getattr(self, f'laje_{letra}', None)
                                if campo_laje:
                                    try:
                                        laje_interface = campo_laje.get()
                                        if str(laje_interface) == str(laje_valor):
                                            lajes_ok += 1
                                    except Exception:
                                        pass
                    
                    # CRÍTICO: Verificar novamente se excel_column está correto antes de salvar
                    if hasattr(self, 'excel_column'):
                        numero_verificacao = self.excel_column.get().strip()
                        if numero_verificacao != numero_item:
                            self.excel_column.set(numero_item)
                            time.sleep(0.05)
                            self.update_idletasks()
                    
                    # Verificar pavimento também
                    if hasattr(self, 'pavimento_var'):
                        pavimento_verificacao = self.pavimento_var.get().strip()
                        if pavimento_verificacao != pavimento_nome:
                            self.pavimento_var.set(pavimento_nome)
                            time.sleep(0.05)
                            self.update_idletasks()
                    
                    # Salvar o item com todos os campos atualizados
                    # CRÍTICO: skip_conflict_check=True para evitar diálogos no modo frozen
                    self.salvar_pilar(mostrar_mensagem=False, skip_conflict_check=True)
                    
                    # CRÍTICO: Verificar se os dados foram salvos corretamente
                    if obra_atual in self.obras and pavimento_nome in self.obras[obra_atual]:
                        if numero_item in self.obras[obra_atual][pavimento_nome]:
                            dados_salvos = self.obras[obra_atual][pavimento_nome][numero_item].get("dados", {})
                            paineis_salvos = dados_salvos.get('paineis', {})
                    
                    total_itens_salvos += 1
                    
                except Exception as e:
                    total_erros += 1
                    import traceback
                    continue
    
    def _carregar_item_para_salvamento(self, numero_item, pavimento_nome, dados_item):
        """
        Carrega um item na interface para garantir que todos os campos sejam salvos.
        Versão simplificada que apenas preenche os campos sem triggerar eventos.
        
        FUNCIONA EM MODO FROZEN: Usa hasattr e getattr com tratamento de erros robusto.
        """
        def _definir_valor_campo(campo, valor):
            """Função auxiliar para definir valor em campo (StringVar ou Entry)"""
            if not campo:
                return
            try:
                if hasattr(campo, 'set'):
                    # É StringVar ou similar
                    campo.set(str(valor) if valor else '')
                elif hasattr(campo, 'delete') and hasattr(campo, 'insert'):
                    # É Entry widget
                    campo.delete(0, tk.END)
                    if valor:
                        campo.insert(0, str(valor))
            except Exception:
                pass
        
        try:
            # Preencher campos básicos
            if hasattr(self, 'numero_pilar'):
                try:
                    self.numero_pilar.set(str(numero_item))
                except Exception as e:
                    pass
            
            if hasattr(self, 'nome_pilar'):
                try:
                    nome = dados_item.get('nome', '') if isinstance(dados_item, dict) else ''
                    if not nome:
                        nome = str(numero_item)
                    self.nome_pilar.set(nome)
                except Exception as e:
                    pass
            
            if hasattr(self, 'pavimento_var'):
                try:
                    self.pavimento_var.set(pavimento_nome)
                except Exception as e:
                    pass
        except Exception as e:
            import traceback
            traceback.print_exc()
        
        # Preencher todos os campos do item usando os dados salvos
        # Em modo frozen, dados_item pode já ser um dict com 'dados' ou ser diretamente os dados
        if isinstance(dados_item, dict) and 'dados' in dados_item:
            dados = dados_item.get('dados', {})
        else:
            dados = dados_item if isinstance(dados_item, dict) else {}
        
        # Campos básicos (com tratamento de erros individual)
        campos_basicos = {
            'comprimento': dados.get('comprimento', ''),
            'largura': dados.get('largura', ''),
            'altura': dados.get('altura', ''),
            'pavimento_abc': dados.get('pavimento_anterior', ''),
            'nivel_saida': dados.get('nivel_saida', ''),
            'nivel_chegada': dados.get('nivel_chegada', ''),
            'nivel_diferencial': dados.get('nivel_diferencial', '')
        }
        
        # Primeiro, carregar o pavimento_var para que o binding atualize o pavimento_abc
        if 'pavimento' in dados and hasattr(self, 'pavimento_var'):
            try:
                pavimento_nome = dados.get('pavimento', '')
                if pavimento_nome:
                    self.pavimento_var.set(pavimento_nome)
            except Exception:
                pass
        
        # Depois, carregar os outros campos básicos
        for campo_nome, valor in campos_basicos.items():
            if hasattr(self, campo_nome):
                try:
                    campo = getattr(self, campo_nome)
                    if hasattr(campo, 'set'):
                        campo.set(str(valor) if valor is not None else '')
                    elif hasattr(campo, 'delete') and hasattr(campo, 'insert'):
                        # Se for Entry, usar delete/insert
                        campo.delete(0, tk.END)
                        if valor:
                            campo.insert(0, str(valor))
                except Exception as e:
                    pass
        
        # Parafusos
        parafusos = dados.get('parafusos', {})
        for i in range(1, 9):
            campo_par = getattr(self, f'par_{i}_{i+1}', None)
            valor_par = parafusos.get(f'par_{i}_{i+1}', '')
            _definir_valor_campo(campo_par, valor_par)
        
        # Grades
        grades = dados.get('grades', {})
        campos_grades = {
            'grade_1': grades.get('grade_1', ''),
            'grade_2': grades.get('grade_2', ''),
            'grade_3': grades.get('grade_3', ''),
            'distancia_1': grades.get('distancia_1', ''),
            'distancia_2': grades.get('distancia_2', '')
        }
        for campo_nome, valor in campos_grades.items():
            campo = getattr(self, campo_nome, None)
            _definir_valor_campo(campo, valor)
        
        # Detalhes das grades
        detalhes_grades = dados.get('detalhes_grades', {})
        for i in range(3):
            for j in range(5):
                campo = getattr(self, f'detalhe_grade{i+1}_{j+1}', None)
                valor = detalhes_grades.get(f'detalhe_grade{i+1}_{j+1}', '')
                _definir_valor_campo(campo, valor)
        
        # Altura dos detalhes das grades - Grade A
        altura_detalhes_grades = dados.get('altura_detalhes_grades', {})
        for i in range(3):
            for j in range(6):  # Detalhes 0 a 5 (incluindo campo 0)
                campo = getattr(self, f'altura_detalhe_grade_a_{i+1}_{j}', None)
                valor = altura_detalhes_grades.get(f'altura_detalhe_grade_a_{i+1}_{j}', '')
                _definir_valor_campo(campo, valor)
        
        # Grades grupo 2
        grades_grupo2 = dados.get('grades_grupo2', {})
        campos_grades_grupo2 = {
            'grade_1_grupo2': grades_grupo2.get('grade_1_grupo2', ''),
            'grade_2_grupo2': grades_grupo2.get('grade_2_grupo2', ''),
            'grade_3_grupo2': grades_grupo2.get('grade_3_grupo2', ''),
            'distancia_1_grupo2': grades_grupo2.get('distancia_1_grupo2', ''),
            'distancia_2_grupo2': grades_grupo2.get('distancia_2_grupo2', '')
        }
        for campo_nome, valor in campos_grades_grupo2.items():
            campo = getattr(self, campo_nome, None)
            _definir_valor_campo(campo, valor)
        
        # Detalhes grades grupo 2
        detalhes_grades_grupo2 = dados.get('detalhes_grades_grupo2', {})
        for i in range(3):
            for j in range(5):
                campo = getattr(self, f'detalhe_grade{i+1}_{j+1}_grupo2', None)
                valor = detalhes_grades_grupo2.get(f'detalhe_grade{i+1}_{j+1}_grupo2', '')
                _definir_valor_campo(campo, valor)
        
        # Altura dos detalhes das grades - Grade B (Grupo 2)
        altura_detalhes_grades_b = dados.get('altura_detalhes_grades_b', {})
        for i in range(3):
            for j in range(6):  # Detalhes 0 a 5 (incluindo campo 0)
                campo = getattr(self, f'altura_detalhe_grade_b_{i+1}_{j}', None)
                valor = altura_detalhes_grades_b.get(f'altura_detalhe_grade_b_{i+1}_{j}', '')
                _definir_valor_campo(campo, valor)
        
        # PAINÉIS - LAJES E POSIÇÕES DE LAJE
        # CRÍTICO: Garantir que TODOS os painéis A-H sejam carregados corretamente
        paineis = dados.get('paineis', {})
        for letra in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:
            painel = paineis.get(letra, {})
            
            try:
                # Laje
                campo_laje = getattr(self, f'laje_{letra}', None)
                if campo_laje and hasattr(campo_laje, 'set'):
                    valor_laje = painel.get('laje', '')
                    campo_laje.set(str(valor_laje) if valor_laje is not None else '')
                
                # Posição de laje
                campo_pos_laje = getattr(self, f'posicao_laje_{letra}', None)
                if campo_pos_laje and hasattr(campo_pos_laje, 'set'):
                    valor_pos_laje = painel.get('posicao_laje', '')
                    campo_pos_laje.set(str(valor_pos_laje) if valor_pos_laje is not None else '')
                
                # Larguras
                for l in range(1, 4):
                    campo_larg = getattr(self, f'larg{l}_{letra}', None)
                    if campo_larg and hasattr(campo_larg, 'set'):
                        valor_larg = painel.get(f'larg{l}', '')
                        campo_larg.set(str(valor_larg) if valor_larg is not None else '')
                
                # Alturas
                for h in range(1, 6):
                    campo_h = getattr(self, f'h{h}_{letra}', None)
                    if campo_h and hasattr(campo_h, 'set'):
                        valor_h = painel.get(f'h{h}', '')
                        campo_h.set(str(valor_h) if valor_h is not None else '')
                
                # ABERTURAS - Esquerda e Direita
                aberturas = painel.get('aberturas', {})
                
                # Aberturas esquerda
                aberturas_esq = aberturas.get('esquerda', {})
                for num in ['1', '2']:
                    abertura_esq = aberturas_esq.get(num, {})
                    campo_dist = getattr(self, f'dist_esq_{num}_{letra}', None)
                    _definir_valor_campo(campo_dist, abertura_esq.get('distancia', ''))
                    campo_larg = getattr(self, f'larg_esq_{num}_{letra}', None)
                    _definir_valor_campo(campo_larg, abertura_esq.get('largura', ''))
                    campo_prof = getattr(self, f'prof_esq_{num}_{letra}', None)
                    _definir_valor_campo(campo_prof, abertura_esq.get('profundidade', ''))
                    campo_pos = getattr(self, f'pos_esq_{num}_{letra}', None)
                    _definir_valor_campo(campo_pos, abertura_esq.get('posicao', ''))
                    campo_tipo = getattr(self, f'tipo_esq_{num}_{letra}', None)
                    _definir_valor_campo(campo_tipo, abertura_esq.get('tipo', ''))
                
                # Aberturas direita
                aberturas_dir = aberturas.get('direita', {})
                for num in ['1', '2']:
                    abertura_dir = aberturas_dir.get(num, {})
                    campo_dist = getattr(self, f'dist_dir_{num}_{letra}', None)
                    _definir_valor_campo(campo_dist, abertura_dir.get('distancia', ''))
                    campo_larg = getattr(self, f'larg_dir_{num}_{letra}', None)
                    _definir_valor_campo(campo_larg, abertura_dir.get('largura', ''))
                    campo_prof = getattr(self, f'prof_dir_{num}_{letra}', None)
                    _definir_valor_campo(campo_prof, abertura_dir.get('profundidade', ''))
                    campo_pos = getattr(self, f'pos_dir_{num}_{letra}', None)
                    _definir_valor_campo(campo_pos, abertura_dir.get('posicao', ''))
                    campo_tipo = getattr(self, f'tipo_dir_{num}_{letra}', None)
                    _definir_valor_campo(campo_tipo, abertura_dir.get('tipo', ''))
                
                # Aberturas de laje
                aberturas_laje = painel.get('aberturas_laje', {})
                if hasattr(self, 'abertura_laje'):
                    painel_key = letra.lower()
                    if painel_key in self.abertura_laje:
                        for k in ['esq1', 'esq2', 'dir1', 'dir2']:
                            try:
                                var = self.abertura_laje[painel_key].get(k)
                                if var and hasattr(var, 'set'):
                                    valor_abertura_laje = aberturas_laje.get(k, '0')
                                    var.set(str(valor_abertura_laje))
                            except Exception as e:
                                pass
            except Exception as e:
                import traceback
                continue
        
        # Hachura dos painéis
        hachura_paineis = dados.get('hachura_paineis', {})
        for letra in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:
            hachura_letra = hachura_paineis.get(letra, {})
            for i in range(1, 6):
                painel_id = f"{letra.lower()}_{i}"
                hachura_var_name = f"hachura_{painel_id}"
                if hasattr(self, hachura_var_name):
                    hachura_var = getattr(self, hachura_var_name)
                    valor = hachura_letra.get(f"painel_{i}", "0")
                    hachura_var.set(valor)
        
        # Pilar especial
        pilar_especial = dados.get('pilar_especial', {})
        if pilar_especial:
            # Ativar pilar especial
            if hasattr(self, 'pilar_especial_ativo_var'):
                self.pilar_especial_ativo_var.set(pilar_especial.get('ativar_pilar_especial', False))
            
            # Tipo de pilar especial
            if hasattr(self, 'tipo_pilar_especial_var'):
                self.tipo_pilar_especial_var.set(pilar_especial.get('tipo_pilar_especial', 'L'))
            
            # Comprimentos e larguras
            comprimentos = pilar_especial.get('comprimentos', {})
            campo_comp_1 = getattr(self, 'comp_1', None)
            _definir_valor_campo(campo_comp_1, comprimentos.get('comp_1', ''))
            campo_comp_2 = getattr(self, 'comp_2', None)
            _definir_valor_campo(campo_comp_2, comprimentos.get('comp_2', ''))
            campo_comp_3 = getattr(self, 'comp_3', None)
            _definir_valor_campo(campo_comp_3, comprimentos.get('comp_3', ''))
            
            larguras = pilar_especial.get('larguras', {})
            campo_larg_1 = getattr(self, 'larg_1', None)
            _definir_valor_campo(campo_larg_1, larguras.get('larg_1', ''))
            campo_larg_2 = getattr(self, 'larg_2', None)
            _definir_valor_campo(campo_larg_2, larguras.get('larg_2', ''))
            campo_larg_3 = getattr(self, 'larg_3', None)
            _definir_valor_campo(campo_larg_3, larguras.get('larg_3', ''))
            
            # Distância
            campo_distancia = getattr(self, 'distancia_especial', None)
            _definir_valor_campo(campo_distancia, pilar_especial.get('distancia', ''))
            
            # Grades especiais
            grades_especiais = pilar_especial.get('grades', {})
            for lado in ['a', 'b', 'e', 'f', 'g', 'h']:
                for num in ['1', '2', '3']:
                    campo_grade = getattr(self, f'grade_{lado}_{num}', None)
                    valor_grade = grades_especiais.get(f'grade_{lado}_{num}', '')
                    _definir_valor_campo(campo_grade, valor_grade)
                for num in ['1', '2']:
                    campo_dist = getattr(self, f'dist_{lado}_{num}', None)
                    valor_dist = grades_especiais.get(f'dist_{lado}_{num}', '')
                    _definir_valor_campo(campo_dist, valor_dist)
            
            # Detalhes das grades especiais
            detalhes_especiais = pilar_especial.get('detalhes_grades_especiais', {})
            for lado in ['a', 'b', 'e', 'f', 'g', 'h']:
                for grade_num in ['1', '2', '3']:
                    for detalhe_num in ['1', '2', '3', '4', '5']:
                        campo = getattr(self, f'detalhe_{lado}_{grade_num}_{detalhe_num}', None)
                        valor = detalhes_especiais.get(f'detalhe_{lado}_{grade_num}_{detalhe_num}', '')
                        _definir_valor_campo(campo, valor)
            
            # Alturas dos detalhes especiais
            alturas_especiais = pilar_especial.get('altura_detalhes_especiais', {})
            for lado in ['a', 'b', 'e', 'f', 'g', 'h']:
                for grade_num in ['1', '2', '3']:
                    for altura_num in ['0', '1', '2', '3', '4', '5']:
                        campo = getattr(self, f'altura_detalhe_{lado}_{grade_num}_{altura_num}', None)
                        valor = alturas_especiais.get(f'altura_detalhe_{lado}_{grade_num}_{altura_num}', '')
                        _definir_valor_campo(campo, valor)
            
            # Parafusos especiais
            parafusos_especiais = pilar_especial.get('parafusos_especiais', {})
            for lado in ['a', 'e']:
                parafusos_lado = parafusos_especiais.get(f'parafusos_{lado}', [])
                for i, valor in enumerate(parafusos_lado):
                    campo = getattr(self, f'par_{lado}_{i+1}', None)
                    _definir_valor_campo(campo, str(valor) if valor else '')
        
        # Modos - Carregar do item salvo
        modo_calculo_salvo = dados.get('modo_calculo', 'INI')
        tipo_distribuicao_salvo = dados.get('tipo_distribuicao_largura', 'INI')
        
        if hasattr(self, 'modo_calculo'):
            # Bloquear sincronização durante carregamento
            self._sync_blocking_modo_calc = True
            try:
                self.modo_calculo.set(modo_calculo_salvo)
            finally:
                self._sync_blocking_modo_calc = False
        
        if hasattr(self, 'tipo_distribuicao_largura'):
            # Bloquear sincronização durante carregamento
            self._sync_blocking_tipo_dist = True
            try:
                self.tipo_distribuicao_largura.set(tipo_distribuicao_salvo)
            finally:
                self._sync_blocking_tipo_dist = False
        
        print(f"[CARREGAR] Modo carregado para item {numero_item}: modo_calculo={modo_calculo_salvo}, tipo_distribuicao={tipo_distribuicao_salvo}")
        
        # Checkboxes
        if hasattr(self, 'checkbox_descontar_laje'):
            self.checkbox_descontar_laje.set(dados.get('checkbox_descontar_laje', 0))
        if hasattr(self, 'checkbox_descontar_aberturas'):
            self.checkbox_descontar_aberturas.set(dados.get('checkbox_descontar_aberturas', 0))
    
    def salvar_obra_json(self):
        """Exporta a obra selecionada completa em formato JSON"""
        from tkinter import filedialog, messagebox
        import json
        import os
        from datetime import datetime
        
        # Verificar se há obra selecionada
        obra_atual = self.obra_filtro_var.get()
        if not obra_atual or obra_atual not in self.obras:
            messagebox.showerror("Erro", "Selecione uma obra para salvar!")
            return
        
        # CRÍTICO: NÃO forçar salvamento - usar diretamente os dados já salvos em self.obras
        # A função _forcar_salvamento_todos_itens_obra pode estar causando perda de dados
        # ao recarregar na interface. Vamos usar diretamente os dados já salvos.
        
        # Salvar dados da obra atual antes de exportar
        try:
            self.salvar_pavimentos_por_obra()
        except Exception as e:
            # Continuar mesmo se houver erro
            pass
        
        # Preparar dados completos da obra
        obra_dados = {
            "nome_obra": obra_atual,
            "data_exportacao": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "versao_formato": "1.0",
            "pavimentos_data": self.obras[obra_atual].get("pavimentos_data", []),
            "pavimentos": {}
        }
        
        # Lista de campos obrigatórios que devem estar em cada item
        campos_obrigatorios = [
            "numero", "nome", "obra", "comprimento", "largura", "pavimento", 
            "pavimento_numero", "pavimento_anterior", "nivel_saida", "nivel_chegada",
            "nivel_diferencial", "altura", "parafusos", "grades", "pilar_especial",
            "detalhes_grades", "altura_detalhes_grades", "grades_grupo2",
            "detalhes_grades_grupo2", "altura_detalhes_grades_b", "ruler_grupo1",
            "paineis", "hachura_paineis", "modo_calculo", "tipo_distribuicao_largura",
            "checkbox_descontar_laje", "checkbox_descontar_aberturas", "m2_total"
        ]
        
        # Estatísticas de validação
        total_itens_validados = 0
        itens_com_campos_faltando = []
        total_paineis_validados = 0
        total_aberturas_validadas = 0
        
        # Copiar todos os pavimentos e seus itens
        import copy
        import hashlib
        
        for pavimento_nome, pavimento_dados in self.obras[obra_atual].items():
            if pavimento_nome != "pavimentos_data" and isinstance(pavimento_dados, dict):
                obra_dados["pavimentos"][pavimento_nome] = {}
                
                # Copiar todos os itens do pavimento com TODOS os campos
                for item_id, item_dados in pavimento_dados.items():
                    # CRÍTICO: Obter dados do item - verificar estrutura completa
                    if not isinstance(item_dados, dict):
                        continue
                    
                    # CRÍTICO: Fazer cópia profunda ANTES de qualquer modificação
                    # Isso garante que não modificamos os dados originais
                    item_dados_copia_original = copy.deepcopy(item_dados)
                    
                    # Obter dados do item (pode estar em "dados" ou diretamente)
                    dados_item_original = item_dados_copia_original.get("dados", {})
                    if not dados_item_original and isinstance(item_dados_copia_original, dict):
                        # Se não tem "dados", o próprio item_dados pode ser os dados
                        dados_item_original = item_dados_copia_original.copy()
                    
                    # CRÍTICO: Fazer cópia profunda dos dados ANTES de modificar
                    dados_item = copy.deepcopy(dados_item_original)
                    
                    
                    # Obter número do item corretamente (priorizar "numero", depois "nome", depois item_id)
                    numero_item = dados_item.get("numero") or dados_item.get("nome") or str(item_id)
                    numero_item = str(numero_item).strip()
                    
                    # CRÍTICO: Criar novo dicionário para modificações, preservando dados_item intacto
                    # Não modificar dados_item diretamente - criar cópia para modificações
                    dados_item_modificado = copy.deepcopy(dados_item)
                    
                    # Garantir que numero e nome estão nos dados (na cópia modificada)
                    if "numero" not in dados_item_modificado:
                        dados_item_modificado["numero"] = numero_item
                    if "nome" not in dados_item_modificado:
                        dados_item_modificado["nome"] = dados_item_modificado.get("nome", numero_item)
                    
                    # Garantir que obra e pavimento estão corretos (na cópia modificada)
                    if "obra" not in dados_item_modificado:
                        dados_item_modificado["obra"] = obra_atual
                    if "pavimento" not in dados_item_modificado:
                        dados_item_modificado["pavimento"] = pavimento_nome
                    
                    # Usar dados_item_modificado daqui em diante
                    dados_item = dados_item_modificado
                    
                    # CRÍTICO: Validar se todos os campos obrigatórios estão presentes
                    campos_faltando = []
                    for campo in campos_obrigatorios:
                        if campo not in dados_item:
                            campos_faltando.append(campo)
                    
                    if campos_faltando:
                        itens_com_campos_faltando.append({
                            "item": f"{pavimento_nome}/{numero_item}",
                            "campos_faltando": campos_faltando
                        })
                    
                    # CRÍTICO: Garantir que o item tem ID único completo
                    # Se não tiver, gerar um baseado nos dados
                    id_unico_completo = item_dados_copia_original.get("id_unico_completo")
                    identificador_base = item_dados_copia_original.get("identificador_base")
                    
                    if not id_unico_completo:
                        # Gerar ID único baseado nos dados
                        nome_item = dados_item.get("nome", numero_item)
                        pavimento_item = dados_item.get("pavimento", pavimento_nome)
                        obra_item = dados_item.get("obra", obra_atual)
                        
                        identificador_base = f"{numero_item}-{nome_item}-{pavimento_item}-{obra_item}"
                        hash_id = hashlib.md5(identificador_base.encode('utf-8')).hexdigest()[:8]
                        id_unico_completo = f"{identificador_base}-{hash_id}"
                    
                    if not identificador_base:
                        # Extrair do id_unico_completo se existir
                        if id_unico_completo and '-' in id_unico_completo:
                            identificador_base = id_unico_completo.rsplit('-', 1)[0]
                        else:
                            nome_item = dados_item.get("nome", numero_item)
                            pavimento_item = dados_item.get("pavimento", pavimento_nome)
                            obra_item = dados_item.get("obra", obra_atual)
                            identificador_base = f"{numero_item}-{nome_item}-{pavimento_item}-{obra_item}"
                    
                    # CRÍTICO: NÃO modificar a estrutura de painéis - apenas validar e contar
                    # Qualquer modificação pode causar perda de dados. A cópia profunda já preserva tudo.
                    paineis = dados_item.get('paineis', {})
                    if paineis:
                        for letra, painel in paineis.items():
                            if isinstance(painel, dict):
                                total_paineis_validados += 1
                                
                                # Verificar campos obrigatórios do painel (apenas para log, não modificar)
                                campos_painel_obrigatorios = ['laje', 'posicao_laje', 'larg1', 'larg2', 'larg3', 'h1', 'h2', 'h3', 'h4', 'h5', 'aberturas']
                                for campo_painel in campos_painel_obrigatorios:
                                    if campo_painel not in painel:
                                        pass
                                
                                # Contar aberturas (NÃO modificar estrutura)
                                aberturas = painel.get('aberturas', {})
                                if aberturas and isinstance(aberturas, dict):
                                    for lado in ['esquerda', 'direita']:
                                        lado_aberturas = aberturas.get(lado, {})
                                        if lado_aberturas and isinstance(lado_aberturas, dict):
                                            for num in ['1', '2']:
                                                abertura = lado_aberturas.get(num, {})
                                                if abertura and isinstance(abertura, dict):
                                                    if abertura.get('distancia', ''):
                                                        total_aberturas_validadas += 1
                                
                                # Verificar aberturas_laje (apenas verificar, não criar se não existir)
                                # Não criar campos vazios - isso pode causar problemas na importação
                                if 'aberturas_laje' not in painel:
                                    # Apenas log, não criar campo vazio
                                    pass
                    else:
                        # Se não tem paineis, apenas log (não criar estrutura vazia)
                        pass
                    
                    # Verificar hachura_paineis (apenas verificar, não criar se não existir)
                    if 'hachura_paineis' not in dados_item:
                        # Apenas log, não criar campo vazio
                        pass
                    
                    # CRÍTICO: Fazer uma NOVA cópia profunda final para garantir que nada foi modificado
                    # Isso garante que mesmo se tivermos modificado algo acidentalmente, temos uma cópia limpa
                    dados_item_copia = copy.deepcopy(dados_item)
                    
                    # Garantir que dados_item_copia tem o ID único completo
                    if "id_unico_completo" not in dados_item_copia:
                        dados_item_copia["id_unico_completo"] = id_unico_completo
                    if "identificador_base" not in dados_item_copia:
                        dados_item_copia["identificador_base"] = identificador_base
                    
                    # Obter item_id correto (pode ser numero_item ou item_id original)
                    # CRÍTICO: Usar item_dados_copia_original, não item_dados original
                    item_id_final = item_dados_copia_original.get("item_id", numero_item)
                    if not item_id_final or item_id_final == item_id:
                        item_id_final = numero_item
                    
                    # CRÍTICO: Copiar TODA a estrutura do item, incluindo locks e outros metadados
                    # Usar item_dados_copia_original para locks também
                    item_copia_completa = {
                        "dados": dados_item_copia,  # Cópia profunda de TODOS os dados
                        "item_id": item_id_final,
                        "id_unico_completo": id_unico_completo,
                        "identificador_base": identificador_base,
                        "locks": copy.deepcopy(item_dados_copia_original.get("locks", {}))  # CRÍTICO: Incluir locks da cópia
                    }
                    
                    
                    # Usar numero_item como chave para garantir consistência
                    obra_dados["pavimentos"][pavimento_nome][numero_item] = item_copia_completa
                    
                    total_itens_validados += 1
                    
        
        # Solicitar local e nome do arquivo
        nome_sugerido = f"{obra_atual.replace(' ', '_')}_{datetime.now().strftime('%Y%m%d')}.json"
        arquivo = filedialog.asksaveasfilename(
            title="Salvar Obra",
            defaultextension=".json",
            initialfile=nome_sugerido,
            filetypes=[("JSON", "*.json"), ("Todos os arquivos", "*.*")]
        )
        
        if not arquivo:
            return
        
        try:
            # CRÍTICO: Verificar se está em modo frozen antes de salvar
            import sys
            is_frozen = getattr(sys, 'frozen', False)
            if is_frozen:
                # CRÍTICO: Validação final antes de salvar no JSON
                total_lajes_final = 0
                total_aberturas_final = 0
                for pav_nome_final, pav_dados_final in obra_dados["pavimentos"].items():
                    for item_id_final, item_dados_final in pav_dados_final.items():
                        dados_final = item_dados_final.get("dados", {})
                        paineis_final = dados_final.get('paineis', {})
                        for letra_final, painel_final in paineis_final.items():
                            if isinstance(painel_final, dict):
                                if painel_final.get('laje', ''):
                                    total_lajes_final += 1
                                ab_final = painel_final.get('aberturas', {})
                                if ab_final:
                                    for lado_final in ['esquerda', 'direita']:
                                        lado_ab_final = ab_final.get(lado_final, {})
                                        for num_final in ['1', '2']:
                                            ab_item_final = lado_ab_final.get(num_final, {})
                                            if ab_item_final and ab_item_final.get('distancia', ''):
                                                total_aberturas_final += 1
            # Salvar em JSON com validação
            with open(arquivo, 'w', encoding='utf-8') as f:
                json.dump(obra_dados, f, indent=2, ensure_ascii=False)
            
            # Verificar se o arquivo foi salvo corretamente
            if not os.path.exists(arquivo):
                raise Exception(f"Arquivo não foi criado: {arquivo}")
            
            tamanho_arquivo = os.path.getsize(arquivo)
            
            # Validar arquivo salvo (ler de volta e verificar estrutura)
            try:
                with open(arquivo, 'r', encoding='utf-8') as f:
                    obra_validacao = json.load(f)
                
                # Verificar estrutura básica
                if "nome_obra" not in obra_validacao:
                    raise Exception("Arquivo salvo não contém 'nome_obra'")
                if "pavimentos" not in obra_validacao:
                    raise Exception("Arquivo salvo não contém 'pavimentos'")
                
                # Contar itens no arquivo salvo
                total_itens_salvos = sum(len(pav) for pav in obra_validacao["pavimentos"].values())
                total_pavimentos = len(obra_validacao["pavimentos"])
                
                # Verificar se todos os itens têm locks
                itens_sem_locks = 0
                for pav_nome, pav_dados in obra_validacao["pavimentos"].items():
                    for item_id, item_dados in pav_dados.items():
                        if "locks" not in item_dados:
                            itens_sem_locks += 1
                
                if itens_sem_locks > 0:
                    pass
                
            except Exception as e:
                pass
                # Continuar mesmo assim
            
            # Contar total de itens
            total_itens = sum(len(pav) for pav in obra_dados["pavimentos"].values())
            total_pavimentos = len(obra_dados["pavimentos"])
            
            mensagem = (
                f"Obra '{obra_atual}' salva com sucesso!\n\n"
                f"📁 Arquivo: {os.path.basename(arquivo)}\n"
                f"📊 Tamanho: {tamanho_arquivo:,} bytes\n"
                f"🏢 Pavimentos: {total_pavimentos}\n"
                f"📦 Total de itens: {total_itens}\n"
                f"🏗️ Painéis: {total_paineis_validados}\n"
                f"🚪 Aberturas: {total_aberturas_validadas}\n"
            )
            
            if itens_com_campos_faltando:
                mensagem += f"\n⚠️ {len(itens_com_campos_faltando)} itens com campos faltando (verifique os logs)"
            
            mensagem += f"\n\nCompartilhe este arquivo para transferir a obra completa!"
            
            messagebox.showinfo("Sucesso", mensagem)
            
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao salvar obra:\n{str(e)}")
    
    def importar_obra_json(self):
        """
        Importa uma obra completa de arquivo JSON de forma robusta.
        Garante que TODOS os dados sejam importados corretamente, incluindo:
        - Dados completos de cada item
        - Locks de cada item
        - Pavimentos_data
        - Estrutura completa de painéis, lajes, aberturas, etc.
        """
        from tkinter import filedialog, messagebox
        import json
        import os
        import copy
        
        # Selecionar arquivo
        arquivo = filedialog.askopenfilename(
            title="Importar Obra",
            filetypes=[("JSON", "*.json"), ("Todos os arquivos", "*.*")]
        )
        
        if not arquivo:
            return
        
        try:
            # CRÍTICO: Verificar se está em modo frozen
            import sys
            is_frozen = getattr(sys, 'frozen', False)
            
            # Verificar se o arquivo existe e é acessível
            if not os.path.exists(arquivo):
                raise Exception(f"Arquivo não encontrado: {arquivo}")
            
            tamanho_arquivo = os.path.getsize(arquivo)
            
            # Carregar dados do JSON
            with open(arquivo, 'r', encoding='utf-8') as f:
                obra_dados = json.load(f)
            
            # Validar estrutura básica
            if "nome_obra" not in obra_dados:
                messagebox.showerror("Erro", "Arquivo JSON inválido! Campo 'nome_obra' não encontrado.")
                return
            
            if "pavimentos" not in obra_dados:
                messagebox.showerror("Erro", "Arquivo JSON inválido! Campo 'pavimentos' não encontrado.")
                return
            
            nome_obra = obra_dados["nome_obra"]
            
            # Verificar se obra já existe
            if nome_obra in self.obras:
                # Contar dados existentes
                total_pavimentos_existentes = 0
                total_itens_existentes = 0
                for pav_nome, pav_dados in self.obras[nome_obra].items():
                    if pav_nome != "pavimentos_data" and isinstance(pav_dados, dict):
                        total_pavimentos_existentes += 1
                        total_itens_existentes += len(pav_dados)
                
                resposta = messagebox.askyesno(
                    "Obra Existente",
                    f"A obra '{nome_obra}' já existe!\n\n"
                    f"⚠️ Dados existentes serão COMPLETAMENTE REMOVIDOS!\n\n"
                    f"Dados existentes:\n"
                    f"  • {total_pavimentos_existentes} pavimento(s)\n"
                    f"  • {total_itens_existentes} item(s)\n\n"
                    f"Deseja substituir completamente a obra existente?\n\n"
                    f"• SIM: Remove TODOS os dados existentes e importa novos\n"
                    f"• NÃO: Cancela importação"
                )
                if not resposta:
                    return
                
                # CRÍTICO: Excluir completamente a obra existente antes de importar
                
                # Excluir todos os itens de pilares_salvos que pertencem à obra usando helpers
                chaves_para_excluir = []
                for chave_composta, item_dados in list(self.pilares_salvos.items()):
                    if isinstance(item_dados, dict):
                        obra_item = item_dados.get("obra")
                        if obra_item == nome_obra:
                            # Obter numero e pavimento do item para usar helper
                            dados_item = item_dados.get("dados", {})
                            numero_item = dados_item.get("numero")
                            pavimento_item = dados_item.get("pavimento")
                            if numero_item and pavimento_item:
                                self._delete_pilar_salvo_entry(numero_item, pavimento_item, obra_item)
                            else:
                                # Fallback: deletar pela chave antiga
                                del self.pilares_salvos[chave_composta]
                            chaves_para_excluir.append(chave_composta)
                
                # Excluir a obra completamente
                del self.obras[nome_obra]
            
            # CRÍTICO: Fazer cópia profunda dos dados para evitar problemas de referência
            obra_dados_copia = copy.deepcopy(obra_dados)
            
            # Criar/substituir obra com estrutura completa
            self.obras[nome_obra] = {
                "pavimentos_data": copy.deepcopy(obra_dados_copia.get("pavimentos_data", []))
            }
            
            # Importar todos os pavimentos e itens com validação completa
            total_itens = 0
            total_paineis_com_laje = 0
            total_aberturas = 0
            itens_com_problemas = []
            
            for pavimento_nome, pavimento_dados in obra_dados_copia["pavimentos"].items():
                if not isinstance(pavimento_dados, dict):
                    continue
                
                self.obras[nome_obra][pavimento_nome] = {}
                
                for item_id, item_dados in pavimento_dados.items():
                    if not isinstance(item_dados, dict):
                        continue
                    
                    # CRÍTICO: Importar TODOS os campos do item
                    dados_item = item_dados.get("dados", {})
                    
                    # Validar se dados existe e não está vazio
                    if not dados_item or not isinstance(dados_item, dict):
                        itens_com_problemas.append(f"{pavimento_nome}/{item_id} (sem dados)")
                        # Criar estrutura mínima para não perder o item
                        dados_item = {"nome": str(item_id), "numero": str(item_id)}
                    
                    # CRÍTICO: Validar e contar painéis com laje e aberturas APENAS se realmente existirem
                    # Não contar valores vazios ou strings vazias
                    paineis = dados_item.get('paineis', {})
                    if paineis and isinstance(paineis, dict):
                        for letra, painel in paineis.items():
                            if isinstance(painel, dict):
                                # Validar se laje existe e não está vazio (não é '', None, 0, '0', etc)
                                laje_valor = painel.get('laje', '')
                                if laje_valor and str(laje_valor).strip() and str(laje_valor).strip() != '0':
                                    total_paineis_com_laje += 1
                                
                                # Validar aberturas - só contar se tiver distancia válida
                                aberturas = painel.get('aberturas', {})
                                if aberturas and isinstance(aberturas, dict):
                                    for lado in ['esquerda', 'direita']:
                                        lado_aberturas = aberturas.get(lado, {})
                                        if lado_aberturas and isinstance(lado_aberturas, dict):
                                            for num in ['1', '2']:
                                                abertura = lado_aberturas.get(num, {})
                                                if abertura and isinstance(abertura, dict):
                                                    distancia = abertura.get('distancia', '')
                                                    # Só contar se distancia não estiver vazia
                                                    if distancia and str(distancia).strip() and str(distancia).strip() != '0':
                                                        total_aberturas += 1
                    
                    # CRÍTICO: Gerar ou recuperar ID único completo
                    id_unico_completo = item_dados.get("id_unico_completo")
                    identificador_base = item_dados.get("identificador_base")
                    
                    if not id_unico_completo:
                        # Gerar ID único baseado nos dados
                        numero_item = dados_item.get("numero", str(item_id))
                        nome_item = dados_item.get("nome", numero_item)
                        pavimento_item = dados_item.get("pavimento", pavimento_nome)
                        obra_item = dados_item.get("obra", nome_obra)
                        
                        import hashlib
                        identificador_base = f"{numero_item}-{nome_item}-{pavimento_item}-{obra_item}"
                        hash_id = hashlib.md5(identificador_base.encode('utf-8')).hexdigest()[:8]
                        id_unico_completo = f"{numero_item}-{nome_item}-{pavimento_item}-{obra_item}-{hash_id}"
                    
                    # CRÍTICO: Validar estrutura de dados antes de importar
                    # Verificar se paineis existe e tem estrutura correta
                    if 'paineis' not in dados_item:
                        dados_item['paineis'] = {}
                    elif not isinstance(dados_item['paineis'], dict):
                        dados_item['paineis'] = {}
                    
                    # Validar estrutura de cada painel
                    paineis_validados = {}
                    for letra_val, painel_val in dados_item.get('paineis', {}).items():
                        if isinstance(painel_val, dict):
                            # Garantir que painel tem estrutura completa
                            painel_completo = {
                                'laje': painel_val.get('laje', ''),
                                'posicao_laje': painel_val.get('posicao_laje', ''),
                                'larg1': painel_val.get('larg1', ''),
                                'larg2': painel_val.get('larg2', ''),
                                'larg3': painel_val.get('larg3', ''),
                                'h1': painel_val.get('h1', ''),
                                'h2': painel_val.get('h2', ''),
                                'h3': painel_val.get('h3', ''),
                                'h4': painel_val.get('h4', ''),
                                'h5': painel_val.get('h5', ''),
                                'aberturas': painel_val.get('aberturas', {}),
                                'aberturas_laje': painel_val.get('aberturas_laje', {})
                            }
                            
                            # CRÍTICO: Garantir que aberturas tem estrutura correta PRESERVANDO dados existentes
                            aberturas_original = painel_val.get('aberturas', {})
                            
                            if not isinstance(aberturas_original, dict):
                                # Se não é dict, criar estrutura vazia
                                aberturas_final = {
                                    'esquerda': {'1': {}, '2': {}},
                                    'direita': {'1': {}, '2': {}}
                                }
                            else:
                                # Preservar dados existentes e garantir estrutura completa
                                aberturas_final = copy.deepcopy(aberturas_original)
                                
                                # Garantir que tem 'esquerda' e 'direita'
                                if 'esquerda' not in aberturas_final or not isinstance(aberturas_final.get('esquerda'), dict):
                                    aberturas_final['esquerda'] = {}
                                
                                if 'direita' not in aberturas_final or not isinstance(aberturas_final.get('direita'), dict):
                                    aberturas_final['direita'] = {}
                                
                                # Garantir que cada lado tem '1' e '2', preservando dados existentes
                                for lado_ab in ['esquerda', 'direita']:
                                    if not isinstance(aberturas_final[lado_ab], dict):
                                        aberturas_final[lado_ab] = {}
                                    
                                    for num_ab in ['1', '2']:
                                        if num_ab not in aberturas_final[lado_ab]:
                                            aberturas_final[lado_ab][num_ab] = {}
                                        elif not isinstance(aberturas_final[lado_ab][num_ab], dict):
                                            # Se existe mas não é dict, preservar valor se possível
                                            valor_antigo = aberturas_final[lado_ab][num_ab]
                                            aberturas_final[lado_ab][num_ab] = {}
                                    
                                    # Garantir que cada abertura tem campos padrão se não existirem
                                    for num_ab in ['1', '2']:
                                        abertura_atual = aberturas_final[lado_ab][num_ab]
                                        if not isinstance(abertura_atual, dict):
                                            abertura_atual = {}
                                        
                                        # Campos padrão de abertura
                                        campos_abertura = ['distancia', 'largura', 'profundidade', 'posicao', 'tipo']
                                        for campo_ab in campos_abertura:
                                            if campo_ab not in abertura_atual:
                                                abertura_atual[campo_ab] = ''
                                        
                                        aberturas_final[lado_ab][num_ab] = abertura_atual
                            
                            painel_completo['aberturas'] = aberturas_final
                            
                            # CRÍTICO: Preservar aberturas_laje também
                            aberturas_laje_original = painel_val.get('aberturas_laje', {})
                            if isinstance(aberturas_laje_original, dict):
                                painel_completo['aberturas_laje'] = copy.deepcopy(aberturas_laje_original)
                            else:
                                # Criar estrutura padrão se não existir
                                painel_completo['aberturas_laje'] = {
                                    'esq1': '0',
                                    'esq2': '0',
                                    'dir1': '0',
                                    'dir2': '0'
                                }
                            
                            paineis_validados[letra_val] = painel_completo
                        else:
                            pass
                    
                    # Substituir paineis com versão validada
                    dados_item['paineis'] = paineis_validados
                    
                    # CRÍTICO: Importar TODOS os campos, incluindo locks e ID único
                    # Usar deepcopy para garantir que não há referências compartilhadas
                    item_importado = {
                        "dados": copy.deepcopy(dados_item),  # Cópia profunda dos dados VALIDADOS
                        "item_id": item_dados.get("item_id", item_id),  # Usar item_id como fallback
                        "id_unico_completo": id_unico_completo,  # CRÍTICO: ID único completo
                        "identificador_base": identificador_base or id_unico_completo.rsplit('-', 1)[0],  # Identificador base
                        "locks": copy.deepcopy(item_dados.get("locks", {}))  # Importar locks também
                    }
                    
                    # Garantir que item_id está presente
                    if not item_importado["item_id"]:
                        item_importado["item_id"] = item_id
                    
                    # Garantir que dados tem campos essenciais
                    if "numero" not in item_importado["dados"]:
                        item_importado["dados"]["numero"] = str(item_id)
                    if "nome" not in item_importado["dados"]:
                        item_importado["dados"]["nome"] = str(item_id)
                    
                    # CRÍTICO: Garantir que dados tem o ID único completo
                    if "id_unico_completo" not in item_importado["dados"]:
                        item_importado["dados"]["id_unico_completo"] = id_unico_completo
                    if "identificador_base" not in item_importado["dados"]:
                        item_importado["dados"]["identificador_base"] = identificador_base
                    
                    # CRÍTICO: Validar dados ANTES de salvar
                    dados_finais = item_importado["dados"]
                    paineis_finais = dados_finais.get('paineis', {})
                    
                    
                    # Salvar na estrutura
                    self.obras[nome_obra][pavimento_nome][item_id] = item_importado
                    
                    # CRÍTICO: Verificar se foi salvo corretamente
                    item_salvo = self.obras[nome_obra][pavimento_nome].get(item_id)
                    
                    total_itens += 1
                    
                    # Log de aberturas encontradas
                    aberturas_encontradas = []
                    for letra_log, painel_log in paineis_finais.items():
                        if isinstance(painel_log, dict):
                            aberturas_log = painel_log.get('aberturas', {})
                            if aberturas_log:
                                for lado_log in ['esquerda', 'direita']:
                                    lado_aberturas_log = aberturas_log.get(lado_log, {})
                                    if lado_aberturas_log:
                                        for num_log in ['1', '2']:
                                            abertura_log = lado_aberturas_log.get(num_log, {})
                                            if abertura_log:
                                                distancia_log = abertura_log.get('distancia', '')
                                                if distancia_log and str(distancia_log).strip() and str(distancia_log).strip() != '0':
                                                    aberturas_encontradas.append(f"{letra_log}-{lado_log}-{num_log}:{distancia_log}")
            
            # CRÍTICO: Validar dados REALMENTE importados após salvar
            # Contar novamente os dados que foram realmente salvos em self.obras
            total_paineis_com_laje_validados = 0
            total_aberturas_validadas = 0
            total_itens_validados = 0
            
            if nome_obra in self.obras:
                for pav_nome, pav_dados in self.obras[nome_obra].items():
                    if pav_nome != "pavimentos_data" and isinstance(pav_dados, dict):
                        for item_id_val, item_dados_val in pav_dados.items():
                            if isinstance(item_dados_val, dict):
                                total_itens_validados += 1
                                dados_item_val = item_dados_val.get("dados", {})
                                paineis_val = dados_item_val.get('paineis', {})
                                
                                if paineis_val and isinstance(paineis_val, dict):
                                    for letra_val, painel_val in paineis_val.items():
                                        if isinstance(painel_val, dict):
                                            # Validar laje realmente importada
                                            laje_valor_val = painel_val.get('laje', '')
                                            if laje_valor_val and str(laje_valor_val).strip() and str(laje_valor_val).strip() != '0':
                                                total_paineis_com_laje_validados += 1
                                            
                                            # Validar aberturas realmente importadas
                                            aberturas_val = painel_val.get('aberturas', {})
                                            if aberturas_val and isinstance(aberturas_val, dict):
                                                for lado_val in ['esquerda', 'direita']:
                                                    lado_aberturas_val = aberturas_val.get(lado_val, {})
                                                    if lado_aberturas_val and isinstance(lado_aberturas_val, dict):
                                                        for num_val in ['1', '2']:
                                                            abertura_val = lado_aberturas_val.get(num_val, {})
                                                            if abertura_val and isinstance(abertura_val, dict):
                                                                distancia_val = abertura_val.get('distancia', '')
                                                                if distancia_val and str(distancia_val).strip() and str(distancia_val).strip() != '0':
                                                                    total_aberturas_validadas += 1
            
            
            # Log detalhado de validação para primeiros itens
            if nome_obra in self.obras and total_itens_validados > 0:
                itens_validados_logados = 0
                for pav_nome_log, pav_dados_log in self.obras[nome_obra].items():
                    if pav_nome_log != "pavimentos_data" and isinstance(pav_dados_log, dict):
                        for item_id_log, item_dados_log in pav_dados_log.items():
                            if itens_validados_logados >= 3:
                                break
                            if isinstance(item_dados_log, dict):
                                dados_item_log = item_dados_log.get("dados", {})
                                paineis_log = dados_item_log.get('paineis', {})
                                
                                
                                itens_validados_logados += 1
                        if itens_validados_logados >= 3:
                            break
            
            # Salvar estrutura de obras
            try:
                self.salvar_obras()
            except Exception as e:
                pass
            
            # Atualizar interface
            try:
                self.atualizar_combo_obras()
                self.obra_filtro_var.set(nome_obra)
                self.atualizar_pavimentos_por_obra()
                self.atualizar_lista()
            except Exception as e:
                import traceback
                traceback.print_exc()
            
            # Mensagem de sucesso com informações detalhadas VALIDADAS
            total_pavimentos = len(obra_dados_copia["pavimentos"])
            data_exp = obra_dados_copia.get("data_exportacao", "desconhecida")
            versao = obra_dados_copia.get("versao_formato", "desconhecida")
            
            # Usar valores VALIDADOS em vez dos valores do JSON
            mensagem = (
                f"Obra '{nome_obra}' importada com sucesso!\n\n"
                f"📁 Arquivo: {os.path.basename(arquivo)}\n"
                f"📅 Data de exportação: {data_exp}\n"
                f"🔢 Versão do formato: {versao}\n"
                f"🏢 Pavimentos: {total_pavimentos}\n"
                f"📦 Total de itens: {total_itens_validados}\n"
                f"🏗️ Painéis com laje: {total_paineis_com_laje_validados}\n"
                f"🚪 Aberturas: {total_aberturas_validadas}\n"
            )
            
            # Adicionar aviso se houver discrepâncias
            if total_paineis_com_laje != total_paineis_com_laje_validados or total_aberturas != total_aberturas_validadas:
                mensagem += (
                    f"\n⚠️ AVISO: Alguns dados do JSON não foram importados corretamente.\n"
                    f"Verifique os logs para mais detalhes."
                )
            
            if itens_com_problemas:
                mensagem += f"\n⚠️ {len(itens_com_problemas)} itens com problemas detectados (verifique os logs)"
            
            mensagem += f"\n\nA obra foi adicionada ao combobox e está pronta para uso!"
            
            messagebox.showinfo("Sucesso", mensagem)
            
        except json.JSONDecodeError as e:
            error_msg = f"Erro ao ler arquivo JSON:\n{str(e)}\n\nVerifique se o arquivo está corrompido ou em formato inválido."
            messagebox.showerror("Erro", error_msg)
        except Exception as e:
            import traceback
            error_msg = f"Erro ao importar obra:\n{str(e)}\n\nTraceback:\n{traceback.format_exc()}"
            messagebox.showerror("Erro", f"Erro ao importar obra:\n{str(e)}")
    
    def salvar_debug_json(self):
        """Salva apenas o item selecionado, do pavimento selecionado, da obra selecionada"""
        from tkinter import filedialog, messagebox
        import json
        import os
        from datetime import datetime
        
        # Verificar se há obra selecionada
        obra_atual = self.obra_filtro_var.get()
        if not obra_atual or obra_atual not in self.obras:
            messagebox.showerror("Erro", "Selecione uma obra para salvar!")
            return
        
        # Verificar se há pavimento selecionado
        pavimento_atual = self.pavimento_filtro_var.get()
        if not pavimento_atual or pavimento_atual == "Todos":
            messagebox.showerror("Erro", "Selecione um pavimento específico no filtro para salvar!")
            return
        
        # Verificar se o pavimento existe na obra
        if pavimento_atual not in self.obras[obra_atual]:
            messagebox.showerror("Erro", f"Pavimento '{pavimento_atual}' não encontrado na obra '{obra_atual}'!")
            return
        
        # Verificar se há item selecionado na lista
        selection = self.lista_pilares.selection()
        if not selection:
            messagebox.showerror("Erro", "Selecione um item na lista para salvar!")
            return
        
        # Obter dados do item selecionado
        item_selecionado = self.lista_pilares.item(selection[0])
        valores = item_selecionado.get('values', [])
        
        if not valores or len(valores) == 0:
            messagebox.showerror("Erro", "Não foi possível obter dados do item selecionado!")
            return
        
        numero_item = str(valores[0]).strip()
        
        # Buscar o item nos dados da obra
        pavimento_dados = self.obras[obra_atual][pavimento_atual]
        
        # Tentar encontrar o item pelo número (pode ser string ou int)
        item_dados = None
        item_id_encontrado = None
        
        if numero_item in pavimento_dados:
            item_dados = pavimento_dados[numero_item]
            item_id_encontrado = numero_item
        else:
            try:
                numero_int = int(numero_item)
                if numero_int in pavimento_dados:
                    item_dados = pavimento_dados[numero_int]
                    item_id_encontrado = numero_int
            except:
                pass
        
        # Se não encontrou pelo número direto, procurar em todos os itens
        if not item_dados:
            for item_id, dados in pavimento_dados.items():
                if isinstance(dados, dict):
                    dados_item = dados.get("dados", {})
                    nome_item = dados_item.get("nome", str(item_id))
                    if str(nome_item) == numero_item:
                        item_dados = dados
                        item_id_encontrado = item_id
                        break
        
        if not item_dados:
            messagebox.showerror("Erro", f"Item '{numero_item}' não encontrado no pavimento '{pavimento_atual}'!")
            return
        
        # CRÍTICO: Forçar salvamento do item selecionado com TODOS os campos antes de exportar
        # Isso garante que lajes, posições de laje, aberturas, checkbuttons, etc. sejam salvos
        try:
            # Carregar item na interface (isso preenche todos os campos)
            dados_item_salvo = item_dados.get("dados", {})
            self._carregar_item_para_salvamento(numero_item, pavimento_atual, {"dados": dados_item_salvo})
            
            # Aguardar um momento para garantir que os campos foram atualizados
            self.update_idletasks()
            
            # Salvar o item com todos os campos atualizados
            self.salvar_pilar(mostrar_mensagem=False)
            
            # Atualizar item_dados com os dados recém-salvos
            obra_atual = self.obra_filtro_var.get()
            if obra_atual in self.obras and pavimento_atual in self.obras[obra_atual]:
                pavimento_dados = self.obras[obra_atual][pavimento_atual]
                if item_id_encontrado in pavimento_dados:
                    item_dados = pavimento_dados[item_id_encontrado]
        except Exception as e:
            import traceback
            # Continuar mesmo se houver erro - pelo menos tentar exportar o que já está salvo
            pass
        
        # Salvar dados do pavimento antes de exportar
        self.salvar_pavimentos_por_obra()
        
        # Obter dados do pavimento (pavimentos_data)
        pavimentos_data = self.obras[obra_atual].get("pavimentos_data", [])
        pavimento_data_info = None
        for pav_data in pavimentos_data:
            if isinstance(pav_data, dict) and pav_data.get("nome") == pavimento_atual:
                pavimento_data_info = pav_data
                break
        
        # CRÍTICO: Garantir que o item tem ID único completo
        id_unico_completo = item_dados.get("id_unico_completo")
        identificador_base = item_dados.get("identificador_base")
        
        if not id_unico_completo:
            # Gerar ID único baseado nos dados
            dados_item_salvo = item_dados.get("dados", {})
            numero_item = dados_item_salvo.get("numero", str(item_id_encontrado))
            nome_item = dados_item_salvo.get("nome", numero_item)
            
            import hashlib
            identificador_base = f"{numero_item}-{nome_item}-{pavimento_atual}-{obra_atual}"
            hash_id = hashlib.md5(identificador_base.encode('utf-8')).hexdigest()[:8]
            id_unico_completo = f"{numero_item}-{nome_item}-{pavimento_atual}-{obra_atual}-{hash_id}"
            
        
        # Garantir que dados tem o ID único completo
        dados_item_final = item_dados.get("dados", {})
        if "id_unico_completo" not in dados_item_final:
            dados_item_final["id_unico_completo"] = id_unico_completo
        if "identificador_base" not in dados_item_final:
            dados_item_final["identificador_base"] = identificador_base or id_unico_completo.rsplit('-', 1)[0]
        
        # Preparar dados para salvar (formato compatível com importar_obra_json)
        obra_dados = {
            "nome_obra": obra_atual,
            "data_exportacao": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "versao_formato": "1.0",
            "pavimentos_data": [pavimento_data_info] if pavimento_data_info else [],
            "pavimentos": {
                pavimento_atual: {
                    item_id_encontrado: {
                        "dados": dados_item_final,  # Dados com ID único completo
                        "item_id": item_dados.get("item_id", item_id_encontrado),
                        "id_unico_completo": id_unico_completo,  # CRÍTICO: ID único completo
                        "identificador_base": identificador_base or id_unico_completo.rsplit('-', 1)[0],  # Identificador base
                        "locks": item_dados.get("locks", {})  # CRÍTICO: Incluir locks também
                    }
                }
            }
        }
        
        # Solicitar local e nome do arquivo
        nome_sugerido = f"{obra_atual.replace(' ', '_')}_{pavimento_atual.replace(' ', '_')}_{numero_item}_{datetime.now().strftime('%Y%m%d')}_debug.json"
        arquivo = filedialog.asksaveasfilename(
            title="Salvar-Debug (Item Selecionado)",
            defaultextension=".json",
            initialfile=nome_sugerido,
            filetypes=[("JSON", "*.json"), ("Todos os arquivos", "*.*")]
        )
        
        if not arquivo:
            return
        
        try:
            # Salvar em JSON
            with open(arquivo, 'w', encoding='utf-8') as f:
                json.dump(obra_dados, f, indent=2, ensure_ascii=False)
            
            messagebox.showinfo(
                "Sucesso",
                f"Item salvo com sucesso!\n\n"
                f"📁 Arquivo: {os.path.basename(arquivo)}\n"
                f"🏢 Obra: {obra_atual}\n"
                f"🏗️ Pavimento: {pavimento_atual}\n"
                f"📦 Item: {numero_item}\n\n"
                f"Este arquivo pode ser importado usando o botão 'Importar Obra'!"
            )
            
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao salvar item:\n{str(e)}")

    def carregar_obras(self):

        """Carrega a estrutura de obras do arquivo"""

        try:

            import pickle

            import os

            caminho_arquivo = self.obter_caminho_dados("obras_salvas.pkl")
            
            print(f">>> [carregar_obras] Carregando de: {caminho_arquivo}")

            if os.path.exists(caminho_arquivo):

                with open(caminho_arquivo, 'rb') as arquivo:

                    self.obras = pickle.load(arquivo)
                
                print(f">>> [carregar_obras] Obras carregadas: {list(self.obras.keys())}")

                return True

            else:

                print(f">>> [carregar_obras] Arquivo não existe: {caminho_arquivo}")
                return False

        except Exception as e:
            print(f">>> [carregar_obras] ERRO ao carregar: {e}")
            import traceback
            traceback.print_exc()
            return False

    

    def criar_obra(self):
        """Cria uma nova obra"""
        try:
            import sys
            from tkinter import simpledialog
            
            nome_obra = simpledialog.askstring("Nova Obra", "Digite o nome da obra:")

            if nome_obra and nome_obra.strip():
                nome_obra = nome_obra.strip()

                if nome_obra not in self.obras:
                    # Salvar dados da obra atual antes de criar nova obra
                    obra_atual = self.obra_filtro_var.get() if hasattr(self, 'obra_filtro_var') else ""
                    if obra_atual and obra_atual in self.obras:
                        self.salvar_pavimentos_por_obra()
                    
                    # Criar nova obra
                    self.obras[nome_obra] = {}

                    # Atualizar combobox
                    self.atualizar_combo_obras()

                    # Mudar para nova obra
                    if hasattr(self, 'obra_filtro_var'):
                        self.obra_filtro_var.set(nome_obra)

                
                # Limpar campos para nova obra (exceto pavimento 0)
                self._limpar_campos_pavimentos()
                
                # Limpar campos dos dados gerais
                self._limpar_campos_abas()
                
                # Pré-preencher campos com valores padrão (APENAS PARA NOVA OBRA)
                self._preencher_campos_padrao_pavimentos()
                
                # Liberar campos após criar obra
                self._liberar_campos_pavimentos()
                
                # Salvar pavimentos da nova obra ANTES de atualizar lista
                self.salvar_pavimentos_por_obra()
                
                # Atualizar lista e comboboxes
                self._atualizar_opcoes_pavimento_combobox()
                self.atualizar_lista()
                
                # Não definir pavimento padrão - deixar em branco
                # self._definir_pavimento_padrao_selecionado()  # Removido
                
                # Salvar automaticamente
                self.salvar_obras()
        except Exception as e:
            import traceback
            traceback.print_exc()

    

    def excluir_obra(self):
        """
        Exclui a obra selecionada incluindo TODOS os seus dados:
        - Todos os pavimentos
        - Todos os itens de todos os pavimentos
        - Todos os dados em pilares_salvos relacionados à obra
        - Pavimentos_data
        - Locks e todos os metadados
        """
        from tkinter import messagebox
        
        obra_atual = self.obra_filtro_var.get() if hasattr(self, 'obra_filtro_var') else None
        
        print(f">>> [excluir_obra] Obra atual: '{obra_atual}'")
        print(f">>> [excluir_obra] Obras disponíveis: {list(self.obras.keys()) if hasattr(self, 'obras') else 'N/A'}")

        if not obra_atual:
            messagebox.showwarning("Aviso", "Selecione uma obra para excluir!")
            return
        
        if obra_atual not in self.obras:
            messagebox.showwarning("Aviso", f"A obra '{obra_atual}' não foi encontrada nos dados salvos!")
            return
        
        # Contar quantos dados serão excluídos
        total_pavimentos = 0
        total_itens = 0
        if obra_atual in self.obras:
            for pavimento_nome, pavimento_dados in self.obras[obra_atual].items():
                if pavimento_nome != "pavimentos_data" and isinstance(pavimento_dados, dict):
                    total_pavimentos += 1
                    total_itens += len(pavimento_dados)
        
        mensagem_confirmacao = (
            f"Tem certeza que deseja excluir a obra '{obra_atual}'?\n\n"
            f"⚠️ Esta ação é IRREVERSÍVEL!\n\n"
            f"Serão excluídos:\n"
            f"  • {total_pavimentos} pavimento(s)\n"
            f"  • {total_itens} item(s)\n"
            f"  • Todos os dados salvos\n"
            f"  • Todos os locks e metadados\n\n"
            f"Deseja continuar?"
        )

        if messagebox.askyesno("Confirmar Exclusão", mensagem_confirmacao):
            
            if obra_atual in self.obras:
                # CRÍTICO: Excluir todos os itens de pilares_salvos que pertencem à obra usando helpers
                itens_pilares_salvos_excluidos = 0
                chaves_para_excluir = []
                
                # Percorrer pilares_salvos e encontrar itens da obra
                for chave_composta, item_dados in list(self.pilares_salvos.items()):
                    if not isinstance(item_dados, dict):
                        # Se não for dict, pular ou tentar deletar diretamente
                        continue
                    
                    obra_item = item_dados.get("obra")
                    if obra_item == obra_atual:
                        # Obter numero e pavimento do item para usar helper
                        # Verificar se "dados" existe e é um dicionário
                        dados_item = item_dados.get("dados")
                        if not isinstance(dados_item, dict):
                            # Se dados não for dict, tentar usar item_dados diretamente ou extrair da chave
                            # Fallback: extrair da chave ou usar pavimento do item_dados
                            numero_item = item_dados.get("item_id") or item_dados.get("numero")
                            pavimento_item = item_dados.get("pavimento")
                        else:
                            numero_item = dados_item.get("numero")
                            pavimento_item = dados_item.get("pavimento") or item_dados.get("pavimento")
                        
                        if numero_item and pavimento_item:
                            try:
                                self._delete_pilar_salvo_entry(numero_item, pavimento_item, obra_item)
                                itens_pilares_salvos_excluidos += 1
                            except Exception as e:
                                print(f">>> [excluir_obra] Erro ao deletar item {chave_composta}: {e}")
                                # Fallback: deletar pela chave antiga
                                if chave_composta in self.pilares_salvos:
                                    del self.pilares_salvos[chave_composta]
                                    itens_pilares_salvos_excluidos += 1
                        else:
                            # Fallback: deletar pela chave antiga se não conseguir extrair numero/pavimento
                            if chave_composta in self.pilares_salvos:
                                del self.pilares_salvos[chave_composta]
                                itens_pilares_salvos_excluidos += 1
                        chaves_para_excluir.append(chave_composta)
                
                # CRÍTICO: Excluir TODA a obra incluindo pavimentos_data e todos os dados
                # Usar del para garantir remoção completa da memória
                obra_dados_backup = self.obras[obra_atual].copy()  # Backup para logs
                del self.obras[obra_atual]
                
                # Verificar se foi realmente excluída
                if obra_atual in self.obras:
                    # Tentar forçar exclusão
                    self.obras.pop(obra_atual, None)
                
                # Atualizar interface
                self.atualizar_combo_obras()

                # Selecionar automaticamente a primeira obra disponível ou limpar se não houver
                if self.obras:
                    primeira_obra = list(self.obras.keys())[0]
                    self.obra_filtro_var.set(primeira_obra)
                else:
                    self.obra_filtro_var.set("")
                
                self.atualizar_pavimentos_por_obra()
                self.atualizar_lista()

                # CRÍTICO: Salvar automaticamente para persistir a exclusão
                # Usar salvamento direto, sem depender de auto_save_enabled
                print(f">>> [excluir_obra] Salvando alterações...")
                print(f">>> [excluir_obra] Obras restantes: {list(self.obras.keys())}")
                
                salvamento_obras_ok = False
                salvamento_pilares_ok = False
                
                # Salvar obras diretamente
                try:
                    import pickle
                    import os
                    caminho_obras = self.obter_caminho_dados("obras_salvas.pkl")
                    with open(caminho_obras, 'wb') as arquivo:
                        pickle.dump(self.obras, arquivo)
                    salvamento_obras_ok = True
                    print(f">>> [excluir_obra] Obras salvas em: {caminho_obras}")
                except Exception as e:
                    print(f">>> [excluir_obra] ERRO ao salvar obras: {e}")
                
                # Salvar pilares_salvos diretamente (sem verificar auto_save_enabled)
                try:
                    import pickle
                    import os
                    caminho_pilares = self.obter_caminho_dados("pilares_salvos.pkl")
                    with open(caminho_pilares, 'wb') as arquivo:
                        pickle.dump(self.pilares_salvos, arquivo)
                    salvamento_pilares_ok = True
                    print(f">>> [excluir_obra] Pilares salvos em: {caminho_pilares}")
                except Exception as e:
                    print(f">>> [excluir_obra] ERRO ao salvar pilares: {e}")
                
                # Verificar se a obra foi realmente excluída
                if obra_atual in self.obras:
                    print(f">>> [excluir_obra] ERRO: Obra '{obra_atual}' ainda existe após exclusão!")
                    messagebox.showerror("Erro", f"Falha ao excluir a obra '{obra_atual}'.\nA obra ainda existe nos dados.")
                    return
                
                print(f">>> [excluir_obra] Exclusão concluída com sucesso!")
                
                messagebox.showinfo(
                    "Exclusão Concluída",
                    f"Obra '{obra_atual}' excluída com sucesso!\n\n"
                    f"📊 Estatísticas:\n"
                    f"  • {total_pavimentos} pavimento(s) excluído(s)\n"
                    f"  • {total_itens} item(s) excluído(s)\n"
                    f"  • {itens_pilares_salvos_excluidos} referência(s) em pilares_salvos removida(s)\n"
                    f"  • Obras salvas: {'✅' if salvamento_obras_ok else '❌'}\n"
                    f"  • Pilares salvos: {'✅' if salvamento_pilares_ok else '❌'}\n\n"
                    f"Todos os dados foram completamente removidos."
                )
            else:
                messagebox.showwarning("Aviso", f"A obra '{obra_atual}' não foi encontrada.")

    

    def atualizar_combo_obras(self):
        """Atualiza o combobox de obras"""
        try:
            import sys
            if not hasattr(self, 'combo_obra'):
                return
            
            if not hasattr(self, 'obra_filtro_var'):
                return
            
            opcoes = list(self.obras.keys())
            
            self.combo_obra['values'] = opcoes

            # Selecionar automaticamente a primeira obra se existir
            if opcoes and not self.obra_filtro_var.get():
                self.obra_filtro_var.set(opcoes[0])
                # Atualizar pavimentos e lista após seleção automática
                self.atualizar_pavimentos_por_obra()
            elif not opcoes:
                
                # Se não há obras, limpar seleção (campos não são mais bloqueados)
                self.obra_filtro_var.set("")
            else:
                # Se já há uma obra selecionada, manter; caso contrário, selecionar a primeira disponível
                obra_atual = self.obra_filtro_var.get()
                if obra_atual not in self.obras and opcoes:
                    self.obra_filtro_var.set(opcoes[0])
                    self.atualizar_pavimentos_por_obra()
            
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            
    

    def atualizar_pavimentos_por_obra(self, event=None):

        """Atualiza o combobox de pavimentos baseado na obra selecionada"""

        # NÃO salvar automaticamente - isso só deve acontecer quando o usuário troca de obra manualmente
        # A criação de nova obra já salva seus próprios dados
        obra_atual = self.obra_filtro_var.get()
        
        # Limpar campos das abas e desselecionar itens ao trocar de obra
        if hasattr(self, 'obra_anterior') and self.obra_anterior != obra_atual:
            pass
            
            # Desselecionar todos os itens da lista
            self.desselecionar_item_lista()
            
            # Limpar campos das abas (exceto pavimento 0)
            self._limpar_campos_abas()
        
        # Carregar pavimentos da obra atual
        self.carregar_pavimentos_por_obra()
        
        # Obter pavimentos dos campos de entrada atuais (após carregar da obra)
        pavimentos = []
        if hasattr(self, 'pavimentos_entries'):
            for i, (entry_pav, entry_nivel) in enumerate(self.pavimentos_entries):
                if i > 0:  # Excluir pavimento 0
                    pavimento_nome = entry_pav.get().strip()
                    nivel = entry_nivel.get().strip()
                    if pavimento_nome and nivel:  # Só incluir se ambos estiverem preenchidos
                        pavimentos.append(pavimento_nome)
        
        # Ordenar pavimentos por sequência numérica (1, 2, 3, 4, 5...)
        pavimentos_ordenados = self._ordenar_pavimentos_por_sequencia(pavimentos)
        opcoes = ["Todos"] + pavimentos_ordenados
        
        # Atualizar combobox
        self.combo_pavimento['values'] = opcoes
        
        if self.pavimento_filtro_var.get() not in opcoes:
            self.pavimento_filtro_var.set("Todos")
        

        # Atualizar a lista após mudar os pavimentos
        self.atualizar_lista()

        
        # Armazenar a obra atual para próxima troca
        self.obra_anterior = obra_atual

    def _bloquear_campos_pavimentos(self):
        """Bloqueia os campos de pavimento quando nenhuma obra está selecionada"""
        if hasattr(self, 'pavimentos_entries'):
            for entry_pav, entry_nivel in self.pavimentos_entries:
                entry_pav.config(state='disabled')
                entry_nivel.config(state='disabled')

    def _liberar_campos_pavimentos(self):
        """Libera os campos de pavimento quando uma obra está selecionada"""
        if hasattr(self, 'pavimentos_entries'):
            for entry_pav, entry_nivel in self.pavimentos_entries:
                entry_pav.config(state='normal')
                entry_nivel.config(state='normal')

    def _limpar_campos_pavimentos(self):
        """Limpa todos os campos de pavimento para começar do zero (exceto pavimento 0)"""
        if hasattr(self, 'pavimentos_entries'):
            for i, (entry_pav, entry_nivel) in enumerate(self.pavimentos_entries):
                if i > 0:  # Não limpar pavimento 0 (usado no set)
                    entry_pav.delete(0, tk.END)
                    entry_nivel.delete(0, tk.END)
    
    def _preencher_campos_padrao_pavimentos(self):
        """Pré-preenche os campos de pavimento com valores padrão"""
        if hasattr(self, 'pavimentos_entries') and len(self.pavimentos_entries) >= 3:
            # Pavimento 0: Fundação 0
            if len(self.pavimentos_entries) > 0:
                entry_pav_0, entry_nivel_0 = self.pavimentos_entries[0]
                entry_pav_0.delete(0, tk.END)
                entry_pav_0.insert(0, "Fundação")
                entry_nivel_0.delete(0, tk.END)
                entry_nivel_0.insert(0, "0")
            
            # Pavimento 1: Subsolo 3
            if len(self.pavimentos_entries) > 1:
                entry_pav_1, entry_nivel_1 = self.pavimentos_entries[1]
                entry_pav_1.delete(0, tk.END)
                entry_pav_1.insert(0, "Subsolo")
                entry_nivel_1.delete(0, tk.END)
                entry_nivel_1.insert(0, "3")
            
            # Pavimento 2: Térreo 6
            if len(self.pavimentos_entries) > 2:
                entry_pav_2, entry_nivel_2 = self.pavimentos_entries[2]
                entry_pav_2.delete(0, tk.END)
                entry_pav_2.insert(0, "Térreo")
                entry_nivel_2.delete(0, tk.END)
                entry_nivel_2.insert(0, "6")
            
    
    def _definir_pavimento_padrao_selecionado(self):
        """Define o pavimento 1 (Subsolo) como seleção padrão nos comboboxes"""
        # Definir no combobox da lista
        if hasattr(self, 'pavimento_filtro_var'):
            self.pavimento_filtro_var.set("Subsolo")
        
        # Definir no combobox dos dados gerais
        if hasattr(self, 'pavimento_var'):
            self.pavimento_var.set("Subsolo")
        
    
    def _limpar_campos_abas(self):
        """Limpa os campos das abas ao trocar de obra"""
        try:
            # Limpar campos básicos
            campos_basicos = ['nome_pilar', 'comprimento', 'largura', 'pavimento_abc', 'nivel_saida', 'nivel_chegada', 
                            'nivel_diferencial', 'altura']
            for campo in campos_basicos:
                if hasattr(self, campo):
                    widget = getattr(self, campo)
                    if hasattr(widget, 'delete'):
                        widget.delete(0, tk.END)
                    elif hasattr(widget, 'set'):
                        widget.set("")
            
            # Limpar campo de número (excel_column)
            if hasattr(self, 'excel_column'):
                self.excel_column.set("")
            
            # Limpar campos de parafusos
            for i in range(1, 10):
                campo = f'par_{i}_{i+1}'
                if hasattr(self, campo):
                    widget = getattr(self, campo)
                    if hasattr(widget, 'delete'):
                        widget.delete(0, tk.END)
            
            # Limpar campos de grades
            for i in range(1, 4):
                campo_grade = f'grade_{i}'
                campo_dist = f'distancia_{i}'
                if hasattr(self, campo_grade):
                    widget = getattr(self, campo_grade)
                    if hasattr(widget, 'delete'):
                        widget.delete(0, tk.END)
                if hasattr(self, campo_dist):
                    widget = getattr(self, campo_dist)
                    if hasattr(widget, 'delete'):
                        widget.delete(0, tk.END)
            
            # Limpar combobox de pavimento nos dados gerais
            if hasattr(self, 'pavimento_var'):
                self.pavimento_var.set("")
            
        except Exception as e:
            pass
    

    def obter_m2_salvo(self, dados):

        """

        Obtém o m² total de um pilar usando dados já salvos, sem recalcular.

        Se não houver m² salvo, calcula apenas quando necessário.

        

        Args:

            dados: Dicionário com dados completos do pilar

            

        Returns:

            float: Total de m² do pilar

        """

        try:

            # Verificar se existe m² pré-calculado salvo

            m2_total_salvo = dados.get('m2_total')

            if m2_total_salvo is not None:

                pass

                return float(m2_total_salvo)

            

            # Se não há m² salvo, calcular apenas uma vez e salvar


            m2 = 0.0

            if 'paineis' in dados:

                for letra in ['A', 'B', 'C', 'D']:

                    painel = dados['paineis'].get(letra, {})

                    m2 += self.calcular_m2_painel(painel, letra, dados)

            

            # Salvar o m² calculado nos dados para uso futuro

            dados['m2_total'] = m2


            return m2

            

        except Exception as e:

            pass

            return 0.0

    

    def calcular_m2_painel(self, dados_painel, tipo_painel=None, dados_pilar=None):

        """

        Calcula o m² total dos painéis (sem descontar aberturas) para um painel (A, B, C, D).

        

        Regras específicas:

        - Painel A e B: (comprimento + 22) × altura

        - Painel C e D: largura × altura

        

        Args:

            dados_painel: Dicionário com os dados do painel (h1, h2, etc.)

            tipo_painel: Letra do painel ('A', 'B', 'C', 'D')

            dados_pilar: Dicionário com dados completos do pilar (opcional, para uso com dados salvos)

        """

        try:

            # Se tipo_painel não foi fornecido, tentar identificar pelo contexto

            if tipo_painel is None:

                # Tentar identificar pelo contexto dos dados

                # Esta é uma implementação de fallback para compatibilidade

                total = 0.0

                for i in range(1, 6):

                    h = parse_valor_soma(dados_painel.get(f"h{i}", "0"))

                    for j in range(1, 4):

                        larg = parse_valor_soma(dados_painel.get(f"larg{j}", "0"))

                        if h > 0 and larg > 0:

                            total += h * larg

                return total / 10000  # cm² para m²

                



            

            # Obter as dimensões principais do pilar

            comprimento = largura = 0

            

            # SEMPRE usar os dados do pilar fornecidos (dados salvos mais recentes)

            if dados_pilar:

                try:

                    comprimento = float(str(dados_pilar.get('comprimento', 0)).replace(',', '.') or 0)

                    largura = float(str(dados_pilar.get('largura', 0)).replace(',', '.') or 0)

                    # Debug: mostrar de onde vieram as dimensões


                except (ValueError, TypeError):

                    pass

            

            # Se não conseguiu dos dados do pilar, tentar obter dos campos da interface (fallback)

            if comprimento == 0 or largura == 0:

                try:

                    comprimento = float(self.comprimento.get().replace(',', '.') or 0)

                    largura = float(self.largura.get().replace(',', '.') or 0)


                except (ValueError, AttributeError):

                    comprimento = largura = 0


            

            # Calcular área base dependendo do tipo de painel

            if tipo_painel.upper() in ['A', 'B']:

                # Para painéis A e B: usar (comprimento + 22)

                area_base = comprimento + 22

            elif tipo_painel.upper() in ['C', 'D']:

                # Para painéis C e D: usar largura

                area_base = largura

            elif tipo_painel.upper() in ['E', 'F', 'G', 'H']:

                # Para painéis especiais E, F, G, H: usar largura total do painel

                # Calcular largura total do painel (soma das larguras 1, 2, 3)

                largura_total = 0.0

                for j in range(1, 4):

                    larg = parse_valor_soma(dados_painel.get(f"larg{j}", "0"))

                    if larg > 0:

                        largura_total += larg

                area_base = largura_total if largura_total > 0 else largura

            else:

                # Fallback para tipos não reconhecidos

                area_base = 0

            

            if area_base <= 0:

                pass

                return 0.0

            

            # Calcular altura total do painel (soma de todas as alturas válidas)

            altura_total = 0.0

            for i in range(1, 6):

                h = parse_valor_soma(dados_painel.get(f"h{i}", "0"))

                if h > 0:

                    altura_total += h

            

            # Calcular m² = área_base × altura_total

            if altura_total > 0:

                m2 = (area_base * altura_total) / 10000  # cm² para m²


                return m2

            else:

                pass

                return 0.0

                

        except Exception as e:

            pass

            return 0.0

    # Funções de canvas e zoom foram movidas para funcoes_auxiliares_4.py

    # atualizar_preview foi movido para funcoes_auxiliares_4.py

    # _get_painel_dict foi movido para funcoes_auxiliares_4.py

    # desenhar_painel foi movido para funcoes_auxiliares_4.py

    # desenhar_aberturas e desenhar_hachura_abertura foram movidas para funcoes_auxiliares_4.py

    def vincular_eventos_alteracao(self):

        def recalcular_por_campo(event):

            if not self.permitir_recalculo:

                return

            if self.campo_em_edicao is None:

                return

            widget = event.widget

            widget_nome = str(widget)

            if widget_nome != self.campo_em_edicao:

                return

            tipo_painel = None

            campo_atual = None

            for letra in ['A', 'B', 'C', 'D']:

                if widget == getattr(self, f"laje_{letra}", None):

                    tipo_painel = letra

                    campo_atual = 'laje'

                    break

                for i in range(1, 6):

                    if widget == getattr(self, f"h{i}_{letra}", None):

                        tipo_painel = letra

                        campo_atual = f"h{i}"

                        break

                if tipo_painel:

                    break

            if tipo_painel and campo_atual:

                self.recalcular_alturas_hierarquicas(tipo_painel, campo_atual)

            else:

                pass

        def recalcular_por_niveis(event):

            if not self.permitir_recalculo:

                return

            if self.campo_em_edicao is None:

                return

            widget = event.widget

            widget_nome = str(widget)

            if widget_nome != self.campo_em_edicao:

                return

            self.recalcular_por_niveis()

        for letra in ['A', 'B', 'C', 'D']:

            campo_laje = getattr(self, f"laje_{letra}", None)

            if campo_laje:

                campo_laje.bind('<KeyRelease>', recalcular_por_campo)

                campo_laje.bind('<FocusIn>', self.marcar_inicio_edicao)

                campo_laje.bind('<FocusOut>', self.marcar_fim_edicao)

            for i in range(1, 6):

                campo = getattr(self, f"h{i}_{letra}", None)

                if campo:

                    campo.bind('<KeyRelease>', recalcular_por_campo)

                    campo.bind('<FocusIn>', self.marcar_inicio_edicao)

                    campo.bind('<FocusOut>', self.marcar_fim_edicao)

        campos_nivel = ['nivel_saida', 'nivel_chegada', 'nivel_diferencial']

        for campo in campos_nivel:

            widget = getattr(self, campo, None)

            if widget:

                widget.bind('<KeyRelease>', recalcular_por_niveis)

                widget.bind('<FocusIn>', self.marcar_inicio_edicao)

                widget.bind('<FocusOut>', self.marcar_fim_edicao)
                
                # Adicionar binding para sincronizar altura dos detalhes ao sair do campo
                widget.bind('<FocusOut>', lambda e, w=widget: self.sincronizar_altura_detalhes(), add='+')

        for attr_name in ["comprimento", "largura"]:

            attr = getattr(self, attr_name)

            attr.bind('<KeyRelease>', lambda e: self.calcular_dimensoes_painel(e))

            attr.bind('<FocusIn>', self.marcar_inicio_edicao)

            if attr_name == "comprimento":

                attr.bind('<FocusOut>', lambda e: self.processar_focusout_comprimento(e))

            else:

                attr.bind('<FocusOut>', lambda e: (self.marcar_fim_edicao(e), self.calcular_dimensoes_painel(e)))

        for attr_name in dir(self):

            attr = getattr(self, attr_name)

            if not isinstance(attr, (ttk.Entry, tk.Entry)):

                continue

            if attr_name not in ["comprimento", "largura"] + campos_nivel + \
               [f"laje_{l}" for l in ['A','B','C','D']] + \
               [f"h{i}_{l}" for i in range(1,6) for l in ['A','B','C','D']]:

                attr.bind('<FocusIn>', self.marcar_inicio_edicao)

                attr.bind('<FocusOut>', lambda e: (self.marcar_fim_edicao(e), self.salvar_pilar(mostrar_mensagem=False, event=e)))

        self.registrar_eventos_aberturas()

    def criar_interface(self):
        import sys
        

        self.main_frame = ttk.PanedWindow(self, orient=tk.HORIZONTAL)
        

        self.main_frame.grid(row=1, column=0, sticky="nsew", padx=0, pady=0)
        

        

