        self.tipo_distribuicao_largura = tk.StringVar(value="NOVA")
        
        # Flag para prevenir loop circular entre traces
        self._sync_blocking_tipo_dist = False

        def on_radio_change():
            # Sincronizar com modo_calculo da aba pilares especiais
            modo_selecionado = self.tipo_distribuicao_largura.get()
            if modo_selecionado in ["NOVA", "INI"]:
                # Bloquear trace para evitar loop
                self._sync_blocking_tipo_dist = True
                self.modo_calculo.set(modo_selecionado)
                self._sync_blocking_tipo_dist = False
                
                # Carregar templates automaticamente para CIMA, ABCD e GRADE
                self._carregar_templates_automatico(modo_selecionado)
            
            self.calcular_dimensoes_painel()
            
            # Salvar automaticamente quando o modo é alterado
            if hasattr(self, 'excel_column') and self.excel_column.get().strip():
                # Prevenir salvamento duplicado durante sincronização
                if not getattr(self, '_salvando_modo', False):
                    try:
                        self._salvando_modo = True
                        self.salvar_pilar(mostrar_mensagem=False, skip_conflict_check=True)
                    except Exception as e:
                        print(f"⚠️ Erro ao salvar após alteração de modo: {e}")
                    finally:
                        self._salvando_modo = False

        # Adicionar listener para sincronização automática
        def sync_to_pilares_especiais(*args):
            # Prevenir loop circular
            if getattr(self, '_sync_blocking_modo_calc', False):
                return
            # Prevenir salvamento duplicado durante sincronização
            if getattr(self, '_salvando_modo', False):
                return
            # Prevenir sincronização durante cálculo de campos especiais (evita loop infinito)
            if getattr(self, '_calculando_campos_especiais', False):
                return
            modo_selecionado = self.tipo_distribuicao_largura.get()
            if modo_selecionado in ["NOVA", "INI"]:
                # Bloquear trace do modo_calculo para evitar loop
                self._sync_blocking_modo_calc = True
                self.modo_calculo.set(modo_selecionado)
                self._sync_blocking_modo_calc = False
                
                # Carregar templates automaticamente para CIMA, ABCD e GRADE
                self._carregar_templates_automatico(modo_selecionado)
                
                # Salvar automaticamente quando o modo é alterado via trace
                if hasattr(self, 'excel_column') and self.excel_column.get().strip():
                    try:
                        self._salvando_modo = True
                        self.salvar_pilar(mostrar_mensagem=False, skip_conflict_check=True)
                    except Exception as e:
                        print(f"⚠️ Erro ao salvar após sincronização de modo: {e}")
                    finally:
                        self._salvando_modo = False

        self.tipo_distribuicao_largura.trace('w', sync_to_pilares_especiais)

        

        radio_nova = ttk.Radiobutton(radio_frame, text="NOVA", variable=self.tipo_distribuicao_largura, value="NOVA", command=on_radio_change)

