            # Adicionar "blockinho" (espaço) para simetria com campo 0 das alturas
            blockinho = tk.Frame(detalhes_campos_frame, width=32, height=20, bg="lightgray", relief="sunken", bd=1)
            blockinho.pack(side=tk.LEFT, padx=1)
