    def _contar_campos_detalhes_preenchidos_grupo1(self, grade_num):

        """Conta quantos campos de detalhes estão preenchidos para uma grade específica"""

        try:

            campos_preenchidos = 0

            for i in range(1, 6):  # 5 campos de detalhes por grade

                campo = getattr(self, f"detalhe_grade{grade_num}_{i}", None)

                if campo:

                    valor = campo.get().strip()

                    if valor and valor != "0" and valor != "0.0":

                        campos_preenchidos += 1

            return campos_preenchidos

            

        except Exception as e:
            return 0



    def _restaurar_campos_detalhes_vazios_grupo1(self, grade_num, quantidade_restaurar):

        """Restaura campos vazios para manter a quantidade de campos preenchidos"""

        try:


            

            campos_restaurados = 0

            for i in range(1, 6):  # 5 campos de detalhes por grade

                if campos_restaurados >= quantidade_restaurar:

                    break

                    

                campo = getattr(self, f"detalhe_grade{grade_num}_{i}", None)

                if campo:

                    valor_atual = campo.get().strip()

                    # Se campo está vazio, preencher com valor padrão

                    if not valor_atual or valor_atual == "0" or valor_atual == "0.0":

                        # Usar valor padrão baseado na posição (exemplo: 5, 10, 15, 20, 25)

                        valor_padrao = str(i * 5)

                        campo.delete(0, tk.END)

                        campo.insert(0, valor_padrao)

                        campos_restaurados += 1


            

        except Exception as e:
            pass



