    def _resolver_conflitos_grade_especifica_grupo1(self, grade_num):
        """Resolve conflitos de uma grade específica do Grupo 1"""
        try:
            # 1. Coletar posições dos detalhes (ponteiros azuis)
            detalhes_posicoes = self._coletar_posicoes_detalhes_grupo1()
            
            # 2. Coletar posições dos parafusos (ponteiros vermelhos)
            parafusos_posicoes = self._calcular_posicoes_parafusos_grupo1()
            
            # 3. Coletar posições das distâncias (ponteiros das distâncias)
            distancias_posicoes = self._calcular_posicoes_distancias_grupo1()
            
            if not detalhes_posicoes or not parafusos_posicoes:
                return
            
            # 4. Detectar conflitos
            conflitos = self._detectar_conflitos_regua_grupo1(detalhes_posicoes, parafusos_posicoes, distancias_posicoes)
            
            if not conflitos:
                pass
                # Mesmo sem conflitos, garantir que os detalhes sejam calculados
                self.atualizar_detalhes_grade(grade_num)
                # Processo final: Verificar campo especial mesmo sem conflitos
                self._ajustar_campo_especial_grupo1(grade_num)
                return
            
            # 5. Filtrar conflitos apenas da grade específica
            conflitos_grade = []
            
            for i, conflito in enumerate(conflitos):
                if 'detalhe' in conflito:
                    detalhe_grade = conflito['detalhe']['grade_num']
                    detalhe_num = conflito['detalhe']['detalhe_num']
                    if detalhe_grade == grade_num:
                        conflitos_grade.append(conflito)
                elif 'dist' in conflito and conflito['tipo'] == "TIPO1_DIST":
                    pass
                    conflitos_grade.append(conflito)
            
            if not conflitos_grade:
                pass
                # Mesmo sem conflitos, garantir que os detalhes sejam calculados
                self.atualizar_detalhes_grade(grade_num)
                # Processo final: Verificar campo especial mesmo sem conflitos
                self._ajustar_campo_especial_grupo1(grade_num)
                return
            
            
            # 6. Resolver conflitos da grade específica
            conflitos_resolvidos = 0
            for i, conflito in enumerate(conflitos_grade):
                sucesso = self._resolver_conflito_especifico_grupo1(conflito)
                
                if sucesso:
                    conflitos_resolvidos += 1
                else:
                    # Estratégia alternativa: Ajustar posição do parafuso se possível
                    if self._ajustar_posicao_parafuso_alternativa(conflito):
                        conflitos_resolvidos += 1
            
            # 7. PROCESSO FINAL: Verificar e ajustar campo "especial" (maior que os demais)
            try:
                self._ajustar_campo_especial_grupo1(grade_num)
            except Exception as e_ajuste:
                pass
            
        except Exception as e:
            pass
            # Garantir que o processo final seja executado mesmo em caso de erro
            try:
                self._ajustar_campo_especial_grupo1(grade_num)
            except:
                pass

    def _detectar_conflitos_regua_grupo1(self, detalhes_posicoes, parafusos_posicoes, distancias_posicoes=None):
        """Detecta conflitos entre ponteiros azuis (detalhes) e zonas vermelhas (±3cm)"""
        try:
            conflitos = []
            
            # Verificar conflitos entre detalhes e parafusos
            for detalhe in detalhes_posicoes:
                detalhe_pos = detalhe['posicao']
                detalhe_grade = detalhe['grade_num']
                detalhe_num = detalhe['detalhe_num']
                
                for parafuso in parafusos_posicoes:
                    parafuso_pos = parafuso['posicao']
                    parafuso_zona = 3.0  # ±3cm
                    
                    # Verificar se há conflito (detalhe dentro da zona do parafuso)
                    if abs(detalhe_pos - parafuso_pos) <= parafuso_zona:
                        conflito = {
                            'tipo': 'TIPO2',
                            'detalhe': {
                                'grade_num': detalhe_grade,
                                'detalhe_num': detalhe_num,
                                'posicao': detalhe_pos
                            },
                            'parafuso': {
                                'posicao': parafuso_pos,
                                'zona': parafuso_zona
                            }
                        }
                        conflitos.append(conflito)
            
            return conflitos
            
        except Exception as e:
            return []

    def _resolver_conflito_especifico_grupo1(self, conflito):
        """Resolve um conflito específico do Grupo 1 baseado no tipo"""
        try:
            if conflito['tipo'] == 'TIPO2':
                return self._resolver_conflito_tipo2_grupo1(conflito)
            else:
                return False
                
        except Exception as e:
            return False

    def _resolver_conflito_tipo2_grupo1(self, conflito):
        """Resolve conflito TIPO2 (detalhe vs parafuso) do Grupo 1 com compensação e equalização"""
        try:
            detalhe = conflito['detalhe']
            grade_num = detalhe['grade_num']
            detalhe_num = detalhe['detalhe_num']
            detalhe_pos = detalhe['posicao']
            
            # Se parafuso ou zona não estiverem no conflito, tentar extrair
            if 'parafuso' in conflito:
                parafuso_pos = conflito['parafuso']['posicao']
                # Tentar obter zona do dicionário parafuso, com fallback seguro
                parafuso_zona = conflito['parafuso'].get('zona', 3.0)
            else:
                 # Fallback para chaves diretas no conflito
                 parafuso_pos = conflito.get('posicao_parafuso', 0)
                 parafuso_zona = conflito.get('zona_parafuso', 3.0)

            zona_inicio = parafuso_pos - parafuso_zona
            zona_fim = parafuso_pos + parafuso_zona
            
            # 1. Coletar informações de todos os detalhes ativos
            valores_atuais = {}
            detalhes_ativos = []
            soma_total = 0
            
            for i in range(1, 6):
                campo = getattr(self, f"detalhe_grade{grade_num}_{i}", None)
                if campo:
                    try:
                        val_str = campo.get().strip().replace(',', '.')
                        val = float(val_str) if val_str else 0
                        valores_atuais[i] = val
                        if val > 0:
                            detalhes_ativos.append(i)
                            soma_total += val
                    except:
                        valores_atuais[i] = 0
            
            if detalhe_num not in detalhes_ativos:
                return False
            
            num_detalhes_depois = len([x for x in detalhes_ativos if x > detalhe_num])
            
            if num_detalhes_depois == 0:
                 return False

            # 2. Calcular candidatos para resolução (Normalização Uniforme)
            # Estratégia: Definir valor V para todos os NÃO conflitantes.
            # Nova Posição = Total - (num_detalhes_depois) * V
            # Queremos Nova Posição <= (zona_inicio - 0.5) OU >= (zona_fim + 0.5)
            
            target_left = zona_inicio - 0.5
            target_right = zona_fim + 0.5
            
            v_left = (soma_total - target_left) / num_detalhes_depois
            v_right = (soma_total - target_right) / num_detalhes_depois
            
            candidates = []
            ranges = set()
            # Tentar inteiros próximos aos valores ideais
            for v_base in [v_left, v_right]:
                 ranges.add(int(v_base))
                 ranges.add(int(v_base)+1)
                 ranges.add(int(v_base)-1)
                 ranges.add(int(v_base)+2)
                 ranges.add(int(v_base)-2)
            
            num_outros = len(detalhes_ativos) - 1
            if num_outros == 0:
                 return False

            for v in ranges:
                if v <= 0: continue
                
                val_c = soma_total - num_outros * v
                if val_c <= 0: continue
                
                nova_pos = soma_total - num_detalhes_depois * v
                
                safe = nova_pos <= (zona_inicio - 0.5) or nova_pos >= (zona_fim + 0.5)
                
                if safe:
                    dist_move = abs(nova_pos - detalhe_pos)
                    candidates.append({
                        'v': v,
                        'val_c': val_c,
                        'pos': nova_pos,
                        'dist': dist_move
                    })
            
            if not candidates:
                return self._resolver_conflito_tipo2_compensacao_simples(conflito, detalhes_ativos, soma_total)
            
            # Escolher melhor candidato (menor movimento)
            candidates.sort(key=lambda x: x['dist'])
            best = candidates[0]
            
            # Aplicar valores
            for i in detalhes_ativos:
                campo = getattr(self, f"detalhe_grade{grade_num}_{i}")
                if i == detalhe_num:
                    campo.delete(0, tk.END)
                    campo.insert(0, str(int(best['val_c'])))
                else:
                    campo.delete(0, tk.END)
                    campo.insert(0, str(int(best['v'])))
            
            return True
            
        except Exception as e:
            return False

    def _resolver_conflito_tipo2_compensacao_simples(self, conflito, detalhes_ativos, soma_total):
        """
        Método de fallback: Tenta resolver movendo o ponteiro conflitante e compensando
        em APENAS UM vizinho (lógica anterior), usada quando a normalização uniforme falha.
        """
        try:
            detalhe = conflito['detalhe']
            grade_num = detalhe['grade_num']
            detalhe_num = detalhe['detalhe_num']
            detalhe_pos = detalhe['posicao']
            
            # Recalcular zonas (garantir consistência)
            if 'parafuso' in conflito:
                parafuso_pos = conflito['parafuso']['posicao']
                parafuso_zona = conflito['parafuso'].get('zona', 3.0)
            else:
                 parafuso_pos = conflito.get('posicao_parafuso', 0)
                 parafuso_zona = conflito.get('zona_parafuso', 3.0)
                 
            zona_inicio = parafuso_pos - parafuso_zona
            zona_fim = parafuso_pos + parafuso_zona
            
            # Obter valor atual do conflitante
            campo_atual = getattr(self, f"detalhe_grade{grade_num}_{detalhe_num}", None)
            if not campo_atual: return False
            valor_atual = float(campo_atual.get() or 0)
            
            # Calcular deslocamento necessário
            dist_inicio = abs(detalhe_pos - (zona_inicio - 0.5))
            dist_fim = abs(detalhe_pos - (zona_fim + 0.5))
            
            is_grade_integer = (soma_total % 1 == 0)
            
            if dist_inicio <= dist_fim:
                # Mover para esquerda
                if is_grade_integer:
                    # Se grade é inteira, força alvo inteiro para a esquerda (floor do alvo - 0.5)
                    # Alvo original: zona_inicio - 0.5.
                    # Para garantir <= zona_inicio - 0.5 com inteiro, deve ser <= floor(zona_inicio - 0.5)
                    # Ex: Zona 58. Inicio 58. Alvo 57.5. Inteiro: 57.
                    nova_pos_alvo = math.floor(zona_inicio - 0.5)
                else:
                    nova_pos_alvo = zona_inicio - 0.5
                    
                deslocamento = nova_pos_alvo - detalhe_pos
            else:
                # Mover para direita
                if is_grade_integer:
                     # Alvo original: zona_fim + 0.5
                     # Para garantir >= zona_fim + 0.5 com inteiro, deve ser >= ceil(zona_fim + 0.5)
                     # Ex: Zona 64. Fim 64. Alvo 64.5. Inteiro: 65.
                     nova_pos_alvo = math.ceil(zona_fim + 0.5)
                else:
                    nova_pos_alvo = zona_fim + 0.5
                    
                deslocamento = nova_pos_alvo - detalhe_pos
            
            novo_valor_atual = valor_atual + deslocamento
            if novo_valor_atual <= 0:
                return False
                
            # Escolher vizinho para compensar
            # Preferência: Vizinho seguinte (direita) se existir, senão anterior
            vizinho_num = -1
            if detalhe_num < 5 and (detalhe_num + 1) in detalhes_ativos:
                vizinho_num = detalhe_num + 1
            elif detalhe_num > 1 and (detalhe_num - 1) in detalhes_ativos:
                vizinho_num = detalhe_num - 1
                
            if vizinho_num == -1:
                return False
                
            campo_vizinho = getattr(self, f"detalhe_grade{grade_num}_{vizinho_num}", None)
            if not campo_vizinho: return False
            valor_vizinho = float(campo_vizinho.get() or 0)
            
            # Compensar: se aumentou um, diminui o outro
            novo_valor_vizinho = valor_vizinho - deslocamento
            
            if novo_valor_vizinho <= 0:
                # Tentar o outro vizinho se possível?
                return False

            # Tentar inteiros se possível
            # Se o deslocamento for quebrado, vai gerar quebrados.
            # Se a soma é inteira, tentar arredondar.
            
            # Aplicar
            campo_atual.delete(0, tk.END)
            campo_atual.insert(0, str(int(novo_valor_atual) if novo_valor_atual.is_integer() else round(novo_valor_atual, 1)))
            
            campo_vizinho.delete(0, tk.END)
            campo_vizinho.insert(0, str(int(novo_valor_vizinho) if novo_valor_vizinho.is_integer() else round(novo_valor_vizinho, 1)))
            
            return True
            
        except Exception as e:
            return False

    def _ajustar_campo_especial_grupo1(self, grade_num):
        """
        Processo final: Verifica se há um campo "especial" (maior que os demais que são iguais)
        Se a diferença for superior a 7:
        - Subtrai do maior um valor = quantidade de detalhes iguais
        - Distribui 1 em cada um dos outros detalhes
        """
        try:
            # 1. Coletar todos os valores dos detalhes da grade
            valores = {}
            detalhes_ativos = []
            
            for i in range(1, 6):
                nome_campo = f"detalhe_grade{grade_num}_{i}"
                campo = getattr(self, nome_campo, None)
                if campo:
                    try:
                        val_str = campo.get().strip().replace(',', '.')
                        val = float(val_str) if val_str else 0
                        valores[i] = val
                        if val > 0:
                            detalhes_ativos.append(i)
                    except Exception as e:
                        valores[i] = 0
                else:
                    # Tentar variações do nome
                    for var in [f"detalhe_grade{grade_num}_{i}_grupo1", f"detalhe_g{grade_num}_{i}"]:
                        campo_alt = getattr(self, var, None)
                        if campo_alt:
                            try:
                                val_str = campo_alt.get().strip().replace(',', '.')
                                val = float(val_str) if val_str else 0
                                valores[i] = val
                                if val > 0:
                                    detalhes_ativos.append(i)
                                break
                            except:
                                pass
            
            if len(detalhes_ativos) < 2:
                return
            
            # 2. Identificar valores únicos e suas frequências
            valores_unicos = {}
            for i in detalhes_ativos:
                val = valores[i]
                if val not in valores_unicos:
                    valores_unicos[val] = []
                valores_unicos[val].append(i)
            
            # 3. Verificar se há um campo "especial" (maior que os demais que são iguais)
            # Ordenar valores únicos
            valores_ordenados = sorted(valores_unicos.keys())
            
            if len(valores_ordenados) < 2:
                return
            
            # Encontrar o maior valor
            maior_valor = valores_ordenados[-1]
            detalhes_maior = valores_unicos[maior_valor]
            
            # Verificar se há apenas um detalhe com o maior valor
            if len(detalhes_maior) != 1:
                return
            
            # Verificar se todos os outros valores são iguais entre si
            outros_valores = valores_ordenados[:-1]
            
            # Se há apenas um outro valor único, todos os outros são iguais
            if len(outros_valores) == 1:
                valor_igual = outros_valores[0]
                detalhes_iguais = valores_unicos[valor_igual]
                
                diferenca = maior_valor - valor_igual
                
                # 4. Se a diferença for superior a 7, ajustar
                if diferenca > 7:
                    quantidade_iguais = len(detalhes_iguais)
                    valor_subtrair = quantidade_iguais
                    
                    # Subtrair do maior
                    novo_valor_maior = maior_valor - valor_subtrair
                    nome_campo_maior = f"detalhe_grade{grade_num}_{detalhes_maior[0]}"
                    campo_maior = getattr(self, nome_campo_maior, None)
                    if campo_maior:
                        campo_maior.delete(0, tk.END)
                        valor_str_maior = str(int(novo_valor_maior) if novo_valor_maior.is_integer() else round(novo_valor_maior, 1))
                        campo_maior.insert(0, valor_str_maior)
                    else:
                        return  # Não continuar se não encontrar o campo
                    
                    # Adicionar 1 em cada um dos detalhes iguais
                    novo_valor_igual = valor_igual + 1
                    for detalhe_num in detalhes_iguais:
                        nome_campo_igual = f"detalhe_grade{grade_num}_{detalhe_num}"
                        campo_igual = getattr(self, nome_campo_igual, None)
                        if campo_igual:
                            campo_igual.delete(0, tk.END)
                            valor_str_igual = str(int(novo_valor_igual) if novo_valor_igual.is_integer() else round(novo_valor_igual, 1))
                            campo_igual.insert(0, valor_str_igual)
                    
                    return True  # Indica que o ajuste foi aplicado
            
            return False  # Nenhum ajuste foi necessário
                
        except Exception as e:
            pass
            return False

    def calcular_detalhe_grades_com_desvio_conflitos(self):

        """

        Nova função para calcular detalhes das grades com desvio de conflitos.

        REGRAS OBRIGATÓRIAS:

        1. Tentar alternativas dinâmicas até encontrar combinação sem colisão

        2. Soma dos detalhes SEMPRE = total da grade

        3. Manter valores o mais próximos possível entre si

        """


        

        for grade_idx in [1, 2, 3]:

            grade_entry = getattr(self, f"grade_{grade_idx}", None)

            if not grade_entry:

                continue

                

            try:

                valor_grade = float(grade_entry.get().replace(',', '.') or 0)

                if valor_grade <= 0:

                    continue

                

                print(f"   [ESTATISTICA] Processando Grade {grade_idx} (valor: {valor_grade}cm)")

                

                # Obter posições dos parafusos

                pos_parafusos = self._obter_posicoes_parafusos()

                if not pos_parafusos:

                    # Se não há parafusos, usar distribuição equilibrada

                    distribuicao = self._calcular_distribuicao_equilibrada(valor_grade)

                    self._aplicar_distribuicao(grade_idx, distribuicao)

                    continue

                

                # Calcular base inicial para esta grade

                base_inicial = 0

                if grade_idx > 1:

                    for grade_ant in range(1, grade_idx):

                        grade_ant_entry = getattr(self, f"grade_{grade_ant}", None)

                        dist_ant_entry = getattr(self, f"distancia_{grade_ant}", None)

                        if grade_ant_entry:

                            base_inicial += float(grade_ant_entry.get().replace(',', '.') or 0)

                        if dist_ant_entry:

                            base_inicial += float(dist_ant_entry.get().replace(',', '.') or 0)

                

                # BUSCA DINÂMICA: Tentar até encontrar solução sem conflitos

                melhor_distribuicao = self._buscar_distribuicao_sem_conflitos(

                    valor_grade, base_inicial, pos_parafusos, grade_idx

                )

                

                # Aplicar a distribuição encontrada

                if melhor_distribuicao:

                    # VERIFICAR SOMA OBRIGATÓRIA

                    soma_real = sum(melhor_distribuicao[:5])

                    if abs(soma_real - valor_grade) > 0.01:  # Tolerância de 0.01

                        pass

                        melhor_distribuicao = self._corrigir_soma_distribuicao(melhor_distribuicao, valor_grade)

                    

                    conflitos = self._contar_conflitos_distribuicao(melhor_distribuicao, base_inicial, pos_parafusos)

                    soma_final = sum(melhor_distribuicao[:5])


                    self._aplicar_distribuicao(grade_idx, melhor_distribuicao)

                

            except Exception as e:

                pass

                import traceback

                traceback.print_exc()



    def _buscar_distribuicao_sem_conflitos(self, valor_grade, base_inicial, pos_parafusos, grade_idx):

        """

        Busca dinâmica por distribuição sem conflitos.

        Tenta múltiplas estratégias até encontrar solução ou esgotar opções.

        SEMPRE tenta encontrar uma distribuição diferente da atual se há conflitos.

        """

        print(f"     [PESQUISA] Iniciando busca dinâmica para Grade {grade_idx}...")

        

        # Calcular quantidade de detalhes

        quantidade = min(5, max(1, int(math.ceil(valor_grade / 33))))

        print(f"     [ESTATISTICA] Quantidade de detalhes: {quantidade}")

        

        # Obter distribuição atual para comparação

        distribuicao_atual = self._obter_distribuicao_atual(grade_idx)

        print(f"     [INFO] Distribuição atual: {[d for d in distribuicao_atual if d > 0]}")

        

        # Verificar se a distribuição atual tem conflitos

        conflitos_atual = self._contar_conflitos_distribuicao(distribuicao_atual, base_inicial, pos_parafusos)


        

        # Lista para armazenar todas as opções testadas

        opcoes_testadas = []

        

        # ESTRATÉGIA 1: Distribuição equilibrada

        print(f"     [OBJETIVO] Estratégia 1: Distribuição equilibrada")

        distribuicao = self._gerar_distribuicao_equilibrada(valor_grade, quantidade)

        conflitos = self._contar_conflitos_distribuicao(distribuicao, base_inicial, pos_parafusos)


        

        # Só aceitar se não há conflitos E é diferente da atual (quando há conflitos atuais)

        if conflitos == 0:

            if conflitos_atual == 0 or not self._distribuicoes_sao_iguais(distribuicao, distribuicao_atual):

                return distribuicao

            else:

                pass

        

        opcoes_testadas.append((distribuicao, conflitos))

        

        # ESTRATÉGIA 2: Variações pequenas (±1, ±2, ±3)


        for variacao in [1, 2, 3]:

            distribuicoes_teste = self._gerar_variacoes_pequenas(valor_grade, quantidade, variacao)

            for i, dist in enumerate(distribuicoes_teste):

                conflitos = self._contar_conflitos_distribuicao(dist, base_inicial, pos_parafusos)


                if conflitos == 0:

                    return dist

        

        # ESTRATÉGIA 3: Ajustes direcionados (evitar posições específicas)


        distribuicao = self._gerar_distribuicao_evitando_parafusos(valor_grade, quantidade, base_inicial, pos_parafusos)

        conflitos = self._contar_conflitos_distribuicao(distribuicao, base_inicial, pos_parafusos)


        

        if conflitos == 0:

            return distribuicao

        

        # ESTRATÉGIA 4: Força bruta com incrementos

        print(f"     [OBJETIVO] Estratégia 4: Força bruta com incrementos")

        for incremento in [0.5, 1.0, 1.5, 2.0]:

            distribuicoes_teste = self._gerar_distribuicoes_incrementais(valor_grade, quantidade, incremento)

            for i, dist in enumerate(distribuicoes_teste):

                conflitos = self._contar_conflitos_distribuicao(dist, base_inicial, pos_parafusos)

                if conflitos == 0:

                    print(f"       Sucesso incremento {incremento}.{i+1}: {[round(x, 1) for x in dist[:quantidade]]} - 0 conflitos")

                    return dist

        

        # ESTRATÉGIA 5: Redistribuição inteligente


        distribuicao = self._redistribuir_inteligentemente(valor_grade, quantidade, base_inicial, pos_parafusos)

        conflitos = self._contar_conflitos_distribuicao(distribuicao, base_inicial, pos_parafusos)


        

        if conflitos == 0:

            return distribuicao

        

        # ESTRATÉGIA 6: Última tentativa - aceitar menor número de conflitos


        melhor_dist = self._encontrar_melhor_opcao_disponivel(valor_grade, quantidade, base_inicial, pos_parafusos)

        conflitos = self._contar_conflitos_distribuicao(melhor_dist, base_inicial, pos_parafusos)

        print(f"       Melhor opção: {[round(x, 1) for x in melhor_dist[:quantidade]]} - {conflitos} conflitos")

        

        return melhor_dist



    def _gerar_distribuicao_equilibrada(self, valor_grade, quantidade):

        """Gera distribuição perfeitamente equilibrada"""

        valor_por_detalhe = valor_grade / quantidade

        distribuicao = [valor_por_detalhe] * quantidade + [0] * (5 - quantidade)

        return distribuicao



    def _gerar_variacoes_pequenas(self, valor_grade, quantidade, variacao):

        """Gera variações pequenas mantendo a soma total"""

        distribuicoes = []

        valor_base = valor_grade / quantidade

        

        # Padrão alternado: +variacao, -variacao, +variacao, -variacao

        for padrao in range(4):  # 4 padrões diferentes

            dist = [0] * 5

            soma_ajustes = 0

            

            for i in range(quantidade):

                if padrao == 0:  # +, -, +, -, +

                    ajuste = variacao if i % 2 == 0 else -variacao

                elif padrao == 1:  # -, +, -, +, -

                    ajuste = -variacao if i % 2 == 0 else variacao

                elif padrao == 2:  # +, +, -, -, +

                    ajuste = variacao if i < quantidade//2 else -variacao

                else:  # -, -, +, +, -

                    ajuste = -variacao if i < quantidade//2 else variacao

                

                dist[i] = valor_base + ajuste

                soma_ajustes += ajuste

            

            # Corrigir soma para manter total exato

            if soma_ajustes != 0:

                dist[0] -= soma_ajustes

            

            # Garantir valores positivos

            for i in range(quantidade):

                if dist[i] <= 0:

                    dist[i] = 1

                    

            # Recalcular para manter soma exata

            soma_atual = sum(dist[:quantidade])

            if abs(soma_atual - valor_grade) > 0.01:

                fator = valor_grade / soma_atual

                for i in range(quantidade):

                    dist[i] *= fator

            

            distribuicoes.append(dist)

        

        return distribuicoes



    def _gerar_distribuicao_evitando_parafusos(self, valor_grade, quantidade, base_inicial, pos_parafusos):

        """Gera distribuição tentando evitar posições dos parafusos"""

        valor_base = valor_grade / quantidade

        distribuicao = [valor_base] * quantidade + [0] * (5 - quantidade)

        

        # Para cada posição de parafuso, tentar ajustar detalhes próximos

        for pos_parafuso in pos_parafusos:

            pos_acumulada = base_inicial

            

            for i in range(quantidade):

                pos_acumulada += distribuicao[i]

                

                # Se está muito próximo do parafuso, ajustar

                if abs(pos_acumulada - pos_parafuso) <= 3:

                    # Tentar diminuir este detalhe e aumentar outros

                    ajuste = 2  # Ajuste de 2cm

                    if distribuicao[i] > ajuste:

                        distribuicao[i] -= ajuste

                        # Distribuir o ajuste nos outros detalhes

                        ajuste_por_outros = ajuste / (quantidade - 1)

                        for j in range(quantidade):

                            if j != i:

                                distribuicao[j] += ajuste_por_outros

        

        return distribuicao



    def _gerar_distribuicoes_incrementais(self, valor_grade, quantidade, incremento):

        """Gera distribuições com incrementos sistemáticos"""

        distribuicoes = []

        valor_base = valor_grade / quantidade

        

        # Gerar várias combinações com incrementos

        for combinacao in range(min(10, 2**quantidade)):  # Máximo 10 combinações

            dist = [0] * 5

            soma_ajustes = 0

            

            for i in range(quantidade):

                # Usar bits da combinação para decidir +/- incremento

                if (combinacao >> i) & 1:

                    ajuste = incremento

                else:

                    ajuste = -incremento

                

                dist[i] = valor_base + ajuste

                soma_ajustes += ajuste

            

            # Corrigir soma

            if soma_ajustes != 0:

                dist[0] -= soma_ajustes

            

            # Garantir valores positivos

            for i in range(quantidade):

                if dist[i] <= 0:

                    dist[i] = 0.5

            

            # Normalizar para soma exata

            soma_atual = sum(dist[:quantidade])

            if soma_atual > 0:

                fator = valor_grade / soma_atual

                for i in range(quantidade):

                    dist[i] *= fator

            

            distribuicoes.append(dist)

        

        return distribuicoes



    def _redistribuir_inteligentemente(self, valor_grade, quantidade, base_inicial, pos_parafusos):

        """Redistribui de forma inteligente evitando conflitos"""

        # Começar com distribuição equilibrada

        distribuicao = self._gerar_distribuicao_equilibrada(valor_grade, quantidade)

        

        # Identificar posições problemáticas

        pos_acumulada = base_inicial

        indices_problematicos = []

        

        for i in range(quantidade):

            pos_acumulada += distribuicao[i]

            for pos_parafuso in pos_parafusos:

                if abs(pos_acumulada - pos_parafuso) <= 3:

                    indices_problematicos.append(i)

                    break

        

        # Redistribuir valores dos índices problemáticos

        if indices_problematicos:

            # Calcular valor total dos problemáticos

            valor_problematico = sum(distribuicao[i] for i in indices_problematicos)

            

            # Zerar os problemáticos

            for i in indices_problematicos:

                distribuicao[i] = 0

            

            # Redistribuir entre os não problemáticos

            indices_bons = [i for i in range(quantidade) if i not in indices_problematicos]

            if indices_bons:

                valor_extra_por_bom = valor_problematico / len(indices_bons)

                for i in indices_bons:

                    distribuicao[i] += valor_extra_por_bom

        

        return distribuicao



    def _encontrar_melhor_opcao_disponivel(self, valor_grade, quantidade, base_inicial, pos_parafusos):

        """Encontra a melhor opção disponível mesmo com conflitos"""

        melhor_dist = None

        menor_conflitos = float('inf')

        melhor_score_proximidade = float('inf')

        

        # Testar várias distribuições e escolher a melhor

        todas_distribuicoes = []

        

        # Adicionar distribuição equilibrada

        todas_distribuicoes.append(self._gerar_distribuicao_equilibrada(valor_grade, quantidade))

        

        # Adicionar variações

        for var in [1, 2, 3]:

            todas_distribuicoes.extend(self._gerar_variacoes_pequenas(valor_grade, quantidade, var))

        

        # Adicionar incrementais

        for inc in [0.5, 1.0, 1.5]:

            todas_distribuicoes.extend(self._gerar_distribuicoes_incrementais(valor_grade, quantidade, inc))

        

        # Avaliar cada distribuição

        for dist in todas_distribuicoes:

            conflitos = self._contar_conflitos_distribuicao(dist, base_inicial, pos_parafusos)

            score_proximidade = self._calcular_score_proximidade(dist[:quantidade])

            

            # Priorizar menos conflitos, depois proximidade

            if (conflitos < menor_conflitos or 

                (conflitos == menor_conflitos and score_proximidade < melhor_score_proximidade)):

                menor_conflitos = conflitos

                melhor_score_proximidade = score_proximidade

                melhor_dist = dist

        

        return melhor_dist or self._gerar_distribuicao_equilibrada(valor_grade, quantidade)



    def _corrigir_soma_distribuicao(self, distribuicao, valor_grade):

        """

        Corrige a distribuição para que a soma seja exatamente igual ao valor da grade.

        GARANTIA: A soma final será SEMPRE igual ao valor_grade.

        """

        # Identificar quantos detalhes estão ativos (> 0)

        indices_ativos = [i for i in range(5) if distribuicao[i] > 0]

        quantidade_ativa = len(indices_ativos)

        

        if quantidade_ativa == 0:

            # Se nenhum detalhe está ativo, criar distribuição equilibrada

            quantidade = min(5, max(1, int(math.ceil(valor_grade / 33))))

            valor_por_detalhe = valor_grade / quantidade

            for i in range(quantidade):

                distribuicao[i] = valor_por_detalhe

            return distribuicao

        

        # Calcular soma atual apenas dos detalhes ativos

        soma_atual = sum(distribuicao[i] for i in indices_ativos)

        diferenca = valor_grade - soma_atual

        

        print(f"       Correção: soma_atual={soma_atual:.2f}, valor_grade={valor_grade:.2f}, diferença={diferenca:.2f}")

        

        if abs(diferenca) < 0.001:  # Já está correto

            return distribuicao

        

        # MÉTODO 1: Distribuir diferença proporcionalmente

        if soma_atual > 0:

            fator_correcao = valor_grade / soma_atual

            for i in indices_ativos:

                distribuicao[i] *= fator_correcao

        else:

            # Se soma atual é 0, distribuir igualmente

            valor_por_ativo = valor_grade / quantidade_ativa

            for i in indices_ativos:

                distribuicao[i] = valor_por_ativo

        

        # VERIFICAÇÃO FINAL: Garantir soma exata

        soma_corrigida = sum(distribuicao[i] for i in indices_ativos)

        diferenca_final = valor_grade - soma_corrigida

        

        if abs(diferenca_final) > 0.001:

            # Ajuste fino: adicionar/subtrair diferença do primeiro detalhe ativo

            if indices_ativos:

                distribuicao[indices_ativos[0]] += diferenca_final

        

        # Garantir que nenhum valor seja negativo

        for i in indices_ativos:

            if distribuicao[i] < 0.1:

                distribuicao[i] = 0.1

        

        # Verificação final obrigatória

        soma_final = sum(distribuicao[i] for i in indices_ativos)

        if abs(soma_final - valor_grade) > 0.01:

            print(f"       AVISO: Soma final {soma_final:.2f} ainda difere de {valor_grade:.2f}")

            # Forçar correção final

            if indices_ativos:

                diferenca_forcada = valor_grade - soma_final

                distribuicao[indices_ativos[0]] += diferenca_forcada

        

        return distribuicao



    def _encontrar_distribuicao_valores_proximos(self, valor_grade, base_inicial, pos_parafusos):

        """

        Encontra a distribuição com valores mais próximos possível, evitando conflitos.

        

        Estratégia:

        1. Começar com distribuição equilibrada

        2. Se há conflitos, fazer ajustes mínimos

        3. Priorizar manter valores próximos entre si

        """

        print(f"     [OBJETIVO] Buscando distribuição com valores próximos para {valor_grade}cm")

        

        # Calcular quantidade de detalhes necessários

        quantidade = min(5, max(1, int(math.ceil(valor_grade / 33))))

        

        # Começar com distribuição equilibrada

        valor_base = valor_grade / quantidade

        distribuicao_base = [valor_base] * quantidade + [0] * (5 - quantidade)

        

        print(f"     [ESTATISTICA] Distribuição base: {[round(x, 1) for x in distribuicao_base]}")

        

        # Verificar conflitos da distribuição base

        conflitos_base = self._identificar_conflitos_detalhados(distribuicao_base, base_inicial, pos_parafusos)

        

        if not conflitos_base:

            pass

            return distribuicao_base

        


        

        # Tentar resolver conflitos com ajustes mínimos

        melhor_distribuicao = self._resolver_conflitos_valores_proximos(

            distribuicao_base, base_inicial, pos_parafusos, conflitos_base, quantidade

        )

        

        return melhor_distribuicao



    def _resolver_conflitos_valores_proximos(self, distribuicao_base, base_inicial, pos_parafusos, conflitos, quantidade):

        """

        Resolve conflitos fazendo ajustes mínimos para manter valores próximos.

        """


        

        melhor_distribuicao = distribuicao_base.copy()

        valor_total = sum(distribuicao_base)

        

        # Para cada conflito, tentar ajustes pequenos

        for tentativa in range(10):  # Máximo 10 tentativas

            print(f"       Tentativa {tentativa + 1}/10")

            

            # Criar uma cópia para testar

            distribuicao_teste = melhor_distribuicao.copy()

            

            # Para cada posição em conflito, tentar pequenos ajustes

            for conflito in conflitos:

                indice_conflito = conflito['indice']

                pos_conflito = conflito['posicao']

                pos_parafuso = conflito['parafuso']

                

                # Calcular ajuste necessário para evitar conflito

                diferenca = pos_parafuso - pos_conflito

                ajuste_necessario = 4 if abs(diferenca) <= 3 else diferenca + (4 if diferenca > 0 else -4)

                

                # Distribuir o ajuste entre os detalhes de forma equilibrada

                if indice_conflito < quantidade:

                    # Ajustar o detalhe em conflito

                    ajuste_por_detalhe = ajuste_necessario / quantidade

                    

                    for i in range(quantidade):

                        if i == indice_conflito:

                            # Ajuste maior no detalhe em conflito

                            distribuicao_teste[i] += ajuste_necessario * 0.6

                        else:

                            # Ajuste menor nos outros detalhes

                            distribuicao_teste[i] += ajuste_necessario * 0.4 / (quantidade - 1)

                    

                    # Normalizar para manter a soma total

                    soma_atual = sum(distribuicao_teste[:quantidade])

                    if soma_atual != valor_total:

                        fator_correcao = valor_total / soma_atual

                        for i in range(quantidade):

                            distribuicao_teste[i] *= fator_correcao

            

            # Verificar se os conflitos foram resolvidos

            novos_conflitos = self._identificar_conflitos_detalhados(distribuicao_teste, base_inicial, pos_parafusos)

            

            if not novos_conflitos:

                pass

                return distribuicao_teste

            

            # Se ainda há conflitos, tentar uma abordagem diferente

            if len(novos_conflitos) < len(conflitos):

                melhor_distribuicao = distribuicao_teste.copy()

                conflitos = novos_conflitos

                print(f"       [CRESCIMENTO] Melhoria: {len(novos_conflitos)} conflitos restantes")

        

        # Se não conseguiu resolver completamente, tentar distribuições alternativas próximas


        

        distribuicoes_alternativas = self._gerar_distribuicoes_proximas(valor_total, quantidade)

        

        melhor_score = float('inf')

        melhor_alternativa = melhor_distribuicao

        

        for dist in distribuicoes_alternativas:

            conflitos_alt = self._contar_conflitos_distribuicao(dist, base_inicial, pos_parafusos)

            proximidade_score = self._calcular_score_proximidade(dist[:quantidade])

            score_total = conflitos_alt * 100 + proximidade_score  # Priorizar evitar conflitos

            

            if score_total < melhor_score:

                melhor_score = score_total

                melhor_alternativa = dist

        

        conflitos_final = self._contar_conflitos_distribuicao(melhor_alternativa, base_inicial, pos_parafusos)

        print(f"     [ESTATISTICA] Melhor alternativa: {[round(x, 1) for x in melhor_alternativa[:quantidade]]} ({conflitos_final} conflitos)")

        

        return melhor_alternativa



    def _gerar_distribuicoes_proximas(self, valor_total, quantidade):

        """

        Gera distribuições alternativas mantendo valores próximos.

        """

        distribuicoes = []

        valor_base = valor_total / quantidade

        

        # Variações pequenas (+/- 1, 2, 3)

        for variacao in [1, 2, 3]:

            # Distribuição com pequenas diferenças

            dist1 = [0] * 5

            for i in range(quantidade):

                if i % 2 == 0:

                    dist1[i] = valor_base + variacao

                else:

                    dist1[i] = valor_base - variacao

            

            # Ajustar para manter soma total

            soma_atual = sum(dist1[:quantidade])

            if soma_atual != valor_total:

                diferenca = valor_total - soma_atual

                dist1[0] += diferenca

            

            distribuicoes.append(dist1)

            

            # Distribuição inversa

            dist2 = [0] * 5

            for i in range(quantidade):

                if i % 2 == 0:

                    dist2[i] = valor_base - variacao

                else:

                    dist2[i] = valor_base + variacao

            

            # Ajustar para manter soma total

            soma_atual = sum(dist2[:quantidade])

            if soma_atual != valor_total:

                diferenca = valor_total - soma_atual

                dist2[0] += diferenca

            

            distribuicoes.append(dist2)

        

        return distribuicoes



    def _calcular_score_proximidade(self, valores):

        """

        Calcula um score de proximidade - quanto menor, mais próximos os valores.

        """

        if len(valores) <= 1:

            return 0

        

        # Calcular desvio padrão como medida de proximidade

        media = sum(valores) / len(valores)

        variancia = sum((x - media) ** 2 for x in valores) / len(valores)

        return variancia



    def _identificar_conflitos_detalhados(self, distribuicao, base_inicial, pos_parafusos):

        """

        Identifica conflitos de forma detalhada, retornando informações específicas.

        """

        conflitos = []

        pos_acumulada = base_inicial

        

        for i, valor in enumerate(distribuicao):

            if valor > 0:

                pos_acumulada += valor

                for pos_parafuso in pos_parafusos:

                    if abs(pos_acumulada - pos_parafuso) <= 3:

                        conflitos.append({

                            'indice': i,

                            'posicao': pos_acumulada,

                            'parafuso': pos_parafuso,

                            'diferenca': abs(pos_acumulada - pos_parafuso)

                        })

        

        return conflitos



    def _calcular_distribuicao_equilibrada(self, valor_grade):

        """

        Calcula distribuição equilibrada simples.

        GARANTIA: Retorna valores inteiros que somam exatamente valor_grade

        """

        quantidade = min(5, max(1, int(math.ceil(valor_grade / 33))))

        

        # Calcular valores inteiros

        valor_base = valor_grade // quantidade

        resto = valor_grade - (valor_base * quantidade)

        

        # Distribuir igualmente

        distribuicao = [valor_base] * quantidade

        

        # Distribuir o resto nas extremidades, alternando para dentro

        left = 0

        right = quantidade - 1

        for i in range(int(resto)):

            if i % 2 == 0:

                distribuicao[left] += 1

                left += 1

            else:

                distribuicao[right] += 1

                right -= 1

        

        # Completar com zeros

        while len(distribuicao) < 5:

            distribuicao.append(0)

        

        return distribuicao



    def _aplicar_distribuicao(self, grade_idx, distribuicao):

        """

        Aplica a distribuição aos campos da interface.

        GARANTIAS: 

        1. A soma deve ser exatamente igual ao valor da grade

        2. Todos os valores devem ser números inteiros

        3. Sempre trabalha com 5 campos (preenchendo com zeros)

        """

        try:

        # Obter valor da grade

            grade_entry = getattr(self, f"grade_{grade_idx}", None)

            if not grade_entry:

                return

            

            valor_grade = int(float(grade_entry.get().replace(',', '.') or 0))  # Garantir que grade seja inteira

            if valor_grade <= 0:

                return

            

            # Garantir que a distribuição tenha 5 elementos

            distribuicao_completa = list(distribuicao)

            while len(distribuicao_completa) < 5:

                distribuicao_completa.append(0)

            

            # Converter distribuição para inteiros mantendo a soma

            distribuicao_inteira = self._converter_para_inteiros_com_soma_exata(distribuicao_completa, valor_grade)

            

            # Aplicar valores inteiros

            for j in range(5):  # Sempre 5 campos

                campo = getattr(self, f"detalhe_grade{grade_idx}_{j+1}", None)

                if campo:

                    campo.delete(0, tk.END)

                    if j < len(distribuicao_inteira) and distribuicao_inteira[j] > 0:

                        campo.insert(0, str(int(distribuicao_inteira[j])))

                    else:

                        campo.insert(0, "0")

            

            # Verificação final

            soma_final = 0

            for j in range(5):

                campo = getattr(self, f"detalhe_grade{grade_idx}_{j+1}", None)

                if campo:

                    try:

                        valor = int(campo.get() or 0)

                        soma_final += valor

                    except ValueError:

                        pass

            


            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()



    def _converter_para_inteiros_com_soma_exata(self, distribuicao, valor_grade_inteiro):

        """

        Converte distribuição para números inteiros mantendo a soma exata.

        GARANTIA: A soma dos inteiros será exatamente igual ao valor_grade_inteiro.

        IMPORTANTE: Considera apenas os detalhes necessários baseado no limite de 33cm.

        """

        # Calcular quantidade necessária baseada no limite de 33cm
        import math
        quantidade_necessaria = min(5, max(1, int(math.ceil(valor_grade_inteiro / 33.0))))
        
        # Identificar detalhes ativos - apenas os primeiros 'quantidade_necessaria' índices com valor > 0
        indices_ativos = []
        for i in range(5):
            if distribuicao[i] > 0 and len(indices_ativos) < quantidade_necessaria:
                indices_ativos.append(i)
        
        # Se ainda não temos quantidade suficiente, adicionar os próximos índices (mesmo que zero)
        while len(indices_ativos) < quantidade_necessaria and len(indices_ativos) < 5:
            for i in range(5):
                if i not in indices_ativos:
                    indices_ativos.append(i)
                    break

        if not indices_ativos:

            return [0] * 5

        

        # Arredondar para baixo inicialmente

        distribuicao_int = [0] * 5

        for i in indices_ativos:

            distribuicao_int[i] = int(distribuicao[i])

        

        # Calcular diferença

        soma_atual = sum(distribuicao_int)

        diferenca = valor_grade_inteiro - soma_atual

        

        print(f"       Conversão para inteiros: soma_atual={soma_atual}, grade={valor_grade_inteiro}, diferença={diferenca}")

        

        # Distribuir a diferença

        if diferenca > 0:

            # Precisa adicionar - distribuir entre os detalhes ativos

            # Priorizar os que perderam mais no arredondamento

            perdas = [(i, distribuicao[i] - distribuicao_int[i]) for i in indices_ativos]

            perdas.sort(key=lambda x: x[1], reverse=True)  # Maior perda primeiro

            

            for _ in range(diferenca):

                if perdas:

                    idx = perdas[0][0]  # Índice com maior perda

                    distribuicao_int[idx] += 1

                    # Recalcular perdas

                    perdas = [(i, distribuicao[i] - distribuicao_int[i]) for i in indices_ativos]

                    perdas.sort(key=lambda x: x[1], reverse=True)

                else:

                    # Se não há perdas, distribuir no primeiro ativo

                    distribuicao_int[indices_ativos[0]] += 1

        

        elif diferenca < 0:

            # Precisa subtrair - remover dos detalhes com valores maiores

            for _ in range(abs(diferenca)):

                # Encontrar o detalhe com maior valor para subtrair

                maior_idx = max(indices_ativos, key=lambda i: distribuicao_int[i])

                if distribuicao_int[maior_idx] > 1:  # Não deixar zero

                    distribuicao_int[maior_idx] -= 1

                else:

                    # Se todos estão em 1, remover do primeiro

                    if distribuicao_int[indices_ativos[0]] > 0:

                        distribuicao_int[indices_ativos[0]] -= 1

        

        # Garantir que nenhum valor seja zero se estava ativo

        for i in indices_ativos:

            if distribuicao_int[i] <= 0:

                distribuicao_int[i] = 1

        

        # Verificação final e correção forçada se necessário

        soma_final = sum(distribuicao_int)

        if soma_final != valor_grade_inteiro:

            diferenca_final = valor_grade_inteiro - soma_final

            print(f"       Correção final necessária: {diferenca_final}")

            

            if diferenca_final > 0:

                # Adicionar no primeiro detalhe ativo

                distribuicao_int[indices_ativos[0]] += diferenca_final

            elif diferenca_final < 0:

                # Subtrair do maior detalhe

                maior_idx = max(indices_ativos, key=lambda i: distribuicao_int[i])

                distribuicao_int[maior_idx] += diferenca_final  # diferenca_final é negativo

                

                # Garantir que não fique negativo

                if distribuicao_int[maior_idx] < 0:

                    distribuicao_int[maior_idx] = 1

        

        # Verificação final obrigatória

        soma_verificacao = sum(distribuicao_int)

        print(f"       Resultado inteiros: {[x for x in distribuicao_int if x > 0]} (soma: {soma_verificacao})")

        

        return distribuicao_int



