    def _contar_conflitos_distribuicao(self, distribuicao, base_inicial, pos_parafusos):

        """Conta quantos conflitos uma distribuição teria"""

        conflitos = 0

        pos_acumulada = base_inicial

        

        for valor in distribuicao:

            if valor > 0:

                pos_acumulada += valor

                for pos_parafuso in pos_parafusos:

                    if abs(pos_acumulada - pos_parafuso) <= 3:

                        conflitos += 1

        

        return conflitos



