    def atualizar_parafusos(self, event=None):

        """

        Calcula e atualiza automaticamente os parafusos baseado no comprimento da aba Dados Gerais.

        Esta função é chamada quando o campo comprimento é alterado.

        """

        try:


            

            # Obter comprimento atual

            comprimento_str = self.comprimento.get().strip()

            if not comprimento_str:

                pass

                return

            

            # Converter para float, tratando vírgula como decimal

            comprimento = float(comprimento_str.replace(',', '.'))

            if comprimento <= 0:

                print("[PARAFUSOS] ⚠️ Comprimento inválido, não calculando parafusos")

                return

            

            print(f"[PARAFUSOS] 📏 Comprimento obtido: {comprimento}cm")

            

            # Calcular parafusos usando a lógica original

            parafusos = self.calcular_parafusos_com_logica_original(comprimento)

            print(f"[PARAFUSOS] 📊 Parafusos calculados: {parafusos}")

            

            # Aplicar os valores calculados aos campos de parafusos

            # Usar apenas os primeiros 8 parafusos (correspondentes aos campos da aba Dados Gerais)

            campos_parafusos = [

                "par_1_2", "par_2_3", "par_3_4", "par_4_5", 

                "par_5_6", "par_6_7", "par_7_8", "par_8_9"

            ]

            

            for i, campo in enumerate(campos_parafusos):

                if hasattr(self, campo):

                    entry = getattr(self, campo)

                    entry.delete(0, tk.END)

                    # Usar apenas os primeiros 8 parafusos calculados

                    if i < 8 and i < len(parafusos) and parafusos[i] > 0:

                        entry.insert(0, str(parafusos[i]))

                        print(f"[PARAFUSOS] ✅ {campo}: {parafusos[i]}")

                    else:

                        entry.insert(0, "0")

                        print(f"[PARAFUSOS] ⚪ {campo}: 0")

            

            print("[PARAFUSOS] ✅ Cálculo automático de parafusos concluído!")

            

        except ValueError as e:

            pass

        except Exception as e:

            print(f"[PARAFUSOS] ❌ Erro no cálculo de parafusos: {str(e)}")

            import traceback

            traceback.print_exc()

    

