    def atualizar_detalhes_grade(self, grade_num):

        """Atualiza os detalhes de uma grade específica"""

        try:


            

            # Atualizar régua do Grupo 1 se existir

            if hasattr(self, 'atualizar_regua_grupo1'):

                self.atualizar_regua_grupo1()

            

            # Obter o valor da grade

            grade_entry = getattr(self, f"grade_{grade_num}", None)

            if not grade_entry:

                pass

                return

                

            try:

                valor_grade = float(grade_entry.get().replace(',', '.') or 0)

                if valor_grade <= 0:

                    pass

                    return

            except ValueError:

                pass

                return

            

            print(f"   [ESTATISTICA] Processando Grade {grade_num} (valor: {valor_grade}cm)")

            

            # Obter posições dos parafusos

            pos_parafusos = self._obter_posicoes_parafusos() if hasattr(self, '_obter_posicoes_parafusos') else []

            

            if not pos_parafusos:

                # Se não há parafusos, usar distribuição equilibrada

                print(f"   [INFO] Sem parafusos definidos, usando distribuição equilibrada")

                distribuicao = self._calcular_distribuicao_equilibrada(valor_grade)

                self._aplicar_distribuicao(grade_num, distribuicao)

                return

            

            # Calcular base inicial para esta grade

            base_inicial = 0

            if grade_num > 1:

                for grade_ant in range(1, grade_num):

                    grade_ant_entry = getattr(self, f"grade_{grade_ant}", None)

                    dist_ant_entry = getattr(self, f"distancia_{grade_ant}", None)

                    if grade_ant_entry:

                        base_inicial += float(grade_ant_entry.get().replace(',', '.') or 0)

                    if dist_ant_entry:

                        base_inicial += float(dist_ant_entry.get().replace(',', '.') or 0)

            

            print(f"   📍 Base inicial para Grade {grade_num}: {base_inicial}cm")

            

            # Usar a lógica existente de cálculo com desvio de conflitos

            # Tentar diferentes estratégias de distribuição (priorizando valores próximos)

            estrategias = [

                self._calcular_distribuicao_padrao,          # Distribuição igual

                self._calcular_distribuicao_alternativa_1,   # Concentrar no início

                self._calcular_distribuicao_alternativa_2,   # Concentrar no final

                self._calcular_distribuicao_alternativa_3,   # Concentrar no meio

                self._calcular_distribuicao_alternativa_4    # Valores escalonados

            ]

            

            melhor_distribuicao = None

            menor_conflitos = float('inf')

            

            for i, estrategia in enumerate(estrategias):

                try:

                    distribuicao = estrategia(valor_grade)

                    conflitos = self._contar_conflitos_distribuicao(distribuicao, base_inicial, pos_parafusos)

                    

                    print(f"   🧪 Estratégia {i+1}: {[round(x, 1) for x in distribuicao[:5]]} - Conflitos: {conflitos}")

                    

                    if conflitos < menor_conflitos:

                        menor_conflitos = conflitos

                        melhor_distribuicao = distribuicao

                        

                        # Se encontrou distribuição sem conflitos, usar ela

                        if conflitos == 0:

                            break

                            

                except Exception as e:

                    pass

                    continue

            

            # Aplicar a melhor distribuição encontrada

            if melhor_distribuicao:

                soma_final = sum(melhor_distribuicao[:5])


                self._aplicar_distribuicao(grade_num, melhor_distribuicao)

                

                # Verificar conflitos e atualizar cores logo após aplicar a distribuição

                self._verificar_conflitos_detalhes_grade(grade_num)

            else:

                pass

                

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

