    def resolver_conflitos_grade_especifica(self, letra, grade_num):

        """

        Resolve conflitos de uma grade específica (5 detalhes)

        

        Args:

            letra: Letra da grade (a, b, e, f)

            grade_num: Número da grade (1, 2, 3)

        """

        try:

            print(f"[CONFLITOS-GRADE] ========================================")

            print(f"[CONFLITOS-GRADE] Resolvendo conflitos da Grade {grade_num} para {letra.upper()}")

            

            # 1. Coletar posições dos detalhes (ponteiros azuis)

            detalhes_posicoes = self._coletar_posicoes_detalhes(letra)

            print(f"[CONFLITOS-GRADE] Detalhes encontrados: {len(detalhes_posicoes)} posições")

            

            # 2. Coletar posições dos parafusos (ponteiros vermelhos)

            parafusos_posicoes = self._coletar_posicoes_parafusos(letra)

            print(f"[CONFLITOS-GRADE] Parafusos encontrados: {len(parafusos_posicoes)} posições")

            

            # 2.1 Coletar posições das distâncias (ponteiros das distâncias)

            distancias_posicoes = self._coletar_posicoes_distancias(letra)

            print(f"[CONFLITOS-GRADE] Distâncias encontradas: {len(distancias_posicoes)} posições")

            

            if not detalhes_posicoes or not parafusos_posicoes:

                print(f"[CONFLITOS-GRADE] Dados insuficientes para análise de conflitos")

                return

            

            # 3. Detectar conflitos (ponteiro azul ou distância dentro da zona vermelha ±3cm)

            conflitos = self._detectar_conflitos_regua(letra, detalhes_posicoes, parafusos_posicoes, distancias_posicoes)

            

            if not conflitos:

                pass

                return

            

            # 4. Filtrar conflitos apenas da grade específica

            conflitos_grade = []

            print(f"[CONFLITOS-GRADE] Filtrando conflitos para Grade {grade_num}:")

            for i, conflito in enumerate(conflitos):

                if 'detalhe' in conflito:

                    detalhe_grade = conflito['detalhe']['grade_num']

                    detalhe_num = conflito['detalhe']['detalhe_num']


                    if detalhe_grade == grade_num:

                        conflitos_grade.append(conflito)

                elif 'dist' in conflito and conflito['tipo'] == "TIPO1_DIST":

                    pass

                    # Distâncias afetam todas as grades, incluir se relevante

                    conflitos_grade.append(conflito)

            

            if not conflitos_grade:

                print(f"[CONFLITOS-GRADE] ✅ Nenhum conflito encontrado para Grade {grade_num}")

                return

            

            print(f"[CONFLITOS-GRADE] ⚠️ {len(conflitos_grade)} conflito(s) encontrado(s) para Grade {grade_num}")

            

            # 5. Resolver conflitos da grade específica

            conflitos_resolvidos = 0

            for i, conflito in enumerate(conflitos_grade):

                pass

                sucesso = self._resolver_conflito_especifico(letra, conflito)

                if sucesso:

                    conflitos_resolvidos += 1

                    print(f"[CONFLITOS-GRADE] ✅ Conflito {i+1} resolvido: {conflito['tipo']}")

                    # Atualizar régua após resolver conflito

                    self.atualizar_todas_reguas_especiais()

                else:

                    print(f"[CONFLITOS-GRADE] ❌ Não foi possível resolver conflito {i+1}: {conflito['tipo']}")

            

            print(f"[CONFLITOS-GRADE] ========================================")


            print(f"[CONFLITOS-GRADE] ========================================")

            

        except Exception as e:

            print(f"[CONFLITOS-GRADE] Erro ao resolver conflitos da grade específica: {e}")

            import traceback

            traceback.print_exc()



    def resolver_conflitos_especifico(self, letra, tipo_conflito, detalhe_num=None):

        """

        Resolve conflitos específicos de um tipo e detalhe específico

        

        Args:

            letra: Letra da grade (a, b, e, f)

            tipo_conflito: "TIPO1", "TIPO2", "TIPO1_DIST"

            detalhe_num: Número do detalhe específico (1-5) ou None para todos

        """

        try:


            print(f"[CONFLITOS-ESPECIFICO] Resolvendo {tipo_conflito} para grade {letra.upper()}")

            if detalhe_num:

                pass

            

            # 1. Coletar posições dos detalhes (ponteiros azuis)

            detalhes_posicoes = self._coletar_posicoes_detalhes(letra)

            print(f"[CONFLITOS-ESPECIFICO] Detalhes encontrados: {len(detalhes_posicoes)} posições")

            

            # 2. Coletar posições dos parafusos (ponteiros vermelhos)

            parafusos_posicoes = self._coletar_posicoes_parafusos(letra)

            print(f"[CONFLITOS-ESPECIFICO] Parafusos encontrados: {len(parafusos_posicoes)} posições")

            

            # 2.1 Coletar posições das distâncias (ponteiros das distâncias)

            distancias_posicoes = self._coletar_posicoes_distancias(letra)

            print(f"[CONFLITOS-ESPECIFICO] Distâncias encontradas: {len(distancias_posicoes)} posições")

            

            if not detalhes_posicoes or not parafusos_posicoes:

                print(f"[CONFLITOS-ESPECIFICO] Dados insuficientes para análise de conflitos")

                return

            

            # 3. Detectar conflitos (ponteiro azul ou distância dentro da zona vermelha ±3cm)

            conflitos = self._detectar_conflitos_regua(letra, detalhes_posicoes, parafusos_posicoes, distancias_posicoes)

            

            if not conflitos:

                pass

                return

            

            # 4. Filtrar conflitos pelo tipo e detalhe específico

            conflitos_filtrados = []

            for conflito in conflitos:

                if conflito['tipo'] == tipo_conflito:

                    if detalhe_num is None:

                        # Processar todos os conflitos deste tipo

                        conflitos_filtrados.append(conflito)

                    else:

                        # Processar apenas conflitos do detalhe específico

                        if 'detalhe' in conflito and conflito['detalhe']['detalhe_num'] == detalhe_num:

                            conflitos_filtrados.append(conflito)

                        elif 'dist' in conflito and tipo_conflito == "TIPO1_DIST":

                            conflitos_filtrados.append(conflito)

            

            if not conflitos_filtrados:

                print(f"[CONFLITOS-ESPECIFICO] ✅ Nenhum conflito {tipo_conflito} encontrado para processar")

                return

            


            

            # 5. Resolver conflitos filtrados

            conflitos_resolvidos = 0

            for i, conflito in enumerate(conflitos_filtrados):

                print(f"[CONFLITOS-ESPECIFICO] Processando conflito {i+1}/{len(conflitos_filtrados)}: {conflito['tipo']}")

                sucesso = self._resolver_conflito_especifico(letra, conflito)

                if sucesso:

                    conflitos_resolvidos += 1

                    print(f"[CONFLITOS-ESPECIFICO] ✅ Conflito {i+1} resolvido: {conflito['tipo']}")

                    # Atualizar régua após resolver conflito

                    self.atualizar_todas_reguas_especiais()

                else:

                    print(f"[CONFLITOS-ESPECIFICO] ❌ Não foi possível resolver conflito {i+1}: {conflito['tipo']}")

            

            print(f"[CONFLITOS-ESPECIFICO] ========================================")

            print(f"[CONFLITOS-ESPECIFICO] Resolução concluída: {conflitos_resolvidos}/{len(conflitos_filtrados)} conflitos resolvidos")

            print(f"[CONFLITOS-ESPECIFICO] ========================================")

            

        except Exception as e:

            print(f"[CONFLITOS-ESPECIFICO] Erro ao resolver conflitos específicos: {e}")

            import traceback

            traceback.print_exc()



    def resolver_conflitos_grade_ajuste(self, letra):

        """

        Resolve conflitos ajustando o valor da grade em vez dos detalhes

        FOCA APENAS NO ÚLTIMO DETALHE de cada grade

        

        Args:

            letra: Letra da grade (a, b, e, f)

        """

