    def _calcular_distribuicao_alternativa_3(self, valor_grade):

        """Distribuição alternativa 3: usa lógica corrigida"""

        return self.calcular_detalhes_com_logica_original(valor_grade)

    

    def _calcular_distribuicao_alternativa_4(self, valor_grade):

        """Distribuição alternativa 4: usa lógica corrigida"""

        return self.calcular_detalhes_com_logica_original(valor_grade)

    

    def _calcular_distribuicao_alternada(self, valor_grade):

        """Calcula distribuição alternada (maior-menor-maior...) - VALORES INTEIROS"""

        # Interface tem apenas 3 campos de detalhes

        quantidade = 3

        

        # Calcular valores inteiros base

        valor_base = valor_grade // quantidade

        resto = valor_grade - (valor_base * quantidade)

        

        # Distribuir igualmente

        distribuicao = [valor_base] * quantidade

        

        # Alternar valores (inteiros)

        for i in range(quantidade):

            if i % 2 == 0:  # Posições pares maiores

                distribuicao[i] += 1

            else:  # Posições ímpares menores

                distribuicao[i] = max(1, distribuicao[i] - 1)

        

        # Distribuir o resto nas extremidades

        left = 0

        right = quantidade - 1

        for i in range(resto):

            if i % 2 == 0:

                distribuicao[left] += 1

                left += 1

            else:

                distribuicao[right] += 1

                right -= 1

        

        # Completar com zeros para compatibilidade

        while len(distribuicao) < 5:

            distribuicao.append(0)

        

        return distribuicao

    

    def _calcular_distribuicao_crescente(self, valor_grade):

        """Calcula distribuição crescente - VALORES INTEIROS"""

        # Interface tem apenas 3 campos de detalhes

        quantidade = 3

        

        # Calcular valores inteiros base

        valor_base = valor_grade // quantidade

        resto = valor_grade - (valor_base * quantidade)

        

        # Criar sequência crescente (inteiros)

        distribuicao = []

        for i in range(quantidade):

            # Distribuir proporcionalmente ao índice

            valor = valor_base + (i * resto // quantidade)

            distribuicao.append(valor)

        

        # Distribuir o resto restante

        resto_final = resto - sum(i * resto // quantidade for i in range(quantidade))

        for i in range(resto_final):

            distribuicao[i] += 1

        

        # Completar com zeros para compatibilidade

        distribuicao += [0] * (5 - quantidade)

        return distribuicao

    

    def _calcular_distribuicao_decrescente(self, valor_grade):

        """Calcula distribuição decrescente - VALORES INTEIROS"""

        # Interface tem apenas 3 campos de detalhes

        quantidade = 3

        

        # Calcular valores inteiros base

        valor_base = valor_grade // quantidade

        resto = valor_grade - (valor_base * quantidade)

        

        # Criar sequência decrescente (inteiros)

        distribuicao = []

        for i in range(quantidade):

            # Distribuir proporcionalmente ao índice reverso

            valor = valor_base + ((quantidade - 1 - i) * resto // quantidade)

            distribuicao.append(valor)

        

        # Distribuir o resto restante

        resto_final = resto - sum((quantidade - 1 - i) * resto // quantidade for i in range(quantidade))

        for i in range(resto_final):

            distribuicao[i] += 1

        

        # Completar com zeros para compatibilidade

        distribuicao += [0] * (5 - quantidade)

        return distribuicao

    

    def _contar_conflitos_distribuicao(self, distribuicao, base_inicial, pos_parafusos):

        """Conta conflitos de uma distribuição com parafusos"""

        try:

            conflitos = 0

            pos_acumulada = base_inicial

            tolerancia = 3  # ±3cm

            

            for i, valor in enumerate(distribuicao[:5]):

                if valor > 0:

                    pos_acumulada += valor

                    for pos_parafuso in pos_parafusos:

                        if abs(pos_acumulada - pos_parafuso) <= tolerancia:

                            conflitos += 1

                            break

            

            return conflitos

        except Exception as e:

            pass

            return float('inf')

    

    def recalcular_detalhes_grade_proxima_estrategia(self, grade_num):

        """

        Recalcula os detalhes de uma grade usando a próxima estratégia disponível.

        A cada clique do botão, tenta uma estratégia diferente seguindo as regras da grade.

        """

        try:

            import math  # Importar math para as funções de estratégia

            

            print(f"[REPETIR] Recalculando Grade {grade_num} com próxima estratégia...")

            

            # Inicializar contador de estratégias se não existir

            if not hasattr(self, '_estrategias_usadas'):

                self._estrategias_usadas = {}

            

            # Definir chave da grade para controle de estratégias
            chave_grade = f"grade_{grade_num}"
            
            # Obter o valor da grade

            grade_entry = getattr(self, f"grade_{grade_num}", None)

            if not grade_entry:

                pass

                return

                

            try:

                valor_grade = float(grade_entry.get().replace(',', '.') or 0)

                if valor_grade <= 0:

                    pass

                    return

            except ValueError:

                pass

                return

            

            # Lista de estratégias disponíveis

            estrategias = [

                ("Padrão", self._calcular_distribuicao_padrao),

                ("Concentrar no Início", self._calcular_distribuicao_alternativa_1),

                ("Concentrar no Final", self._calcular_distribuicao_alternativa_2),

                ("Concentrar no Meio", self._calcular_distribuicao_alternativa_3),

                ("Valores Escalonados", self._calcular_distribuicao_alternativa_4)

            ]

            

            # SEMPRE usar estratégia "Padrão" para garantir comportamento consistente

            # entre todas as grades com o mesmo valor

            proximo_indice = 0  # Sempre usar primeira estratégia (Padrão)

            nome_estrategia, funcao_estrategia = estrategias[proximo_indice]

            

            print(f"   [OBJETIVO] Usando estratégia: {nome_estrategia} (#{proximo_indice + 1}/{len(estrategias)})")

            

            # Calcular base inicial para esta grade

            base_inicial = 0

            if grade_num > 1:

                for grade_ant in range(1, grade_num):

                    grade_ant_entry = getattr(self, f"grade_{grade_ant}", None)

                    dist_ant_entry = getattr(self, f"distancia_{grade_ant}", None)

                    if grade_ant_entry:

                        base_inicial += float(grade_ant_entry.get().replace(',', '.') or 0)

                    if dist_ant_entry:

                        base_inicial += float(dist_ant_entry.get().replace(',', '.') or 0)

            

            # Aplicar a estratégia escolhida

            try:

                distribuicao = funcao_estrategia(valor_grade)

                

                # Verificar conflitos se houver parafusos

                pos_parafusos = self._obter_posicoes_parafusos() if hasattr(self, '_obter_posicoes_parafusos') else []

                conflitos = 0

                if pos_parafusos:

                    conflitos = self._contar_conflitos_distribuicao(distribuicao, base_inicial, pos_parafusos)

                

                # Mostrar resultado

                soma_final = sum(distribuicao[:5])

                print(f"   [ESTATISTICA] Resultado: {[round(x, 1) for x in distribuicao[:5]]} (soma: {soma_final}, conflitos: {conflitos})")

                

                # Aplicar a distribuição

                self._aplicar_distribuicao(grade_num, distribuicao)

                

                # Verificar conflitos e atualizar cores logo após aplicar a distribuição

                self._verificar_conflitos_detalhes_grade(grade_num)

                

                # Atualizar o índice da estratégia usada

                self._estrategias_usadas[chave_grade] = proximo_indice

                


                

            except Exception as e:

                pass

                # Em caso de erro, tentar a próxima estratégia

                self._estrategias_usadas[chave_grade] = proximo_indice

                return

                

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def calcular_larguras_paineis(self, comprimento, largura):

        """

        Calcula automaticamente as larguras dos painéis A e B baseado nas regras NOVA e UNI

        

        Args:

            comprimento: Comprimento total do pilar

            largura: Largura total do pilar

        """

        try:

            print(f"\n>>> INICIANDO CÁLCULO AUTOMÁTICO DE LARGURAS DOS PAINÉIS")



            

            # Verificar qual tipo de distribuição está selecionado

            tipo_distribuicao = self.tipo_distribuicao_largura.get()


            

            # Calcular comprimento ajustado (adicionando 22 como margem)

            comprimento_ajustado = comprimento + 22

            print(f">>> Comprimento ajustado (+ 22): {comprimento_ajustado:.2f}")

            

            # Aplicar regras específicas baseadas no tipo de distribuição

            if tipo_distribuicao == "NOVA":

                self.aplicar_regras_nova(comprimento_ajustado, largura)

            elif tipo_distribuicao == "UNI":

                self.aplicar_regras_uni(comprimento_ajustado, largura)

            else:

                pass

                # Aplicar regras padrão (NOVA)

                self.aplicar_regras_nova(comprimento_ajustado, largura)

                

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def aplicar_regras_nova(self, comprimento_ajustado, largura):

        """

        Aplica as regras de distribuição NOVA para os painéis A e B

        

        Regras NOVA:

        - Soma 22 ao comprimento

        - Distribui com painéis até 244

        - Se o sobrante for menor que 60, ajusta o anterior para 122 e soma 122 ao último

        """

        print(f"\n>>> APLICANDO REGRAS NOVA")
        
        # DEBUG: Log de entrada na função de largura

        

        for letra in ["A", "B"]:

            pass

            

            # Limpar campos existentes

            for i in range(1, 4):

                campo = getattr(self, f"larg{i}_{letra}")

                campo.delete(0, tk.END)

                campo.insert(0, "0")

            

            # Verificar se é pilar especial e painel B
            if letra == "B" and hasattr(self, 'ativar_pilar_especial') and self.ativar_pilar_especial.get():
                print(f">>> Painel B especial - calculando grade B especial + 2")
                
                # Calcular grade B especial: grade1_B + grade2_B + grade3_B + dist1_B + dist2_B + 2
                try:
                    grade1_b = float(self.grade_b_1.get() or 0)
                    grade2_b = float(self.grade_b_2.get() or 0)
                    grade3_b = float(self.grade_b_3.get() or 0)
                    dist1_b = float(self.dist_b_1.get() or 0)
                    dist2_b = float(self.dist_b_2.get() or 0)
                    
                    grade_b_total = grade1_b + grade2_b + grade3_b + dist1_b + dist2_b + 2
                    print(f">>> Grade B especial total: {grade1_b} + {grade2_b} + {grade3_b} + {dist1_b} + {dist2_b} + 2 = {grade_b_total}")
                    
                    # Distribuir grade B total nos 3 campos (máximo 244 por campo)
                    if grade_b_total <= 244:
                        larg1 = grade_b_total
                        larg2 = 0
                        larg3 = 0
                    elif grade_b_total <= 488:
                        larg1 = 244
                        larg2 = grade_b_total - 244
                        larg3 = 0
                    else:
                        larg1 = 244
                        larg2 = 244
                        larg3 = grade_b_total - 488
                    
                    print(f">>> Painel B especial: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f}")
                    
                    # Aplicar valores calculados
                    getattr(self, f"larg1_{letra}").delete(0, tk.END)
                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))
                    
                    if larg2 > 0:
                        getattr(self, f"larg2_{letra}").delete(0, tk.END)
                        getattr(self, f"larg2_{letra}").insert(0, formatar_valor_numerico(larg2))
                    
                    if larg3 > 0:
                        getattr(self, f"larg3_{letra}").delete(0, tk.END)
                        getattr(self, f"larg3_{letra}").insert(0, formatar_valor_numerico(larg3))
                    
                    continue  # Pular para o próximo painel
                    
                except (ValueError, AttributeError) as e:
                    print(f">>> ERRO ao calcular grade B especial: {e}, usando valores normais")
                    # Fallback para valores normais
                    pass

            # Aplicar regras de distribuição NOVA

            if comprimento_ajustado <= 244:

                # Usar apenas larg1 com a medida exata

                larg1 = comprimento_ajustado

                print(f">>> Painel {letra}: larg1 = {larg1:.1f} (medida exata)")

                getattr(self, f"larg1_{letra}").delete(0, tk.END)

                getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                

            else:

                # Para comprimentos maiores que 244, verificar se o sobrante seria < 60

                larg2 = comprimento_ajustado - 244

                

                if larg2 < 60:

                    # Ajustar para 122 + (restante + 122)

                    larg1 = 122

                    larg2 = larg2 + 122  # soma 122 ao sobrante menor que 60

                    print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f} (ajuste por sobrante < 60)")

                    getattr(self, f"larg1_{letra}").delete(0, tk.END)

                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                    getattr(self, f"larg2_{letra}").delete(0, tk.END)

                    getattr(self, f"larg2_{letra}").insert(0, formatar_valor_numerico(larg2))

                

                elif comprimento_ajustado <= 488:

                    # Usar larg1 = 244 e larg2 para o restante

                    larg1 = 244

                    print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}")

                    getattr(self, f"larg1_{letra}").delete(0, tk.END)

                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                    getattr(self, f"larg2_{letra}").delete(0, tk.END)

                    getattr(self, f"larg2_{letra}").insert(0, formatar_valor_numerico(larg2))

                

                else:  # comprimento_ajustado > 488

                    # Para casos com três painéis, verificar se larg3 seria < 60

                    larg1 = 244

                    larg2 = 244

                    larg3 = comprimento_ajustado - 488

                    

                    if larg3 < 60:

                        # Ajustar larg2 para 122 e somar 122 ao larg3

                        larg2 = 122

                        larg3 = larg3 + 122

                        print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f} (ajuste por larg3 < 60)")

                    else:

                        print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f}")

                    

                    getattr(self, f"larg1_{letra}").delete(0, tk.END)

                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                    getattr(self, f"larg2_{letra}").delete(0, tk.END)

                    getattr(self, f"larg2_{letra}").insert(0, formatar_valor_numerico(larg2))

                    getattr(self, f"larg3_{letra}").delete(0, tk.END)

                    getattr(self, f"larg3_{letra}").insert(0, formatar_valor_numerico(larg3))

    

