    def calcular_larguras_paineis_cd(self, largura):

        """

        Calcula automaticamente as larguras dos painéis C e D baseado no campo Largura da aba dados gerais

        

        Regras para painéis C e D:

        - Se largura <= 122: usar apenas larg1

        - Se largura > 122: distribuir entre larg1 e larg2 (máximo 122 por campo)

        

        Args:

            largura: Largura total do pilar

        """

        try:

            print(f"\n>>> INICIANDO CÁLCULO AUTOMÁTICO DE LARGURAS DOS PAINÉIS C e D")


            

            # Processar painéis C e D separadamente

            for letra in ["C", "D"]:

                pass

                

                # Limpar campos existentes 

                getattr(self, f"larg1_{letra}").delete(0, tk.END)

                getattr(self, f"larg2_{letra}").delete(0, tk.END)

                

                # Aplicar regras de distribuição baseada na largura

                if largura <= 122:

                    # Usar apenas larg1 com a medida exata

                    larg1 = largura

                    print(f">>> Painel {letra}: larg1 = {larg1:.1f} (medida exata)")

                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                    getattr(self, f"larg2_{letra}").insert(0, "0")  # Zerar larg2

                    

                else:

                    # Para larguras maiores que 122, distribuir entre larg1 e larg2

                    # Primeira peça sempre 122, segunda peça recebe o restante

                    larg1 = 122

                    larg2 = largura - 122

                    

                    print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}")

                    getattr(self, f"larg1_{letra}").insert(0, formatar_valor_numerico(larg1))

                    getattr(self, f"larg2_{letra}").insert(0, formatar_valor_numerico(larg2))

                    

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()



    def calcular_alturas_painel(self, event=None, tipo_painel=None, campo_atual=None):

        if not self.permitir_recalculo:

            return

        # DEBUG: Log de entrada na função

        

        # Verificar se pilar especial está ativo

        if hasattr(self, 'ativar_pilar_especial') and self.ativar_pilar_especial.get():

            pass

            # Para pilares especiais, apenas painéis E, F, G, H usam calcular_altura_painel_individual
            # Painéis A, B, C, D devem usar a lógica original

            if tipo_painel in ['E', 'F', 'G', 'H']:
                pass
                self.calcular_altura_painel_individual(tipo_painel)
                return
            elif tipo_painel in ['A', 'B', 'C', 'D']:
                pass
                # NÃO fazer nada - painéis A, B, C, D não devem ser modificados quando pilar especial ativo
                return
            elif not tipo_painel:
                # Se não especificou painel, calcular todos
                self.calcular_alturas_paineis_especiais_efgh()
                return

        

        if hasattr(self, '_calculando_alturas') and self._calculando_alturas:

            return

        self._calculando_alturas = True

        try:

            if not tipo_painel and event and hasattr(event, 'widget'):

                widget_nome = str(event.widget)

                for letra in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:

                    if f"_{letra}" in widget_nome:

                        tipo_painel = letra

                        if not campo_atual:

                            if 'laje_' in widget_nome:

                                campo_atual = 'laje'

                            else:

                                for i in range(1, 6):

                                    if f"h{i}_{letra}" in widget_nome:

                                        campo_atual = f"h{i}"

                                        break

                        break

            if not tipo_painel:

                return

            try:

                altura_total = float(self.altura.get().replace(',', '.') or 0)

                nivel_diferencial = float(self.nivel_diferencial.get().replace(',', '.') or 0)

                altura_disponivel = altura_total - nivel_diferencial

            except ValueError:

                return

            # A, B, E, F seguem o comportamento do B (max_altura = 122)
            # C, D, G, H mantêm comportamento original (max_altura = 244)
            max_altura = 122 if tipo_painel in ['A', 'B', 'E', 'F'] else 244

            campos = []

            for i in range(1, 6):

                campo = getattr(self, f"h{i}_{tipo_painel}")

                campos.append(campo)

            campo_laje = getattr(self, f"laje_{tipo_painel}")

            indice_atual = -1

            if campo_atual == 'laje':

                indice_atual = -1

                proximo_indice = 0

            elif campo_atual and campo_atual.startswith('h'):

                indice_atual = int(campo_atual[1]) - 1

                proximo_indice = indice_atual + 1

            else:

                proximo_indice = 0

                soma_alturas = 0

            try:

                valor_laje = float(campo_laje.get().replace(',', '.') or 0)

                soma_alturas = valor_laje

                for i in range(indice_atual + 1):

                    if i >= 0:

                        try:

                            altura_str = campos[i].get().strip()

                            if '+' in altura_str:

                                partes = altura_str.split('+')

                                valor = sum(float(parte.replace(',', '.')) for parte in partes)

                            else:

                                valor = float(altura_str.replace(',', '.'))

                            soma_alturas += valor

                        except ValueError:

                            continue

            except ValueError:

                pass

            altura_restante = altura_disponivel - soma_alturas

            # h1

            if not self.locks.get(f"h1_{tipo_painel}", tk.BooleanVar()).get():

                campos[0].delete(0, tk.END)

                campos[0].insert(0, "2")
                
                # DEBUG: Log específico para A e B
                if tipo_painel in ['A', 'B']:
                    pass

            if proximo_indice == 0:

                altura_restante -= 2

                proximo_indice = 1

            for i in range(proximo_indice, len(campos)):

                if self.locks.get(f"h{i+1}_{tipo_painel}", tk.BooleanVar()).get():

                    # Campo travado, não altera

                    valor = campos[i].get()

                    try:

                        valor = float(str(valor).replace(',', '.'))

                        altura_restante -= valor

                    except:

                        pass

                    continue

                campos[i].delete(0, tk.END)

                if altura_restante <= 0:

                    campos[i].insert(0, "0")
                    
                    # DEBUG: Log específico para A e B
                    if tipo_painel in ['A', 'B']:
                        pass

                    continue

                valor = min(max_altura, altura_restante)

                campos[i].insert(0, formatar_valor_numerico(valor))
                
                # DEBUG: Log específico para A e B
                if tipo_painel in ['A', 'B']:
                    pass

                altura_restante -= valor

            if nivel_diferencial > 0:

                for i in range(proximo_indice, len(campos)):

                    if self.locks.get(f"h{i+1}_{tipo_painel}", tk.BooleanVar()).get():

                        continue

                    try:

                        valor = float(campos[i].get().replace(',', '.') or 0)

                        if valor == 0:

                            campos[i].delete(0, tk.END)

                            campos[i].insert(0, formatar_valor_numerico(nivel_diferencial))

                            break

                    except ValueError:

                        continue

            self.atualizar_posicao_laje(tipo_painel)

            self.atualizar_preview(event)

            if self.auto_save_enabled:

                self.salvar_pilar(mostrar_mensagem=False, event=event)

            else:

                pass

        except Exception as e:

            pass

        finally:

            self._calculando_alturas = False

    def recalcular_por_niveis(self):

        if not self.permitir_recalculo:

            return

        try:

            nivel_saida = float(self.nivel_saida.get().replace(',', '.') or 0)

            nivel_chegada = float(self.nivel_chegada.get().replace(',', '.') or 0)

            nivel_diferencial = float(self.nivel_diferencial.get().replace(',', '.') or 0)

            if nivel_chegada <= nivel_saida:

                return

            altura_total = ((nivel_chegada - nivel_saida) * 100)

            altura_disponivel = altura_total

            self.altura.delete(0, tk.END)

            self.altura.insert(0, formatar_valor_numerico(altura_total))
            
            # Sincronizar campos de altura dos detalhes após atualização automática
            # REMOVIDO: Não sincronizar automaticamente para permitir edição manual
            # if hasattr(self, 'sincronizar_altura_detalhes'):
            #     self.sincronizar_altura_detalhes()

            for tipo_painel in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:

                max_altura = 122 if tipo_painel in ['A', 'B', 'E', 'F'] else 244

                campos = []

                for i in range(1, 6):

                    campo = getattr(self, f"h{i}_{tipo_painel}")

                    campos.append(campo)

                campo_laje = getattr(self, f"laje_{tipo_painel}")

                try:

                    altura_laje = float(campo_laje.get().replace(',', '.') or 0)

                except ValueError:

                    altura_laje = 0

                altura_disponivel_painel = altura_total - altura_laje

                for i, campo in enumerate(campos):

                    if self.locks.get(f"h{i+1}_{tipo_painel}", tk.BooleanVar()).get():

                        continue

                    campo.delete(0, tk.END)

                    campo.insert(0, "0")

                if not self.locks.get(f"h1_{tipo_painel}", tk.BooleanVar()).get():

                    campos[0].delete(0, tk.END)

                    campos[0].insert(0, "2")

                altura_disponivel_painel -= 2  

                altura_restante = altura_disponivel_painel

                indice = 1  

                while altura_restante > 0 and indice < len(campos):

                    if self.locks.get(f"h{indice+1}_{tipo_painel}", tk.BooleanVar()).get():

                        valor = campos[indice].get()

                        try:

                            valor = float(str(valor).replace(',', '.'))

                            altura_restante -= valor

                        except:

                            pass

                        indice += 1

                        continue

                    valor = min(max_altura, altura_restante)

                    campos[indice].delete(0, tk.END)

                    campos[indice].insert(0, formatar_valor_numerico(valor))

                    altura_restante -= valor

                    indice += 1

                if nivel_diferencial > 0:

                    for i in range(1, len(campos)):

                        if self.locks.get(f"h{i+1}_{tipo_painel}", tk.BooleanVar()).get():

                            continue

                        try:

                            valor = float(campos[i].get().replace(',', '.') or 0)

                            if valor == 0:

                                campos[i].delete(0, tk.END)

                                campos[i].insert(0, formatar_valor_numerico(nivel_diferencial))

                                break

                        except ValueError:

                            continue

                self.atualizar_posicao_laje(tipo_painel)

            self.atualizar_preview(None)

            if self.auto_save_enabled:

                self.salvar_pilar(mostrar_mensagem=False)

        except ValueError as e:

            pass

        except Exception as e:

            pass

    def atualizar_posicao_laje(self, tipo_painel):

        try:

            tipo_painel_upper = tipo_painel.upper()

            campo_posicao = getattr(self, f"posicao_laje_{tipo_painel_upper}")

            # Só altera se não estiver travado

            if not self.locks.get(f"posicao_laje_{tipo_painel_upper}", tk.BooleanVar()).get():

                campo_posicao.delete(0, tk.END)

                campo_posicao.insert(0, "5")

            # Atualiza as cores dos campos de altura

            for i in range(1, 6):

                try:

                    campo = getattr(self, f"h{i}_{tipo_painel_upper}")

                    campo.configure(bg="white")

                except Exception as e:

                    pass

            

            # Atualizar alturas dos painéis especiais se pilar especial estiver ativo

            if hasattr(self, 'ativar_pilar_especial') and self.ativar_pilar_especial.get():

                # Se for um painel especial (E, F, G, H) ou um painel que afeta os especiais

                if tipo_painel_upper in ['E', 'F', 'G', 'H'] or tipo_painel_upper in ['A', 'B', 'C', 'D']:

                    self.calcular_altura_painel_individual(tipo_painel_upper)

        except Exception as e:

            pass

    def atualizar_cores_campos_altura(self, tipo_painel, posicao_texto, altura_laje):

        try:

            if altura_laje <= 0:

                for i in range(1, 6):

                    try:

                        campo = getattr(self, f"h{i}_{tipo_painel}")

                        campo.configure(bg="white")

                    except Exception as e:

                        pass

                return

            campos_colorir = []

            if posicao_texto == "5":

                campos_colorir = [1, 2, 3, 4, 5]

            elif posicao_texto.isdigit():

                pos = int(posicao_texto)

                campos_colorir = list(range(pos + 1, 6))

            for i in range(1, 6):

                try:

                    campo = getattr(self, f"h{i}_{tipo_painel}")

                    if i in campos_colorir:

                        campo.configure(bg="orange")

                    else:

                        campo.configure(bg="white")

                except Exception as e:

                    pass

        except Exception as e:

            pass

    # center_window, calcular_altura_e_atualizar e atualizar_altura foram movidas para funcoes_auxiliares_4.py

    def criar_excel(self):

        try:

            import openpyxl

            from openpyxl import load_workbook

            import os

            import sys

            import shutil

            template_path = localizar_template()

            if not template_path or not os.path.exists(template_path):

                # Tentar criar template básico se não existir

                try:

                    wb_temp = openpyxl.Workbook()

                    template_path = os.path.join(self._get_project_root(), "templates", "template_robo.xlsx")

                    wb_temp.save(template_path)

                    print(f">>> Template básico criado em: {template_path}")

                except Exception as e:

                    messagebox.showerror("Erro", f"Não foi possível criar template básico: {str(e)}")

                    return False

            novo_arquivo = filedialog.asksaveasfilename(

                title="Salvar Novo Excel",

                filetypes=[("Excel", "*.xlsx")],

                defaultextension=".xlsx"

            )

            if not novo_arquivo:

                return  

            template_encontrado = False

            mensagens_erro = []

            template_path = localizar_template()

            if template_path and os.path.exists(template_path):

                try:

                    shutil.copy2(template_path, novo_arquivo)

                    template_encontrado = True

                except Exception as e:

                    erro = f"Erro ao copiar de {template_path}: {str(e)}"

                    mensagens_erro.append(erro)

            else:

                possiveis_locais = [

                    os.path.join(self._get_project_root(), "templates", "template_robo.xlsx"),

                    os.path.join(self._get_project_root(), "templates", "template_robo.xlsx"),

                    os.path.join(os.path.dirname(os.path.dirname(sys.executable)), "template_robo.xlsx"),

                    os.path.join(sys._MEIPASS, "template_robo.xlsx") if hasattr(sys, "_MEIPASS") else None,

                ]

                possiveis_locais = [p for p in possiveis_locais if p]

                for path in possiveis_locais:

                    try:

                        if os.path.exists(path):

                            shutil.copy2(path, novo_arquivo)

                            template_encontrado = True

                            break

                    except Exception as e:

                        erro = f"Erro ao copiar de {path}: {str(e)}"

                        mensagens_erro.append(erro)

            if not template_encontrado:

                try:

                    wb = openpyxl.Workbook()

                    wb.save(novo_arquivo)

                    template_encontrado = True

                    messagebox.showwarning("Atenção", "Template não encontrado. Um arquivo Excel em branco foi criado, mas o mapeamento pode não funcionar corretamente.")

                except Exception as e:

                    mensagens_erro.append(f"Erro ao criar Excel em branco: {str(e)}")

                    messagebox.showerror("Erro", f"Não foi possível encontrar o template nem criar um arquivo em branco:\n{mensagens_erro[-1]}")

                    return False

            if not template_encontrado:

                messagebox.showerror("Erro", "Não foi possível encontrar o template ou criar o arquivo Excel.")

                return False

            try:

                wb = load_workbook(novo_arquivo)

                ws = wb.active

                # Coletar todos os itens da lista e ordenar pelo campo número (alfabético)

                itens_lista = []

                for item_id in self.lista_pilares.get_children():

                    item = self.lista_pilares.item(item_id)

                    if not item:

                        continue

                    valores = item.get('values')

                    if not valores or len(valores) == 0:

                        continue

                    numero = str(valores[0]).strip() if valores[0] is not None else ""

                    if not numero:

                        continue

                    if numero not in self.pilares_salvos:

                        continue

                    item_dados = self.pilares_salvos[numero]

                    if not item_dados or "dados" not in item_dados:

                        continue

                    itens_lista.append((numero, item_dados["dados"]))

                # Ordenar alfabeticamente pelo campo número

                itens_lista.sort(key=lambda x: x[0])

                # Carregar mapeamento do Excel

                if 'EXCEL_MAPPING' not in globals() or EXCEL_MAPPING is None:

                    excel_mapping = {}

                else:

                    excel_mapping = EXCEL_MAPPING



                # Exportar sequencialmente a partir da coluna E

                col_base = 4  # Coluna E

                for idx, (numero, dados) in enumerate(itens_lista):

                    coluna_idx = col_base + idx

                    coluna = numero_para_coluna_excel(coluna_idx + 1)

                    ws.cell(row=1, column=coluna_idx + 1, value=numero)

                    

                    for campo, linha in excel_mapping.items():

                        valor = None

                        

                        # Verificar campos básicos

                        if campo in dados:

                            valor = dados[campo]

                        # Verificar parafusos

                        elif "parafusos" in dados and campo in dados["parafusos"]:

                            valor = dados["parafusos"][campo]

                        # Verificar grades

                        elif "grades" in dados and campo in dados["grades"]:

                            valor = dados["grades"][campo]

                        # Verificar detalhes das grades

                        elif "detalhes_grades" in dados and campo in dados["detalhes_grades"]:

                            valor = dados["detalhes_grades"][campo]

                        # Verificar painéis

                        elif "paineis" in dados:

                            for letra in ['A', 'B', 'C', 'D']:

                                if campo.endswith(f"_{letra}") and letra in dados["paineis"]:

                                    painel = dados["paineis"][letra]

                                    base = campo[:-2]

                                    if base in painel:

                                        valor = painel[base]

                                        break

                                    elif "aberturas" in painel:

                                        # Processar aberturas

                                        for lado in ["esquerda", "direita"]:

                                            if lado not in painel["aberturas"]:

                                                continue

                                            prefixo = "esq" if lado == "esquerda" else "dir"

                                            for num in ["1", "2"]:

                                                if num not in painel["aberturas"][lado]:

                                                    continue

                                                

                                                # Mapeamento de nomes de campos

                                                mapeamentos_campo = [

                                                    (f"distancia_{prefixo}_{num}_{letra}", "distancia"),

                                                    (f"largura_{prefixo}_{num}_{letra}", "largura"),

                                                    (f"profundidade_{prefixo}_{num}_{letra}", "profundidade"),

                                                    (f"posicao_{prefixo}_{num}_{letra}", "posicao"),

                                                    (f"dist_{prefixo}_{num}_{letra}", "distancia"),

                                                    (f"larg_{prefixo}_{num}_{letra}", "largura"),

                                                    (f"prof_{prefixo}_{num}_{letra}", "profundidade"),

                                                    (f"pos_{prefixo}_{num}_{letra}", "posicao")

                                                ]

                                                

                                                for nome_campo, nome_interno in mapeamentos_campo:

                                                    if campo == nome_campo:

                                                        if nome_interno in painel["aberturas"][lado][num]:

                                                            valor = painel["aberturas"][lado][num][nome_interno]

                                                            break

                                                if valor is not None:

                                                    break

                                            if valor is not None:

                                                break

                                        if valor is not None:

                                            break

                        

                        # Escrever valor na célula se não for vazio

                        if valor is not None and str(valor).strip():

                            try:

                                valor_numerico = float(str(valor).replace(",", "."))

                                if abs(round(valor_numerico) - valor_numerico) < 0.001:

                                    ws.cell(row=linha + 1, column=coluna_idx + 1, value=int(round(valor_numerico)))

                                else:

                                    ws.cell(row=linha + 1, column=coluna_idx + 1, value=round(valor_numerico, 2))

                            except (ValueError, TypeError):

                                ws.cell(row=linha + 1, column=coluna_idx + 1, value=str(valor).strip())

                    

                    # Processar campos especiais do Excel

                    self.processar_campos_tipo_excel('exportar', wb, coluna_idx)

                

                # Salvar apenas uma vez após processar todos os pilares

                print(f">>> Salvando Excel com {len(itens_lista)} pilares...")

                wb.save(novo_arquivo)

                print(f">>> Excel salvo com sucesso em: {novo_arquivo}")

                messagebox.showinfo("Sucesso", f"Excel criado com sucesso em {novo_arquivo}!\nPilares exportados: {len(itens_lista)}")

                return True

            except Exception as e:

                messagebox.showerror("Erro", f"Erro ao processar o Excel: {str(e)}")

                return False

        except Exception as e:

            messagebox.showerror("Erro", f"Erro ao criar Excel: {str(e)}")

            return False

