    def selecionar_texto_laje(self, letra_laje):

        try:

            ac = load_ac_functions(parent_tk_root=self)

            # Texto instrutivo para seleção da laje

            laje_selection = ac.get_autocad_selection("Selecione um texto contendo o valor de laje (ex: h=20 e 200x20 ou 200/20) e pressione Enter")

            if not laje_selection or len(laje_selection) == 0:

                self.deiconify()

                self.lift()

                self.focus_force()

                campo_laje = getattr(self, f"laje_{letra_laje}")

                campo_laje.delete(0, tk.END)

                campo_laje.insert(0, "0")

                self.calcular_alturas_painel()

                return True

            textos = ac.get_text_objects(laje_selection)

            if not textos:

                self.deiconify()

                self.lift()

                self.focus_force()

                campo_laje = getattr(self, f"laje_{letra_laje}")

                campo_laje.delete(0, tk.END)

                campo_laje.insert(0, "0")

                self.calcular_alturas_painel()

                return True

            texto = textos[0]["text"]

            valor_laje = ac.extract_laje_value_from_text(texto)

            if valor_laje:

                campo_laje = getattr(self, f"laje_{letra_laje}")

                campo_laje.delete(0, tk.END)

                campo_laje.insert(0, valor_laje)

                self.calcular_alturas_painel()

                self.deiconify()

                self.lift()

                self.focus_force()

                return True

            else:

                self.deiconify()

                self.lift()

                self.focus_force()

                campo_laje = getattr(self, f"laje_{letra_laje}")

                campo_laje.delete(0, tk.END)

                campo_laje.insert(0, "0")

                self.calcular_alturas_painel()

                return True

        except Exception as e:

            pass

            self.deiconify()

            self.lift()

            self.focus_force()

            try:

                campo_laje = getattr(self, f"laje_{letra_laje}")

                campo_laje.delete(0, tk.END)

                campo_laje.insert(0, "0")

            except:

                pass

            return True

        finally:

            if laje_selection:

                # Seleção já foi limpa internamente pela função get_autocad_selection
                pass

            self.deiconify()

            self.lift()

            self.focus_force()

            try:

                import win32gui, win32con

                hwnd = self.winfo_id()

                win32gui.ShowWindow(hwnd, win32con.SW_RESTORE)

                win32gui.SetForegroundWindow(hwnd)

            except Exception:

                pass

            hwnd = self.winfo_id()

            bring_window_to_front(hwnd)

