    def calcular_alturas_laje(self, laje_valor, larguras, tipo_painel='A'):

        try:

            if not larguras:

                return None

            alturas = []

            alturas.append(2.0)

            altura_restante = laje_valor - 2.0  

            max_altura = 122.0 if tipo_painel.upper() in ['A', 'B', 'E', 'F'] else 244.0

            if tipo_painel.upper() in ['A', 'B'] and 290 <= laje_valor <= 310:

                return [2.0, 122.0, 122.0, 54.0, 0.0]  

            if tipo_painel.upper() in ['C', 'D']:

                h2 = min(altura_restante, 244.0)

                alturas.append(h2)

                altura_restante -= h2

                if altura_restante > 0:

                    alturas.append(altura_restante)

                    altura_restante = 0

            else:

                while altura_restante > 0 and len(alturas) < 5:

                    proxima_altura = min(max_altura, altura_restante)

                    alturas.append(proxima_altura)

                    altura_restante -= proxima_altura

            while len(alturas) < 5:

                alturas.append(0.0)

            return alturas

        except Exception as e:

            pass

            return None

    def calcular_alturas_e_salvar(self, event=None):

        try:

            self.atualizar_altura()

            self.calcular_alturas_painel()

            self.atualizar_preview()

            self.salvar_pilar(mostrar_mensagem=False, event=event)

            # Garantir que a lista está atualizada com os novos cálculos

            self.atualizar_lista()

        except Exception as e:

            pass

    def get_hierarquia_campos(self, tipo_painel):

        campos = [

            f"laje_{tipo_painel}",

            f"h1_{tipo_painel}",

            f"h2_{tipo_painel}",

            f"h3_{tipo_painel}",

            f"h4_{tipo_painel}",

            f"h5_{tipo_painel}"

        ]

        return campos

    def get_indice_hierarquia(self, campo_nome):

        if "laje_" in campo_nome:

            return 0

        elif "h1_" in campo_nome:

            return 1

        elif "h2_" in campo_nome:

            return 2

        elif "h3_" in campo_nome:

            return 3

        elif "h4_" in campo_nome:

            return 4

        elif "h5_" in campo_nome:

            return 5

        return -1

    def recalcular_alturas_subsequentes(self, tipo_painel, campo_alterado, event=None):

        try:

            campo_atual = None

            if isinstance(campo_alterado, str):

                campo_atual = campo_alterado

            else:

                campo_atual = f"h{campo_alterado}_{tipo_painel}"

            indice_atual = self.get_indice_hierarquia(campo_atual)

            if indice_atual == -1:

                pass

                return

            hierarquia = self.get_hierarquia_campos(tipo_painel)

            campos_para_recalcular = hierarquia[indice_atual + 1:]

            nivel_diferencial_str = self.nivel_diferencial.get().strip()

            valor_diferencial = float(nivel_diferencial_str.replace(',', '.')) if nivel_diferencial_str else 0

            bindings_temp = {}

            for campo in campos_para_recalcular:

                try:

                    widget = getattr(self, campo)

                    bindings_temp[campo] = widget.bind('<KeyRelease>')

                    widget.unbind('<KeyRelease>')

                except:

                    pass

            try:

                altura_total = float(self.altura.get().replace(',', '.') or 0)

            except ValueError:

                altura_total = 0

            altura_usada = 0

            for campo in hierarquia[:indice_atual + 1]:

                try:

                    widget = getattr(self, campo)

                    valor = float(widget.get().replace(',', '.') or 0)

                    altura_usada += valor

                except:

                    continue

            altura_disponivel = altura_total - altura_usada

            max_altura = 122 if tipo_painel in ['A', 'B', 'E', 'F'] else 244

            for campo in campos_para_recalcular:

                widget = getattr(self, campo)

                if altura_disponivel <= 0:

                    widget.delete(0, tk.END)

                    widget.insert(0, "0")

                    continue

                if "laje_" in campo:

                    continue

                elif "h1_" in campo:

                    valor = 2

                else:

                    valor = min(max_altura, altura_disponivel)

                widget.delete(0, tk.END)

                widget.insert(0, formatar_valor_numerico(valor))

                altura_disponivel -= valor

            for campo, binding in bindings_temp.items():

                try:

                    widget = getattr(self, campo)

                    if binding:

                        widget.bind('<KeyRelease>', binding)

                except Exception as e:

                    pass

            self.atualizar_posicao_laje(tipo_painel)

            self.atualizar_preview(event)

            if self.auto_save_enabled:

                self.salvar_pilar(mostrar_mensagem=False, event=event)

            else:

                pass

        except Exception as e:

            pass

    def excluir_item_selecionado(self, forcar_exclusao=False):

        if not getattr(self, '_exclusao_explicitamente_autorizada', False) and not forcar_exclusao:

            return

        self._exclusao_explicitamente_autorizada = False

        try:

            selected_item = self.lista_pilares.selection()

            if not selected_item:

                messagebox.showwarning("Atenção", "Nenhum item selecionado para exclusão.")

                return

            
            # Obter dados do item antes de removê-lo da lista
            item = self.lista_pilares.item(selected_item[0])

            item_id_raw = item['values'][0]  
            # Converter para string para garantir consistência (funciona com inteiros e frações)
            item_id = str(item_id_raw) if item_id_raw else None

            nome_pilar = item['values'][1]  

            pavimento_pilar = item['values'][2]  # Adicionar pavimento para identificação única
            
            # Obter obra atual para verificação
            obra_atual = self.obra_filtro_var.get() if hasattr(self, 'obra_filtro_var') else None
            if not obra_atual:
                obra_atual = "Obra Padrão"
            
            print(f">>> Iniciando exclusão do item: {item_id} - {nome_pilar} (Pav: {pavimento_pilar}, Obra: {obra_atual})")
            
            confirmacao = messagebox.askyesno(

                "Confirmar Exclusão",

                f"Tem certeza que deseja excluir o pilar '{nome_pilar}' do pavimento '{pavimento_pilar}'?",
                parent=self

            )

            if not confirmacao:

                return

            
            # Remover da lista visual
            print(f">>> Removendo {len(selected_item)} item(s) da lista visual")
            for item in selected_item:

                self.lista_pilares.delete(item)

            print(f">>> Itens removidos da lista visual")
            
            # Remover dos dados salvos - usar identificação mais específica
            item_removido = False

            chave_removida = None
            
            # CRÍTICO: Usar helper para deletar com chave única
            obra_atual = self.obra_filtro_var.get() if hasattr(self, 'obra_filtro_var') else None
            if not obra_atual:
                obra_atual = "Obra Padrão"
            
            # Tentar deletar usando helper primeiro
            if self._delete_pilar_salvo_entry(item_id, pavimento_pilar, obra_atual):
                item_removido = True
                chave_removida = f"{item_id}_{pavimento_pilar}"
                print(f">>> Item removido usando helper: {chave_removida}")
            else:
                # Fallback: procurar manualmente se helper não encontrou
                for key, value in list(self.pilares_salvos.items()):
                    if isinstance(value, dict) and "dados" in value:
                        dados = value["dados"]
                        # Verificar se número, nome, pavimento e obra coincidem
                        dados_numero = dados.get("numero", "")
                        dados_nome = dados.get("nome", "")
                        dados_pavimento = dados.get("pavimento", "")
                        dados_obra = dados.get("obra", obra_atual)
                        
                        if (str(dados_numero) == str(item_id) and
                            dados_nome == nome_pilar and 
                            dados_pavimento == pavimento_pilar and
                            dados_obra == obra_atual):
                            # Usar helper para deletar
                            if self._delete_pilar_salvo_entry(dados_numero, dados_pavimento, dados_obra):
                                item_removido = True
                                chave_removida = key
                                print(f">>> Item removido por busca manual: {key}")
                                break

            
            # Remover da estrutura de obras se existir - buscar em todos os pavimentos
            obra_atual = self.obra_filtro_var.get()
            if obra_atual and obra_atual in self.obras:
                item_removido_obra = False
                # Procurar em todos os pavimentos da obra
                for pav_nome, pav_dados in list(self.obras[obra_atual].items()):
                    if isinstance(pav_dados, dict) and pav_nome != "pavimentos_data":
                        # Tentar remover usando item_id (string) diretamente
                        if item_id and item_id in pav_dados:
                            del pav_dados[item_id]
                            print(f">>> Item removido do pavimento '{pav_nome}' da obra '{obra_atual}' por item_id: {item_id}")
                            item_removido_obra = True
                            break
                        # Tentar remover usando item_id como float (para casos onde está armazenado como 1.1)
                        elif item_id_raw:
                            try:
                                item_id_float = float(item_id_raw)
                                # Tentar encontrar chave que corresponde ao número (pode estar como string ou float)
                                for key in list(pav_dados.keys()):
                                    try:
                                        key_float = float(key)
                                        if key_float == item_id_float:
                                            del pav_dados[key]
                                            print(f">>> Item removido do pavimento '{pav_nome}' da obra '{obra_atual}' por item_id (float): {key}")
                                            item_removido_obra = True
                                            break
                                    except (ValueError, TypeError):
                                        continue
                                if item_removido_obra:
                                    break
                            except (ValueError, TypeError):
                                pass
                        # Tentar remover usando chave_removida se existir
                        if not item_removido_obra and chave_removida and chave_removida in pav_dados:
                            del pav_dados[chave_removida]
                            print(f">>> Item removido do pavimento '{pav_nome}' da obra '{obra_atual}' por chave: {chave_removida}")
                            item_removido_obra = True
                            break
                        # Procurar por número + nome + pavimento (identificador único) - último recurso
                        if not item_removido_obra:
                            item_id_numero = None
                            try:
                                item_id_numero = float(item_id_raw) if item_id_raw else None
                            except (ValueError, TypeError):
                                pass
                            
                            for key, value in list(pav_dados.items()):
                                if isinstance(value, dict) and "dados" in value:
                                    dados = value["dados"]
                                    
                                    # Extrair número da chave
                                    key_numero = None
                                    try:
                                        key_numero = float(key) if key else None
                                    except (ValueError, TypeError):
                                        # Tentar extrair número da chave composta
                                        if '_' in str(key):
                                            try:
                                                key_numero = float(str(key).split('_')[0])
                                            except (ValueError, TypeError):
                                                pass
                                    
                                    # Extrair número dos dados (se existir)
                                    dados_numero = None
                                    try:
                                        dados_numero_str = dados.get("numero", "")
                                        if dados_numero_str:
                                            dados_numero = float(dados_numero_str)
                                    except (ValueError, TypeError):
                                        pass
                                    
                                    # Verificar se número (da chave ou dos dados), nome e pavimento coincidem (identificador único)
                                    numero_coincide = False
                                    if item_id_numero is not None:
                                        if key_numero is not None and key_numero == item_id_numero:
                                            numero_coincide = True
                                        elif dados_numero is not None and dados_numero == item_id_numero:
                                            numero_coincide = True
                                    
                                    # Verificar também a obra (se estiver nos dados)
                                    obra_dados = dados.get("obra", obra_atual if obra_atual else None)
                                    obra_coincide = (obra_dados == obra_atual) if obra_atual else True
                                    
                                    if (numero_coincide and
                                        dados.get("nome") == nome_pilar and 
                                        dados.get("pavimento") == pavimento_pilar and
                                        obra_coincide):
                                        del pav_dados[key]
                                        print(f">>> Item removido do pavimento '{pav_nome}' da obra '{obra_atual}' por número+nome+pavimento+obra: {key}")
                                        item_removido_obra = True
                                        break
                            if item_removido_obra:
                                break
                
                if item_removido_obra:
                    item_removido = True
            
                # CRÍTICO: Limpar pavimentos vazios após exclusão
                if obra_atual in self.obras:
                    for pav_nome in list(self.obras[obra_atual].keys()):
                        if pav_nome != "pavimentos_data":
                            pav_dados = self.obras[obra_atual][pav_nome]
                            if isinstance(pav_dados, dict) and len(pav_dados) == 0:
                                del self.obras[obra_atual][pav_nome]
                                print(f">>> Pavimento vazio '{pav_nome}' removido da obra '{obra_atual}'")
            
            # CRÍTICO: Garantir que o item foi realmente removido de todas as estruturas antes de salvar
            # Verificar se ainda existe em obras
            item_ainda_existe_obras = False
            if obra_atual in self.obras:
                for pav_nome, pav_dados in self.obras[obra_atual].items():
                    if isinstance(pav_dados, dict) and pav_nome != "pavimentos_data":
                        if item_id in pav_dados:
                            item_ainda_existe_obras = True
                            # Tentar remover novamente
                            try:
                                del pav_dados[item_id]
                                print(f">>> Item {item_id} removido novamente do pavimento '{pav_nome}'")
                            except:
                                pass
            
            # Verificar se ainda existe em pilares_salvos
            item_ainda_existe_pilares = False
            _, entry_check = self._get_pilar_salvo_entry(item_id, pavimento_pilar, obra_atual, allow_partial=False)
            if entry_check:
                item_ainda_existe_pilares = True
                # Tentar remover novamente
                self._delete_pilar_salvo_entry(item_id, pavimento_pilar, obra_atual)
                print(f">>> Item {item_id} removido novamente de pilares_salvos")
            
            # Salvar alterações APENAS se o item foi realmente removido
            if not item_ainda_existe_obras and not item_ainda_existe_pilares:
                try:
                    import pickle
                    import os
                    caminho_arquivo = self.obter_caminho_dados("pilares_salvos.pkl")
                    with open(caminho_arquivo, 'wb') as arquivo:
                        pickle.dump(self.pilares_salvos, arquivo)
                    print(f">>> Dados salvos após exclusão do item '{nome_pilar}'")
                except Exception as e:
                    print(f">>> Erro ao salvar após exclusão: {e}")
                
                # Salvar obras também
                self.salvar_obras()
            else:
                print(f">>> AVISO: Item ainda existe em alguma estrutura após tentativa de exclusão!")
            
            # Limpar campos das abas após exclusão
            self._limpar_campos_abas()
            
            # Atualizar lista IMEDIATAMENTE (sem esperar refresh)
            self.atualizar_lista()
            

            
            if item_removido:

                messagebox.showinfo(

                    "Exclusão",

                    f"Pilar '{nome_pilar}' excluído com sucesso.",

                    parent=self

                )

            else:

                messagebox.showwarning(

                    "Atenção",

                    f"Pilar removido da lista, mas não encontrado no dicionário de dados.",

                    parent=self

                )

        except Exception as e:

            pass

            messagebox.showerror(

                "Erro",

                f"Erro ao excluir o pilar: {str(e)}",

                parent=self

            )

    def excluir_itens_selecionados(self):
        """Exclui apenas os itens selecionados na lista (Ctrl+Click)"""
        from tkinter import messagebox
        
        # Obter itens selecionados na lista
        selected_items = self.lista_pilares.selection()
        
        if not selected_items:
            messagebox.showwarning("Atenção", "Selecione pelo menos um item na lista para excluir.\n\nUse Ctrl+Click para selecionar múltiplos itens.")
            return
        
        # Confirmar exclusão
        confirmacao = messagebox.askyesno(
            "Confirmar Exclusão",
            f"Tem certeza que deseja excluir {len(selected_items)} item(s) selecionado(s)?\n\nEsta ação não pode ser desfeita!",
            parent=self
        )
        
        if not confirmacao:
            return
        
        # Obter obra atual
        obra_atual = self.obra_filtro_var.get()
        
        if not obra_atual or obra_atual not in self.obras:
            messagebox.showerror("Erro", "Nenhuma obra selecionada.")
            return
        
        # Processar cada item selecionado
        itens_removidos = 0
        for item in selected_items:
            # Obter dados do item da lista
            item_values = self.lista_pilares.item(item, 'values')
            if len(item_values) >= 2:
                nome_pilar = item_values[1]  # Nome está na coluna 1
                pavimento = item_values[2]  # Pavimento está na coluna 2
                
                # Remover da estrutura de obras e pilares_salvos
                if pavimento in self.obras[obra_atual]:
                    for item_id in list(self.obras[obra_atual][pavimento].keys()):
                        if isinstance(self.obras[obra_atual][pavimento][item_id], dict):
                            dados = self.obras[obra_atual][pavimento][item_id].get("dados", {})
                            if dados.get("nome") == nome_pilar:
                                # Obter numero do item para usar helper
                                numero_item = dados.get("numero", item_id)
                                
                                # Remover de obras
                                del self.obras[obra_atual][pavimento][item_id]
                                
                                # Remover de pilares_salvos usando helper
                                self._delete_pilar_salvo_entry(numero_item, pavimento, obra_atual)
                                
                                itens_removidos += 1
                                print(f">>> Item '{nome_pilar}' excluído do pavimento '{pavimento}'")
                                break
        
        # Salvar alterações
        self.salvar_obras()
        
        try:
            import pickle
            import os
            # Usar obter_caminho_dados() para garantir compatibilidade com frozen mode
            caminho_pilares = self.obter_caminho_dados("pilares_salvos.pkl")
            with open(caminho_pilares, 'wb') as f:
                pickle.dump(self.pilares_salvos, f)
            print(f">>> Pilares salvos atualizados: {caminho_pilares}")
        except Exception as e:
            print(f">>> Erro ao salvar pilares após exclusão: {e}")
            pass
        
        # Atualizar lista
        self.atualizar_lista()
        
        messagebox.showinfo("Sucesso", f"{itens_removidos} item(s) excluído(s) com sucesso!")
        print(f">>> Exclusão concluída: {itens_removidos} itens removidos")

    def excluir_todos_itens_pavimento(self):
        """Exclui todos os itens do pavimento selecionado"""
        from tkinter import messagebox
        
        # Obter pavimento selecionado
        pavimento_selecionado = self.pavimento_filtro_var.get()
        
        if not pavimento_selecionado or pavimento_selecionado == "Todos":
            messagebox.showwarning("Atenção", "Selecione um pavimento específico para excluir os itens.")
            return
        
        # Confirmar exclusão
        confirmacao = messagebox.askyesno(
            "Confirmar Exclusão",
            f"Tem certeza que deseja excluir TODOS os itens do pavimento '{pavimento_selecionado}'?\n\nEsta ação não pode ser desfeita!",
            parent=self
        )
        
        if not confirmacao:
            return
        
        # Obter obra atual
        obra_atual = self.obra_filtro_var.get()
        
        if not obra_atual or obra_atual not in self.obras:
            messagebox.showerror("Erro", "Nenhuma obra selecionada.")
            return
        
        # Contar itens a serem excluídos na estrutura de obras
        itens_removidos = 0
        if pavimento_selecionado in self.obras[obra_atual]:
            itens_removidos = len(self.obras[obra_atual][pavimento_selecionado])
            del self.obras[obra_atual][pavimento_selecionado]
            print(f">>> Pavimento '{pavimento_selecionado}' excluído da obra '{obra_atual}' - {itens_removidos} itens removidos")
        
        # CRÍTICO: Remover de pilares_salvos usando helpers para garantir chaves únicas corretas
        itens_pilares_removidos = 0
        # Primeiro, encontrar todos os itens do pavimento
        itens_para_remover = []
        for key, item_dados in list(self.pilares_salvos.items()):
            if isinstance(item_dados, dict) and "dados" in item_dados:
                dados = item_dados["dados"]
                item_obra = item_dados.get("obra", obra_atual)
                if dados.get("pavimento") == pavimento_selecionado and item_obra == obra_atual:
                    numero_item = dados.get("numero")
                    if numero_item:
                        itens_para_remover.append((numero_item, pavimento_selecionado, item_obra))
        
        # Remover usando helpers
        for numero_item, pav_item, obra_item in itens_para_remover:
            self._delete_pilar_salvo_entry(numero_item, pav_item, obra_item)
            itens_pilares_removidos += 1
        
        # Salvar alterações
        self.salvar_obras()
        
        try:
            import pickle
            import os
            caminho_arquivo = self.obter_caminho_dados("pilares_salvos.pkl")
            with open(caminho_arquivo, 'wb') as arquivo:
                pickle.dump(self.pilares_salvos, arquivo)
            print(f">>> Dados salvos após exclusão do pavimento '{pavimento_selecionado}'")
        except Exception as e:
            pass
        
        # Atualizar lista
        self.atualizar_lista()
        
        # Mostrar mensagem de sucesso
        total_removidos = max(itens_removidos, itens_pilares_removidos)
        messagebox.showinfo(
            "Exclusão",
            f"Todos os itens do pavimento '{pavimento_selecionado}' foram excluídos com sucesso!\n\nTotal: {total_removidos} item(s) removido(s).",
            parent=self
        )

    def mostrar_menu_contexto(self, event):

        try:

            item = self.lista_pilares.identify_row(event.y)

            if item:

                self.lista_pilares.selection_set(item)

                self._exclusao_explicitamente_autorizada = True

                self.menu_contexto.post(event.x_root, event.y_root)

        except Exception as e:

            pass

    def mostrar_instrucoes_nivel_diferencial(self):

        instrucoes = (

            "Instruções para Nível Diferencial:\n\n"

            "1. Clique em 'Select NV' para iniciar a seleção\n"

            "2. No AutoCAD, selecione um texto contendo um valor numérico (ex: 752,00)\n"

            "3. O sistema extrairá esse valor e o colocará no campo 'Nível Diferencial'\n\n"

            "Funcionamento:\n"

            "- O sistema calcula: (Nível Diferencial - Nível de Chegada) × 100\n\n"

            "- Se o resultado for positivo:\n"

            "  → O sistema preencherá o primeiro campo de altura vazio (0) nos painéis A, B, C e D\n\n"

            "- Se o resultado for negativo:\n"

            "  → O sistema subtrairá esse valor do último valor de altura válido\n"

            "  → Se a subtração resultar em valor negativo, o campo será zerado\n"

            "    e a subtração continuará no campo anterior\n\n"

            "Exemplos:\n"

            "Valor = 802,00 e Nível Chegada = 800,00:\n"

            "- Diferença = 2,00 × 100 = 200 (Positivo)\n"

            "- Preenche primeiro campo vazio com 200\n\n"

            "Valor = 790,00 e Nível Chegada = 800,00:\n"

            "- Diferença = -10,00 × 100 = -1000 (Negativo)\n"

            "- Subtrai 1000 do último campo preenchido"

        )

