    def marcar_inicio_edicao(self, event):

        widget = event.widget

        widget_nome = str(widget)

        self.campo_em_edicao = widget_nome

    def marcar_fim_edicao(self, event):

        widget = event.widget

        widget_nome = str(widget)

        if any(nivel in widget_nome for nivel in ['nivel_saida', 'nivel_chegada', 'nivel_diferencial']):

            self.recalcular_por_niveis()

        elif any(f"_{letra}" in widget_nome for letra in ['A', 'B', 'C', 'D']):

            if any(campo in widget_nome for campo in ['laje', 'h1', 'h2', 'h3', 'h4', 'h5']):

                for letra in ['A', 'B', 'C', 'D']:

                    if f"_{letra}" in widget_nome:

                        tipo_painel = letra

                        campo_atual = None

                        if 'laje_' in widget_nome:

                            campo_atual = 'laje'

                        else:

                            for i in range(1, 6):

                                if f"h{i}_" in widget_nome:

                                    campo_atual = f"h{i}"

                                    break

                        if campo_atual:

                            self.calcular_alturas_painel(event, tipo_painel=tipo_painel, campo_atual=campo_atual)

                        break

        self.campo_em_edicao = None

    def recalcular_alturas_hierarquicas(self, tipo_painel, campo_atual):

        if not self.permitir_recalculo:

            return

        try:

            altura_total = float(self.altura.get().replace(',', '.') or 0)

            nivel_diferencial = float(self.nivel_diferencial.get().replace(',', '.') or 0)

            altura_disponivel = altura_total

            max_altura = 122 if tipo_painel in ['A', 'B', 'E', 'F'] else 244

            campos = []

            campo_laje = getattr(self, f"laje_{tipo_painel}")

            campos.append(('laje', campo_laje))

            for i in range(1, 6):

                campo = getattr(self, f"h{i}_{tipo_painel}")

                campos.append((f"h{i}", campo))

            indice_atual = -1

            for i, (nome, _) in enumerate(campos):

                if nome == campo_atual:

                    indice_atual = i

                    break

            soma_alturas = 0

            for i in range(indice_atual + 1):

                nome, campo = campos[i]

                try:

                    altura_str = campo.get() or "0"

                    if '+' in altura_str:

                        partes = altura_str.split('+')

                        valor = sum(float(parte.replace(',', '.')) for parte in partes)

                    else:

                        valor = float(altura_str.replace(',', '.'))

                    soma_alturas += valor

                except ValueError:

                    continue

            altura_restante = altura_disponivel - soma_alturas

            for i in range(indice_atual + 1, len(campos)):

                nome, campo = campos[i]

                lock_nome = f"{nome}_{tipo_painel}" if not nome.startswith("laje") else f"laje_{tipo_painel}"

                if self.locks.get(lock_nome, tk.BooleanVar()).get():

                    # Campo travado, não altera, mas considera valor atual

                    try:

                        altura_str = campo.get() or "0"

                        if '+' in altura_str:

                            partes = altura_str.split('+')

                            valor = sum(float(parte.replace(',', '.')) for parte in partes)

                        else:

                            valor = float(altura_str.replace(',', '.'))

                        altura_restante -= valor

                    except ValueError:

                        pass

                    continue

                campo.delete(0, tk.END)

                if nome == 'h1':

                    valor = 2

                    altura_restante -= 2

                elif altura_restante <= 0:

                    valor = 0

                else:

                    limite = 244 if tipo_painel in ['C', 'D'] else 122

                    valor = min(limite, altura_restante)

                    altura_restante -= valor

                campo.insert(0, formatar_valor_numerico(valor))

            if nivel_diferencial > 0:

                for i in range(indice_atual + 1, len(campos)):

                    nome, campo = campos[i]

                    lock_nome = f"{nome}_{tipo_painel}" if not nome.startswith("laje") else f"laje_{tipo_painel}"

                    if self.locks.get(lock_nome, tk.BooleanVar()).get():

                        continue

                    if nome == 'h1':

                        continue

                    try:

                        valor = float(campo.get().replace(',', '.') or 0)

                        if valor == 0:

                            campo.delete(0, tk.END)

                            campo.insert(0, formatar_valor_numerico(nivel_diferencial))

                            break

                    except ValueError:

                        continue

            self.atualizar_posicao_laje(tipo_painel)

            self.atualizar_preview(None)

        except Exception as e:

            pass

    def registrar_eventos_aberturas(self):

        self.desvincula_eventos_aberturas()

        self.campos_abertura_bindings = []

        for letra in ['A', 'B']:

            for lado in ['esq', 'dir']:

                for num in ['1', '2']:

                    for tipo in ['dist', 'larg', 'prof', 'pos']:

                        campo_nome = f"{tipo}_{lado}_{num}_{letra}"

                        if hasattr(self, campo_nome):

                            campo = getattr(self, campo_nome)

                            binding_id = campo.bind("<FocusOut>", 

                                         lambda event, cn=campo_nome: self.salvar_campo_abertura(event, cn),

                                         add="+")

                            self.campos_abertura_bindings.append((campo, binding_id))

    def desvincula_eventos_aberturas(self):

        if hasattr(self, 'campos_abertura_bindings'):

            for campo, binding_id in self.campos_abertura_bindings:

                try:

                    campo.unbind("<FocusOut>", binding_id)

                except:

                    pass

            self.campos_abertura_bindings = []

    def salvar_campo_abertura(self, event, campo_nome):

        selected_item = self.lista_pilares.selection()

        if not selected_item:

            return

        numero_atual = self.excel_column.get().strip()

        if not numero_atual:

            return
        
        # CRÍTICO: Obter obra e pavimento do contexto para usar helper
        obra_atual = self.obra_filtro_var.get() if hasattr(self, 'obra_filtro_var') else "Obra Padrão"
        if not obra_atual:
            obra_atual = "Obra Padrão"
        
        pavimento_atual = self.pavimento_var.get().strip() if hasattr(self, 'pavimento_var') else ""
        if not pavimento_atual:
            pavimento_atual = self.pavimento_filtro_var.get().strip() if hasattr(self, 'pavimento_filtro_var') else ""
            if not pavimento_atual or pavimento_atual == "Todos":
                pavimento_atual = "Subsolo"
        
        # Verificar se item existe usando helper
        _, item_dados = self._get_pilar_salvo_entry(numero_atual, pavimento_atual, obra_atual, allow_partial=True)
        if not item_dados:
            # Fallback: tentar chave simples (compatibilidade)
            if numero_atual not in self.pilares_salvos:
                return
            item_dados = self.pilares_salvos[numero_atual]

        partes = campo_nome.split('_')

        if len(partes) != 4:

            return

        tipo, lado, num, letra = partes

        mapeamento_campos = {

            "dist": "distancia",

            "larg": "largura",

            "prof": "profundidade",

            "pos": "posicao"

        }

        try:

            lado_completo = "esquerda" if lado == "esq" else "direita"

            campo_obj = getattr(self, campo_nome)

            valor = campo_obj.get()

            campo_completo = mapeamento_campos.get(tipo, tipo)

            # CRÍTICO: Atualizar usando helper para garantir chave única correta
            if item_dados and "dados" in item_dados:
                item_dados["dados"]["paineis"][letra]["aberturas"][lado_completo][num][campo_completo] = valor
                # Salvar usando helper
                self._set_pilar_salvo_entry(numero_atual, pavimento_atual, obra_atual, item_dados)

            self.auto_salvar_dados()

        except Exception as e:

            pass

    def auto_salvar_dados(self):

        try:

            import pickle

            import os

            if not self.auto_save_enabled:

                return

            caminho_arquivo = self.obter_caminho_dados("pilares_salvos.pkl")

            with open(caminho_arquivo, 'wb') as arquivo:

                pickle.dump(self.pilares_salvos, arquivo)

            # Salva pavimentos_lista

            self.salvar_pavimentos_lista()

            caminho_pav = self.obter_caminho_dados("pavimentos_lista.pkl")

            with open(caminho_pav, 'wb') as arquivo:

                pickle.dump(self.pavimentos_lista, arquivo)

            # Salva obras

            self.salvar_obras()

        except Exception as e:

            pass

    def _atualizar_campos_abertura(self, dados_pilar):

        for letra in ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H']:

            if letra in dados_pilar["paineis"] and "aberturas" in dados_pilar["paineis"][letra]:

                aberturas = dados_pilar["paineis"][letra]["aberturas"]

                altura_total = float(self.altura.get().replace(',', '.') or 0)

                alturas = []

                for i in range(1, 6):

                    campo_nome = f"h{i}_{letra}"

                    if hasattr(self, campo_nome):

                        campo = getattr(self, campo_nome)

                        try:

                            altura_str = campo.get().strip()

                            if altura_str:

                                altura = float(altura_str.replace(',', '.'))

                                if altura > 0:

                                    alturas.append(altura)

                        except (ValueError, AttributeError):

                            continue

                soma_alturas = sum(alturas)

                for lado, lado_comp in [("esq", "esquerda"), ("dir", "direita")]:

                    for num in ["1", "2"]:

                        if lado_comp in aberturas and num in aberturas[lado_comp]:

                            abertura = aberturas[lado_comp][num]

                            mapeamento_campos = {

                                "dist": "distancia",

                                "larg": "largura",

                                "prof": "profundidade",

                                "pos": "posicao",

                                "tipo": "tipo"

                            }

                            for tipo_abrev, tipo_completo in mapeamento_campos.items():

                                campo_nome = f"{tipo_abrev}_{lado}_{num}_{letra}"

                                if hasattr(self, campo_nome) and tipo_completo in abertura:

                                    campo = getattr(self, campo_nome)

                                    valor = abertura[tipo_completo]

                                    if tipo_abrev == "pos":

                                        if valor == 0:

                                            valor = altura_total - soma_alturas

                                        elif valor == 1:

                                            valor = altura_total

                                        elif valor == 2:

                                            valor = 0

                                    campo.delete(0, tk.END)

                                    campo.insert(0, valor)

    def processar_campos_tipo_excel(self, acao, wb=None, coluna_idx=None):

        """

        Processa os campos tipo no Excel.

        Args:

            acao (str): 'importar' ou 'exportar'

            wb (Workbook): Workbook do openpyxl

            coluna_idx (int): Índice da coluna atual no Excel

        """

        try:

            if not wb:

                return



            ws = wb.active

            mapeamento_tipo = {

                "tipo_esq_1_A": 187,

                "tipo_esq_2_A": 188,

                "tipo_dir_1_A": 189,

                "tipo_dir_2_A": 190,

                "tipo_esq_1_B": 207,

                "tipo_esq_2_B": 208,

                "tipo_dir_1_B": 209,

                "tipo_dir_2_B": 210

            }



            if acao == 'exportar':

                # Para exportação, usamos o coluna_idx fornecido

                if coluna_idx is not None:

                    # Obtém o número do pilar da primeira linha

                    numero = ws.cell(row=1, column=coluna_idx + 1).value

                    if numero is None:

                        return

                    numero = str(numero).strip()

                    if not numero or numero not in self.pilares_salvos:

                        return



                    # Obtém os dados do pilar

                    dados = self.pilares_salvos[numero]["dados"]

                    

                    # Processa cada campo tipo

                    for campo, linha in mapeamento_tipo.items():

                        partes = campo.split('_')

                        lado = "esquerda" if partes[1] == "esq" else "direita"

                        num = partes[2]

                        letra = partes[3]



                        # Obtém o valor do tipo do dicionário de dados

                        try:

                            valor = dados["paineis"][letra]["aberturas"][lado][num].get("tipo", "")

                            if valor:

                                ws.cell(row=linha + 1, column=coluna_idx + 1, value=valor)

                        except:

                            continue



            elif acao == 'importar':

                # Para importação, processamos todas as colunas a partir da coluna E

                for col in range(5, ws.max_column + 1):  # Começa da coluna E (5)

                    try:

                        # Obtém o número do pilar da primeira linha

                        numero = ws.cell(row=1, column=col).value

                        if numero is None:

                            continue

                        numero = str(numero).strip()

                        if not numero:

                            continue



                        # Processa os campos tipo para este pilar

                        for campo, linha in mapeamento_tipo.items():

                            valor = ws.cell(row=linha + 1, column=col).value

                            if valor is not None:

                                # Extrai informações do nome do campo

                                partes = campo.split('_')

                                lado = "esquerda" if partes[1] == "esq" else "direita"

                                num = partes[2]

                                letra = partes[3]



                                # Atualiza o dicionário de dados

                                if numero in self.pilares_salvos:

                                    dados = self.pilares_salvos[numero]["dados"]

                                    if "paineis" not in dados:

                                        dados["paineis"] = {}

                                    if letra not in dados["paineis"]:

                                        dados["paineis"][letra] = {}

                                    if "aberturas" not in dados["paineis"][letra]:

                                        dados["paineis"][letra]["aberturas"] = {}

                                    if lado not in dados["paineis"][letra]["aberturas"]:

                                        dados["paineis"][letra]["aberturas"][lado] = {}

                                    if num not in dados["paineis"][letra]["aberturas"][lado]:

                                        dados["paineis"][letra]["aberturas"][lado][num] = {}

                                    

                                    # Atualiza o campo tipo

                                    dados["paineis"][letra]["aberturas"][lado][num]["tipo"] = str(valor)



                                    # Atualiza o campo na interface se existir

                                    campo_interface = f"tipo_{partes[1]}_{partes[2]}_{partes[3]}"

                                    if hasattr(self, campo_interface):

                                        campo = getattr(self, campo_interface)

                                        campo.delete(0, tk.END)

                                        campo.insert(0, str(valor))

                    except Exception as e:

                        continue



                # Salva os dados após processar todos os campos tipo

                try:

                    import pickle

                    import os

                    caminho_arquivo = self.obter_caminho_dados("pilares_salvos.pkl")

                    with open(caminho_arquivo, 'wb') as arquivo:

                        pickle.dump(self.pilares_salvos, arquivo)

                except Exception as e:

                    pass



        except Exception as e:

            print(f"Erro ao processar campos tipo no Excel: {str(e)}")

            return None

    def recalcular_todas_dimensoes(self):

        """Função que recalcula todas as dimensões, incluindo alturas dos painéis"""

        # Primeiro calcula as dimensões básicas

        self.calcular_dimensoes_painel(None)

        

        # Depois recalcula as alturas para cada painel

        for letra in ['A', 'B', 'C', 'D']:

            self.calcular_alturas_painel(None, tipo_painel=letra)

        

        # Atualiza o preview

        self.atualizar_preview(None)

        

        # Força atualização da lista para recalcular totais de m²

        self.atualizar_lista()

        

