    def set_pavimento_from_lista(self, idx):

        """Define o pavimento selecionado na lista para os campos do item atual"""

        if idx < 1 or idx >= len(self.pavimentos_entries):

            return

        

        # Obter dados do pavimento anterior (idx-1)

        pavimento_anterior = self.pavimentos_entries[idx-1][0].get().strip()

        nivel_saida = self.pavimentos_entries[idx-1][1].get().strip()

        

        # Obter dados do pavimento atual (idx)

        pavimento = self.pavimentos_entries[idx][0].get().strip()

        nivel_chegada = self.pavimentos_entries[idx][1].get().strip()

        

        # Verificar se ambos os campos estão preenchidos

        if not (pavimento and nivel_chegada):

            pass

            return

        

        # Atualizar campos do item

        self.pavimento_abc.delete(0, tk.END)

        self.pavimento_abc.insert(0, pavimento_anterior)

        self.nivel_saida.delete(0, tk.END)

        self.nivel_saida.insert(0, nivel_saida)

        

        # Atualizar combobox de pavimento

        if hasattr(self, 'pavimento_var'):

            self.pavimento_var.set(pavimento)  # Apenas o nome, sem numeração

        else:

            print(f">>> Erro: pavimento_var não encontrado")

        

        self.nivel_chegada.delete(0, tk.END)

        self.nivel_chegada.insert(0, nivel_chegada)

        # Simular os bindings automáticos que ocorrem no FocusOut dos campos de nível
        # (nivel_saida e nivel_chegada têm os mesmos bindings)
        # 1. Recalcular por níveis (chamado por marcar_fim_edicao quando detecta campo de nível)
        self.recalcular_por_niveis()
        
        # 2. Sincronizar altura dos detalhes (binding adicional do FocusOut)
        if hasattr(self, 'sincronizar_altura_detalhes'):
            self.sincronizar_altura_detalhes()
        
        # 3. Calcular altura e atualizar (função original)
        self.calcular_altura_e_atualizar(None)

        # Chama o cálculo hierárquico das alturas dos paineis
        # COMENTADO: Estava causando alteração indesejada de A e B após cálculos corretos
        # for letra in ['A', 'B', 'C', 'D']:
        #     self.recalcular_alturas_hierarquicas(letra, 'laje')

    

    def criar_pavimento_from_lista(self, idx):

        """Cria uma cópia do item atual para o pavimento especificado"""

        # Verificar se uma obra está selecionada

        obra_atual = self.obra_filtro_var.get()

        if not obra_atual:
            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Selecione uma obra antes de criar um pavimento!")

            return

        

        # Verificar se o pavimento está preenchido

        if idx < 1 or idx >= len(self.pavimentos_entries):

            return

        

        pavimento_nome = self.pavimentos_entries[idx][0].get().strip()

        nivel = self.pavimentos_entries[idx][1].get().strip()

        

        # Verificar se AMBOS os campos estão preenchidos

        if not (pavimento_nome and nivel):

            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Preencha AMBOS os campos (pavimento e nível) antes de criar!")

            return

        

        # Verificar se já existe um pilar com o mesmo número no pavimento de destino

        numero_pilar_atual = self.excel_column.get().strip()

        print(f"🔍 DEBUG - Verificando conflito:")

        print(f"   - Obra atual: '{obra_atual}'")

        print(f"   - Pavimento destino: '{pavimento_nome}'")

        print(f"   - Número do pilar: '{numero_pilar_atual}'")

        

        # Verificar se o pavimento de destino existe

        print(f"   - Estrutura obras: {list(self.obras.keys()) if self.obras else 'VAZIA'}")

        if obra_atual in self.obras:

            print(f"   - Pavimentos na obra '{obra_atual}': {list(self.obras[obra_atual].keys())}")

        else:

            print(f"   - Obra '{obra_atual}' não existe")

        

        pavimento_existe = (obra_atual in self.obras and 

                           pavimento_nome in self.obras[obra_atual])

        

        print(f"   - Pavimento destino existe: {pavimento_existe}")

        

        if pavimento_existe:

            # Se o pavimento existe, verificar se o número já existe dentro dele

            pilares_no_pavimento = self.obras[obra_atual][pavimento_nome]

            print(f"   - Pilares no pavimento destino: {list(pilares_no_pavimento.keys())}")

            print(f"   - Tipo do número pilar: {type(numero_pilar_atual)}")

            print(f"   - Número pilar como string: '{numero_pilar_atual}'")

            

            # Verificar se existe como string

            pilar_existe_str = numero_pilar_atual in pilares_no_pavimento

            # Verificar se existe como int (caso seja número)

            pilar_existe_int = False

            try:

                numero_int = int(numero_pilar_atual)

                pilar_existe_int = numero_int in pilares_no_pavimento

            except:

                pass

            

            pilar_existe = pilar_existe_str or pilar_existe_int

            

            print(f"   - Pilar existe como string: {pilar_existe_str}")


            print(f"   - Pilar existe no pavimento destino: {pilar_existe}")

            

            if pilar_existe:

                pass

                from tkinter import messagebox

                resposta = messagebox.askyesno("Pilar Existente", 

                    f"Já existe um pilar com número '{numero_pilar_atual}' no pavimento '{pavimento_nome}' da obra '{obra_atual}'. Deseja sobrescrever?")

                if not resposta:

                    return

            else:

                pass

        else:

            print(f"✅ SEM CONFLITO - Pavimento destino não existe, criando novo")

        

        # Primeiro, fazer o mesmo que set_pavimento_from_lista

        self.set_pavimento_from_lista(idx)

        

        # Depois, salvar o pilar automaticamente no novo pavimento

        try:

            # Garantir que a obra existe

            if obra_atual not in self.obras:

                self.obras[obra_atual] = {}

            

            # Garantir que o pavimento existe

            if pavimento_nome not in self.obras[obra_atual]:

                self.obras[obra_atual][pavimento_nome] = {}

            

            # Salvar o pilar (pular verificação de conflito pois já verificamos)

            self.salvar_pilar(mostrar_mensagem=False, skip_conflict_check=True)

            

            # Atualizar apenas o combobox de pavimentos sem limpar campos
            self._atualizar_combobox_pavimentos_apenas()
            

            print(f"✅ Cópia criada para pavimento '{pavimento_nome}' na obra '{obra_atual}'")

        except Exception as e:

            print(f"❌ Erro ao criar cópia: {e}")

    def copiar_pavimento_atual(self, idx):
        """
        Copia todos os itens do pavimento selecionado no combobox de pavimento para o pavimento do botão clicado.
        Similar ao botão Criar, mas copia todos os itens do pavimento de origem de uma vez.
        """
        from tkinter import messagebox
        
        # Verificar se uma obra está selecionada
        obra_atual = self.obra_filtro_var.get()
        if not obra_atual:
            messagebox.showwarning("Aviso", "Selecione uma obra antes de copiar pavimento!")
            return
        
        # Verificar se o pavimento de destino está preenchido
        if idx < 1 or idx >= len(self.pavimentos_entries):
            return
        
        pavimento_destino_nome = self.pavimentos_entries[idx][0].get().strip()
        nivel_destino = self.pavimentos_entries[idx][1].get().strip()
        
        # Verificar se AMBOS os campos estão preenchidos
        if not (pavimento_destino_nome and nivel_destino):
            messagebox.showwarning("Aviso", "Preencha AMBOS os campos (pavimento e nível) do pavimento de destino antes de copiar!")
            return
        
        # Obter o pavimento de origem do combobox de pavimento
        pavimento_origem = self.pavimento_filtro_var.get()
        
        # Verificar se o pavimento de origem é válido
        if not pavimento_origem or pavimento_origem == "Todos":
            messagebox.showwarning("Aviso", "Selecione um pavimento específico no filtro (combobox de pavimento) antes de copiar!\n\nO botão C.P.A não funciona quando 'Todos' está selecionado.")
            return
        
        # Verificar se o pavimento de origem existe
        if obra_atual not in self.obras or pavimento_origem not in self.obras[obra_atual]:
            messagebox.showerror("Erro", f"Pavimento de origem '{pavimento_origem}' não encontrado na obra '{obra_atual}'!")
            return
        
        # Obter todos os itens do pavimento de origem
        itens_origem = self.obras[obra_atual][pavimento_origem]
        
        if not itens_origem or len(itens_origem) == 0:
            messagebox.showwarning("Aviso", f"O pavimento de origem '{pavimento_origem}' não possui itens para copiar!")
            return
        
        # Perguntar se deseja copiar
        resposta = messagebox.askyesno(
            "Copiar Pavimento",
            f"Deseja copiar todos os {len(itens_origem)} item(ns) do pavimento '{pavimento_origem}' para o pavimento '{pavimento_destino_nome}'?\n\n"
            f"Se já existirem itens com o mesmo nome no pavimento destino, será perguntado se deseja sobrescrever."
        )
        
        if not resposta:
            return
        
        # Garantir que o pavimento de destino existe
        if obra_atual not in self.obras:
            self.obras[obra_atual] = {}
        
        if pavimento_destino_nome not in self.obras[obra_atual]:
            self.obras[obra_atual][pavimento_destino_nome] = {}
        
        # Contadores para relatório
        itens_copiados = 0
        itens_sobrescritos = 0
        itens_pulados = 0
        itens_com_erro = 0
        
        # Copiar cada item do pavimento de origem para o pavimento de destino
        # Usar a mesma lógica de criar_pavimento_from_lista, mas adaptada para copiar todos os itens
        import copy
        import hashlib
        
        # Obter número do pavimento de destino
        nivel_destino_num = self._obter_numero_pavimento_por_nome(pavimento_destino_nome)
        
        for item_id, item_dados in itens_origem.items():
            try:
                # Obter o número/nome do item - verificar tanto "numero" quanto "nome" nos dados
                numero_item = None
                dados_item = None
                
                if isinstance(item_dados, dict) and "dados" in item_dados:
                    dados_item = item_dados["dados"]
                    # Priorizar "numero", depois "nome", depois item_id
                    numero_item = dados_item.get("numero") or dados_item.get("nome") or str(item_id)
                elif isinstance(item_dados, dict):
                    dados_item = item_dados
                    numero_item = item_dados.get("numero") or item_dados.get("nome") or str(item_id)
                else:
                    numero_item = str(item_id)
                    dados_item = {}
                
                # Garantir que numero_item é string para consistência
                numero_item = str(numero_item).strip()
                
                # Verificar se já existe item com mesmo número/nome no pavimento de destino
                pavimento_destino_itens = self.obras[obra_atual][pavimento_destino_nome]
                
                # Verificar se existe item com mesmo número/nome (não apenas pelo item_id)
                item_existe = False
                item_id_existente = None
                
                # Primeiro verificar se existe diretamente pelo número_item (string ou int)
                if numero_item in pavimento_destino_itens:
                    item_existe = True
                    item_id_existente = numero_item
                else:
                    try:
                        numero_int = int(numero_item)
                        if numero_int in pavimento_destino_itens:
                            item_existe = True
                            item_id_existente = numero_int
                    except:
                        pass
                
                # Se não encontrou pelo número direto, verificar todos os itens pelo nome dentro dos dados
                if not item_existe:
                    for dest_item_id, dest_item_dados in pavimento_destino_itens.items():
                        # Obter o nome do item de destino
                        dest_nome = None
                        if isinstance(dest_item_dados, dict) and "dados" in dest_item_dados:
                            dest_dados = dest_item_dados["dados"]
                            dest_nome = dest_dados.get("numero") or dest_dados.get("nome") or str(dest_item_id)
                        elif isinstance(dest_item_dados, dict):
                            dest_nome = dest_item_dados.get("numero") or dest_item_dados.get("nome") or str(dest_item_id)
                        else:
                            dest_nome = str(dest_item_id)
                        
                        # Comparar nomes (string ou int)
                        if str(dest_nome).strip() == numero_item:
                            item_existe = True
                            item_id_existente = dest_item_id
                            break
                        try:
                            if int(dest_nome) == int(numero_item):
                                item_existe = True
                                item_id_existente = dest_item_id
                                break
                        except:
                            pass
                
                # Se já existe, perguntar se deseja sobrescrever
                if item_existe:
                    resposta_sobrescrever = messagebox.askyesno(
                        "Item Existente",
                        f"Já existe um item com número/nome '{numero_item}' no pavimento '{pavimento_destino_nome}'.\n\n"
                        f"Deseja sobrescrever?"
                    )
                    
                    if not resposta_sobrescrever:
                        print(f"⏭️ Item '{numero_item}' pulado (usuário escolheu não sobrescrever)")
                        itens_pulados += 1
                        continue
                    
                    # Remover item existente antes de copiar
                    if item_id_existente is not None and item_id_existente in pavimento_destino_itens:
                        del pavimento_destino_itens[item_id_existente]
                    
                    itens_sobrescritos += 1
                
                # Criar cópia profunda do item com TODOS os dados
                item_dados_copia = copy.deepcopy(item_dados)
                
                # Atualizar TODOS os campos relacionados ao pavimento nos dados
                if isinstance(item_dados_copia, dict):
                    if "dados" in item_dados_copia:
                        # Atualizar pavimento e pavimento_numero nos dados
                        item_dados_copia["dados"]["pavimento"] = pavimento_destino_nome
                        if nivel_destino_num is not None:
                            item_dados_copia["dados"]["pavimento_numero"] = nivel_destino_num
                        # Garantir que obra está correta
                        item_dados_copia["dados"]["obra"] = obra_atual
                    else:
                        # Estrutura antiga sem "dados"
                        item_dados_copia["pavimento"] = pavimento_destino_nome
                        if nivel_destino_num is not None:
                            item_dados_copia["pavimento_numero"] = nivel_destino_num
                        item_dados_copia["obra"] = obra_atual
                
                # Atualizar identificadores únicos se existirem
                if isinstance(item_dados_copia, dict) and "dados" in item_dados_copia:
                    dados_copia = item_dados_copia["dados"]
                    nome_pilar = dados_copia.get("nome", numero_item)
                    
                    # Criar novo identificador_base: Numero-Nome-Pavimento-Obra
                    identificador_base = f"{numero_item}-{nome_pilar}-{pavimento_destino_nome}-{obra_atual}"
                    
                    # Criar novo id_unico_completo: Numero-Nome-Pavimento-Obra-Hash
                    hash_str = hashlib.md5(identificador_base.encode()).hexdigest()[:8]
                    id_unico_completo = f"{identificador_base}-{hash_str}"
                    
                    # Atualizar os identificadores
                    item_dados_copia["identificador_base"] = identificador_base
                    item_dados_copia["id_unico_completo"] = id_unico_completo
                    item_dados_copia["item_id"] = numero_item
                
                # Salvar o item no pavimento de destino usando numero_item como chave
                # Isso garante que cada item é salvo separadamente com sua própria chave
                pavimento_destino_itens[numero_item] = item_dados_copia
                
                # CRÍTICO: Atualizar pilares_salvos usando helpers para garantir chaves únicas corretas
                if hasattr(self, 'pilares_salvos'):
                    # Tentar obter da origem usando helper
                    _, pilar_origem = self._get_pilar_salvo_entry(numero_item, pavimento_origem, obra_atual, allow_partial=True)
                    
                    if pilar_origem:
                        # Copiar da origem
                        pilar_salvo_copia = copy.deepcopy(pilar_origem)
                        if isinstance(pilar_salvo_copia, dict):
                            pilar_salvo_copia["pavimento"] = pavimento_destino_nome
                            pilar_salvo_copia["obra"] = obra_atual
                            if "dados" in pilar_salvo_copia:
                                pilar_salvo_copia["dados"]["pavimento"] = pavimento_destino_nome
                                if nivel_destino_num is not None:
                                    pilar_salvo_copia["dados"]["pavimento_numero"] = nivel_destino_num
                                pilar_salvo_copia["dados"]["obra"] = obra_atual
                        
                        # Salvar com helper usando chave única
                        self._set_pilar_salvo_entry(numero_item, pavimento_destino_nome, obra_atual, pilar_salvo_copia)
                    else:
                        # Se não existe na origem, criar novo baseado nos dados copiados
                        if isinstance(item_dados_copia, dict) and "dados" in item_dados_copia:
                            novo_pilar_salvo = {
                                "dados": copy.deepcopy(item_dados_copia["dados"]),
                                "item_id": numero_item,
                                "locks": item_dados_copia.get("locks", {}),
                                "obra": obra_atual,
                                "pavimento": pavimento_destino_nome
                            }
                            # Salvar com helper usando chave única
                            self._set_pilar_salvo_entry(numero_item, pavimento_destino_nome, obra_atual, novo_pilar_salvo)
                
                itens_copiados += 1
                print(f"✅ Item '{numero_item}' copiado completamente para pavimento '{pavimento_destino_nome}' (chave: {numero_item})")
                
            except Exception as e:
                print(f"❌ Erro ao copiar item '{item_id}': {e}")
                import traceback
                traceback.print_exc()
                itens_com_erro += 1
        
        # Salvar alterações
        self.salvar_obras()
        
        # Atualizar interface
        self._atualizar_combobox_pavimentos_apenas()
        self.atualizar_lista()
        
        # Mostrar relatório
        mensagem_relatorio = (
            f"Operação concluída!\n\n"
            f"✅ Itens copiados: {itens_copiados}\n"
            f"🔄 Itens sobrescritos: {itens_sobrescritos}\n"
            f"⏭️ Itens pulados: {itens_pulados}\n"
        )
        
        if itens_com_erro > 0:
            mensagem_relatorio += f"❌ Itens com erro: {itens_com_erro}\n"
        
        messagebox.showinfo("Cópia Concluída", mensagem_relatorio)
        
        print(f"✅ Cópia de pavimento concluída: {itens_copiados} itens copiados de '{pavimento_origem}' para '{pavimento_destino_nome}'")

    def criar_todos_pavimentos(self):

        """Cria cópias para todos os pavimentos que estiverem preenchidos"""

        # Verificar se uma obra está selecionada

        obra_atual = self.obra_filtro_var.get()

        if not obra_atual:
            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Selecione uma obra antes de criar pavimentos!")

            return

        

        print("🔄 Iniciando criação de todos os pavimentos...")

        criados = 0

        erros = 0

        

        for i in range(1, len(self.pavimentos_entries)):  # Começar do 1 para excluir pavimento 0
            # Verificar se AMBOS os campos estão preenchidos

            pavimento = self.pavimentos_entries[i][0].get().strip()

            nivel = self.pavimentos_entries[i][1].get().strip()

            if pavimento and nivel:  # Se AMBOS os campos estão preenchidos

                try:

                    print(f"📋 Criando cópia para pavimento {i}: {pavimento}")

                    self.criar_pavimento_from_lista(i)

                    criados += 1

                except Exception as e:

                    print(f"❌ Erro ao criar pavimento {i}: {e}")

                    erros += 1

        

        print(f"✅ Criação concluída: {criados} pavimentos criados, {erros} erros")

    

    def criar_pavimentos_todos_itens(self):

        """Cria pavimentos para todos os itens da lista atual"""

        # Verificar se uma obra está selecionada

        obra_atual = self.obra_filtro_var.get()

        if not obra_atual:
            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Selecione uma obra antes de criar pavimentos!")

            return

        

        # Verificar se há pavimentos preenchidos (AMBOS os campos, excluindo pavimento 0)
        pavimentos_preenchidos = []

        for i in range(1, len(self.pavimentos_entries)):  # Começar do 1 para excluir pavimento 0
            pavimento = self.pavimentos_entries[i][0].get().strip()

            nivel = self.pavimentos_entries[i][1].get().strip()

            if pavimento and nivel:  # AMBOS os campos preenchidos

                pavimentos_preenchidos.append((i, pavimento))

        

        if not pavimentos_preenchidos:

            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Preencha pelo menos um pavimento antes de criar!")

            return

        

        # Obter todos os itens da lista atual

        itens_lista = []

        for item in self.lista_pilares.get_children():

            item_data = self.lista_pilares.item(item)

            numero = item_data['values'][0]

            itens_lista.append(numero)

        

        if not itens_lista:

            from tkinter import messagebox

            messagebox.showwarning("Aviso", "Nenhum item encontrado na lista atual!")

            return

        

        print(f"🔄 Iniciando criação de pavimentos para {len(itens_lista)} itens...")

        print(f"📋 Pavimentos a criar: {[p[1] for p in pavimentos_preenchidos]}")

        

        total_criados = 0

        total_erros = 0

        itens_processados = 0

        

        # Processar cada item da lista

        for numero_item in itens_lista:

            itens_processados += 1

            print(f"\n📌 Processando item {itens_processados}/{len(itens_lista)}: {numero_item}")

            

            # Selecionar o item na lista

            try:

                # Encontrar o item na lista

                item_encontrado = None

                for item in self.lista_pilares.get_children():

                    item_data = self.lista_pilares.item(item)

                    if item_data['values'][0] == numero_item:

                        item_encontrado = item

                        break

                

                if not item_encontrado:

                    print(f"❌ Item {numero_item} não encontrado na lista")

                    total_erros += 1

                    continue

                

                # Selecionar o item

                self.lista_pilares.selection_set(item_encontrado)

                self.lista_pilares.focus(item_encontrado)

                

                # Carregar os dados do item

                self.carregar_item_selecionado(None)

                

                # Criar pavimentos para este item

                criados_item = 0

                erros_item = 0

                

                for idx, pavimento_nome in pavimentos_preenchidos:

                    try:

                        print(f"  📋 Criando pavimento: {pavimento_nome}")

                        

                        # Verificar conflito

                        numero_pilar_atual = self.excel_column.get().strip()

                        pavimento_existe = (obra_atual in self.obras and 

                                          pavimento_nome in self.obras[obra_atual])

                        

                        if pavimento_existe:

                            pilar_existe = numero_pilar_atual in self.obras[obra_atual][pavimento_nome]

                            if pilar_existe:

                                print(f"  ⚠️ Conflito detectado - pulando pavimento {pavimento_nome}")

                                erros_item += 1

                                continue

                        

                        # Preencher campos (set_pavimento_from_lista)

                        self.set_pavimento_from_lista(idx)

                        

                        # Salvar pilar

                        self.salvar_pilar(mostrar_mensagem=False, skip_conflict_check=True)

                        

                        # Atualizar lista de pavimentos

                        self.atualizar_pavimentos_por_obra()

                        

                        criados_item += 1

                        print(f"  ✅ Pavimento {pavimento_nome} criado com sucesso")

                        

                    except Exception as e:

                        pass

                        erros_item += 1

                

                total_criados += criados_item

                total_erros += erros_item

                print(f"  📊 Item {numero_item}: {criados_item} criados, {erros_item} erros")

                

            except Exception as e:

                print(f"❌ Erro ao processar item {numero_item}: {e}")

                total_erros += 1

        

        print(f"\n✅ Processamento concluído:")

        print(f"   - Itens processados: {itens_processados}")

        print(f"   - Total de pavimentos criados: {total_criados}")


        

        # Mostrar resumo final

        if total_erros > 0:

            from tkinter import messagebox

            messagebox.showinfo("Processamento Concluído", 

                f"Processamento concluído!\n\n"

                f"Itens processados: {itens_processados}\n"

                f"Pavimentos criados: {total_criados}\n"

                f"Erros: {total_erros}\n\n"

                f"Verifique os logs para detalhes dos erros.")

    

    def salvar_pavimentos_lista(self):

        self.pavimentos_lista = [[e[0].get(), e[1].get()] for e in self.pavimentos_entries]

        import os, pickle

        caminho_arquivo = self.obter_caminho_dados("pavimentos_lista.pkl")

        try:

            with open(caminho_arquivo, 'wb') as f:

                pickle.dump(self.pavimentos_lista, f)

        except Exception as e:

            pass

    def carregar_pavimentos_lista(self):

        # Tenta carregar do arquivo, se existir

        import os, pickle

        caminho_arquivo = self.obter_caminho_dados("pavimentos_lista.pkl")

        if os.path.exists(caminho_arquivo):

            try:

                with open(caminho_arquivo, 'rb') as f:

                    self.pavimentos_lista = pickle.load(f)

            except:

                pass

        # Preenche os campos

        for i, (pav, niv) in enumerate(self.pavimentos_lista):

            if i < len(self.pavimentos_entries):

                self.pavimentos_entries[i][0].delete(0, tk.END)

                self.pavimentos_entries[i][0].insert(0, pav)

                self.pavimentos_entries[i][1].delete(0, tk.END)

                self.pavimentos_entries[i][1].insert(0, niv)



    def selecionar_niveis_autocad(self):

        ac = load_ac_functions()

        for i in range(10):

            try:

                import pythoncom, win32com.client, win32gui

                pythoncom.CoInitialize()

                app = win32com.client.Dispatch("AutoCAD.Application")

                app.Visible = True

                try:

                    acad_window = win32gui.FindWindow(None, app.Caption)

                    if acad_window:

                        win32gui.SetForegroundWindow(acad_window)

                        win32gui.ShowWindow(acad_window, 5)

                except:

                    pass

                self.iconify()

                info_label = tk.Label(self, text=f"Selecione o texto do nível para a linha {i+1} e pressione Enter", font=("Arial", 10, "bold"), fg="blue", bg="light yellow")

                info_label.place(relx=0.5, rely=0.1, anchor="center")

                self.update()

                selection = ac.get_autocad_selection(f"Selecione o texto do nível para a linha {i+1} e pressione Enter")

                info_label.destroy()

                valor = "0"

                if selection and len(selection) > 0:

                    textos = ac.get_text_objects(selection)

                    if textos and textos[0].get("text"):

                        valor_texto = textos[0]["text"]

                        valor = re.sub(r'[^.,-]', '', valor_texto)

                        if not valor:

                            valor = "0"

                self.pavimentos_entries[i][1].delete(0, tk.END)

                self.pavimentos_entries[i][1].insert(0, valor)

                self.update()

                self.deiconify()

                self.lift()

                self.focus_force()

                try:

                    # Seleção já foi limpa internamente pela função get_autocad_selection
                    pass

                except:

                    pass

                pythoncom.CoUninitialize()

            except Exception as e:

                self.pavimentos_entries[i][1].delete(0, tk.END)

                self.pavimentos_entries[i][1].insert(0, "0")

                self.deiconify()

                self.lift()

                self.focus_force()

                continue

        self.salvar_pavimentos_lista()

