    def _calcular_area_pilar(self, dados_pilar=None):

        """

        Calcula a área de um pilar específico usando o m² total da visão ABCD (soma de todos os painéis).

        

        Args:

            dados_pilar: Dicionário com dados do pilar. Se None, usa o item selecionado.

            

        Returns:

            tuple: (sucesso: bool, area: float, mensagem: str)

        """

        try:

            # Se não foram fornecidos dados, obter do item selecionado

            if dados_pilar is None:

                if not hasattr(self, 'conector_painel'):

                    return False, 0.0, "Conector não disponível"

                

                # Verificar se conector existe e não é None
                if not hasattr(self, 'conector_painel') or self.conector_painel is None:
                    return False, 0.0, "Conector não disponível"
                numero, dados_pilar = self.conector_painel.get_item_selecionado()

                if not dados_pilar:

                    return False, 0.0, "Nenhum item selecionado"

            

            # Usar o método obter_m2_salvo que calcula corretamente o m² total da visão ABCD

            area_m2 = self.obter_m2_salvo(dados_pilar)

            

            # Validar se a área é válida

            if area_m2 <= 0:

                return False, 0.0, f"Área inválida calculada: {area_m2:.4f} m²"

            

            nome_pilar = dados_pilar.get('nome', 'N/A')

            pavimento = dados_pilar.get('pavimento', 'N/A')

            comprimento = dados_pilar.get('comprimento', 'N/A')

            largura = dados_pilar.get('largura', 'N/A')

            

            print(f">>> Área total calculada para pilar '{nome_pilar}' (Pavimento {pavimento}): {area_m2:.4f} m²")



            

            return True, area_m2, f"Área total calculada: {area_m2:.4f} m²"

            

        except Exception as e:

            import traceback

            traceback.print_exc()

            return False, 0.0, f"Erro ao calcular área do pilar: {str(e)}"



    def _calcular_area_pavimento(self, pavimento=None):

        """

        Calcula a área total de todos os pilares de um pavimento específico.

        

        Args:

            pavimento: Nome do pavimento. Se None, usa o pavimento do item selecionado.

            

        Returns:

            tuple: (sucesso: bool, area_total: float, detalhes: dict, mensagem: str)

        """

        try:

            # Se não foi fornecido pavimento, obter do item selecionado

            if pavimento is None:

                if not hasattr(self, 'conector_painel'):

                    return False, 0.0, {}, "Conector não disponível"

                

                # Verificar se conector existe e não é None
                if not hasattr(self, 'conector_painel') or self.conector_painel is None:
                    return False, 0.0, {}, "Conector não disponível"
                numero, dados_item = self.conector_painel.get_item_selecionado()

                if not dados_item:

                    return False, 0.0, {}, "Nenhum item selecionado"

                

                pavimento = dados_item.get('pavimento', '')

            

            if not pavimento or pavimento == "Todos":

                return False, 0.0, {}, "Pavimento inválido ou não especificado"

            

            # Obter todos os pilares do pavimento

            pilares_pavimento = []

            area_total = 0.0

            detalhes = {

                'pavimento': pavimento,

                'pilares': [],

                'total_pilares': 0,

                'area_total': 0.0

            }

            

            # Iterar sobre todos os pilares salvos

            for numero, item_dados in self.pilares_salvos.items():

                dados_pilar = item_dados.get('dados', {})

                pav_pilar = str(dados_pilar.get('pavimento', '')).strip()

                

                # Verificar se o pilar pertence ao pavimento desejado

                if pav_pilar == pavimento:

                    # Calcular área do pilar

                    sucesso, area_pilar, mensagem = self._calcular_area_pilar(dados_pilar)

                    

                    if sucesso:

                        area_total += area_pilar

                        nome_pilar = dados_pilar.get('nome', numero)

                        

                        detalhes['pilares'].append({

                            'numero': numero,

                            'nome': nome_pilar,

                            'area': area_pilar,

                            'comprimento': dados_pilar.get('comprimento', ''),

                            'largura': dados_pilar.get('largura', '')

                        })

                        

                        pilares_pavimento.append(f"{nome_pilar}: {area_pilar:.4f} m²")

                    else:

                        print(f">>> Erro ao calcular área do pilar {numero}: {mensagem}")

                        # Continuar com outros pilares mesmo se um falhar

            

            detalhes['total_pilares'] = len(detalhes['pilares'])

            detalhes['area_total'] = area_total

            

            if detalhes['total_pilares'] == 0:

                return False, 0.0, detalhes, f"Nenhum pilar encontrado no pavimento '{pavimento}'"

            

            print(f">>> Área total calculada para pavimento '{pavimento}': {area_total:.4f} m²")


            for pilar_info in pilares_pavimento:

                print(f">>>   - {pilar_info}")

            

            mensagem = f"Pavimento '{pavimento}': {area_total:.4f} m² ({detalhes['total_pilares']} pilares)"

            return True, area_total, detalhes, mensagem

            

        except Exception as e:

            import traceback

            traceback.print_exc()

            return False, 0.0, {}, f"Erro ao calcular área do pavimento: {str(e)}"



    def atualizar_creditos_interface(self):

        """

        Atualiza a exibição de créditos na interface da lista.

        Consulta o saldo atual e exibe na interface.

        """

        try:
            # CRÍTICO: Verificar se label_creditos existe antes de acessar
            if not hasattr(self, 'label_creditos') or self.label_creditos is None:
                # Interface ainda não foi criada, aguardar
                return

            # Verificar se o sistema de créditos está disponível

            credit_manager = getattr(self, 'credit_manager', None)
            
            # Se não estiver disponível como atributo, tentar obter do módulo global
            if credit_manager is None:
                try:
                    # Tentar obter do módulo global credit_system
                    try:
                        from core.credit_system import obter_gerenciador_creditos
                    except ImportError:
                        try:
                            from src.core.credit_system import obter_gerenciador_creditos
                        except ImportError:
                            try:
                                import credit_system  # type: ignore[reportMissingImports]
                                obter_gerenciador_creditos = credit_system.obter_gerenciador_creditos
                            except ImportError:
                                obter_gerenciador_creditos = None
                    
                    if obter_gerenciador_creditos:
                        credit_manager = obter_gerenciador_creditos()
                        # Se obtido do módulo global, salvar como atributo para próximas chamadas
                        if credit_manager:
                            self.credit_manager = credit_manager
                except Exception as e:
                    print(_get_obf_str("credit"))
            
            if credit_manager is None:
                # Sistema de créditos não disponível
                if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                    self.label_creditos.config(
                        text="💳 Créditos: Sistema não ativo",
                        foreground="gray"
                    )
                return

            

            # Consultar saldo de créditos (usar cache se disponível)

            try:

                sucesso, saldo = credit_manager.consultar_saldo()

                if sucesso:

                    # Exibir saldo com cor baseada na quantidade

                    if saldo >= 100:

                        cor = "green"

                        status = "Alto"

                    elif saldo >= 10:

                        cor = "blue"

                        status = "Médio"

                    elif saldo >= 1:

                        cor = "orange"

                        status = "Baixo"

                    else:

                        cor = "red"

                        status = "Crítico"

                    

                    if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                        self.label_creditos.config(

                            text=_get_obf_str("saldo"),

                            foreground=cor

                        )

                    

                    print(_get_obf_str("saldo"))

                else:

                    # Erro ao consultar saldo online, tentar offline

                    try:

                        sucesso_offline, saldo_offline = credit_manager.consultar_saldo_offline_first()

                        if sucesso_offline:

                            if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                                self.label_creditos.config(

                                    text=_get_obf_str("saldo"),

                                    foreground="purple"

                                )

                        else:

                            if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                                self.label_creditos.config(

                                    text="💳 Créditos: Erro ao consultar",

                                    foreground="red"

                                )

                    except:

                        if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                            self.label_creditos.config(

                                text="💳 Créditos: Erro ao consultar",

                                foreground="red"

                            )

                        

            except Exception as e:

                print(_get_obf_str("saldo"))

                if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                    self.label_creditos.config(

                        text="💳 Créditos: Erro de conexão",

                        foreground="red"

                    )

                

        except Exception as e:

            print(f">>> Erro ao atualizar créditos na interface: {str(e)}")

            # Em caso de erro, não quebrar a interface

            try:
                if hasattr(self, 'label_creditos') and self.label_creditos is not None:
                    self.label_creditos.config(

                        text="💳 Créditos: Erro",

                        foreground="red"

                    )

            except:

                pass  # Se até isso falhar, ignorar silenciosamente



    def atualizar_creditos_periodicamente(self):

        """

        Atualiza os créditos periodicamente (a cada 5 minutos).

        Método chamado automaticamente em background.

        """

        try:

            self.atualizar_creditos_interface()

            # Reagendar para 5 minutos (300000 ms)

            self.after(300000, self.atualizar_creditos_periodicamente)

        except Exception as e:

            print(f">>> Erro na atualização periódica de créditos: {str(e)}")

            # Reagendar mesmo em caso de erro

            self.after(300000, self.atualizar_creditos_periodicamente)



