        # Vincular eventos de alteração aos campos de comprimento e largura para cálculo automático

        def calcular_pilar_especial_unificado(event=None):

            """Função unificada para evitar duplicações nos cálculos especiais"""

            print(f"[FUNCAO-UNIFICADA] ========================================")
            print(f"[FUNCAO-UNIFICADA] Função chamada! Event: {event}")
            print(f"[FUNCAO-UNIFICADA] Widget: {event.widget if event and hasattr(event, 'widget') else 'N/A'}")
            
            # Prevenir loops infinitos - bloquear sincronização durante cálculo
            if getattr(self, '_calculando_campos_especiais', False):
                print(f"[FUNCAO-UNIFICADA] ⚠️ Já está calculando campos especiais, ignorando chamada duplicada")
                return
            
            # Marcar que está calculando campos especiais
            self._calculando_campos_especiais = True
            
            try:
                try:
                    ativar = self.ativar_pilar_especial.get()
                    print(f"[FUNCAO-UNIFICADA] Ativar pilar especial: {ativar}")
                except Exception as e:
                    print(f"[FUNCAO-UNIFICADA] Erro ao verificar ativar_pilar_especial: {e}")
                    return

                if self.ativar_pilar_especial.get():
                    try:
                        tipo_pilar = self.tipo_pilar_especial.get()
                        print(f"[FUNCAO-UNIFICADA] Tipo pilar: {tipo_pilar}")
                    except Exception as e:
                        print(f"[FUNCAO-UNIFICADA] Erro ao obter tipo_pilar: {e}")
                        return

                    if tipo_pilar in ["L", "T", "U"]:

                        # Identificar qual campo foi alterado
                        campo_alterado = "desconhecido"
                        
                        # Tentar identificar pelo widget do evento
                        if event and hasattr(event, 'widget'):
                            widget = event.widget
                            if widget == self.comp_1:
                                campo_alterado = "comprimento 1"
                            elif widget == self.comp_2:
                                campo_alterado = "comprimento 2"
                            elif widget == self.comp_3:
                                campo_alterado = "comprimento 3"
                            elif widget == self.larg_1:
                                campo_alterado = "largura 1"
                            elif widget == self.larg_2:
                                campo_alterado = "largura 2"
                            elif widget == self.larg_3:
                                campo_alterado = "largura 3"
                            elif widget == self.distancia:
                                campo_alterado = "distância"
                        
                        # Se não identificou pelo widget, tentar identificar pelo foco atual
                        if campo_alterado == "desconhecido":
                            try:
                                widget_focado = self.focus_get()
                                if widget_focado == self.comp_1:
                                    campo_alterado = "comprimento 1"
                                elif widget_focado == self.comp_2:
                                    campo_alterado = "comprimento 2"
                                elif widget_focado == self.comp_3:
                                    campo_alterado = "comprimento 3"
                                elif widget_focado == self.larg_1:
                                    campo_alterado = "largura 1"
                                elif widget_focado == self.larg_2:
                                    campo_alterado = "largura 2"
                                elif widget_focado == self.larg_3:
                                    campo_alterado = "largura 3"
                                elif widget_focado == self.distancia:
                                    campo_alterado = "distância"
                            except:
                                pass
                        
                        # Se ainda não identificou, assumir que é um dos 4 campos principais
                        if campo_alterado == "desconhecido":
                            # Verificar qual campo tem valor recentemente alterado (heurística)
                            # Por padrão, executar sequência completa para garantir
                            campo_alterado = "comprimento 1"  # Default seguro

                    

                    print(f"[RECALCULO-AUTO] ========================================")

                    print(f"[RECALCULO-AUTO] Alteração detectada no campo: {campo_alterado}")

                    print(f"[RECALCULO-AUTO] Iniciando recálculo automático para pilar tipo {tipo_pilar}")

                    print(f"[RECALCULO-AUTO] ========================================")

                    

                    # DEBUG: Verificar se campo_alterado está correto






                    

                    # Chamar calcular_dimensoes_painel() que é a mesma função chamada quando clica nos RoundButtons NOVA/INI
                    # Esta função verifica se pilar especial está ativo e chama calcular_todas_grades_especiais_automatico()
                    # que por sua vez executa a sequência completa de bindings
                    print("[RECALCULO-AUTO] Chamando calcular_dimensoes_painel() (mesma função dos RoundButtons)...")
                    try:
                        self.calcular_dimensoes_painel(event)
                        print("[RECALCULO-AUTO] ✅ calcular_dimensoes_painel() executado com sucesso")
                        # Ajustes já são aplicados dentro de calcular_todas_grades_especiais_automatico()
                    except Exception as e:
                        print(f"[RECALCULO-AUTO] ❌ Erro ao chamar calcular_dimensoes_painel(): {e}")
                        import traceback
                        traceback.print_exc()
                        
                        # Fallback: chamar diretamente calcular_todas_grades_especiais_automatico()
                        print("[RECALCULO-AUTO] Tentando fallback: calcular_todas_grades_especiais_automatico()...")
                        try:
                            self.calcular_todas_grades_especiais_automatico()
                            print("[RECALCULO-AUTO] ✅ Fallback executado com sucesso")
                            # Ajustes já são aplicados dentro de calcular_todas_grades_especiais_automatico()
                        except Exception as e2:
                            print(f"[RECALCULO-AUTO] ❌ Erro no fallback: {e2}")
                            import traceback
                            traceback.print_exc()
                    else:
                        print(f"[FUNCAO-UNIFICADA] ⚠️ Tipo pilar '{tipo_pilar}' não está em ['L', 'T', 'U']")
                else:
                    print(f"[FUNCAO-UNIFICADA] ⚠️ Pilar especial não está ativado")
            finally:
                # Liberar flag de cálculo de campos especiais
                self._calculando_campos_especiais = False
            
            print(f"[FUNCAO-UNIFICADA] ========================================")

        # Vincular apenas os 4 campos específicos que afetam todas as grades
        # MUDADO de KeyRelease para FocusOut para melhorar performance durante digitação
        print("[BINDINGS] ========================================")
        print("[BINDINGS] Configurando bindings FocusOut para comp_1, comp_2, larg_1, larg_2")
        print("[BINDINGS] ========================================")
        
        # Flag para evitar execuções simultâneas
        if not hasattr(self, '_calculando_especial_focusout'):
            self._calculando_especial_focusout = False
        
        # Timer para debounce (evitar múltiplas execuções rápidas)
        if not hasattr(self, '_timer_focusout_especial'):
            self._timer_focusout_especial = None
        
        def wrapper_focusout(event):
            """Wrapper para garantir que a função seja chamada - mesma sequência dos RoundButtons NOVA/INI"""
            # Verificar se já está calculando para evitar execuções simultâneas
            if self._calculando_especial_focusout:
                return  # Silenciar log para performance
            
            # Cancelar timer anterior se existir (debounce)
            if self._timer_focusout_especial:
                try:
                    root = event.widget.winfo_toplevel()
                    if root:
                        root.after_cancel(self._timer_focusout_especial)
                except:
                    pass
                self._timer_focusout_especial = None
            
            # Removido logs excessivos para melhorar performance
            
            # Usar debounce: agendar execução após pequeno delay para evitar múltiplas execuções
            def executar_calculo():
                # Verificar novamente se já está calculando (double-check)
                if self._calculando_especial_focusout:
                    return
                
                # Marcar como calculando
                self._calculando_especial_focusout = True
                
                try:
                    # Chamar calcular_dimensoes_painel() que já atualiza tudo necessário
                    # Esta função já verifica se pilar especial está ativo e chama as funções apropriadas:
                    # - calcular_todas_grades_especiais_automatico() para tipos L, T, U (que já atualiza larguras/alturas)
                    # - calcular_pilar_especial_automatico(event) para outros tipos
                    # - processar_comprimento_com_desvio_conflitos(event) para pilares normais
                    self.calcular_dimensoes_painel()
                    
                    # NOTA: calcular_todas_grades_especiais_automatico() já aplica os ajustes corretamente:
                    # 1. Calcula larguras a partir das grades ORIGINAIS
                    # 2. Aplica ajustes nas larguras
                    # 3. Aplica ajustes nas grades (separadamente)
                    # Não precisa aplicar novamente aqui para evitar duplicação
                except Exception as e:
                    print(f"[BINDINGS] ❌ Erro ao processar FocusOut: {e}")
                finally:
                    # Liberar flag após pequeno delay para evitar race conditions
                    def liberar_flag():
                        self._calculando_especial_focusout = False
                        self._timer_focusout_especial = None
                    
                    root = event.widget.winfo_toplevel()
                    if root:
                        root.after(100, liberar_flag)  # Liberar após 100ms
                    else:
                        self._calculando_especial_focusout = False
            
            # Obter a janela principal usando winfo_toplevel()
            try:
                root = event.widget.winfo_toplevel()
                if root and hasattr(root, 'after'):
                    # Usar debounce: agendar execução após 150ms (evita múltiplas execuções rápidas)
                    self._timer_focusout_especial = root.after(150, executar_calculo)
                else:
                    # Fallback: executar diretamente se não conseguir obter root
                    executar_calculo()
            except Exception as e:
                # Fallback: executar diretamente em caso de erro
                executar_calculo()
        
        # Vincular os 4 campos principais usando add='+' para não remover bindings existentes
        # Verificar se os campos existem antes de vincular
        print("[BINDINGS] Verificando e vinculando campos...")
        
        # Função de teste simples para verificar se o evento está sendo disparado
        def teste_focusout_simples(event):
            # Removido logs excessivos para melhorar performance
            wrapper_focusout(event)
        
        # Função alternativa usando Leave (quando o mouse sai do widget)
        def teste_leave(event):
            # Removido logs para melhorar performance - apenas para debug se necessário
            pass
        
        # Variável para rastrear qual campo tinha foco antes do clique
        self._ultimo_campo_especial_focado = None
        
        # Função para rastrear quando um campo especial recebe foco
        def rastrear_foco_entrada(event):
            """Rastreia quando um campo especial recebe foco"""
            if event.widget in [self.comp_1, self.comp_2, self.larg_1, self.larg_2]:
                self._ultimo_campo_especial_focado = event.widget
                # Removido log para melhorar performance
        
        # Função para verificar e executar cálculo quando clicar fora
        def verificar_e_executar_ao_clicar(event):
            """Verifica se um campo especial tinha foco e executa cálculo ao clicar fora"""
            try:
                # Verificar se algum campo especial tinha foco antes
                if hasattr(self, '_ultimo_campo_especial_focado') and self._ultimo_campo_especial_focado:
                    # Verificar se o clique foi fora do campo que tinha foco
                    widget_clicado = event.widget
                    campo_focado = self._ultimo_campo_especial_focado
                    
                    # Verificar se o widget clicado não é o campo que tinha foco
                    # e também não é um filho do campo (para evitar falsos positivos)
                    try:
                        # Obter o widget que realmente recebeu o clique
                        widget_atual = self.focus_get()
                        
                        # Se o widget atual não é o campo que tinha foco, executar cálculo
                        if widget_atual != campo_focado:
                            # Removido logs para melhorar performance
                            
                            # Usar after_idle para garantir que o FocusOut seja processado primeiro
                            def executar_apos_focusout():
                                try:
                                    # Simular FocusOut
                                    class FakeEvent:
                                        def __init__(self, widget):
                                            self.widget = widget
                                    fake_event = FakeEvent(campo_focado)
                                    wrapper_focusout(fake_event)
                                except Exception as e:
                                    print(f"[CLIQUE-FORA] Erro ao executar wrapper_focusout: {e}")
                            
                            # Agendar execução após o evento de clique ser processado
                            root = self.winfo_toplevel()
                            if root:
                                root.after_idle(executar_apos_focusout)
                            
                            # Limpar rastreamento
                            self._ultimo_campo_especial_focado = None
                    except Exception as e:
                        print(f"[CLIQUE-FORA] Erro ao verificar foco: {e}")
            except Exception as e:
                print(f"[CLIQUE-FORA] Erro geral: {e}")
        
        # Função usando KeyRelease como fallback
        def teste_keyrelease(event):
            # Só executar se Enter ou Tab foram pressionados
            if event.keysym in ['Return', 'Tab']:
                # Removido log para melhorar performance
                # Simular FocusOut chamando diretamente wrapper_focusout para garantir atualização
                class FakeEvent:
                    def __init__(self, widget):
                        self.widget = widget
                fake_event = FakeEvent(event.widget)
                # Chamar wrapper_focusout diretamente para garantir que a atualização seja feita
                wrapper_focusout(fake_event)
        
        # Lista de campos para vincular
        campos_para_vincular = [
            ('comp_1', 'Comprimento 1'),
            ('comp_2', 'Comprimento 2'),
            ('larg_1', 'Largura 1'),
            ('larg_2', 'Largura 2')
        ]
        
        for campo_attr, campo_nome in campos_para_vincular:
            if hasattr(self, campo_attr):
                campo = getattr(self, campo_attr)
                if campo:
                    print(f"[BINDINGS] ✅ {campo_nome} ({campo_attr}) existe: {campo}")
                    print(f"[BINDINGS] Tipo: {type(campo)}")
                    print(f"[BINDINGS] Widget ID: {id(campo)}")
                    
                    # Verificar bindings existentes
                    try:
                        bind_info = campo.bind('<FocusOut>')
                        print(f"[BINDINGS] Bindings FocusOut existentes no widget: {bind_info}")
                    except Exception as e:
                        print(f"[BINDINGS] Não foi possível verificar bindings existentes: {e}")
                    
                    # Tentar múltiplas abordagens
                    binding_sucesso = False
                    
                    # Abordagem 1: FocusOut sem add='+'
                    try:
                        campo.bind('<FocusOut>', teste_focusout_simples)
                        print(f"[BINDINGS] ✅ Binding FocusOut adicionado a {campo_nome} (sem add='+')")
                        binding_sucesso = True
                    except Exception as e:
                        print(f"[BINDINGS] ⚠️ Erro ao vincular {campo_nome} sem add='+': {e}")
                    
                    # Abordagem 2: FocusOut com add='+'
                    if not binding_sucesso:
                        try:
                            campo.bind('<FocusOut>', teste_focusout_simples, add='+')
                            print(f"[BINDINGS] ✅ Binding FocusOut adicionado a {campo_nome} (com add='+')")
                            binding_sucesso = True
                        except Exception as e:
                            print(f"[BINDINGS] ⚠️ Erro ao vincular {campo_nome} com add='+': {e}")
                    
                    # Abordagem 3: KeyRelease como fallback (Enter ou Tab)
                    try:
                        campo.bind('<KeyRelease>', teste_keyrelease, add='+')
                        print(f"[BINDINGS] ✅ Binding KeyRelease adicionado a {campo_nome} (fallback)")
                    except Exception as e:
                        print(f"[BINDINGS] ⚠️ Erro ao vincular KeyRelease em {campo_nome}: {e}")
                    
                    # Abordagem 4: Leave (quando mouse sai do widget) - apenas para debug
                    try:
                        campo.bind('<Leave>', teste_leave, add='+')
                        print(f"[BINDINGS] ✅ Binding Leave adicionado a {campo_nome} (debug)")
                    except Exception as e:
                        print(f"[BINDINGS] ⚠️ Erro ao vincular Leave em {campo_nome}: {e}")
                    
                    # Abordagem 5: FocusIn para rastrear quando campo recebe foco
                    try:
                        campo.bind('<FocusIn>', rastrear_foco_entrada, add='+')
                        print(f"[BINDINGS] ✅ Binding FocusIn adicionado a {campo_nome} (rastreamento)")
                    except Exception as e:
                        print(f"[BINDINGS] ⚠️ Erro ao vincular FocusIn em {campo_nome}: {e}")
                else:
                    print(f"[BINDINGS] ⚠️ {campo_nome} ({campo_attr}) é None")
            else:
                print(f"[BINDINGS] ⚠️ {campo_nome} ({campo_attr}) não existe")
        
        print("[BINDINGS] ========================================")
        print("[BINDINGS] ✅ Bindings FocusOut configurados com sucesso para comp_1, comp_2, larg_1, larg_2")
        print("[BINDINGS] ========================================")
        
        # Adicionar binding de clique na janela principal para detectar cliques fora dos campos
        try:
            # Obter a janela principal
            root = self.winfo_toplevel()
            if root:
                # Binding de Button-1 (clique do mouse) na janela principal
                root.bind('<Button-1>', verificar_e_executar_ao_clicar, add='+')
                print("[BINDINGS] ✅ Binding Button-1 adicionado à janela principal para detectar cliques fora")
        except Exception as e:
            print(f"[BINDINGS] ⚠️ Erro ao adicionar binding de clique na janela: {e}")

        

        # Campos comp_3 e larg_3 não afetam todas as grades, então mantêm função simples
        # NOTA: Estes campos mantêm KeyRelease pois não afetam todas as grades automaticamente
        
        if hasattr(self, 'comp_3') and self.comp_3:
            self.comp_3.bind('<KeyRelease>', calcular_pilar_especial_unificado)
        
        if hasattr(self, 'larg_3') and self.larg_3:
            self.larg_3.bind('<KeyRelease>', calcular_pilar_especial_unificado)

        

        # Distância (apenas para modo T)

        dist_frame = ttk.Frame(dimensoes_frame)

        dist_frame.pack(fill=tk.X, padx=5, pady=5)

        

        ttk.Label(dist_frame, text="Distância:").pack(side=tk.LEFT, padx=(0,10))

        

        self.distancia = ttk.Entry(dist_frame, width=8)

        self.distancia.pack(side=tk.LEFT, padx=2)

        

        # Vincular evento de alteração do campo distância para cálculo automático

        self.distancia.bind('<KeyRelease>', calcular_pilar_especial_unificado)

        

        # --- GRADES ---

        grades_frame = ttk.LabelFrame(scroll_frame, text="Grades")

        grades_frame.pack(fill=tk.X, padx=2, pady=2)

        

        # Criar grades com botões usando função auxiliar

        self.criar_grade_especial_com_botoes(grades_frame, 'A', "Grades A")

        self.criar_grade_especial_com_botoes(grades_frame, 'B', "Grades B")

        self.criar_grade_especial_com_botoes(grades_frame, 'E', "Grades E")

        self.criar_grade_especial_com_botoes(grades_frame, 'F', "Grades F")

        self.criar_grade_especial_com_botoes(grades_frame, 'G', "Grades G")

        self.criar_grade_especial_com_botoes(grades_frame, 'H', "Grades H")



        

        # --- PARAFUSOS ---

        parafusos_frame = ttk.LabelFrame(scroll_frame, text="Parafusos")

        parafusos_frame.pack(fill=tk.X, padx=2, pady=2)

        

