    def atualizar_campos_pilares_especiais(self):

        """Atualiza a visibilidade dos campos baseado no tipo de pilar selecionado"""

        tipo = self.tipo_pilar_especial.get()

        

        # Campos de comprimento

        if tipo in ["L", "T"]:

            # Ativar apenas 2 campos

            self.comp_3.config(state="disabled")

            self.larg_3.config(state="disabled")

        else:  # U

            # Ativar todos os 3 campos

            self.comp_3.config(state="normal")

            self.larg_3.config(state="normal")

        

        # Campo de distância (apenas para modo T)

        if tipo == "T":

            self.distancia.config(state="normal")

        else:

            self.distancia.config(state="disabled")

    

