    def calcular_pilar_especial_automatico(self, event=None):

        """
        Calcula automaticamente os valores dos painéis E e F, grades A, B, E, F
        baseado nas dimensões dos pilares especiais tipo L, T, U.
        
        ⚠️ ATUALIZADO: Agora usa calcular_todas_grades_especiais_automatico() que aplica
        as novas fórmulas definidas pelo usuário:
        - Grade A: comp_1 + 22
        - Grade B: comp_1 - 13.2 + (larg_2 - 20)
        - Grade E: comp_2 + 11 + (larg_1 - 20)
        - Grade F (INI): comp_2 - 27.4
        - Grade F (NOVA): comp_1 - 27.4
        """

        try:

            # Verificar se pilar especial está ativo e é tipo L

            if not self.ativar_pilar_especial.get():

                return

                

            tipo = self.tipo_pilar_especial.get()
            
            # Para tipos L, T, U, usar a função que aplica as novas fórmulas
            if tipo in ["L", "T", "U"]:
                return self.calcular_todas_grades_especiais_automatico()
            else:
                return  # Tipo não suportado

            



            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def calcular_pilar_especial_tipo_L(self):

        """

        Cálculos específicos para pilar especial tipo L

        ⚠️ DEPRECADO PARA GRADES A, B, E, F: Esta função usa fórmulas antigas baseadas em proporções.
        Para grades A, B, E, F, use calcular_grades_especiais_com_regras_completas() que aplica as novas fórmulas.
        Esta função é mantida apenas como fallback para outras grades (ex: G-H) ou compatibilidade.

        """

        try:

            # LIMPEZA COMPLETA ANTES DE CALCULAR


            # CORRIGIDO: Não deve limpar painéis A e B, apenas E e F
            self.limpar_todos_campos_especiais(['e', 'f'])

            

            # Obter valores dos campos

            try:

                comp_1 = float(self.comp_1.get().replace(',', '.') or 0)

                comp_2 = float(self.comp_2.get().replace(',', '.') or 0)

                larg_1 = float(self.larg_1.get().replace(',', '.') or 0)

                larg_2 = float(self.larg_2.get().replace(',', '.') or 0)

            except ValueError:

                return  # Se algum valor não for numérico, não calcular

            


            

            # Verificar se há comprimentos válidos

            if comp_1 <= 0 or comp_2 <= 0:

                print("[AVISO] Comprimentos inválidos para cálculo das grades")

                return

            

            # Verificar o modo de cálculo selecionado (NOVA = PLINE, INI = MLINE)

            modo_selecionado = self.modo_calculo.get()

            modo_pline = (modo_selecionado == "NOVA")


            

            # ⚠️ CÓDIGO ANTIGO - DEPRECADO PARA GRADES A, B, E, F
            # As novas fórmulas são:
            # - Grade A: comp_1 + 22
            # - Grade B: comp_1 - 13.2 + (larg_2 - 20)
            # - Grade E: comp_2 + 11 + (larg_1 - 20)
            # - Grade F (INI): comp_2 - 27.4
            # - Grade F (NOVA): comp_1 - 27.4
            # Este código é mantido apenas para compatibilidade com outras grades (ex: G-H)
            
            if modo_pline:

                # PROPORÇÕES PARA MODO PLINE (baseadas em pilar de 100cm) - ⚠️ DEPRECADO

                proporcoes = {

                    'A': 122.4,  # Pilar 1 - Grade A (para comprimento 1) - NÃO AFETADA PELA LARGURA

                    'B': 89.0,   # Pilar 1 - Grade B (para comprimento 1) - AFETADA PELA LARGURA DO PILAR 2

                    'E': 111.0,  # Pilar 2 - Grade E (para comprimento 2) - AFETADA PELA LARGURA DO PILAR 1

                    'F': 72.6    # Pilar 2 - Grade F (para comprimento 2) - APENAS COMPRIMENTO, SEM LARGURA

                }

            else:

                # PROPORÇÕES PARA MODO MLINE (baseadas em pilar de 100cm) - ⚠️ DEPRECADO

                proporcoes = {

                    'A': 120.0,  # Pilar 1 - Grade A (para comprimento 1) - NÃO AFETADA PELA LARGURA

                    'B': 89.0,   # Pilar 1 - Grade B (para comprimento 1) - AFETADA PELA LARGURA DO PILAR 2

                    'E': 111.0,  # Pilar 2 - Grade E (para comprimento 2) - AFETADA PELA LARGURA DO PILAR 1

                    'F': 72.6    # Pilar 2 - Grade F (para comprimento 2) - APENAS COMPRIMENTO, SEM LARGURA

                }

            

            # Calcular diferença baseada nos comprimentos individuais

            diferenca_comp_1 = comp_1 - 100.0  # Diferença do comprimento 1 para 100cm

            diferenca_comp_2 = comp_2 - 100.0  # Diferença do comprimento 2 para 100cm

            

            print(f"[CALCULO] Comprimento 1: {comp_1}cm, Diferença para 100cm: {diferenca_comp_1}cm")

            print(f"[CALCULO] Comprimento 2: {comp_2}cm, Diferença para 100cm: {diferenca_comp_2}cm")

            print(f"[CALCULO] Modo: {'PLINE' if modo_pline else 'MLINE'}")

            

            # Calcular grades somando a diferença aos valores base

            # Grade A: NÃO AFETADA PELA LARGURA

            grade_a_1 = proporcoes['A'] + diferenca_comp_1

            

            # Grade B: AFETADA PELA LARGURA DO PILAR 2 (larg_2)

            # Base: 89 para largura 20, ajuste: (larg_2 - 20) * -1

            ajuste_largura_b = (larg_2 - 20.0) * -1  # Se larg_2=30, ajuste=-10; se larg_2=15, ajuste=+5

            grade_b_1 = proporcoes['B'] + diferenca_comp_1 + ajuste_largura_b

            

            # Grade E: AFETADA PELA LARGURA DO PILAR 1 (larg_1)

            # Base: 111 para largura 20, ajuste: (larg_1 - 20) * 1

            ajuste_largura_e = (larg_1 - 20.0) * 1  # Se larg_1=30, ajuste=+10; se larg_1=15, ajuste=-5

            grade_e_2 = proporcoes['E'] + diferenca_comp_2 + ajuste_largura_e
            

            

            # Grade F: APENAS COMPRIMENTO, SEM AJUSTE DE LARGURA

            grade_f_2 = proporcoes['F'] + diferenca_comp_2

            



            

            print(f"[CALCULO] Grades calculadas com proporções e ajustes:")



            print(f"[CALCULO]   Grade E: {grade_e_2:.1f}cm (ajuste larg_1: {ajuste_largura_e:+.1f}cm)")


            

            # Calcular painéis (usar lógica original para compatibilidade)

            pai_a_1 = comp_1 + 22

            pai_b_1 = comp_1 - larg_2 - 18.5 + 11 + 4.4

            pai_a_2 = comp_2 + larg_1 + 11

            # Ajuste dinâmico da largura do painel E baseado na diferença de larg_1 para 20
            diferenca_largura = larg_1 - 20.0
            pai_b_2 = comp_2 + 11 + diferenca_largura  # Ajuste dinâmico para acompanhar Grade E

            

            # Calcular parafusos usando os comprimentos diretos (nova lógica)

            parafuso_1 = comp_1  # Parafusos A e B baseados no comprimento 1

            parafuso_2 = comp_2  # Parafusos E e F baseados no comprimento 2

            




            

            # Aplicar os valores calculados aos campos da interface

            self.aplicar_calculos_pilar_especial_L(

                pai_a_1, pai_b_1, grade_a_1, grade_b_1, parafuso_1,

                pai_a_2, pai_b_2, grade_e_2, grade_f_2, parafuso_2, modo_pline

            )

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def calcular_pilar_especial_tipo_T(self):

        """

        Cálculos específicos para pilar especial tipo T

        """

        try:

            # Obter valores dos campos

            try:

                comp_1 = float(self.comp_1.get().replace(',', '.') or 0)

                comp_2 = float(self.comp_2.get().replace(',', '.') or 0)

                larg_1 = float(self.larg_1.get().replace(',', '.') or 0)

                larg_2 = float(self.larg_2.get().replace(',', '.') or 0)

                distancia = float(self.distancia.get() or 0)

            except ValueError:

                return  # Se algum valor não for numérico, não calcular

            


            
            
            # Determinar modo de cálculo (NOVA = PLINE, INI = MLINE)
            modo_selecionado = self.modo_calculo.get()
            modo_pline = (modo_selecionado == "NOVA")
            print(f"[CALCULO] Modo selecionado: {modo_selecionado} ({'PLINE' if modo_pline else 'MLINE'})")

            

            # PILAR 1 - Cálculos (similar ao L, mas com ajustes para T)

            # PAI.A = Comprimento do 1 + 22 = Painel A

            pai_a_1 = comp_1 + 22

            # Grade A = Comprimento do 1 + 22

            grade_a_1 = comp_1 + 22

            

            # PAI.B = Comprimento 1 - (distancia/2) - 18.5 + 11 + 4.4 = Painel B

            pai_b_1 = comp_1 - (distancia / 2) - 18.5 + 11 + 4.4

            # Grade B = Comprimento do 1 - (distancia/2) - 18.5 + 11

            grade_b_1 = comp_1 - (distancia / 2) - 18.5 + 11

            

            # Parafuso 1 = Comprimento 1 (nova lógica)

            parafuso_1 = comp_1

            

            # PILAR 2 - Cálculos (perpendicular ao pilar 1)

            # PAI.A = Comprimento do 2 + larg_1 + 11 = Painel F

            pai_a_2 = comp_2 + larg_1 + 11

            # Grade F = Comprimento do 2 + larg_1 + 11

            grade_f_2 = comp_2 + larg_1 + 11

            

            # PAI.B = Comprimento 2 + 11 = Painel E

            # Ajuste dinâmico da largura do painel E baseado na diferença de larg_1 para 20
            diferenca_largura = larg_1 - 20.0
            pai_b_2 = comp_2 + 11 + diferenca_largura  # Ajuste dinâmico para acompanhar Grade E

            # Grade E = Comprimento do 2 + 11 - 18.5

            grade_e_2 = comp_2 + 11 - 18.5
            
            print(f"[GRADE_E] Grade E calculada (Tipo T): {grade_e_2:.1f}cm (sem ajuste dinâmico)")

            

            # Parafuso 2 = Comprimento 2 - 30 + 22

            parafuso_2 = comp_2

            

            print(f"[ESTATISTICA] Resultados calculados tipo T:")

            print(f"   Pilar 1: PAI.A={pai_a_1}, PAI.B={pai_b_1}, Grade A={grade_a_1}, Grade B={grade_b_1}, Parafuso={parafuso_1}")

            print(f"   Pilar 2: PAI.A={pai_a_2}, PAI.B={pai_b_2}, Grade F={grade_f_2}, Grade E={grade_e_2}, Parafuso={parafuso_2}")

            

            # Aplicar os valores calculados aos campos da interface

            self.aplicar_calculos_pilar_especial_T(

                pai_a_1, pai_b_1, grade_a_1, grade_b_1, parafuso_1,

                pai_a_2, pai_b_2, grade_f_2, grade_e_2, parafuso_2, modo_pline

            )

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def calcular_pilar_especial_tipo_U(self):

        """

        Cálculos específicos para pilar especial tipo U

        """

        try:

            # Obter valores dos campos

            try:

                comp_1 = float(self.comp_1.get().replace(',', '.') or 0)

                comp_2 = float(self.comp_2.get().replace(',', '.') or 0)

                comp_3 = float(self.comp_3.get().replace(',', '.') or 0)

                larg_1 = float(self.larg_1.get().replace(',', '.') or 0)

                larg_2 = float(self.larg_2.get().replace(',', '.') or 0)

                larg_3 = float(self.larg_3.get().replace(',', '.') or 0)

            except ValueError:

                return  # Se algum valor não for numérico, não calcular

            


            print(f"   Larguras: larg_1={larg_1}, larg_2={larg_2}, larg_3={larg_3}")

            
            
            # Determinar modo de cálculo (NOVA = PLINE, INI = MLINE)
            modo_selecionado = self.modo_calculo.get()
            modo_pline = (modo_selecionado == "NOVA")
            print(f"[CALCULO] Modo selecionado: {modo_selecionado} ({'PLINE' if modo_pline else 'MLINE'})")

            

            # PILAR 1 - Cálculos (base do U)

            # PAI.A = Comprimento do 1 + 22 = Painel A

            pai_a_1 = comp_1 + 22

            # Grade A = Comprimento do 1 + 22

            grade_a_1 = comp_1 + 22

            

            # PAI.B = Comprimento 1 - larg_2 - larg_3 - 18.5 + 11 + 4.4 = Painel B

            pai_b_1 = comp_1 - larg_2 - larg_3 - 18.5 + 11 + 4.4

            # Grade B = Comprimento do 1 - larg_2 - larg_3 - 18.5 + 11

            grade_b_1 = comp_1 - larg_2 - larg_3 - 18.5 + 11

            

            # Parafuso 1 = Comprimento do 1 - larg_2 - larg_3 - 30 + 22

            parafuso_1 = comp_1

            

            # PILAR 2 - Cálculos (braço esquerdo do U)

            # PAI.A = Comprimento do 2 + larg_1 + 11 = Painel F

            pai_a_2 = comp_2 + larg_1 + 11

            # Grade F = Comprimento do 2 + larg_1 + 11

            grade_f_2 = comp_2 + larg_1 + 11

            

            # PAI.B = Comprimento 2 + 11 = Painel E

            # Ajuste dinâmico da largura do painel E baseado na diferença de larg_1 para 20
            diferenca_largura = larg_1 - 20.0
            pai_b_2 = comp_2 + 11 + diferenca_largura  # Ajuste dinâmico para acompanhar Grade E

            # Grade E = Comprimento do 2 + 11 - 18.5

            grade_e_2 = comp_2 + 11 - 18.5
            
            print(f"[GRADE_E] Grade E calculada (Tipo U): {grade_e_2:.1f}cm (sem ajuste dinâmico)")

            

            # Parafuso 2 = Comprimento 2 - 30 + 22

            parafuso_2 = comp_2

            

            # PILAR 3 - Cálculos (braço direito do U) - usar painéis G e H

            # PAI.A = Comprimento do 3 + larg_1 + 11 = Painel G

            pai_a_3 = comp_3 + larg_1 + 11

            # Grade G = Comprimento do 3 + larg_1 + 11

            grade_g_3 = comp_3 + larg_1 + 11

            

            # PAI.B = Comprimento 3 + 11 = Painel H

            pai_b_3 = comp_3 + 11

            # Grade H = Comprimento do 3 + 11 - 18.5

            grade_h_3 = comp_3 + 11 - 18.5

            

            # Parafuso 3 = Comprimento 3 - 30 + 22

            parafuso_3 = comp_3

            

            print(f"[ESTATISTICA] Resultados calculados tipo U:")

            print(f"   Pilar 1: PAI.A={pai_a_1}, PAI.B={pai_b_1}, Grade A={grade_a_1}, Grade B={grade_b_1}, Parafuso={parafuso_1}")

            print(f"   Pilar 2: PAI.A={pai_a_2}, PAI.B={pai_b_2}, Grade F={grade_f_2}, Grade E={grade_e_2}, Parafuso={parafuso_2}")

            print(f"   Pilar 3: PAI.A={pai_a_3}, PAI.B={pai_b_3}, Grade G={grade_g_3}, Grade H={grade_h_3}, Parafuso={parafuso_3}")

            

            # Aplicar os valores calculados aos campos da interface

            self.aplicar_calculos_pilar_especial_U(

                pai_a_1, pai_b_1, grade_a_1, grade_b_1, parafuso_1,

                pai_a_2, pai_b_2, grade_f_2, grade_e_2, parafuso_2,

                pai_a_3, pai_b_3, grade_g_3, grade_h_3, parafuso_3, modo_pline

            )

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def aplicar_calculos_pilar_especial_L(self, pai_a_1, pai_b_1, grade_a_1, grade_b_1, parafuso_1,

                                         pai_a_2, pai_b_2, grade_e_2, grade_f_2, parafuso_2, modo_pline=True):

        """

        Aplica os valores calculados aos campos da interface para pilar especial tipo L.

        """

        try:

            # Atualizar comprimento e largura principais (usar valores do pilar 1)

            comp_1 = float(self.comp_1.get().replace(',', '.') or 0)

            larg_1 = float(self.larg_1.get().replace(',', '.') or 0)

            

            if comp_1 > 0:

                # REMOVIDO: Causa loop infinito

                # self.comprimento.delete(0, tk.END)

                # self.comprimento.insert(0, str(int(comp_1)))

                pass

            

            if larg_1 > 0:

                # REMOVIDO: Causa loop infinito

                # self.largura.delete(0, tk.END)

                # self.largura.insert(0, str(int(larg_1)))

                pass

            

            # Aplicar larguras usando a lógica original de distribuição

            # Painel A (pai_a_1)

            # COMENTADO: Não deve modificar painel A quando pilar especial ativo
            # if pai_a_1 > 0:
            #     self.aplicar_larguras_painel_especial('A', pai_a_1)

            # COMENTADO: Não deve modificar painel B quando pilar especial ativo
            # if pai_b_1 > 0:
            #     self.aplicar_larguras_painel_especial('B', pai_b_1)

            

            # Painel E (pai_b_2)

            if pai_b_2 > 0:

                self.aplicar_larguras_painel_especial('E', pai_b_2)

            

            # Painel F - usar Grade F para distribuição + ajuste baseado no modo
            if grade_f_2 > 0:
                if modo_pline:  # Modo NOVA
                    self.aplicar_larguras_painel_especial('F', grade_f_2 + 16.4)
                else:  # Modo INI - adicionar +3.6 extra para larguras do painel F
                    self.aplicar_larguras_painel_especial('F', grade_f_2 + 12.8 + 3.6)
                    print(f"[PAINEL_F] Modo INI - Aplicado ajuste extra de +3.6 para larguras do painel F: {grade_f_2 + 12.8 + 3.6:.1f}cm")
            
            # Aplicar grades especiais diretamente com valores proporcionais
            self.aplicar_grades_especiais_proporcionais(grade_a_1, grade_b_1, grade_e_2, grade_f_2, modo_pline)

            # Painel A - somar todos os valores da Grade A e distribuir nos 3 campos até 244
            if grade_a_1 > 0:
                try:
                    # Somar todos os valores da Grade A: grade1 + distância1 + grade2 + distância2 + grade3
                    grade_a_total = 0
                    grade_a_total += float(self.grade_a_1.get() or 0)
                    grade_a_total += float(self.dist_a_1.get() or 0)
                    grade_a_total += float(self.grade_a_2.get() or 0)
                    grade_a_total += float(self.dist_a_2.get() or 0)
                    grade_a_total += float(self.grade_a_3.get() or 0)
                    
                    print(f"[LARGURA_A] Grade A total calculada: {grade_a_total:.1f}cm")
                    
                    # Distribuir o valor total nos 3 campos de largura A usando a função de distribuição
                    self.aplicar_larguras_painel_especial('A', grade_a_total)
                    
                    print(f"[LARGURA_A] Distribuiu Grade A total ({grade_a_total:.1f}cm) nos campos de largura A")
                except Exception as e:
                    print(f"[LARGURA_A] Erro ao somar e distribuir Grade A: {e}")

            

            # Calcular e atualizar parafusos especiais usando campos corretos

            self.calcular_parafusos_especiais_corretos(parafuso_1, parafuso_2)

            

            # Calcular e atualizar detalhes de grades especiais

            self.calcular_detalhes_grades_especiais_corretos(grade_a_1, grade_b_1, grade_e_2, grade_f_2)

            


            

            # Sincronizar todos os painéis especiais (C, D, E, F, G, H) conforme tipo selecionado

            # Obter valores atuais dos campos

            larg_1_atual = float(self.larg_1.get().replace(',', '.') or 0)

            larg_2_atual = float(self.larg_2.get().replace(',', '.') or 0)

            self.sincronizar_todos_paineis_especiais(larg_1_atual, larg_2_atual)

            

            # Atualizar preview

            if hasattr(self, 'atualizar_preview'):

                self.atualizar_preview()

            

            # Calcular perfis metálicos especiais

            self.calcular_perfis_metalicos_especiais_L()

            


            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

