    def aplicar_larguras_painel_especial(self, letra, comprimento_total, modo=None):

        """

        Aplica larguras a um painel específico usando regras NOVA ou UNI baseado no modo selecionado.

        Args:
            letra: Letra do painel (A, B, C, D, E, F, G, H)
            comprimento_total: Comprimento total a ser distribuído
            modo: "NOVA" ou "INI" (UNI). Se None, usa self.modo_calculo ou self.tipo_distribuicao_largura
        """

        try:
            # Obter modo se não foi fornecido
            if modo is None:
                if hasattr(self, 'modo_calculo'):
                    modo = self.modo_calculo.get()
                elif hasattr(self, 'tipo_distribuicao_largura'):
                    modo = self.tipo_distribuicao_largura.get()
                else:
                    modo = "NOVA"  # Padrão
            
            # Converter INI para UNI (mesma lógica)
            if modo == "INI":
                modo = "UNI"
            
            print(f"\n>>> Aplicando larguras ao Painel {letra} com comprimento {comprimento_total} (modo: {modo})")

            # Limpar campos existentes
            for i in range(1, 4):
                campo_nome = f"larg{i}_{letra}"
                if hasattr(self, campo_nome):
                    campo = getattr(self, campo_nome)
                    campo.delete(0, tk.END)
                    campo.insert(0, "0")

            # Aplicar regras baseado no modo
            if modo == "NOVA":
                # Regras NOVA: ajuste de 122 para sobrantes < 60
                if comprimento_total <= 244:
                    # Usar apenas larg1 com a medida exata
                    larg1 = comprimento_total
                    print(f">>> Painel {letra}: larg1 = {larg1:.1f} (medida exata - NOVA)")
                    if hasattr(self, f"larg1_{letra}"):
                        getattr(self, f"larg1_{letra}").delete(0, tk.END)
                        getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                else:
                    # Para comprimentos maiores que 244, verificar se o sobrante seria < 60
                    larg2 = comprimento_total - 244
                    if larg2 < 60:
                        # Ajustar para 122 + (restante + 122)
                        larg1 = 122
                        larg2 = larg2 + 122  # soma 122 ao sobrante menor que 60
                        print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f} (ajuste por sobrante < 60 - NOVA)")
                        if hasattr(self, f"larg1_{letra}"):
                            getattr(self, f"larg1_{letra}").delete(0, tk.END)
                            getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                        if hasattr(self, f"larg2_{letra}"):
                            getattr(self, f"larg2_{letra}").delete(0, tk.END)
                            getattr(self, f"larg2_{letra}").insert(0, str(larg2))
                    elif comprimento_total <= 488:
                        # Usar larg1 = 244 e larg2 para o restante
                        larg1 = 244
                        print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f} (NOVA)")
                        if hasattr(self, f"larg1_{letra}"):
                            getattr(self, f"larg1_{letra}").delete(0, tk.END)
                            getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                        if hasattr(self, f"larg2_{letra}"):
                            getattr(self, f"larg2_{letra}").delete(0, tk.END)
                            getattr(self, f"larg2_{letra}").insert(0, str(larg2))
                    else:  # comprimento_total > 488
                        # Para casos com três painéis, verificar se larg3 seria < 60
                        larg1 = 244
                        larg2 = 244
                        larg3 = comprimento_total - 488
                        if larg3 < 60:
                            # Ajustar larg2 para 122 e somar 122 ao larg3
                            larg2 = 122
                            larg3 = larg3 + 122
                            print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f} (ajuste por larg3 < 60 - NOVA)")
                        else:
                            print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f} (NOVA)")
                        if hasattr(self, f"larg1_{letra}"):
                            getattr(self, f"larg1_{letra}").delete(0, tk.END)
                            getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                        if hasattr(self, f"larg2_{letra}"):
                            getattr(self, f"larg2_{letra}").delete(0, tk.END)
                            getattr(self, f"larg2_{letra}").insert(0, str(larg2))
                        if hasattr(self, f"larg3_{letra}"):
                            getattr(self, f"larg3_{letra}").delete(0, tk.END)
                            getattr(self, f"larg3_{letra}").insert(0, str(larg3))
            else:  # modo == "UNI" ou "INI"
                # Regras UNI: sem ajuste de 122, distribuição direta
                if comprimento_total <= 244:
                    # Usar apenas larg1 com a medida exata
                    larg1 = comprimento_total
                    print(f">>> Painel {letra}: larg1 = {larg1:.1f} (medida exata - UNI)")
                    if hasattr(self, f"larg1_{letra}"):
                        getattr(self, f"larg1_{letra}").delete(0, tk.END)
                        getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                elif comprimento_total <= 488:
                    # Usar larg1 = 244 e larg2 para o restante
                    larg1 = 244
                    larg2 = comprimento_total - 244
                    print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f} (UNI)")
                    if hasattr(self, f"larg1_{letra}"):
                        getattr(self, f"larg1_{letra}").delete(0, tk.END)
                        getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                    if hasattr(self, f"larg2_{letra}"):
                        getattr(self, f"larg2_{letra}").delete(0, tk.END)
                        getattr(self, f"larg2_{letra}").insert(0, str(larg2))
                else:  # comprimento_total > 488
                    # Usar larg1 = 244, larg2 = 244 e larg3 para o restante
                    larg1 = 244
                    larg2 = 244
                    larg3 = comprimento_total - 488
                    print(f">>> Painel {letra}: larg1 = {larg1:.1f}, larg2 = {larg2:.1f}, larg3 = {larg3:.1f} (UNI)")
                    if hasattr(self, f"larg1_{letra}"):
                        getattr(self, f"larg1_{letra}").delete(0, tk.END)
                        getattr(self, f"larg1_{letra}").insert(0, str(larg1))
                    if hasattr(self, f"larg2_{letra}"):
                        getattr(self, f"larg2_{letra}").delete(0, tk.END)
                        getattr(self, f"larg2_{letra}").insert(0, str(larg2))
                    if hasattr(self, f"larg3_{letra}"):
                        getattr(self, f"larg3_{letra}").delete(0, tk.END)
                        getattr(self, f"larg3_{letra}").insert(0, str(larg3))

                    

        except Exception as e:

            pass

    
    def aplicar_ajustes_fixos_larguras(self):
        """
        Aplica ajustes fixos nas larguras dos painéis após a distribuição.
        
        Ajustes (somar no valor total da distribuição):
        - A: +0.2 (INI e NOVA)
        - B: +5 (INI e NOVA)
        - C: sem ajuste
        - D: sem ajuste
        - E: sem ajuste
        - F: +17 (INI e NOVA)
        
        O ajuste é somado ao total e redistribuído proporcionalmente entre larg1, larg2, larg3.
        """
        try:
            print("[AJUSTE-FIXO] Iniciando aplicação de ajustes fixos nas larguras...")
            ajustes = {
                'A': 0.2,
                'B': 5.0,
                'C': 0.0,
                'D': 0.0,
                'E': 0.0,
                'F': 17.0
            }
            
            for letra, ajuste in ajustes.items():
                if ajuste == 0:
                    continue  # Pular painéis sem ajuste
                
                # Obter valores atuais das larguras
                larg1_val = 0
                larg2_val = 0
                larg3_val = 0
                
                # Ler larg1
                campo_larg1 = getattr(self, f"larg1_{letra}", None)
                if campo_larg1:
                    try:
                        larg1_str = campo_larg1.get().replace(',', '.').strip()
                        larg1_val = float(larg1_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO] Erro ao ler larg1_{letra}: {e}")
                        pass
                
                # Ler larg2
                campo_larg2 = getattr(self, f"larg2_{letra}", None)
                if campo_larg2:
                    try:
                        larg2_str = campo_larg2.get().replace(',', '.').strip()
                        larg2_val = float(larg2_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO] Erro ao ler larg2_{letra}: {e}")
                        pass
                
                # Ler larg3
                campo_larg3 = getattr(self, f"larg3_{letra}", None)
                if campo_larg3:
                    try:
                        larg3_str = campo_larg3.get().replace(',', '.').strip()
                        larg3_val = float(larg3_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO] Erro ao ler larg3_{letra}: {e}")
                        pass
                
                # Calcular total atual
                total_atual = larg1_val + larg2_val + larg3_val
                
                # Aplicar ajuste apenas se houver valores nas larguras
                if total_atual > 0:
                    # Adicionar ajuste ao total
                    total_ajustado = total_atual + ajuste
                    
                    print(f"[AJUSTE-FIXO] Painel {letra}: Total atual = {total_atual:.1f}, Ajuste = +{ajuste:.1f}, Total ajustado = {total_ajustado:.1f}")
                    
                    # Redistribuir mantendo proporções
                    if larg1_val > 0:
                        nova_larg1 = (larg1_val / total_atual) * total_ajustado
                        campo_larg1.delete(0, tk.END)
                        campo_larg1.insert(0, str(round(nova_larg1, 1)))
                        print(f"[AJUSTE-FIXO] Painel {letra}: larg1 {larg1_val:.1f} -> {nova_larg1:.1f}")
                    
                    if larg2_val > 0:
                        nova_larg2 = (larg2_val / total_atual) * total_ajustado
                        campo_larg2.delete(0, tk.END)
                        campo_larg2.insert(0, str(round(nova_larg2, 1)))
                        print(f"[AJUSTE-FIXO] Painel {letra}: larg2 {larg2_val:.1f} -> {nova_larg2:.1f}")
                    
                    if larg3_val > 0:
                        nova_larg3 = (larg3_val / total_atual) * total_ajustado
                        campo_larg3.delete(0, tk.END)
                        campo_larg3.insert(0, str(round(nova_larg3, 1)))
                        print(f"[AJUSTE-FIXO] Painel {letra}: larg3 {larg3_val:.1f} -> {nova_larg3:.1f}")
                    
                    print(f"[AJUSTE-FIXO] ✅ Painel {letra} ajustado: {total_atual:.1f} -> {total_ajustado:.1f} (+{ajuste:.1f})")
                else:
                    print(f"[AJUSTE-FIXO] ⚠️ Painel {letra}: Total = 0, pulando ajuste")
            
            print("[AJUSTE-FIXO] ✅ Aplicação de ajustes fixos concluída")
        except Exception as e:
            print(f"[AJUSTE-FIXO] ❌ Erro ao aplicar ajustes: {e}")
            import traceback
            traceback.print_exc()

    
    def aplicar_ajustes_fixos_grades(self):
        """
        Aplica ajustes fixos nas grades especiais após a distribuição.
        
        Ajustes (somar no valor total da distribuição):
        - A: +0.2 (INI e NOVA)
        - B: +0.8 (INI e NOVA)
        - E: sem ajuste
        - F: +0.8 (INI e NOVA)
        
        O ajuste é somado ao total (grade1 + dist1 + grade2 + dist2 + grade3) e redistribuído proporcionalmente.
        """
        try:
            print("[AJUSTE-FIXO-GRADES] ========================================")
            print("[AJUSTE-FIXO-GRADES] Iniciando aplicação de ajustes fixos nas grades...")
            print("[AJUSTE-FIXO-GRADES] ========================================")
            ajustes = {
                'a': 0.2,  # Grade A
                'b': 0.8,  # Grade B
                'e': 0.0,  # Grade E - sem ajuste
                'f': 0.8   # Grade F
            }
            
            for letra, ajuste in ajustes.items():
                if ajuste == 0:
                    print(f"[AJUSTE-FIXO-GRADES] Pulando Grade {letra.upper()} (sem ajuste)")
                    continue  # Pular grades sem ajuste
                
                print(f"[AJUSTE-FIXO-GRADES] Processando Grade {letra.upper()} (ajuste: +{ajuste})")
                
                # Obter valores atuais das grades
                grade1_val = 0
                dist1_val = 0
                grade2_val = 0
                dist2_val = 0
                grade3_val = 0
                
                # Ler grade1
                campo_grade1 = getattr(self, f"grade_{letra}_1", None)
                if campo_grade1:
                    try:
                        grade1_str = campo_grade1.get().replace(',', '.').strip()
                        grade1_val = float(grade1_str or 0)
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: grade1 = {grade1_val}")
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO-GRADES] ⚠️ Campo grade_{letra}_1 não encontrado ou erro ao ler: {e}")
                        campo_grade1 = None
                else:
                    print(f"[AJUSTE-FIXO-GRADES] ⚠️ Campo grade_{letra}_1 não existe")
                
                # Ler dist1
                campo_dist1 = getattr(self, f"dist_{letra}_1", None)
                if campo_dist1:
                    try:
                        dist1_str = campo_dist1.get().replace(',', '.').strip()
                        dist1_val = float(dist1_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO-GRADES] Erro ao ler dist_{letra}_1: {e}")
                        pass
                
                # Ler grade2
                campo_grade2 = getattr(self, f"grade_{letra}_2", None)
                if campo_grade2:
                    try:
                        grade2_str = campo_grade2.get().replace(',', '.').strip()
                        grade2_val = float(grade2_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO-GRADES] Erro ao ler grade_{letra}_2: {e}")
                        pass
                
                # Ler dist2
                campo_dist2 = getattr(self, f"dist_{letra}_2", None)
                if campo_dist2:
                    try:
                        dist2_str = campo_dist2.get().replace(',', '.').strip()
                        dist2_val = float(dist2_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO-GRADES] Erro ao ler dist_{letra}_2: {e}")
                        pass
                
                # Ler grade3
                campo_grade3 = getattr(self, f"grade_{letra}_3", None)
                if campo_grade3:
                    try:
                        grade3_str = campo_grade3.get().replace(',', '.').strip()
                        grade3_val = float(grade3_str or 0)
                    except (ValueError, AttributeError) as e:
                        print(f"[AJUSTE-FIXO-GRADES] Erro ao ler grade_{letra}_3: {e}")
                        pass
                
                # Calcular total atual (grade1 + dist1 + grade2 + dist2 + grade3)
                total_atual = grade1_val + dist1_val + grade2_val + dist2_val + grade3_val
                
                # Aplicar ajuste apenas se houver valores nas grades
                if total_atual > 0:
                    # Adicionar ajuste ao total
                    total_ajustado = total_atual + ajuste
                    
                    print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: Total atual = {total_atual:.1f}, Ajuste = +{ajuste:.1f}, Total ajustado = {total_ajustado:.1f}")
                    
                    # REGRA: Se houver dist1 ou dist2, as frações do ajuste vão para as distâncias, não para as grades
                    total_distancias = dist1_val + dist2_val
                    total_grades = grade1_val + grade2_val + grade3_val
                    
                    if total_distancias > 0:
                        # Há distâncias: aplicar frações nas distâncias primeiro
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: Há distâncias ({total_distancias:.1f}), aplicando frações nas distâncias")
                        
                        # Extrair parte inteira e parte decimal do ajuste
                        parte_inteira = int(ajuste)
                        parte_decimal = ajuste - parte_inteira
                        
                        # Calcular proporção das distâncias e grades no total
                        proporcao_distancias = total_distancias / total_atual if total_atual > 0 else 0
                        proporcao_grades = total_grades / total_atual if total_atual > 0 else 0
                        
                        # REGRA: Frações vão para distâncias, parte inteira vai proporcionalmente
                        # Se há parte decimal, ela vai toda para as distâncias
                        ajuste_distancias = (parte_inteira * proporcao_distancias) + parte_decimal
                        ajuste_grades = parte_inteira * proporcao_grades
                        
                        # Se não há grades, todo ajuste vai para distâncias
                        if total_grades == 0:
                            ajuste_distancias = ajuste
                            ajuste_grades = 0
                        
                        # Aplicar ajuste nas distâncias
                        if dist1_val > 0 and dist2_val > 0:
                            # Ambas distâncias existem: distribuir proporcionalmente
                            proporcao_dist1 = dist1_val / total_distancias
                            proporcao_dist2 = dist2_val / total_distancias
                            nova_dist1 = dist1_val + (ajuste_distancias * proporcao_dist1)
                            nova_dist2 = dist2_val + (ajuste_distancias * proporcao_dist2)
                        elif dist1_val > 0:
                            # Apenas dist1 existe: todo ajuste vai para dist1
                            nova_dist1 = dist1_val + ajuste_distancias
                            nova_dist2 = dist2_val
                        elif dist2_val > 0:
                            # Apenas dist2 existe: todo ajuste vai para dist2
                            nova_dist1 = dist1_val
                            nova_dist2 = dist2_val + ajuste_distancias
                        else:
                            nova_dist1 = dist1_val
                            nova_dist2 = dist2_val
                        
                        # Aplicar ajuste nas grades (apenas parte inteira, sem frações)
                        if total_grades > 0 and ajuste_grades > 0:
                            if grade1_val > 0:
                                proporcao_grade1 = grade1_val / total_grades
                                nova_grade1 = grade1_val + (ajuste_grades * proporcao_grade1)
                            else:
                                nova_grade1 = grade1_val
                            
                            if grade2_val > 0:
                                proporcao_grade2 = grade2_val / total_grades
                                nova_grade2 = grade2_val + (ajuste_grades * proporcao_grade2)
                            else:
                                nova_grade2 = grade2_val
                            
                            if grade3_val > 0:
                                proporcao_grade3 = grade3_val / total_grades
                                nova_grade3 = grade3_val + (ajuste_grades * proporcao_grade3)
                            else:
                                nova_grade3 = grade3_val
                        else:
                            # Sem ajuste nas grades (mantém valores originais)
                            nova_grade1 = grade1_val
                            nova_grade2 = grade2_val
                            nova_grade3 = grade3_val
                    else:
                        # Não há distâncias: distribuir proporcionalmente entre todas as grades
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: Sem distâncias, distribuindo proporcionalmente entre grades")
                        if grade1_val > 0:
                            nova_grade1 = (grade1_val / total_atual) * total_ajustado
                        else:
                            nova_grade1 = grade1_val
                        
                        if grade2_val > 0:
                            nova_grade2 = (grade2_val / total_atual) * total_ajustado
                        else:
                            nova_grade2 = grade2_val
                        
                        if grade3_val > 0:
                            nova_grade3 = (grade3_val / total_atual) * total_ajustado
                        else:
                            nova_grade3 = grade3_val
                        
                        nova_dist1 = dist1_val
                        nova_dist2 = dist2_val
                    
                    # Atualizar campos
                    if grade1_val > 0 and campo_grade1:
                        campo_grade1.delete(0, tk.END)
                        campo_grade1.insert(0, str(round(nova_grade1, 1)))
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: grade1 {grade1_val:.1f} -> {nova_grade1:.1f}")
                    
                    if dist1_val > 0 and campo_dist1:
                        campo_dist1.delete(0, tk.END)
                        campo_dist1.insert(0, str(round(nova_dist1, 1)))
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: dist1 {dist1_val:.1f} -> {nova_dist1:.1f}")
                    
                    if grade2_val > 0 and campo_grade2:
                        campo_grade2.delete(0, tk.END)
                        campo_grade2.insert(0, str(round(nova_grade2, 1)))
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: grade2 {grade2_val:.1f} -> {nova_grade2:.1f}")
                    
                    if dist2_val > 0 and campo_dist2:
                        campo_dist2.delete(0, tk.END)
                        campo_dist2.insert(0, str(round(nova_dist2, 1)))
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: dist2 {dist2_val:.1f} -> {nova_dist2:.1f}")
                    
                    if grade3_val > 0 and campo_grade3:
                        campo_grade3.delete(0, tk.END)
                        campo_grade3.insert(0, str(round(nova_grade3, 1)))
                        print(f"[AJUSTE-FIXO-GRADES] Grade {letra.upper()}: grade3 {grade3_val:.1f} -> {nova_grade3:.1f}")
                    
                    # Verificar total final
                    total_final = nova_grade1 + nova_dist1 + nova_grade2 + nova_dist2 + nova_grade3
                    print(f"[AJUSTE-FIXO-GRADES] ✅ Grade {letra.upper()} ajustada: {total_atual:.1f} -> {total_final:.1f} (+{ajuste:.1f})")
                else:
                    print(f"[AJUSTE-FIXO-GRADES] ⚠️ Grade {letra.upper()}: Total = 0, pulando ajuste")
            
            print("[AJUSTE-FIXO-GRADES] ✅ Aplicação de ajustes fixos nas grades concluída")
        except Exception as e:
            print(f"[AJUSTE-FIXO-GRADES] ❌ Erro ao aplicar ajustes nas grades: {e}")
            import traceback
            traceback.print_exc()

    

    def calcular_alturas_paineis_especiais_efgh(self):

        """

        Calcula alturas para painéis especiais E, F, G, H

        E, F seguem o comportamento do B (max_altura = 122)
        G, H mantêm comportamento original (max_altura = 244)

        """

        try:

            # Para painéis E e F, usar a mesma lógica de cálculo de alturas dos painéis A e B

            for letra in ['E', 'F']:

                self.calcular_altura_painel_individual(letra)

            # Para painéis G e H, usar a mesma lógica de cálculo de alturas dos painéis C e D

            for letra in ['G', 'H']:

                self.calcular_altura_painel_individual(letra)

                

        except Exception as e:

            pass

    

    def calcular_altura_painel_individual(self, letra):

        """

        Calcula altura para um painel individual usando a lógica original

        """
        
        # DEBUG: Log de entrada na função

        try:

            # Obter altura total e nível diferencial

            try:

                altura_total = float(self.altura.get().replace(',', '.') or 0)

                nivel_diferencial = float(self.nivel_diferencial.get().replace(',', '.') or 0)

                altura_disponivel = altura_total - nivel_diferencial

            except ValueError:

                return

            

            # Obter valor da laje do painel

            laje_campo = f"laje_{letra}"

            laje_valor = 0

            if hasattr(self, laje_campo):

                try:

                    laje_str = getattr(self, laje_campo).get().strip()

                    laje_valor = float(laje_str.replace(',', '.')) if laje_str else 0

                except:

                    laje_valor = 0

            

            # Calcular altura efetiva

            altura_efetiva = altura_disponivel - laje_valor

            

            # E, F seguem o comportamento do B (max_altura = 122)
            # G, H mantêm comportamento original (max_altura = 244)
            max_altura = 122 if letra in ['E', 'F'] else 244

            

            # Coletar campos de altura do painel

            campos = []

            for i in range(1, 6):

                campo_nome = f"h{i}_{letra}"

                if hasattr(self, campo_nome):

                    campos.append(getattr(self, campo_nome))

            

            if not campos:

                return

            

            # Aplicar lógica de distribuição de altura (mesma dos painéis originais)
            # SEMPRE definir h1 = 2 primeiro

            # h1 sempre = 2
            campos[0].delete(0, tk.END)
            campos[0].insert(0, "2")
            
            # DEBUG: Log específico para A e B
            if letra in ['A', 'B']:
                pass
            
            # Calcular altura restante após h1 = 2
            altura_restante = altura_efetiva - 2

            if altura_restante <= 0:
                # Se não há altura suficiente, zerar outros campos
                for i, campo in enumerate(campos[1:], 2):
                    campo.delete(0, tk.END)
                    campo.insert(0, "0")
                    
                    # DEBUG: Log específico para A e B
                    if letra in ['A', 'B']:
                        pass
            elif altura_restante <= max_altura:
                # Usar apenas h2 com a altura restante
                campos[1].delete(0, tk.END)
                valor_h2 = str(int(altura_restante))
                campos[1].insert(0, valor_h2)
                
                # DEBUG: Log específico para A e B
                if letra in ['A', 'B']:
                    pass
                
                # Zerar outros campos
                for i, campo in enumerate(campos[2:], 3):
                    campo.delete(0, tk.END)
                    campo.insert(0, "0")
                    
                    # DEBUG: Log específico para A e B
                    if letra in ['A', 'B']:
                        pass
            else:
                # Distribuir altura restante em múltiplos campos (h2, h3, h4, h5)
                for i, campo in enumerate(campos[1:], 2):  # Começar do h2
                    if altura_restante <= 0:
                        campo.delete(0, tk.END)
                        campo.insert(0, "0")
                        
                        # DEBUG: Log específico para A e B
                        if letra in ['A', 'B']:
                            pass
                    elif altura_restante <= max_altura:
                        campo.delete(0, tk.END)
                        valor_final = str(int(altura_restante))
                        campo.insert(0, valor_final)
                        
                        # DEBUG: Log específico para A e B
                        if letra in ['A', 'B']:
                            pass
                        
                        altura_restante = 0
                    else:
                        campo.delete(0, tk.END)
                        campo.insert(0, str(max_altura))
                        
                        # DEBUG: Log específico para A e B
                        if letra in ['A', 'B']:
                            pass
                        
                        altura_restante -= max_altura

            

            print(f"[RÉGUA] Painel {letra}: altura_total={altura_total}, laje={laje_valor}, efetiva={altura_efetiva}")
            
            # Atualizar posição da laje após calcular alturas
            self.atualizar_posicao_laje(letra)

                    

        except Exception as e:

            pass

    

