    def calcular_parafusos_com_logica_original(self, comprimento):

        """

        Replica exatamente a lógica original de cálculo de parafusos

        """

        try:

            import math

            

            if not comprimento or float(comprimento) <= 0:

                return [0] * 9

                

            comprimento = float(comprimento)

            comprimento_ajustado = comprimento + 24  # Ajustado para +24cm para parafusos

            quantidade = int(math.ceil(comprimento_ajustado / 72))

            

            if quantidade == 0:

                return [0] * 9

                

            if quantidade == 2:

                valor = round(comprimento_ajustado / 2, 1)

                parafusos = [valor, valor]

            else:

                valor_base = int(math.floor(comprimento_ajustado / quantidade))

                resto = int(round(comprimento_ajustado - (valor_base * quantidade)))

                parafusos = [valor_base] * quantidade

                

                # Distribuir o resto nas extremidades, alternando para dentro

                left = 0

                right = quantidade - 1

                for i in range(resto):

                    if i % 2 == 0:

                        parafusos[left] += 1

                        left += 1

                    else:

                        parafusos[right] += 1

                        right -= 1

            

            # Completar com zeros até 9 elementos (par_a_1 a par_a_9, par_b_1 a par_b_9, etc.)

            while len(parafusos) < 9:

                parafusos.append(0)

                

            return parafusos

            

        except Exception as e:

            pass

            return [0] * 9



    def calcular_parafusos_especiais_nova_logica(self, comprimento, tipo_parafuso):

        """

        Calcula parafusos especiais com a nova lógica de valores predefinidos e distribuição proporcional

        

        Parâmetros:

        - comprimento: comprimento do pilar

        - tipo_parafuso: 'a', 'b', 'e', 'f', 'g', 'h'

        

        Regras:

        - A e B: distribuem normalmente

        - E: primeiro parafuso sempre 73.5, resto distribui

        - F: primeiro parafuso sempre 35.1, resto distribui

        - G e H: distribuem normalmente

        - Máximo por parafuso: 70cm

        - Se > 70cm: divide por 2, se > 140cm: divide por 3, etc.

        """

        try:

            if not comprimento or float(comprimento) <= 0:

                return [0] * 9

                

            comprimento = float(comprimento)

            

            # Valores base para pilar de 100cm (referência)

            valores_base_100 = {

                'a': 38,

                'b': 38,

                'e': 113,  # AJUSTADO: era 111, agora 113 (+2)

                'f': 74.6, # AJUSTADO: era 72.6, agora 74.6 (+2)

                'g': 100,

                'h': 100

            }

            

            # Obter valor base para este tipo de parafuso

            valor_base = valores_base_100.get(tipo_parafuso.lower(), 0)

            

            if valor_base == 0:

                print(f"[AVISO] Tipo de parafuso '{tipo_parafuso}' não tem valor base definido")

                return [0] * 9

            

            # Calcular valor proporcional baseado no comprimento

            # Fórmula: valor_atual = valor_base + (comprimento - 100)

            if comprimento >= 100:

                valor_atual = valor_base + (comprimento - 100)

            else:

                # LÓGICA ESPECIAL PARA A e B: manter proporção como se fosse 100cm

                if tipo_parafuso.lower() in ['a', 'b']:

                    # Para A e B, quando comprimento < 100, manter valor base (proporção de 100cm)

                    valor_atual = valor_base

                    print(f"[PARAFUSOS-ESPECIAL] {tipo_parafuso.upper()}: comprimento {comprimento} < 100, mantendo proporção de 100cm = {valor_atual}")

                else:

                    # Para outros tipos (E, F, G, H), aplicar redução normal

                    valor_atual = valor_base - (100 - comprimento)

                    # Não permitir valores negativos

                    if valor_atual < 0:

                        valor_atual = 0

            

            print(f"[PARAFUSOS-NOVA] Tipo: {tipo_parafuso.upper()}, Base: {valor_base}, Atual: {valor_atual}")

            

            # Aplicar regras específicas por tipo

            if tipo_parafuso.lower() == 'e':

                # Parafuso E: primeiro sempre 73.5, resto distribui

                # AJUSTE ESPECIAL: Se comprimento < 100, diminuir primeiro valor pela diferença

                primeiro_valor = 73.5

                if comprimento < 100:

                    diferenca = 100 - comprimento

                    primeiro_valor = max(0, primeiro_valor - diferenca)

                    print(f"[PARAFUSOS-ESPECIAL] E: comprimento {comprimento} < 100, ajustando primeiro valor de 73.5 para {primeiro_valor}")

                

                resto_valor = valor_atual - primeiro_valor

                

                if resto_valor <= 0:

                    # Se não há resto, usar apenas o primeiro

                    parafusos = [primeiro_valor] + [0] * 8

                else:

                    # Distribuir o resto seguindo as regras de tamanho máximo

                    parafusos = [primeiro_valor]

                    parafusos.extend(self._distribuir_parafusos_por_tamanho(resto_valor))

                    

            elif tipo_parafuso.lower() == 'f':

                # Parafuso F: primeiro sempre 35.1, resto distribui

                # AJUSTE ESPECIAL: Se comprimento < 100, diminuir primeiro valor pela diferença

                primeiro_valor = 35.1

                if comprimento < 100:

                    diferenca = 100 - comprimento

                    primeiro_valor = max(0, primeiro_valor - diferenca)


                

                resto_valor = valor_atual - primeiro_valor

                

                if resto_valor <= 0:

                    # Se não há resto, usar apenas o primeiro

                    parafusos = [primeiro_valor] + [0] * 8

                else:

                    # Distribuir o resto seguindo as regras de tamanho máximo

                    parafusos = [primeiro_valor]

                    parafusos.extend(self._distribuir_parafusos_por_tamanho(resto_valor))

                    

            else:

                # A, B, G, H: distribuem normalmente

                parafusos = self._distribuir_parafusos_por_tamanho(valor_atual)

            

            # Completar com zeros até 9 elementos

            while len(parafusos) < 9:

                parafusos.append(0)

            

            print(f"[PARAFUSOS-NOVA] Resultado para {tipo_parafuso.upper()}: {parafusos}")

            return parafusos

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

            return [0] * 9



    def _distribuir_parafusos_por_tamanho(self, valor_total):

        """

        Distribui parafusos respeitando o tamanho máximo de 70cm por parafuso

        

        Regras:

        - Máximo por parafuso: 70cm

        - Se > 70cm: divide por 2

        - Se > 140cm: divide por 3

        - E assim por diante

        - IMPORTANTE: Todos os parafusos adicionais devem ser iguais entre si

        """

        try:

            if valor_total <= 0:

                return [0]

            

            if valor_total <= 70:

                # Um único parafuso

                return [round(valor_total, 1)]

            

            # Calcular quantos parafusos são necessários

            if valor_total <= 140:

                # 2 parafusos - ambos iguais

                valor_por_parafuso = valor_total / 2

                return [round(valor_por_parafuso, 1), round(valor_por_parafuso, 1)]

            elif valor_total <= 210:

                # 3 parafusos - todos iguais

                valor_por_parafuso = valor_total / 3

                return [round(valor_por_parafuso, 1)] * 3

            elif valor_total <= 280:

                # 4 parafusos - todos iguais

                valor_por_parafuso = valor_total / 4

                return [round(valor_por_parafuso, 1)] * 4

            elif valor_total <= 350:

                # 5 parafusos - todos iguais

                valor_por_parafuso = valor_total / 5

                return [round(valor_por_parafuso, 1)] * 5

            elif valor_total <= 420:

                # 6 parafusos - todos iguais

                valor_por_parafuso = valor_total / 6

                return [round(valor_por_parafuso, 1)] * 6

            elif valor_total <= 490:

                # 7 parafusos - todos iguais

                valor_por_parafuso = valor_total / 7

                return [round(valor_por_parafuso, 1)] * 7

            elif valor_total <= 560:

                # 8 parafusos - todos iguais

                valor_por_parafuso = valor_total / 8

                return [round(valor_por_parafuso, 1)] * 8

            else:

                # 9 parafusos (máximo) - todos iguais

                valor_por_parafuso = valor_total / 9

                return [round(valor_por_parafuso, 1)] * 9

                

        except Exception as e:

            pass

            return [0]

    

    def aplicar_parafusos_campos_corretos(self, parafusos, prefixo):

        """

        Aplica os valores dos parafusos aos campos corretos da interface

        CORREÇÃO: Limpa TODOS os campos antes de aplicar os novos valores

        """

        try:

            print(f"[APLICAR-PARAFUSOS] 🎯 Aplicando {len(parafusos)} parafusos com prefixo '{prefixo}': {parafusos}")

            

            # PRIMEIRO: Limpar TODOS os campos deste prefixo (1 a 9)

            for i in range(1, 10):

                campo_nome = f"{prefixo}{i}"  # par_a_1, par_b_1, par_e_1, etc.

                if hasattr(self, campo_nome):

                    campo = getattr(self, campo_nome)

                    campo.delete(0, tk.END)

            

            # SEGUNDO: Aplicar os novos valores (incluindo zeros)

            for i, valor in enumerate(parafusos):

                campo_nome = f"{prefixo}{i+1}"  # par_a_1, par_b_1, par_e_1, etc.

                if hasattr(self, campo_nome):

                    campo = getattr(self, campo_nome)

                    # Aplicar valor (mesmo se for 0)

                    if valor > 0:

                        campo.insert(0, str(int(valor)))

                        print(f"[APLICAR-PARAFUSOS] ✅ {campo_nome}: {int(valor)}")

                    # Campo fica vazio para valor 0

                        

        except Exception as e:

            pass

    

