    def aplicar_detalhes_grade_especifica(self, detalhes, letra, grade_num):

        """

        Aplica detalhes para uma grade específica (1, 2 ou 3)

        SEMPRE LIMPA TODOS OS CAMPOS ANTES DE ATUALIZAR

        """

        try:

            print(f"[APLICAR-DETALHES] Aplicando detalhes para {letra.upper()}{grade_num}")

            

            # SEMPRE LIMPAR TODOS OS CAMPOS PRIMEIRO

            for i in range(1, 6):

                campo_nome = f"detalhe_{letra}_{grade_num}_{i}"

                if hasattr(self, campo_nome):

                    campo = getattr(self, campo_nome)

                    campo.delete(0, tk.END)

                    campo.insert(0, "0")

            

            # Aplicar aos campos específicos desta grade

            for i, valor in enumerate(detalhes):

                campo_nome = f"detalhe_{letra}_{grade_num}_{i+1}"

                if hasattr(self, campo_nome) and valor > 0:

                    campo = getattr(self, campo_nome)

                    campo.delete(0, tk.END)

                    campo.insert(0, str(round(valor, 1)))

                    print(f"[APLICAR-DETALHES] {campo_nome}: {valor}")

                        

        except Exception as e:

            pass

    

    # FUNÇÃO DUPLICADA - REMOVIDA

    def calcular_detalhes_com_logica_original_REMOVIDA(self, valor_grade):

        """

        Calcula detalhes usando quantidade necessária de campos para não exceder 33cm

        Frações apenas em 1 detalhe, priorizando inteiros

        """

        try:

            import math

            

            if valor_grade <= 0:

                return [0, 0, 0, 0, 0]  # 5 detalhes por grade

            

            # Calcular quantidade MÍNIMA de detalhes para que nenhum exceda 33cm

            quantidade_necessaria = math.ceil(valor_grade / 33.0)

            quantidade = min(quantidade_necessaria, 5)  # Máximo 5 campos

            

            print(f"[CALC-DETALHES] Grade: {valor_grade}cm, Quantidade necessária: {quantidade} campos")

            

            # Verificar se a grade é inteira ou tem fração

            eh_inteira = abs(valor_grade - round(valor_grade)) < 0.01

            

            if eh_inteira:

                # Grade é inteira - todos os detalhes devem ser inteiros

                valor_int = int(round(valor_grade))

                detalhes = [0] * 5  # Inicializar com 5 zeros

                

            if quantidade == 1:

                    detalhes[0] = valor_int

            elif quantidade == 2:

                    base = valor_int // 2

                    resto = valor_int % 2

                    detalhes[0] = base + resto

                    detalhes[1] = base

            elif quantidade == 3:

                    base = valor_int // 3

                    resto = valor_int % 3

                    detalhes[0] = base

                    detalhes[1] = base + resto

                    detalhes[2] = base

            elif quantidade == 4:

                    base = valor_int // 4

                    resto = valor_int % 4

                    detalhes[0] = base

                    detalhes[1] = base + resto

                    detalhes[2] = base

                    detalhes[3] = base

            elif quantidade == 5:

                    base = valor_int // 5

                    resto = valor_int % 5

                    detalhes[0] = base

                    detalhes[1] = base

                    detalhes[2] = base + resto

                    detalhes[3] = base

                    detalhes[4] = base

            else:

                # Grade tem fração - fração fica em APENAS UM detalhe

                detalhes = [0] * 5  # Inicializar com 5 zeros

                

                if quantidade == 1:

                    detalhes[0] = valor_grade

                elif quantidade == 2:

                    base = int(valor_grade / 2)

                    resto = valor_grade - (base * 2)

                    detalhes[0] = base + resto

                    detalhes[1] = base

                elif quantidade == 3:

                    base = int(valor_grade / 3)

                    resto = valor_grade - (base * 3)

                    detalhes[0] = base

                    detalhes[1] = base + resto

                    detalhes[2] = base

                elif quantidade == 4:

                    base = int(valor_grade / 4)

                    resto = valor_grade - (base * 4)

                    detalhes[0] = base

                    detalhes[1] = base + resto

                    detalhes[2] = base

                    detalhes[3] = base

                elif quantidade == 5:

                    base = int(valor_grade / 5)

                    resto = valor_grade - (base * 5)

                    detalhes[0] = base

                    detalhes[1] = base

                    detalhes[2] = base + resto

                    detalhes[3] = base

                    detalhes[4] = base

            

            # VALIDAÇÃO: Garantir que nenhum detalhe exceda 33cm

            for i, detalhe in enumerate(detalhes):

                if detalhe > 33.01:  # Margem para float

                    print(f"   [VALIDAÇÃO] ⚠️ Detalhe {i+1} = {detalhe}cm > 33cm - Redistribuindo...")

                    # Redistribuir o excesso

                    excesso = detalhe - 33

                    detalhes[i] = 33

                    

                    # Distribuir o excesso nos outros detalhes

                    outros_detalhes = [j for j in range(quantidade) if j != i and detalhes[j] < 33]

                    if outros_detalhes:

                        excesso_por_detalhe = excesso / len(outros_detalhes)

                        for j in outros_detalhes:

                            detalhes[j] = min(30, detalhes[j] + excesso_por_detalhe)

                        print(f"   [VALIDAÇÃO] ✅ Redistribuído excesso de {excesso}cm")

            

            # VALIDAÇÃO FINAL: Garantir soma exata

            soma_atual = sum(detalhes)

            if abs(soma_atual - valor_grade) > 0.01:

                diferenca = valor_grade - soma_atual

                print(f"   [VALIDAÇÃO] ⚠️ Ajustando diferença: {diferenca}cm")

                # Adicionar diferença ao último detalhe preenchido

                for i in range(quantidade - 1, -1, -1):

                    if detalhes[i] > 0:

                        detalhes[i] += diferenca

                        break

            

            print(f"[CALC-DETALHES] Resultado: {detalhes[:quantidade]} (soma: {sum(detalhes):.1f}cm)")

            return detalhes

            

        except Exception as e:

            print(f"[CALC-DETALHES] Erro: {e}")

            return [0, 0, 0, 0, 0]

            

        except Exception as e:

            pass

            return [0, 0, 0]

    

