    def _calcular_base_inicial_grade_especial(self, grade_letra, grade_num, tipo_calculo):

        """

        Calcula a base inicial para uma grade especial (posição acumulada das grades anteriores)

        """

        base_inicial = 0



        # Mapear ordem das grades por tipo

        ordem_grades = {

            "ab": ["a_1", "a_2", "a_3", "b_1", "b_2", "b_3"],

            "ef": ["e_1", "e_2", "e_3", "f_1", "f_2", "f_3"],

            "gh": ["g_1", "g_2", "g_3", "h_1", "h_2", "h_3"]

        }



        grade_atual = f"{grade_letra}_{grade_num}"

        grades_ate_atual = ordem_grades.get(tipo_calculo, [])



        try:

            idx_atual = grades_ate_atual.index(grade_atual)



            # Somar todas as grades anteriores

            for i in range(idx_atual):

                grade_anterior = grades_ate_atual[i]

                campo_anterior = f"grade_{grade_anterior}"



                if hasattr(self, campo_anterior):

                    campo = getattr(self, campo_anterior)

                    valor = campo.get().strip()

                    if valor:

                        base_inicial += float(valor)



                # Adicionar distâncias entre grades (se existir)

                if "_" in grade_anterior:

                    partes = grade_anterior.split("_")

                    if len(partes) == 2 and partes[1].isdigit():

                        num_grade = int(partes[1])

                        if num_grade < 3:  # Só há dist_1 e dist_2

                            campo_dist = f"dist_{partes[0]}_{num_grade}"

                            if hasattr(self, campo_dist):

                                campo = getattr(self, campo_dist)

                                valor = campo.get().strip()

                                if valor:

                                    base_inicial += float(valor)



        except (ValueError, IndexError):

            pass



        return base_inicial



    def _calcular_distribuicao_grade_especial(self, valor_grade, base_inicial, pos_parafusos, grade_letra, grade_num):

        """

        Calcula a distribuição dos detalhes usando exatamente a mesma lógica do Conjunto 1

        """

        print(f"   [DISTRIBUICAO] Calculando distribuição para Grade {grade_letra.upper()}{grade_num}...")



        # Mesmo sistema de estratégias do Conjunto 1

        estrategias = [

            self._calcular_distribuicao_equilibrada,

            self._calcular_distribuicao_centro_maior,

            self._calcular_distribuicao_extremidades_maiores,

            self._calcular_distribuicao_alternada,

            self._calcular_distribuicao_crescente,

            self._calcular_distribuicao_decrescente

        ]



        melhor_distribuicao = None

        menor_conflitos = float('inf')



        for i, estrategia in enumerate(estrategias):

            try:

                distribuicao = estrategia(valor_grade)

                conflitos = self._contar_conflitos_distribuicao_especial(

                    distribuicao, base_inicial, pos_parafusos, grade_letra, grade_num

                )



                if conflitos < menor_conflitos:

                    menor_conflitos = conflitos

                    melhor_distribuicao = distribuicao



                    if conflitos == 0:

                        print(f"   [DISTRIBUICAO] ✅ Estratégia {i+1}: 0 conflitos - Perfeita!")

                        break

                    else:

                        print(f"   [DISTRIBUICAO] Estratégia {i+1}: {conflitos} conflitos")



            except Exception as e:

                print(f"   [DISTRIBUICAO] Erro na estratégia {i+1}: {e}")

                continue



        if melhor_distribuicao:

            soma_final = sum(melhor_distribuicao[:5])

            print(f"   [DISTRIBUICAO] Melhor distribuição: {menor_conflitos} conflitos, soma: {soma_final}")

            return melhor_distribuicao

        else:

            print(f"   [DISTRIBUICAO] ❌ Nenhuma estratégia funcionou")

            return None



    def _contar_conflitos_distribuicao_especial(self, distribuicao, base_inicial, pos_parafusos, grade_letra, grade_num):

        """

        Conta conflitos usando a mesma lógica do Conjunto 1, mas adaptada para grades especiais

        """

        try:

            conflitos = 0

            pos_acumulada = base_inicial

            tolerancia = 3  # ±3cm (mesma tolerância do Conjunto 1)



            for i, valor in enumerate(distribuicao[:5]):  # Apenas os primeiros 5 valores

                if valor > 0:

                    pos_acumulada += valor

                    for pos_parafuso in pos_parafusos:

                        if abs(pos_acumulada - pos_parafuso) <= tolerancia:

                            conflitos += 1


                            break



            return conflitos

        except Exception as e:

            pass

            return float('inf')



    def _aplicar_distribuicao_grade_especial(self, distribuicao, grade_letra, grade_num):

        """

        Aplica a distribuição calculada aos campos de detalhes da grade especial

        """

        try:




            for i, valor in enumerate(distribuicao[:5]):  # Apenas os primeiros 5 valores

                campo_detalhe = f"detalhe_{grade_letra}_{grade_num}_{i+1}"



                if hasattr(self, campo_detalhe):

                    campo = getattr(self, campo_detalhe)

                    campo.delete(0, tk.END)



                    if valor > 0:

                        campo.insert(0, f"{int(valor)}")

                        print(f"   [APLICAR] {campo_detalhe}: {int(valor)}cm")

                    else:

                        pass



        except Exception as e:

            pass



