    def verificar_colisao_detalhes_com_parafusos(self, grade_letra, grade_num, parafusos):

        """

        Verifica se os detalhes da grade colidem com os parafusos e atualiza cores

        """

        try:

            # Obter detalhes da grade

            detalhes = []

            for j in range(1, 6):

                campo_nome = f"detalhe_{grade_letra.lower()}_{grade_num}_{j}"

                if hasattr(self, campo_nome):

                    campo = getattr(self, campo_nome)

                    valor = campo.get().strip()

                    if valor:

                        detalhes.append((float(valor), campo))

                    else:

                        detalhes.append((0, campo))

            

            # Calcular posições dos detalhes (cumulativa)

            pos_detalhes = []

            pos_acumulada = 0

            for valor, campo in detalhes:

                if valor > 0:

                    pos_acumulada += valor

                    pos_detalhes.append((pos_acumulada, campo))

            

            # Calcular posições dos parafusos (cumulativa)

            pos_parafusos = []

            pos_acumulada = 0

            for parafuso in parafusos:

                pos_acumulada += parafuso

                pos_parafusos.append(pos_acumulada)

            

            # Verificar colisões (tolerância de ±3cm)

            tolerancia = 3

            

            for pos_detalhe, campo in pos_detalhes:

                tem_colisao = False

                for pos_parafuso in pos_parafusos:

                    if abs(pos_detalhe - pos_parafuso) <= tolerancia:

                        tem_colisao = True

                        break

                

                # Atualizar cor do campo

                try:

                    if tem_colisao:

                        campo.configure(background='#ffcccc')  # Vermelho claro

                        print(f"[AVISO] Colisão detectada na posição {pos_detalhe}")

                    else:

                        campo.configure(background='white')  # Branco

                except:

                    pass  # Ignorar se não suportar configuração de cor

            

        except Exception as e:

            pass

    

    def aplicar_grades_especiais_proporcionais(self, grade_a_valor, grade_b_valor, grade_e_valor, grade_f_valor, modo_pline=True):

        """

        Aplica grades especiais com distribuição correta quando ultrapassam 106cm

        """

        try:


            print(f"[PROPORCIONAL]   Grade A: {grade_a_valor:.1f}cm")

            print(f"[PROPORCIONAL]   Grade B: {grade_b_valor:.1f}cm")

            print(f"[PROPORCIONAL]   Grade E: {grade_e_valor:.1f}cm")

            print(f"[PROPORCIONAL]   Grade F: {grade_f_valor:.1f}cm")

            

            # Aplicar Grade A com distribuição

            if grade_a_valor > 0:

                self._aplicar_grade_com_distribuicao('a', grade_a_valor)

            

            # Aplicar Grade B com distribuição

            if grade_b_valor > 0:

                self._aplicar_grade_com_distribuicao('b', grade_b_valor)



            # Aplicar Grade E com distribuição

            if grade_e_valor > 0:

                self._aplicar_grade_com_distribuicao('e', grade_e_valor)



            # Aplicar Grade F com distribuição (ajuste baseado no modo)
            if grade_f_valor > 0:
                if modo_pline:  # Modo NOVA - sem ajuste adicional
                    self._aplicar_grade_com_distribuicao('f', grade_f_valor)
                else:  # Modo INI - adicionar 3.6 na distribuição
                    self._aplicar_grade_com_distribuicao('f', grade_f_valor + 3.6)

                

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def _aplicar_grade_com_distribuicao(self, letra, valor_total):

        """

        Aplica uma grade com distribuição correta usando a mesma lógica da aba Dados Gerais

        SEMPRE LIMPA TODOS OS CAMPOS ANTES DE ATUALIZAR

        """

        try:

            print(f"[DISTRIBUICAO] Aplicando grade {letra.upper()} com valor {valor_total:.1f}cm")

            

            # LIMPEZA COMPLETA ANTES DE APLICAR NOVA DISTRIBUIÇÃO


            self.limpar_todos_campos_especiais([letra.lower()])

            

            # VERIFICAR SE É PILAR ESPECIAL - se for, aplicar regras específicas dos pilares especiais
            if self.ativar_pilar_especial.get():
                print(f"[DISTRIBUICAO] Modo pilar especial detectado - aplicando regras específicas para: {valor_total:.1f}cm")
                
                # Aplicar regras específicas dos pilares especiais:
                # 1. Até 106cm = 1 grade única
                # 2. Acima de 122cm = distribuir respeitando regras
                if valor_total <= 106.0:
                    pass
                    
                    # Aplicar valor diretamente na grade_1
                    campo_grade_1 = f"grade_{letra}_1"
                    if hasattr(self, campo_grade_1):
                        getattr(self, campo_grade_1).delete(0, tk.END)
                        getattr(self, campo_grade_1).insert(0, f"{valor_total:.1f}")
                    
                    # Limpar outras grades
                    for i in [2, 3]:
                        campo_grade = f"grade_{letra}_{i}"
                        if hasattr(self, campo_grade):
                            getattr(self, campo_grade).delete(0, tk.END)
                            getattr(self, campo_grade).insert(0, "")
                    
                    # Limpar distâncias
                    for i in [1, 2]:
                        campo_dist = f"dist_{letra}_{i}"
                        if hasattr(self, campo_dist):
                            getattr(self, campo_dist).delete(0, tk.END)
                            getattr(self, campo_dist).insert(0, "")
                else:
                    print(f"[DISTRIBUICAO] Grade {letra.upper()} ({valor_total:.1f}cm) > 106cm - DISTRIBUINDO com regras especiais")
                    
                    # Para valores > 106cm, usar distribuição normal mas com regras específicas
                    # Calcular distribuição respeitando máximo 106cm por grade
                    if valor_total <= 259.0:  # 2 grades (106 + 26 + 106 = 270, mas ajustamos para 259 para manter compatibilidade)
                        # Calcular tamanho ideal das grades (máximo 106cm cada)
                        tamanho_ideal = (valor_total - 26) / 2  # Subtrair distância de 26cm
                        tamanho_grade = min(106.0, tamanho_ideal)
                        
                        # Tentar encontrar múltiplos de 5 próximos ao tamanho ideal
                        tamanho_grade_arredondado = round(tamanho_grade / 5) * 5
                        if tamanho_grade_arredondado > 0:
                            tamanho_grade = min(106.0, tamanho_grade_arredondado)
                        
                        # Calcular distância
                        distancia = valor_total - (2 * tamanho_grade)
                        distancia = max(1.0, min(26.0, distancia))  # Entre 1 e 26cm
                        
                        
                        # Aplicar grade_1
                        campo_grade_1 = f"grade_{letra}_1"
                        if hasattr(self, campo_grade_1):
                            getattr(self, campo_grade_1).delete(0, tk.END)
                            getattr(self, campo_grade_1).insert(0, f"{tamanho_grade:.1f}")
                        
                        # Aplicar grade_2
                        campo_grade_2 = f"grade_{letra}_2"
                        if hasattr(self, campo_grade_2):
                            getattr(self, campo_grade_2).delete(0, tk.END)
                            getattr(self, campo_grade_2).insert(0, f"{tamanho_grade:.1f}")
                        
                        # Aplicar distância_1
                        campo_dist_1 = f"dist_{letra}_1"
                        if hasattr(self, campo_dist_1):
                            getattr(self, campo_dist_1).delete(0, tk.END)
                            getattr(self, campo_dist_1).insert(0, f"{distancia:.1f}")
                        
                        # Limpar grade_3 e dist_2
                        campo_grade_3 = f"grade_{letra}_3"
                        if hasattr(self, campo_grade_3):
                            getattr(self, campo_grade_3).delete(0, tk.END)
                            getattr(self, campo_grade_3).insert(0, "")
                        
                        campo_dist_2 = f"dist_{letra}_2"
                        if hasattr(self, campo_dist_2):
                            getattr(self, campo_dist_2).delete(0, tk.END)
                            getattr(self, campo_dist_2).insert(0, "")
                    else:  # 3 grades
                        # Calcular tamanho ideal das grades (máximo 106cm cada)
                        tamanho_ideal = (valor_total - 52) / 3  # Subtrair 2 distâncias de 26cm cada
                        tamanho_grade = min(106.0, tamanho_ideal)
                        
                        # Tentar encontrar múltiplos de 5 próximos ao tamanho ideal
                        tamanho_grade_arredondado = round(tamanho_grade / 5) * 5
                        if tamanho_grade_arredondado > 0:
                            tamanho_grade = min(106.0, tamanho_grade_arredondado)
                        
                        # Calcular distância
                        distancia = (valor_total - (3 * tamanho_grade)) / 2
                        distancia = max(1.0, min(26.0, distancia))  # Entre 1 e 26cm
                        
                        
                        # Aplicar todas as 3 grades
                        for i in [1, 2, 3]:
                            campo_grade = f"grade_{letra}_{i}"
                            if hasattr(self, campo_grade):
                                getattr(self, campo_grade).delete(0, tk.END)
                                getattr(self, campo_grade).insert(0, f"{tamanho_grade:.1f}")
                                print(f"[DISTRIBUICAO] ✅ Aplicado grade_{letra}_{i}: {tamanho_grade:.1f}cm")
                        
                        # Aplicar distâncias
                        for i in [1, 2]:
                            campo_dist = f"dist_{letra}_{i}"
                            if hasattr(self, campo_dist):
                                getattr(self, campo_dist).delete(0, tk.END)
                                getattr(self, campo_dist).insert(0, f"{distancia:.1f}")
                                print(f"[DISTRIBUICAO] ✅ Aplicado dist_{letra}_{i}: {distancia:.1f}cm")
                
                # Se for grade B especial, chamar aplicar_regras_nova para recalcular
                if letra.lower() == 'b' and self.ativar_pilar_especial.get():
                    print(f"[GRADE_B_ESPECIAL_DISTRIBUICAO] Grade B alterada - chamando aplicar_regras_nova")
                    try:
                        # Obter comprimento e largura atuais
                        comprimento = float(self.comprimento.get().replace(',', '.') or 0)
                        largura = float(self.largura.get().replace(',', '.') or 0)
                        # Chamar aplicar_regras_nova para recalcular o painel B
                        self.aplicar_regras_nova(comprimento + 22, largura)
                        print(f"[GRADE_B_ESPECIAL_DISTRIBUICAO] Larguras atualizadas via aplicar_regras_nova!")
                    except Exception as e:
                        print(f"[GRADE_B_ESPECIAL_DISTRIBUICAO] Erro ao atualizar larguras: {e}")
                        import traceback
                        traceback.print_exc()
                
                return

            # Usar a mesma lógica de calcular_grades_com_desvio_conflitos dos dados gerais

            num_grades, tamanho_grade, distancia = self.calcular_grades_com_desvio_conflitos(valor_total)

            
            # Definir variáveis para compatibilidade com o código existente
            num_grades_distribuicao = num_grades
            tamanho_grade_final = tamanho_grade
            distancia_1 = distancia
            distancia_2 = 0  # Será definida se necessário
            

            print(f"[DISTRIBUICAO] Grade {letra.upper()}: {num_grades} grades de {tamanho_grade}cm, distância: {distancia}cm")

            

            # Aplicar grade_1

            campo_grade_1 = f"grade_{letra}_1"

            if hasattr(self, campo_grade_1):

                getattr(self, campo_grade_1).delete(0, tk.END)

                getattr(self, campo_grade_1).insert(0, f"{tamanho_grade:.1f}")


            

            # Aplicar grade_2 se necessário

            if num_grades >= 2:

                campo_grade_2 = f"grade_{letra}_2"

                if hasattr(self, campo_grade_2):

                    getattr(self, campo_grade_2).delete(0, tk.END)

                    getattr(self, campo_grade_2).insert(0, f"{tamanho_grade:.1f}")

                    print(f"[DISTRIBUICAO] ✅ Aplicado grade_{letra}_2: {tamanho_grade:.1f}cm")

                

                # Aplicar distância 1

                campo_dist_1 = f"dist_{letra}_1"

                if hasattr(self, campo_dist_1):

                    getattr(self, campo_dist_1).delete(0, tk.END)

                    getattr(self, campo_dist_1).insert(0, f"{distancia:.1f}")

                    print(f"[DISTRIBUICAO] ✅ Aplicado dist_{letra}_1: {distancia:.1f}cm")

            

            # Aplicar grade_3 se necessário

            if num_grades >= 3:

                campo_grade_3 = f"grade_{letra}_3"

                if hasattr(self, campo_grade_3):

                    getattr(self, campo_grade_3).delete(0, tk.END)

                    getattr(self, campo_grade_3).insert(0, f"{tamanho_grade:.1f}")

                    print(f"[DISTRIBUICAO] ✅ Aplicado grade_{letra}_3: {tamanho_grade:.1f}cm")

                

                # Aplicar distância 2

                campo_dist_2 = f"dist_{letra}_2"

                if hasattr(self, campo_dist_2):

                    getattr(self, campo_dist_2).delete(0, tk.END)

                    getattr(self, campo_dist_2).insert(0, f"{distancia:.1f}")

                    print(f"[DISTRIBUICAO] ✅ Aplicado dist_{letra}_2: {distancia:.1f}cm")

            

            # Verificar soma total

            if num_grades == 1:

                soma_calculada = tamanho_grade

            elif num_grades == 2:

                soma_calculada = (2 * tamanho_grade) + distancia

            else:  # 3 grades

                soma_calculada = (3 * tamanho_grade) + (2 * distancia)

            

            print(f"[DISTRIBUICAO] Soma total: {soma_calculada:.1f}cm (valor original: {valor_total:.1f}cm)")

            

            # Verificar se a distribuição está correta

            diferenca = abs(soma_calculada - valor_total)

            if diferenca > 0.1:

                print(f"[DISTRIBUICAO] ⚠️ Diferença detectada: {diferenca:.1f}cm - Ajustando...")

                # Ajustar distância para compensar a diferença

                if num_grades_distribuicao == 2:

                    distancia_1 = distancia_1 + (valor_total - soma_calculada)

                    distancia_1 = max(1, min(15, distancia_1))

                    # Reaplicar distância ajustada

                    campo_dist_1 = f"dist_{letra}_1"

                    if hasattr(self, campo_dist_1):

                        getattr(self, campo_dist_1).delete(0, tk.END)

                        getattr(self, campo_dist_1).insert(0, f"{distancia_1:.1f}")

                        print(f"[DISTRIBUICAO] ✅ Distância ajustada: {distancia_1:.1f}cm")

                elif num_grades_distribuicao == 3:

                    ajuste = (valor_total - soma_calculada) / 2

                    distancia_1 = distancia_1 + ajuste

                    distancia_2 = distancia_2 + ajuste

                    distancia_1 = max(1, min(15, distancia_1))

                    distancia_2 = max(1, min(15, distancia_2))

                    # Reaplicar distâncias ajustadas

                    campo_dist_1 = f"dist_{letra}_1"

                    campo_dist_2 = f"dist_{letra}_2"

                    if hasattr(self, campo_dist_1):

                        getattr(self, campo_dist_1).delete(0, tk.END)

                        getattr(self, campo_dist_1).insert(0, f"{distancia_1:.1f}")

                    if hasattr(self, campo_dist_2):

                        getattr(self, campo_dist_2).delete(0, tk.END)

                        getattr(self, campo_dist_2).insert(0, f"{distancia_2:.1f}")

                    print(f"[DISTRIBUICAO] ✅ Distâncias ajustadas: {distancia_1:.1f}cm e {distancia_2:.1f}cm")

                

                # Recalcular soma

                soma_calculada = (num_grades_distribuicao * tamanho_grade_final) + distancia_1 + distancia_2

                print(f"[DISTRIBUICAO] Nova soma: {soma_calculada:.1f}cm")

            

            # Recalcular detalhes automaticamente para a primeira grade

            self._recalcular_detalhes_grade_automatico(letra, 1, tamanho_grade_final)


            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()



    def _recalcular_detalhes_grade_automatico(self, letra_grade, grade_num, valor_grade):

        """

        Função auxiliar para recalcular detalhes automaticamente quando uma grade é alterada

        SEMPRE LIMPA TODOS OS CAMPOS ANTES DE ATUALIZAR

        """

        try:

            print(f"[DETALHES-AUTO-PROG] Recalculando detalhes para grade {letra_grade.upper()}{grade_num} = {valor_grade}cm")

            

            # SEMPRE LIMPAR TODOS OS CAMPOS PRIMEIRO

            for j in range(1, 6):

                campo_detalhe = getattr(self, f"detalhe_{letra_grade.lower()}_{grade_num}_{j}", None)

                if campo_detalhe:

                    campo_detalhe.delete(0, tk.END)

                    campo_detalhe.insert(0, "0")

            

            if valor_grade > 0:

                # Calcular detalhes usando a lógica original

                detalhes = self.calcular_detalhes_com_logica_original(valor_grade)

                

                # Aplicar aos campos de detalhes

                for j in range(1, 6):

                    campo_detalhe = getattr(self, f"detalhe_{letra_grade.lower()}_{grade_num}_{j}", None)

                    if campo_detalhe:

                        # Aplicar o valor do detalhe (pode ser 0 se não for usado)

                        valor_detalhe = detalhes[j-1]

                        if valor_detalhe > 0:

                            campo_detalhe.delete(0, tk.END)

                            campo_detalhe.insert(0, str(round(valor_detalhe, 1)))

                

                print(f"[DETALHES-AUTO-PROG] ✅ Detalhes recalculados para grade {letra_grade.upper()}{grade_num}: {detalhes}")

            else:

                print(f"[DETALHES-AUTO-PROG] ⚠️ Valor da grade {letra_grade.upper()}{grade_num} é zero - campos limpos")

                

        except Exception as e:

            print(f"[DETALHES-AUTO-PROG] ❌ Erro ao recalcular detalhes automaticamente: {e}")

    

