    def _carregar_dados_pilar_especial(self, dados):

        """

        Carrega os dados do pilar especial salvos.

        Inclui checkboxes, radio buttons, campos de dimensões, grades, parafusos e detalhes.

        """

        try:

            dados_especiais = dados.get("pilar_especial", {})

            

            # Carregar checkbox ativar pilar especial

            ativar = dados_especiais.get("ativar_pilar_especial", False)

            self.ativar_pilar_especial.set(ativar)

            

            # Carregar tipo de pilar especial

            tipo = dados_especiais.get("tipo_pilar_especial", "L")

            self.tipo_pilar_especial.set(tipo)

            

            # Carregar modo de cálculo

            modo = dados_especiais.get("modo_calculo", "NOVA")

            self.modo_calculo.set(modo)

            # Sincronizar com tipo_distribuicao_largura da aba dados gerais
            if modo in ["NOVA", "INI"]:
                self.tipo_distribuicao_largura.set(modo)
                print(f"[CARREGAMENTO] Sincronizando modos: {modo}")

            

            # Carregar comprimentos

            comprimentos = dados_especiais.get("comprimentos", {})

            for campo, valor in comprimentos.items():

                if hasattr(self, campo):

                    widget = getattr(self, campo)

                    widget.delete(0, tk.END)

                    if valor:

                        widget.insert(0, str(valor))

            

            # Carregar larguras

            larguras = dados_especiais.get("larguras", {})

            for campo, valor in larguras.items():

                if hasattr(self, campo):

                    widget = getattr(self, campo)

                    widget.delete(0, tk.END)

                    if valor:

                        widget.insert(0, str(valor))

            

            # Carregar distância

            distancia = dados_especiais.get("distancia", "")

            if hasattr(self, 'distancia'):

                self.distancia.delete(0, tk.END)

                if distancia:

                    self.distancia.insert(0, str(distancia))

            

            # Carregar grades (A, B, E, F, G, H) - inclui grades e distâncias

            grades = dados_especiais.get("grades", {})

            for grade_key, valor in grades.items():

                if hasattr(self, grade_key):

                    widget = getattr(self, grade_key)

                    widget.delete(0, tk.END)

                    if valor:

                        widget.insert(0, str(valor))

            

            # Carregar detalhes das grades especiais

            detalhes_grades = dados_especiais.get("detalhes_grades_especiais", {})

            for detalhe_key, valor in detalhes_grades.items():

                if hasattr(self, detalhe_key):

                    widget = getattr(self, detalhe_key)

                    widget.delete(0, tk.END)

                    if valor:

                        widget.insert(0, str(valor))

            
            # Carregar altura dos detalhes das grades especiais
            altura_detalhes = dados_especiais.get("altura_detalhes_especiais", {})
            for altura_key, valor in altura_detalhes.items():
                if hasattr(self, altura_key):
                    widget = getattr(self, altura_key)
                    widget.delete(0, tk.END)
                    if valor:
                        widget.insert(0, str(valor))

            # Carregar parafusos (AB, EF, GH, GFH)

            parafusos = dados_especiais.get("parafusos", {})

            for prefixo, parafusos_grupo in parafusos.items():

                for parafuso_key, valor in parafusos_grupo.items():

                    if hasattr(self, parafuso_key):

                        widget = getattr(self, parafuso_key)

                        widget.delete(0, tk.END)

                        if valor:

                            widget.insert(0, str(valor))

            

            # Carregar NOVOS PARAFUSOS INDIVIDUAIS (A, B, E, F, G, H)

            parafusos_especiais = dados_especiais.get("parafusos_especiais", {})

            for letra, parafusos_grupo in parafusos_especiais.items():

                for parafuso_key, valor in parafusos_grupo.items():

                    if hasattr(self, parafuso_key):

                        widget = getattr(self, parafuso_key)

                        widget.delete(0, tk.END)

                        if valor:

                            widget.insert(0, str(valor))

            

            # Atualizar campos baseado no tipo

            self.atualizar_campos_pilares_especiais()

            

            # Se pilar especial estava ativo, ativar o checkbox do robô

            if ativar:

                pass

                self._ativar_checkbox_pilar_rotacionado(True)

            

            print(f"[INFO] Dados do pilar especial carregados:")

            print(f"   - Ativar: {ativar}")


            print(f"   - Grades carregadas: {len(grades)}")

            print(f"   - Detalhes carregados: {len(detalhes_grades)}")

            print(f"   - Grupos de parafusos: {len(parafusos)}")

            print(f"   - Parafusos especiais individuais: {len(parafusos_especiais)}")

            

        except Exception as e:

            pass

            # Em caso de erro, definir valores padrão

            self.ativar_pilar_especial.set(False)

            self.tipo_pilar_especial.set("L")

    

    def _ativar_checkbox_pilar_rotacionado(self, ativar):

        """

        Ativa ou desativa o checkbox "Pilar Rotacionado" no robô visão cima.

        """

        try:

            # Tentar usar a função global do robô visão cima

            from robots.Robo_Pilar_Visao_Cima import definir_checkbox_pilar_rotacionado

            sucesso = definir_checkbox_pilar_rotacionado(ativar)

            if sucesso:

                status = "ATIVADO" if ativar else "DESATIVADO"


            else:

                print("[AVISO] Robô visão cima não está ativo no momento")

                

        except ImportError:

            print("[AVISO] Não foi possível importar função do robô visão cima")

        except Exception as e:

            pass

    

    def calcular_perfis_metalicos_especiais_L(self):

        """

        Calcula perfis metálicos especiais para pilar tipo L conforme requirements 5.1 e 5.2:

        - Perfil Metálico A e B 1 SHALL ter tamanho reduzido em 47.5

        - Perfil Metálico A e B 1 SHALL começar 47.5 para a direita

        """

        try:


            

            # Obter valores atuais dos painéis A e B

            comp_1 = float(self.comp_1.get().replace(',', '.') or 0)

            comp_2 = float(self.comp_2.get().replace(',', '.') or 0)

            larg_1 = float(self.larg_1.get().replace(',', '.') or 0)

            larg_2 = float(self.larg_2.get().replace(',', '.') or 0)

            

            if comp_1 <= 0 or comp_2 <= 0:

                print("[AVISO] Valores de comprimento inválidos para cálculo de perfis metálicos")

                return

            

            # PILAR 1 - Metal B: tamanho reduzido em 47.5 e posição ajustada em -11

            # Conforme requirement 3.6: Metal B SHALL ter tamanho reduzido em 47.5 e posição ajustada em -11

            metal_b_1_tamanho = comp_1 - larg_2 - 18.5 + 11 - 47.5

            metal_b_1_posicao = -11

            

            # PILAR 2 - Metal A: valor "-47.5 + largura do 1 - 11"

            # Conforme requirement 4.4: METAL A SHALL ter valor "-47.5 + largura do 1 - 11"

            metal_a_2_valor = -47.5 + larg_1 - 11

            

            # Perfil Metálico A e B 1: tamanho reduzido em 47.5, começar 47.5 para a direita

            # Conforme requirements 5.1 e 5.2

            perfil_metalico_a_tamanho = comp_1 + 22 - 47.5

            perfil_metalico_b_tamanho = comp_1 - larg_2 - 18.5 + 11 - 47.5

            perfil_metalico_posicao_inicial = 47.5

            

            print(f"[ESTATISTICA] Perfis metálicos calculados:")

            print(f"   Metal B Pilar 1: tamanho={metal_b_1_tamanho}, posição={metal_b_1_posicao}")

            print(f"   Metal A Pilar 2: valor={metal_a_2_valor}")

            print(f"   Perfil Metálico A: tamanho={perfil_metalico_a_tamanho}, início={perfil_metalico_posicao_inicial}")

            print(f"   Perfil Metálico B: tamanho={perfil_metalico_b_tamanho}, início={perfil_metalico_posicao_inicial}")

            

            # Aplicar ajustes dos metais aos painéis correspondentes

            self.aplicar_ajustes_metais_pilar_especial_L(

                metal_b_1_tamanho, metal_b_1_posicao,

                metal_a_2_valor,

                perfil_metalico_a_tamanho, perfil_metalico_b_tamanho, perfil_metalico_posicao_inicial

            )

            


            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

    def aplicar_ajustes_metais_pilar_especial_L(self, metal_b_1_tamanho, metal_b_1_posicao,

                                               metal_a_2_valor, perfil_metalico_a_tamanho, 

                                               perfil_metalico_b_tamanho, perfil_metalico_posicao_inicial):

        """

        Aplica os ajustes dos metais aos painéis correspondentes para pilar especial tipo L.

        

        Os ajustes são aplicados através de modificações nas larguras dos painéis,

        que posteriormente são convertidas em coordenadas nos scripts.

        """

        try:


            

            # PILAR 1 - Metal B: aplicar ajuste ao painel B

            # Requirement 3.6: Metal B SHALL ter tamanho reduzido em 47.5 e posição ajustada em -11

            if metal_b_1_tamanho > 0:

                # Aplicar o tamanho ajustado ao painel B

                # COMENTADO: Não deve modificar painel B quando pilar especial ativo
                # self.aplicar_larguras_painel_especial('B', metal_b_1_tamanho)

                pass

                

                # Armazenar offset de posição para uso posterior nos scripts

                if not hasattr(self, 'offsets_metais'):

                    self.offsets_metais = {}

                self.offsets_metais['metal_b_1_posicao'] = metal_b_1_posicao


            

            # PILAR 2 - Metal A: aplicar ajuste ao painel F (que corresponde ao PAI.A do pilar 2)

            # Requirement 4.4: METAL A SHALL ter valor "-47.5 + largura do 1 - 11"

            if metal_a_2_valor != 0:  # Pode ser negativo

                # Para valores negativos, aplicar como offset

                if metal_a_2_valor < 0:

                    # Armazenar como offset para aplicação posterior

                    if not hasattr(self, 'offsets_metais'):

                        self.offsets_metais = {}

                    self.offsets_metais['metal_a_2_offset'] = metal_a_2_valor


                else:

                    # Se positivo, aplicar como largura

                    self.aplicar_larguras_painel_especial('F', metal_a_2_valor)


            

            # PERFIS METÁLICOS A e B: aplicar ajustes aos painéis A e B

            # Requirements 5.1 e 5.2: tamanho reduzido em 47.5, começar 47.5 para a direita

            if perfil_metalico_a_tamanho > 0:

                # Aplicar tamanho ajustado ao painel A

                # COMENTADO: Não deve modificar painel A quando pilar especial ativo
                # self.aplicar_larguras_painel_especial('A', perfil_metalico_a_tamanho)

                pass

                

                # Armazenar offset de posição inicial

                if not hasattr(self, 'offsets_metais'):

                    self.offsets_metais = {}

                self.offsets_metais['perfil_metalico_a_offset'] = perfil_metalico_posicao_inicial


            

            if perfil_metalico_b_tamanho > 0:

                # Aplicar tamanho ajustado ao painel B (adicional ao metal B do pilar 1)

                # Como o painel B já foi ajustado pelo metal B do pilar 1, vamos armazenar como offset adicional

                if not hasattr(self, 'offsets_metais'):

                    self.offsets_metais = {}

                self.offsets_metais['perfil_metalico_b_tamanho'] = perfil_metalico_b_tamanho

                self.offsets_metais['perfil_metalico_b_offset'] = perfil_metalico_posicao_inicial


            


            

            # Rastrear comunicação com o robô

            self.rastrear_comunicacao_metais_com_robo()

            

            # Enviar offsets para o robô

            self.enviar_offsets_metais_para_robo()

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

    

