    def _limpar_campos_especiais(self, tipo_calculo):

        """

        Limpa todos os campos relacionados ao tipo_calculo antes de aplicar novos valores

        """

        try:


            

            # Mapear tipo para letras das grades

            mapeamento_grades = {

                "ab": ["a", "b"],

                "ef": ["e", "f"]

            }

            

            grades = mapeamento_grades.get(tipo_calculo, [])

            

            # Limpar todos os campos para cada grade

            for letra in grades:

                # Limpar grades (1, 2, 3)

                for i in range(1, 4):

                    campo_nome = f"grade_{letra}_{i}"

                    if hasattr(self, campo_nome):

                        campo = getattr(self, campo_nome)

                        campo.delete(0, tk.END)


                

                # Limpar distâncias (1, 2)

                for i in range(1, 3):

                    campo_nome = f"dist_{letra}_{i}"

                    if hasattr(self, campo_nome):

                        campo = getattr(self, campo_nome)

                        campo.delete(0, tk.END)


                

                # Limpar detalhes (1 a 5) para todas as grades (1 a 3)

                for grade_num in range(1, 4):

                    for i in range(1, 6):

                        campo_nome = f"detalhe_{letra}_{grade_num}_{i}"

                        if hasattr(self, campo_nome):

                            campo = getattr(self, campo_nome)

                            campo.delete(0, tk.END)


            


            

        except Exception as e:

            print(f"[ERRO] Erro ao limpar campos: {e}")

            import traceback

            traceback.print_exc()



    def calcular_grades_com_desvio_conflitos(self, medida_total):

        """

        Calcula grades evitando conflitos com parafusos.

        Tenta usar a maior distância possível (até 15) e grades múltiplos de 5.

        

        Regras:

        1. Até 106cm: 1 grade única

        2. 106cm até 259cm: 2 grades (106 + 15 + 106 = 259)

        3. Acima de 259cm: 3 grades

        4. Grades: preferencialmente múltiplos de 5

        5. Tamanho máximo de grade: 106cm

        6. Distância máxima: 26cm (tentar usar o máximo possível)

        7. Soma exata: grades + distâncias = comprimento + 22

        """

        try:

            if not medida_total or float(medida_total) <= 0:

                return 0, 0, 0



            medida_total = float(medida_total)

            medida_total_ajustada = medida_total + 22  # Ajustar o comprimento



            # REGRA 1: Até 106cm = 1 grade única

            if medida_total_ajustada <= 106:

                return 1, medida_total_ajustada, 0



            # REGRA 2: 106cm até 270cm = 2 grades (106 + 26 + 106 = 270)

            elif medida_total_ajustada <= 270:

                # Tentar usar a maior distância possível (até 26)

                for distancia in range(26, 0, -1):  # Começar do 26 e ir diminuindo

                    # Calcular tamanho das grades

                    tamanho_grade = (medida_total_ajustada - distancia) / 2

                    

                    # Se o tamanho é maior que 106, continuar tentando

                    if tamanho_grade > 106:

                        continue

                    

                    # Tentar encontrar múltiplo de 5 mais próximo

                    tamanho_grade_mult5 = round(tamanho_grade / 5) * 5

                    

                    # Verificar se a combinação é válida

                    if tamanho_grade_mult5 > 0 and tamanho_grade_mult5 <= 106:

                        # Recalcular a distância para garantir soma exata

                        distancia_ajustada = medida_total_ajustada - (2 * tamanho_grade_mult5)

                        if 1 <= distancia_ajustada <= 26:

                            return 2, tamanho_grade_mult5, distancia_ajustada

                

                # Se não encontrou combinação com múltiplos de 5, usar valores exatos

                tamanho_grade = (medida_total_ajustada - 1) / 2  # Usar distância mínima

                if tamanho_grade <= 106:

                    return 2, tamanho_grade, 1

                else:

                    tamanho_grade = 106  # Usar tamanho máximo

                    distancia = medida_total_ajustada - (2 * tamanho_grade)

                    if 1 <= distancia <= 26:

                        return 2, tamanho_grade, distancia



            # REGRA 3: Acima de 270cm = 3 grades

            else:

                # Tentar usar a maior distância possível (até 26)

                for distancia in range(26, 0, -1):  # Começar do 26 e ir diminuindo

                    # Calcular tamanho das grades

                    tamanho_grade = (medida_total_ajustada - (2 * distancia)) / 3

                    

                    # Se o tamanho é maior que 106, continuar tentando

                    if tamanho_grade > 106:

                        continue

                    

                    # Tentar encontrar múltiplo de 5 mais próximo

                    tamanho_grade_mult5 = round(tamanho_grade / 5) * 5

                    

                    # Verificar se a combinação é válida

                    if tamanho_grade_mult5 > 0 and tamanho_grade_mult5 <= 106:

                        # Recalcular a distância para garantir soma exata

                        distancia_ajustada = (medida_total_ajustada - (3 * tamanho_grade_mult5)) / 2

                        if 1 <= distancia_ajustada <= 26:

                            return 3, tamanho_grade_mult5, distancia_ajustada

                

                # Se não encontrou combinação com múltiplos de 5, usar valores exatos

                tamanho_grade = (medida_total_ajustada - 2) / 3  # Usar distância mínima

                if tamanho_grade <= 106:

                    return 3, tamanho_grade, 1

                else:

                    tamanho_grade = 106  # Usar tamanho máximo

                    distancia = (medida_total_ajustada - (3 * tamanho_grade)) / 2

                    if 1 <= distancia <= 26:

                        return 3, tamanho_grade, distancia



            # Se nenhuma combinação funcionar, retornar erro


            return 0, 0, 0



        except Exception as e:

            pass

            return 0, 0, 0



    def _obter_posicoes_parafusos_especiais(self, grupo):

        """

        Obtém as posições dos parafusos especiais por grupo.

        grupo: 'a', 'b', 'e', 'f', 'g' ou 'h'

        """


        pos_parafusos = []

        prefixo = f"par_{grupo.lower()}_"  # Garantir que seja minúsculo

        


        

        # Verificar parafusos de 1 a 9

        for i in range(1, 10):

            campo_nome = f"{prefixo}{i}"

            campo = getattr(self, campo_nome, None)


            

            if campo:

                try:

                    valor_texto = campo.get()


                    

                    if valor_texto and valor_texto.strip():

                        valor = float(valor_texto)


                        if valor > 0:

                            pos_parafusos.append(valor)


                        else:

                            pass

                    else:

                        pass

                except Exception as e:

                    pass

            else:

                pass

        


        

        # Aplicar regra especial APENAS para parafusos E e F

        if prefixo.endswith('_e_') or prefixo.endswith('_f_'):

            resultado = pos_parafusos[:-1] if len(pos_parafusos) > 1 else []


        else:

            resultado = pos_parafusos


        

        return resultado



    def verificar_conflitos_detalhes_grade_especial(self, letra_grade):

        """

        Verifica conflitos dos detalhes de uma grade especial com seus respectivos parafusos.

        Usa a mesma lógica da aba dados gerais.

        letra_grade: A, B, E, F, G ou H

        """

        try:




            

            # Determinar qual grupo de parafusos usar

            grupo_parafusos = letra_grade.lower()  # Usar minúsculo para corresponder aos campos

            


            

            # Obter posições dos parafusos do grupo

            pos_parafusos = self._obter_posicoes_parafusos_especiais(grupo_parafusos)


            

            if not pos_parafusos:

                # Se não há parafusos, não há conflitos

                pass

                self._atualizar_cores_detalhes_grade_especial(letra_grade, {})

                return False

            

            # Calcular base inicial para esta grade (soma das grades anteriores)

            base_inicial = 0

            # Para grades especiais, a base inicial é 0 pois cada grade é independente

            

            # Obter valores dos detalhes de TODAS AS 3 GRADES e calcular posições

            detalhes = []

            posicoes_detalhes = []

            posicao_atual = base_inicial

            

            # Processar grades 1, 2 e 3

            for grade_num in range(1, 4):

                for i in range(1, 6):

                    entry = getattr(self, f"detalhe_{letra_grade.lower()}_{grade_num}_{i}", None)

                    if entry:

                        try:

                            valor = float(entry.get().replace(',', '.') or 0)

                            detalhes.append(valor)

                            if valor > 0:

                                posicao_atual += valor

                            posicoes_detalhes.append(posicao_atual)

                        except ValueError:

                            detalhes.append(0)

                            posicoes_detalhes.append(posicao_atual)

                else:

                    detalhes.append(0)

                    posicoes_detalhes.append(posicao_atual)

            

            # Verificar conflitos específicos por campo

            conflitos_por_campo = {}

            tolerancia = 3  # Tolerância de 3cm (mesma da aba dados gerais)

            




            

            for i in range(1, 6):

                conflitos_por_campo[i] = False

                if detalhes[i-1] > 0:  # Se o campo tem valor

                    posicao_detalhe = posicoes_detalhes[i-1]


                    

                    for pos_parafuso in pos_parafusos:

                        diferenca = abs(posicao_detalhe - pos_parafuso)


                        if diferenca <= tolerancia:

                            conflitos_por_campo[i] = True


                            break

                else:

                    pass

            

            # Atualizar cores dos campos


            self._atualizar_cores_detalhes_grade_especial(letra_grade, conflitos_por_campo)

            

            # Retornar se há algum conflito

            resultado = any(conflitos_por_campo.values())





            return resultado

            

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()

            return False



    def _atualizar_cores_detalhes_grade_especial(self, letra_grade, conflitos_por_campo):

        """Atualiza as cores dos campos de detalhes da grade especial baseado em conflitos específicos"""

        try:



            

            for i in range(1, 6):

                campo_nome = f"detalhe_{letra_grade.lower()}_1_{i}"

                entry = getattr(self, campo_nome, None)


                

                if entry:

                    # Verificar se este campo específico tem conflito

                    tem_conflito = conflitos_por_campo.get(i, False)

                    cor_fundo = "red" if tem_conflito else "white"


                    

                    # Usar a mesma lógica da aba "Dados Gerais" - configure(bg=cor_fundo)

                    entry.configure(bg=cor_fundo)


                else:

                    pass

                    

            # Contar quantos campos têm conflito

            campos_com_conflito = sum(1 for conflito in conflitos_por_campo.values() if conflito)

            if campos_com_conflito > 0:

                pass

            else:

                pass

                

        except Exception as e:

            pass

            import traceback

            traceback.print_exc()



